  // ── Semantic Memory Migration ────────────────────────────────────

  router.post('/semantic/migrate', async (req, res) => {
    if (!ctx.semanticMemory) { res.status(503).json({ error: 'Semantic memory not enabled' }); return; }
    try {
      const { MemoryMigrator } = await import('../memory/MemoryMigrator.js');
      const migrator = new MemoryMigrator({
        stateDir: ctx.config.stateDir,
        semanticMemory: ctx.semanticMemory,
      });

      const memoryMdPath = req.body?.memoryMdPath;
      const report = await migrator.migrateAll({ memoryMdPath });
      res.json(report);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : 'Migration failed' });
    }
  });

  router.post('/semantic/migrate/memory-md', async (req, res) => {
    if (!ctx.semanticMemory) { res.status(503).json({ error: 'Semantic memory not enabled' }); return; }
    try {
      const { MemoryMigrator } = await import('../memory/MemoryMigrator.js');
      const migrator = new MemoryMigrator({
        stateDir: ctx.config.stateDir,
        semanticMemory: ctx.semanticMemory,
      });

      const filePath = req.body?.filePath;
      if (!filePath) { res.status(400).json({ error: 'filePath required' }); return; }
      const report = await migrator.migrateMemoryMd(filePath);
      res.json(report);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : 'Migration failed' });
    }
  });

  router.post('/semantic/migrate/relationships', async (req, res) => {
    if (!ctx.semanticMemory) { res.status(503).json({ error: 'Semantic memory not enabled' }); return; }
    try {
      const { MemoryMigrator } = await import('../memory/MemoryMigrator.js');
      const migrator = new MemoryMigrator({
        stateDir: ctx.config.stateDir,
        semanticMemory: ctx.semanticMemory,
      });

      const report = await migrator.migrateRelationships();
      res.json(report);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : 'Migration failed' });
    }
  });

  router.post('/semantic/migrate/canonical-state', async (req, res) => {
    if (!ctx.semanticMemory) { res.status(503).json({ error: 'Semantic memory not enabled' }); return; }
    try {
      const { MemoryMigrator } = await import('../memory/MemoryMigrator.js');
      const migrator = new MemoryMigrator({
        stateDir: ctx.config.stateDir,
        semanticMemory: ctx.semanticMemory,
      });

      const report = await migrator.migrateCanonicalState();
      res.json(report);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : 'Migration failed' });
    }
  });

  router.post('/semantic/migrate/decisions', async (req, res) => {
    if (!ctx.semanticMemory) { res.status(503).json({ error: 'Semantic memory not enabled' }); return; }
    try {
      const { MemoryMigrator } = await import('../memory/MemoryMigrator.js');
      const migrator = new MemoryMigrator({
        stateDir: ctx.config.stateDir,
        semanticMemory: ctx.semanticMemory,
      });

      const report = await migrator.migrateDecisionJournal();
      res.json(report);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : 'Migration failed' });
    }
  });

  // ── Status ──────────────────────────────────────────────────────

  router.get('/status', (_req, res) => {
    // Read-only status — serve from the cache so a degraded shared tmux can't wedge /status
    // (and every concurrent request) on per-session sync isSessionAlive probes (A1 hardening).
    const sessions = ctx.sessionManager.getCachedRunningSessions().sessions;
    const schedulerStatus = ctx.scheduler?.getStatus() ?? null;

    res.json({
      sessions: {
        running: sessions.length,
        max: ctx.config.sessions.maxSessions,
        list: sessions.map(s => ({ id: s.id, name: s.name, jobSlug: s.jobSlug })),
      },
      scheduler: schedulerStatus,
    });
  });

  // ── Capabilities (Self-Discovery) ──────────────────────────────
  //
  // Returns a structured self-portrait of what this agent has available.
  // Agents should query this at session start rather than guessing
  // about what infrastructure exists.

  // ══ Scope-Accretion Completion Discipline ═══════════════════════════════
  // Spec: docs/specs/autonomous-scope-accretion-completion.md. The load-bearing
  // facts (what did this session create? did the verified operator ratify
  // deferral?) are computed SERVER-SIDE at the evaluate-completion chokepoint
  // from git truth + server-owned state — never transported from the session's
  // environment, never read from files the session routinely edits (R11/R12).
  // (The AutonomousRunStore instance is declared near the top of createRoutes
  // so the /hooks/events advisory-ledger hook can reference it.)

  const scopeAccretionMetric = (
    outcome: 'fired' | 'noop' | 'error' | 'shed',
    verdictId?: string,
    latencyMs?: number,
  ): void => {
    try {
      ctx.featureMetricsLedger?.record({ feature: 'scope-accretion', kind: 'event', outcome, verdictId, latencyMs });
    } catch { /* @silent-fallback-ok — observability must never break the gate path */ }
  };

  // Read-only git funnel for the sweep (R15: SafeGitExecutor.readSync verbs only).
  const scopeAccretionReadGit = (args: string[], cwd: string, timeoutMs?: number): string =>
    SafeGitExecutor.readSync(args, {
      cwd,
      operation: 'src/server/routes.ts:scope-accretion-sweep',
      timeout: timeoutMs ?? 4000,
    });

  const scopeAccretionEffective = (rec: AutonomousRunRecord): boolean =>
    rec.scopeAccretionOverride ? rec.scopeAccretionOverride.enabled : rec.scopeAccretion.enabled;

  /** Registration-time base roots (R13): the work_dir repo + the agent-home repo. */
  const deriveBaseRoots = (workDir: string): AutonomousRunRecord['baseRoots'] => {
    const resolveRepo = (dir: string): { root: string; sha: string } | null => {
      try {
        const root = scopeAccretionReadGit(['rev-parse', '--show-toplevel'], dir).trim();
        const sha = scopeAccretionReadGit(['rev-parse', 'HEAD'], root).trim();
        if (!root || !/^[0-9a-f]{7,40}$/.test(sha)) return null;
        return { root, sha };
      } catch {
        /* @silent-fallback-ok — a non-git workDir/agent-home is a legitimate shape:
           the sweep degrades to the porcelain-only best-effort root (spec §2.2),
           never a false hold and never a false done. */
        return null;
      }
    };
    const roots: AutonomousRunRecord['baseRoots'] = [];
    const wd = resolveRepo(workDir);
    const home = resolveRepo(ctx.config.projectDir);
    const sameRoot = wd && home && path.resolve(wd.root) === path.resolve(home.root);
    if (wd) {
      // R48: if the run's work_dir IS the shared agent-home clone, HEAD-only
      // attribution wins (concurrent sessions must not hold this run).
      roots.push({ root: wd.root, startSha: wd.sha, shared: !!sameRoot });
    } else {
      roots.push({ root: workDir, startSha: null, shared: false });
    }
    if (home && !sameRoot) roots.push({ root: home.root, startSha: home.sha, shared: true });
    return roots;
  };

  interface AccretionComputation {
    rec: AutonomousRunRecord;
    sweep: SweepResult;
    unbuilt: AccretedArtifact[];
    clearedCount: number;
    degraded: boolean;
  }

  /** §2.8 steps 1: sweep (R31) + corroboration (R21) + persistence (monotone). */
  const computeAccretion = (rec: AutonomousRunRecord): AccretionComputation => {
    const sweep = runAccretionSweep(rec, {
      readGit: scopeAccretionReadGit,
      worktreesDir: path.join(ctx.config.projectDir, '.worktrees'),
    });
    const declared = parseDeclaredDeliverables(rec.condition, rec.declaredDeliverables);
    const preliminary = computeUnbuiltSet(sweep, declared, rec.ratifiedArtifacts, rec.corroborated);
    const negativeCached = new Set(
      preliminary.filter((a) => autonomousRunStore.isNegativeCached(rec, a.path)).map((a) => a.path),
    );
    const artifactStartShas: Record<string, string | null> = {};
    for (const b of rec.baseRoots) artifactStartShas[path.resolve(b.root)] = b.startSha;
    for (const [wt, sha] of Object.entries({ ...rec.worktreeFirstSeen, ...sweep.newWorktrees })) {
      artifactStartShas[path.resolve(wt)] = sha;
    }
    const corr = resolveCorroboration(
      {
        artifacts: preliminary,
        alreadyCorroborated: rec.corroborated,
        negativeCached,
        startedAt: rec.startedAt,
        workDir: rec.workDir,
        artifactStartShas,
      } as Parameters<typeof resolveCorroboration>[0],
      {
        // gh resolves the repo from its cwd — pin it to the run's registered
        // work_dir so merged-PR evidence is queried against the run's OWN repo.
        // withSyncOp: judge-path-only, `-m`-bounded (R22) — funneled so the
        // in-flight marker sees the blocking call (tmux-event-loop-resilience).
        runGh: (args: string[], timeoutMs: number) =>
          withSyncOp(() => execFileSync('gh', args, { cwd: rec.workDir, timeout: timeoutMs, encoding: 'utf8', maxBuffer: 10 * 1024 * 1024 }) as string),
        readGit: scopeAccretionReadGit,
        fsExists: (p: string) => fs.existsSync(p),
        conformanceInvocationsInWindow: (slug, a, b) =>
          autonomousRunStore.conformanceInvocationsInWindow(slug, a, b),
      },
    );
    const nowIso = new Date().toISOString();
    const updated =
      autonomousRunStore.update(rec.topicId, rec.runId, (r) => {
        for (const [p, ev] of Object.entries(corr.cleared)) {
          if (!r.corroborated[p]) r.corroborated[p] = { by: ev.by, at: nowIso, detail: ev.detail };
          delete r.negativeCache[p];
        }
        for (const p of corr.newNegatives) r.negativeCache[p] = nowIso;
        for (const [wt, sha] of Object.entries(sweep.newWorktrees)) {
          if (!r.worktreeFirstSeen[wt]) r.worktreeFirstSeen[wt] = sha;
        }
      }) ?? rec;
    const unbuilt = computeUnbuiltSet(sweep, declared, updated.ratifiedArtifacts, updated.corroborated);
    const final =
      autonomousRunStore.update(rec.topicId, rec.runId, (r) => {
        const prior = new Map(r.lastUnbuilt.map((u) => [u.path, u.firstSeenAt]));
        r.lastUnbuilt = unbuilt.map((a) => ({
          path: a.path,
          cls: a.cls,
          deleted: a.deleted,
          firstSeenAt: prior.get(a.path) ?? nowIso,
        }));
        r.lastSweepAt = nowIso;
      }) ?? updated;
    const clearedCount = Object.keys(final.corroborated).length + final.ratifiedArtifacts.length;
    return { rec: final, sweep, unbuilt, clearedCount, degraded: sweep.degraded || corr.degraded };
  };

  const clampPathList = (paths: string[], limit = 50): string => {
    const shown = paths.slice(0, limit);
    const more = paths.length - shown.length;
    return shown.join(', ') + (more > 0 ? ` — and ${more} more` : '');
  };

  /**
   * EVERY exit is loud (R40): enumerate a non-empty unbuilt accreted set in the
   * end-of-run notice + ONE deduped attention item. Best-effort, never blocks.
   */
  const enumerateUnbuiltLoudly = async (
    rec: AutonomousRunRecord,
    unbuilt: Array<{ path: string; deleted: boolean }>,
    surface: string,
    extra?: string,
  ): Promise<void> => {
    if (unbuilt.length === 0) return;
    const paths = unbuilt.map((u) => u.path);
    const deleted = unbuilt.filter((u) => u.deleted).map((u) => u.path);
    const deletedNote = deleted.length
      ? ` The session DELETED ${deleted.length} accreted deliverable(s): ${clampPathList(deleted, 20)}.`
      : '';
    const text =
      `⚠️ Autonomous run on topic ${rec.topicId} ended (${surface}) with ${paths.length} unbuilt accreted ` +
      `artifact(s) that were neither built, corroborated, nor ratified: ${clampPathList(paths)}.${deletedNote}` +
      (extra ? ` ${extra}` : '');
    const topicNum = Number(rec.topicId);
    if (ctx.telegram && Number.isFinite(topicNum)) {
      await ctx.telegram.sendToTopic(topicNum, text).catch(() => { /* best-effort notice */ });
      await ctx.telegram
        .createAttentionItem({
          id: `scope-accretion-exit-${rec.topicId}-${rec.runId}`,
          title: `Autonomous run left ${paths.length} accreted artifact(s) unbuilt`,
          summary: text.slice(0, 1000),
          priority: 'NORMAL',
          sourceContext: 'scope-accretion',
          category: 'autonomous',
        })
        .catch(() => { /* best-effort attention */ });
    }
    scopeAccretionMetric('fired', `exit-enumeration:${surface}`);
  };

  /** R28b daily-sweep backstop — reaped crashed records get their loud enumeration. */
  const runDailySweepBackstop = (): void => {
    try {
      const reaped = autonomousRunStore.dailySweep();
      for (const rec of reaped) {
        void enumerateUnbuiltLoudly(
          rec,
          rec.lastUnbuilt ?? [],
          'expired >24h ago (daily-sweep backstop)',
          'Late-but-loud: the run ended without a run-end call.',
        );
      }
    } catch { /* @silent-fallback-ok — the backstop is best-effort; the next call retries */ }
  };

  // Conversational ratification (R37/R38/R45) — trigger + confirmation matched
  // ONLY at the live receive path; server-authored enumeration; server-owned records.
  const scopeAccretionRatifier = new ScopeAccretionRatifier({
    store: autonomousRunStore,
    getOperatorUid: (topicId: number) => ctx.topicOperatorStore?.getOperator(topicId)?.uid ?? null,
    sendToTopic: async (topicId: number, text: string) => {
      if (!ctx.telegram) throw new Error('telegram adapter unavailable');
      const r = await ctx.telegram.sendToTopic(topicId, text);
      return { messageId: r.messageId };
    },
    dashboardLink: (topicId: string) =>
      `http://localhost:${ctx.config.port}/dashboard?ratify-deferral=${encodeURIComponent(topicId)}`,
    recordMetric: (o) => scopeAccretionMetric(o, 'ratification'),
    log: (m) => console.warn(m),
  });
  if (ctx.telegram) {
    // Direct-poll ingress (the server long-polls Telegram itself, R45). The
    // lifeline-forward ingress fires the same observer inside
    // POST /internal/telegram-forward below.
    ctx.telegram.onScopeAccretionInbound = (evt) => {
      void scopeAccretionRatifier.observeInbound(evt);
    };
  }

  // ── POST /autonomous/register (R30/R43/R49) — the server-side start snapshot ──
  // Bearer-auth like every /autonomous route (localhost trust plane — the setup
  // path is the intended caller; there is no finer ambient caller identity, R49).
  router.post('/autonomous/register', (req, res) => {
    runDailySweepBackstop();
    const body = (req.body ?? {}) as Record<string, unknown>;
    const topicId = typeof body.topicId === 'string' || typeof body.topicId === 'number' ? String(body.topicId) : '';
    const condition = typeof body.condition === 'string' ? body.condition : '';
    const workDir = typeof body.workDir === 'string' && body.workDir ? body.workDir : ctx.config.projectDir;
    if (!topicId || !condition) {
      res.status(400).json({ error: '"topicId" and "condition" (string) required' });
      return;
    }
    const declaredDeliverables = Array.isArray(body.declaredDeliverables)
      ? body.declaredDeliverables.filter((d): d is string => typeof d === 'string' && !!d.trim()).slice(0, 100)
      : [];
    const startedAt = typeof body.startedAt === 'string' && Number.isFinite(Date.parse(body.startedAt))
      ? body.startedAt
      : new Date().toISOString();
    const endAt = typeof body.endAt === 'string' ? body.endAt : undefined;
    const sessionId = typeof body.sessionId === 'string' && body.sessionId ? body.sessionId : undefined;
    // Snapshot the WHOLE scopeAccretion sub-object at registration (R13): the
    // session editing .instar/config.json mid-run changes nothing the
    // chokepoint reads. The operator's live lever is the PIN override (R14).
    const cfg = ctx.config.autonomousSessions?.completionDiscipline?.scopeAccretion ?? {};
    const snapshot = {
      enabled: cfg.enabled ?? true,
      breakerK: Math.max(2, typeof cfg.breakerK === 'number' && Number.isFinite(cfg.breakerK) ? Math.floor(cfg.breakerK) : 3),
    };
    const result = autonomousRunStore.register({
      topicId,
      condition,
      workDir,
      declaredDeliverables,
      startedAt,
      endAt,
      sessionId,
      scopeAccretion: snapshot,
      baseRoots: deriveBaseRoots(workDir),
      maxDurationMs: ctx.config.autonomousSessions?.maxDurationMs ?? 172_800_000,
    });
    if (!result.ok) {
      // One registration per active run (R43): refused + flagged.
      scopeAccretionMetric('noop', 'register-conflict');
      void ctx.telegram
        ?.createAttentionItem({
          id: `scope-accretion-reregister-${topicId}`,
          title: `Autonomous re-registration refused for topic ${topicId}`,
          summary: `A re-register arrived while run ${result.existingRunId} is still active and unexpired.`,
          priority: 'LOW',
          sourceContext: 'scope-accretion',
          category: 'autonomous',
        })
        .catch(() => { /* best-effort */ });
      res.status(409).json({ error: 'a run is already registered and active for this topic', existingRunId: result.existingRunId });
      return;
    }
    scopeAccretionMetric('fired', 'register');
    res.json({ runId: result.runId, endAt: result.endAt, clamped: result.clamped });
  });

  // ── POST /autonomous/:topic/run-end (R44) — every exit surface reports here ──
  // Best-effort, `-m`-bounded on the hook side, NEVER blocking or delaying the
  // exit: the handler runs the advisory sweep, composes the enumerated notice
  // (R40), and marks the record ended.
  router.post('/autonomous/:topic/run-end', async (req, res) => {
    runDailySweepBackstop();
    const topic = String(req.params.topic);
    const body = (req.body ?? {}) as Record<string, unknown>;
    const reason = typeof body.reason === 'string' ? body.reason.slice(0, 200) : 'run-end';
    const runId = typeof body.runId === 'string' ? body.runId : undefined;
    const rec = autonomousRunStore.getRecord(topic);
    if (!rec) {
      res.status(404).json({ ok: false, error: 'no registered run for topic' });
      return;
    }
    if (runId && rec.runId !== runId) {
      res.status(409).json({ ok: false, error: 'runId mismatch', currentRunId: rec.runId });
      return;
    }
    let unbuiltEnumerated = 0;
    if (scopeAccretionEffective(rec)) {
      try {
        const comp = computeAccretion(rec);
        if (comp.unbuilt.length > 0) {
          await enumerateUnbuiltLoudly(comp.rec, comp.unbuilt, `run-end: ${reason}`);
          unbuiltEnumerated = comp.unbuilt.length;
        }
      } catch (err) {
        // The advisory sweep must never block the exit (R44) — record + proceed.
        console.warn(`[scope-accretion] run-end sweep failed (exit proceeds): ${err instanceof Error ? err.message : String(err)}`);
        scopeAccretionMetric('error', 'run-end-sweep');
      }
    }
    autonomousRunStore.markTerminal(rec.topicId, rec.runId, 'ended', reason);
    res.json({ ok: true, runId: rec.runId, unbuiltEnumerated });
  });

  // ── POST /autonomous/:topic/ratify-deferral (R23 path 1 — PIN, phone-first) ──
  router.post('/autonomous/:topic/ratify-deferral', async (req, res) => {
    if (!checkMandatePin(req, res)) return;
    const topic = String(req.params.topic);
    const rec = autonomousRunStore.getRecord(topic);
    if (!rec || !autonomousRunStore.isActive(rec)) {
      res.status(404).json({ error: 'no ACTIVE registered run for topic' });
      return;
    }
    const body = (req.body ?? {}) as Record<string, unknown>;
    const all = body.all === true;
    const listed = Array.isArray(body.artifacts)
      ? body.artifacts.filter((a): a is string => typeof a === 'string' && !!a.trim())
      : [];
    if (!all && listed.length === 0) {
      res.status(400).json({ error: '"artifacts" (string[]) or "all": true required' });
      return;
    }
    // {all:true} ratifies the server's CURRENT unbuilt list at call time — the
    // response echoes exactly what was ratified (display authority = executed
    // authority). Re-sweep for freshness; fall back to the last persisted set.
    let current = rec.lastUnbuilt.map((u) => u.path);
    try {
      const comp = computeAccretion(rec);
      current = comp.unbuilt.map((a) => a.path);
    } catch { /* @silent-fallback-ok — the persisted lastUnbuilt set is the documented fallback */ }
    const ratified = all ? current : listed;
    autonomousRunStore.update(rec.topicId, rec.runId, (r) => {
      for (const p of ratified) {
        if (!r.ratifiedArtifacts.includes(p)) r.ratifiedArtifacts.push(p);
      }
      r.ratifications.push({ via: 'pin', at: new Date().toISOString(), artifacts: [...ratified] });
    });
    scopeAccretionMetric('fired', 'ratify-pin');
    res.json({ ok: true, ratified, runId: rec.runId });
  });

  // ── POST /autonomous/:topic/scope-accretion-override (R14 — the operator's
  // instant mid-run lever; dashboard-PIN-gated, audited, principal-verified) ──
  router.post('/autonomous/:topic/scope-accretion-override', (req, res) => {
    if (!checkMandatePin(req, res)) return;
    const topic = String(req.params.topic);
    const body = (req.body ?? {}) as Record<string, unknown>;
    if (typeof body.enabled !== 'boolean' || typeof body.reason !== 'string' || !body.reason.trim()) {
      res.status(400).json({ error: '"enabled" (boolean) and "reason" (string) required' });
      return;
    }
    const rec = autonomousRunStore.getRecord(topic);
    if (!rec) {
      res.status(404).json({ error: 'no registered run for topic' });
      return;
    }
    const enabled = body.enabled;
    autonomousRunStore.update(rec.topicId, rec.runId, (r) => {
      r.scopeAccretionOverride = { enabled, reason: String(body.reason).slice(0, 300), at: new Date().toISOString() };
    });
    console.log(`[scope-accretion] operator PIN override for topic ${topic}: enabled=${enabled} (${String(body.reason).slice(0, 120)})`);
    scopeAccretionMetric('fired', `override-${enabled ? 'enable' : 'disable'}`);
    res.json({ ok: true, topic, enabled, runId: rec.runId });
  });

  // ── Multi-session autonomy: list / start-gate / stop ──────────────────
  // Per-topic autonomous jobs live at .instar/autonomous/<topicId>.local.md.
  // These routes are the management surface; the stop hook is the per-session enforcer.
  router.get('/autonomous/sessions', (_req, res) => {
    res.json({ sessions: listAutonomousJobs(ctx.config.stateDir) });
  });

  // Level-triggered liveness reconciler status (spec: autonomous-liveness-reconciler.md).
  // 503 when dark/disabled (dev-gate resolves enablement); else the content-free
  // status (topic ids + counters + conditions — no topic content/paths/secrets).
  router.get('/autonomous/liveness', (_req, res) => {
    if (!ctx.autonomousLivenessReconciler) {
      res.status(503).json({ error: 'autonomous-liveness-reconciler not available on this agent' });
      return;
    }
    res.json(ctx.autonomousLivenessReconciler.status());
  });

  // ── Standby-Write Reconciliation (docs/specs/standby-write-reconciliation.md §6) ──
  // The observability surface: mode, per-domain admitted/refused/would-verdict
  // counters, recent typed refusals (minus hints), the ownership-index stats,
  // and the event-loop-lag gauge (the P2-6 attribution instrument). 503 when
  // the dev gate resolves dark (house rule).
  router.get('/write-admission', (_req, res) => {
    if (!ctx.writeAdmission) {
      res.status(503).json({ error: 'write-admission not available on this agent' });
      return;
    }
    res.json(ctx.writeAdmission.status());
  });

  // F2 Enforced Termination — external hard-stop status (spec: enforced-termination-watchdog.md).
  router.get('/autonomous/enforced-termination', (_req, res) => {
    if (!ctx.enforcedTerminationStatus) {
      res.status(503).json({ error: 'enforced-termination watchdog not available on this agent' });
      return;
    }
    res.json(ctx.enforcedTerminationStatus());
  });

  router.get('/autonomous/can-start', (req, res) => {
    const priority = req.query.priority as JobPriority | undefined;
    const maxConcurrent =
      ctx.config.autonomousSessions?.maxConcurrent ?? DEFAULT_MAX_CONCURRENT_AUTONOMOUS;
    const result = canStartAutonomousJob({
      stateDir: ctx.config.stateDir,
      maxConcurrent,
      priority,
      quotaCanStart: ctx.quotaTracker
        ? (p) => ctx.quotaTracker!.shouldSpawnSession(p)
        : undefined,
    });
    res.json(result);
  });

  router.post('/autonomous/stop-all', (_req, res) => {
    const result = stopAllAutonomousJobs(ctx.config.stateDir, ctx.state.getCoherenceJournal());
    // Emergency stop reaches the resume queue (reap-notify R2.7): the
    // queue-global pause flag is set (entries + states untouched, TTLs
    // frozen); the explicit unpause lever is POST /sessions/resume-queue/resume.
    try {
      ctx.resumeQueue?.pause('autonomous stop-all');
    } catch { /* the stop must succeed regardless */ }
    res.json({ ok: true, ...result });
  });

  router.post('/autonomous/sessions/:topic/stop', (req, res) => {
    const topic = req.params.topic;
    const stopped = stopAutonomousTopic(ctx.config.stateDir, topic, ctx.state.getCoherenceJournal());
    // An explicit per-topic stop cancels that topic's queued resumes (R2.7).
    try {
      const topicNum = Number(topic);
      if (Number.isFinite(topicNum)) ctx.resumeQueue?.cancelByTopic(topicNum);
      ctx.operatorStopRecorder?.(Number.isFinite(topicNum) ? topicNum : null);
    } catch { /* @silent-fallback-ok — an operator STOP must never fail because queue-cancel bookkeeping raised; an uncancelled entry is still recoverable via TTL + the cancel lever */ }
    res.status(stopped ? 200 : 404).json({ ok: stopped, topic });
  });

  // Parse the optional, backward-compatible `signals` (+ `stopKind`) object the
  // completion-discipline stop-hook sends (AUTONOMOUS-COMPLETION-DISCIPLINE.md
  // §2b.4 surface 2). Unknown/absent → undefined, so the evaluator omits the
  // OBJECTIVE-SIGNALS block and an OLD hook gets the identical verdict.
  const parseStopSignals = (body: unknown): StopSignals | undefined => {
    if (!body || typeof body !== 'object') return undefined;
    const raw = (body as Record<string, unknown>).signals;
    if (!raw || typeof raw !== 'object') return undefined;
    const s = raw as Record<string, unknown>;
    const out: StopSignals = {};
    if (typeof s.completionConditionMet === 'boolean') out.completionConditionMet = s.completionConditionMet;
    if (typeof s.uncheckedTaskCount === 'number' && Number.isFinite(s.uncheckedTaskCount)) out.uncheckedTaskCount = s.uncheckedTaskCount;
    if (s.taskStructure === 'has-tasks' || s.taskStructure === 'indeterminate') out.taskStructure = s.taskStructure;
    if (typeof s.milestoneRationalizationDetected === 'boolean') out.milestoneRationalizationDetected = s.milestoneRationalizationDetected;
    if (typeof s.injectionSuspected === 'boolean') out.injectionSuspected = s.injectionSuspected;
    // Scope-accretion: the advisory Layer-B boolean is the ONE new whitelisted
    // client field (R23). The BLOCKING inputs (`unbuiltAccretedArtifacts`,
    // `operatorRatifiedDeferral`, `scopeAccretion` facts) are computed inside
    // the route and NEVER accepted from the client — anything else on the
    // signals object is dropped here by construction.
    if (typeof s.scopeAccretionSuspected === 'boolean') out.scopeAccretionSuspected = s.scopeAccretionSuspected;
    // stopKind may arrive either inside signals or as a sibling field of the body.
    const stopKind = s.stopKind ?? (body as Record<string, unknown>).stopKind;
    if (stopKind === 'hard-blocker') out.stopKind = 'hard-blocker';
    // Only return an object when at least one field is set, so a `{signals:{}}`
    // payload still behaves like no-signals (byte-identical prompt).
    return Object.keys(out).length > 0 ? out : undefined;
  };

  // Independent completion judge for the autonomous stop-hook (mirrors /goal):
  // given a verifiable condition + the recent transcript, decide met/not-met.
  // The hook treats 503/unreachable as "keep working" (fail-safe — never a false done).
  router.post('/autonomous/evaluate-completion', async (req, res) => {
    if (!ctx.completionEvaluator) {
      res.status(503).json({ error: 'No completion evaluator (IntelligenceProvider not configured)' });
      return;
    }
    const { condition, transcriptTail } = req.body ?? {};
    if (!condition || typeof condition !== 'string') {
      res.status(400).json({ error: '"condition" (string) required' });
      return;
    }
    try {
      const tail = typeof transcriptTail === 'string' ? transcriptTail : '';

      // ══ Scope-accretion deterministic pre-judge gate (R25/R35/R36) ══════════
      // Whitelist-validated identity fields — everything else on the body is ignored.
      const saBody = (req.body ?? {}) as Record<string, unknown>;
      const bodyTopicId =
        typeof saBody.topicId === 'string' || typeof saBody.topicId === 'number' ? String(saBody.topicId) : undefined;
      const bodyRunId = typeof saBody.runId === 'string' ? saBody.runId : undefined;
      const bodySessionId = typeof saBody.sessionId === 'string' ? saBody.sessionId : undefined;
      runDailySweepBackstop();

      // Arming is SERVER-resolved, never client-selected (R35): the sessionId↔
      // topicId map from registration, with the body topicId (verified against
      // the registration record below) as the direct carrier.
      let resolvedTopic = bodyTopicId;
      if (!resolvedTopic && bodySessionId) {
        resolvedTopic = autonomousRunStore.resolveSession(bodySessionId)?.topicId;
      }

      let armedRecord: AutonomousRunRecord | null = null;
      if (!resolvedTopic) {
        const active = autonomousRunStore.listActive();
        if (active.length > 0) {
          // A done-claim with NO resolvable topic while registered runs are
          // active is REFUSED (R35). Version-skew vs tamper is distinguished by
          // the migration marker state of the DEPLOYED hook: a pre-migration
          // hook (no SCOPE_ACCRETION marker) is skew; a post-migration omission
          // is tamper-shaped and says so.
          let postMigration = false;
          try {
            const deployedHook = path.join(
              ctx.config.projectDir,
              '.claude', 'skills', 'autonomous', 'hooks', 'autonomous-stop-hook.sh',
            );
            postMigration = fs.readFileSync(deployedHook, 'utf8').includes('SCOPE_ACCRETION');
          } catch { /* @silent-fallback-ok — unreadable hook ⇒ treat as skew (the softer message) */ }
          const shape = postMigration
            ? 'the installed stop hook DOES carry the scope-accretion capability, so an omitted topicId is tamper-shaped'
            : 'the installed stop hook looks pre-migration (version skew) — update instar / re-run the post-update migration';
          scopeAccretionMetric('fired', 'unattributed-done-claim');
          void ctx.telegram
            ?.createAttentionItem({
              id: 'scope-accretion-unattributed-done-claim',
              title: 'Unattributed autonomous done-claim refused',
              summary: `evaluate-completion was called with no topicId/runId while ${active.length} registered run(s) are active. ${shape}.`,
              priority: 'NORMAL',
              sourceContext: 'scope-accretion',
              category: 'autonomous',
            })
            .catch(() => { /* best-effort */ });
          res.json({
            met: false,
            reason: `unattributed-done-claim: ${active.length} registered autonomous run(s) are active on this server but the request carried no topicId/runId (${shape})`,
          });
          return;
        }
        // Zero active registered runs → a true legacy caller: gate inert, logged.
      } else {
        const byTopic = autonomousRunStore.getRecord(resolvedTopic);
        if (bodyRunId && byTopic && byTopic.runId !== bodyRunId && autonomousRunStore.isActive(byTopic)) {
          // runId cross-check (§6): a session presenting ANOTHER run's identifiers
          // is refused by the pair check.
          scopeAccretionMetric('fired', 'run-identity-mismatch');
          res.json({
            met: false,
            reason: `run-identity-mismatch: topic ${resolvedTopic} is registered to a different runId — the presented pair does not match the server's registration record`,
          });
          return;
        }
        if (byTopic && autonomousRunStore.isActive(byTopic)) {
          armedRecord = byTopic;
          if (bodySessionId) autonomousRunStore.mapSession(bodySessionId, byTopic.topicId, byTopic.runId);
        } else if (!byTopic) {
          console.log(`[scope-accretion] evaluate-completion for UNREGISTERED topic ${resolvedTopic} — accretion gate inert (honest degradation)`);
        }
      }

      // R36: when a run is registered, the judge evaluates the SERVER-REGISTERED
      // condition — the body condition is used only for legacy callers. A
      // divergence is logged + flagged once per run (closing the weakened-
      // condition bypass; mid-run state-file edits are ignored for accretion).
      let effectiveCondition = condition;
      if (armedRecord) {
        if (armedRecord.condition.trim() !== condition.trim()) {
          effectiveCondition = armedRecord.condition;
          if (!armedRecord.conditionDivergenceFlagged) {
            autonomousRunStore.update(armedRecord.topicId, armedRecord.runId, (r) => {
              r.conditionDivergenceFlagged = true;
            });
            console.warn(`[scope-accretion] condition divergence for topic ${armedRecord.topicId}: body condition differs from the registered text — judging the REGISTERED condition (R36)`);
            void ctx.telegram
              ?.createAttentionItem({
                id: `scope-accretion-condition-divergence-${armedRecord.topicId}-${armedRecord.runId}`,
                title: `Autonomous run condition diverged mid-run (topic ${armedRecord.topicId})`,
                summary: 'The done-claim carried a condition text different from the one registered at setup. The server judges the REGISTERED condition; mid-run edits are ignored for accretion purposes.',
                priority: 'NORMAL',
                sourceContext: 'scope-accretion',
                category: 'autonomous',
              })
              .catch(() => { /* @silent-fallback-ok — divergence-flag attention is best-effort observability; the REGISTERED condition is already the judged authority either way (R36) */ });
          } else {
            effectiveCondition = armedRecord.condition;
          }
        }
      }

      // §2.8 step 1-2: the deterministic gate — sweep + corroboration +
      // ratification state, then HOLD without spending the judge LLM call.
      let signals = parseStopSignals(req.body);
      if (armedRecord && scopeAccretionEffective(armedRecord)) {
        let comp: ReturnType<typeof computeAccretion> | null = null;
        try {
          comp = computeAccretion(armedRecord);
        } catch (err) {
          // A sweep failure degrades to NO HOLD (the judge still runs) — but is
          // recorded; it can never manufacture a false hold or a false done.
          console.warn(`[scope-accretion] sweep failed (gate degrades to judge-only): ${err instanceof Error ? err.message : String(err)}`);
          scopeAccretionMetric('error', 'sweep-failure');
        }
        if (comp) {
          scopeAccretionMetric(comp.unbuilt.length > 0 ? 'fired' : 'noop', 'sweep', comp.sweep.latencyMs);
          const unbuiltPaths = comp.unbuilt.map((a) => a.path);
          const deletedPaths = comp.unbuilt.filter((a) => a.deleted).map((a) => a.path);
          if (comp.unbuilt.length > 0) {
            // Breaker (R26): persisted server-side state; K consecutive holds
            // with an unchanged set hash and no new corroboration/ratification.
            const setHash = hashPathSet(unbuiltPaths);
            const k = Math.max(2, armedRecord.scopeAccretion.breakerK || 3);
            let rec2 = autonomousRunStore.getByPair(armedRecord.topicId, armedRecord.runId) ?? comp.rec;
            let tripped = rec2.breaker.tripped;
            if (!tripped) {
              rec2 =
                autonomousRunStore.update(armedRecord.topicId, armedRecord.runId, (r) => {
                  const nowIso = new Date().toISOString();
                  if (r.breaker.accretedSetHash === setHash && r.breaker.clearedCount === comp!.clearedCount) {
                    r.breaker.consecutiveHolds += 1;
                  } else {
                    r.breaker = {
                      accretedSetHash: setHash,
                      firstSeenAt: nowIso,
                      consecutiveHolds: 1,
                      lastProgressAt: nowIso,
                      clearedCount: comp!.clearedCount,
                      tripped: false,
                    };
                  }
                  if (r.breaker.consecutiveHolds >= k) {
                    r.breaker.tripped = true;
                    r.breaker.trippedAt = nowIso;
                  }
                }) ?? rec2;
              if (rec2.breaker.tripped) {
                tripped = true;
                // The loud, distinctly-labeled trip — carrying the P13 stop-
                // rationale classification verdict (recorded, never bypassed:
                // a `buildable` verdict is DISPLAYED so the operator sees the
                // evasion shape; the exit is still permitted — no wedge, R39).
                let p13Verdict = 'unavailable';
                try {
                  const v = await ctx.completionEvaluator.evaluateStopRationale(tail, {
                    ...(signals ?? {}),
                    stopKind: 'hard-blocker',
                  });
                  p13Verdict = v.classifiedBlocker ?? (v.stopAllowed ? 'allowed' : 'blocked');
                } catch { /* @silent-fallback-ok — classification is display-only on the trip; the trip itself is already decided */ }
                const tripText =
                  `exiting via scope-accretion breaker with ${unbuiltPaths.length} unbuilt accreted artifact(s): ` +
                  `${clampPathList(unbuiltPaths)}${deletedPaths.length ? ` (deleted: ${clampPathList(deletedPaths, 20)})` : ''} ` +
                  `— P13 classification: ${p13Verdict}`;
                scopeAccretionMetric('fired', 'breaker-trip');
                const topicNum = Number(armedRecord.topicId);
                if (ctx.telegram && Number.isFinite(topicNum)) {
                  await ctx.telegram.sendToTopic(topicNum, `⚠️ ${tripText}`).catch(() => { /* best-effort */ });
                  await ctx.telegram
                    .createAttentionItem({
                      id: `scope-accretion-breaker-${armedRecord.topicId}-${armedRecord.runId}`,
                      title: `Scope-accretion breaker tripped (topic ${armedRecord.topicId})`,
                      summary: tripText,
                      priority: 'HIGH',
                      sourceContext: 'scope-accretion',
                      category: 'autonomous',
                    })
                    .catch(() => { /* best-effort */ });
                }
              }
            }
            if (!tripped) {
              // The HOLD (R25): met:false with the machine-readable reason +
              // clamped path list, WITHOUT spending the judge LLM call. The
              // hook surfaces this verbatim — the session knows what to build.
              scopeAccretionMetric('fired', 'hold');
              res.json({
                met: false,
                reason:
                  `scope-accretion-hold: ${unbuiltPaths.length} accreted deliverable(s) this run created must be ` +
                  `built+corroborated (merged PR / converged report), declared, or operator-ratified before completion: ` +
                  `${clampPathList(unbuiltPaths)}` +
                  (deletedPaths.length ? ` — DELETED accreted deliverables (deletion is not an exit): ${clampPathList(deletedPaths, 20)}` : '') +
                  (comp.degraded ? ' [corroborationDegraded: merged-PR evidence could not be fully fetched this pass]' : ''),
                scopeAccretion: {
                  hold: true,
                  unbuilt: unbuiltPaths.slice(0, 50),
                  deleted: deletedPaths.slice(0, 20),
                  consecutiveHolds: rec2.breaker.consecutiveHolds,
                  breakerK: k,
                },
              });
              return;
            }
            // Post-trip (R39): the gate DISENGAGES for this run — fall through
            // to the judge exactly as today; the label was the deterrent.
          } else {
            // Progress (empty unbuilt set) resets the breaker counters.
            autonomousRunStore.update(armedRecord.topicId, armedRecord.runId, (r) => {
              if (!r.breaker.tripped && r.breaker.consecutiveHolds > 0) {
                r.breaker.consecutiveHolds = 0;
                r.breaker.accretedSetHash = '';
                r.breaker.lastProgressAt = new Date().toISOString();
              }
            });
          }
          // §2.8 step 3: the accretion facts ride along as CONTEXT lines in the
          // signals block (advisory corroboration for the judge's narrative
          // verdict) — gated on field presence so disabled mode is byte-identical.
          signals = {
            ...(signals ?? {}),
            scopeAccretion: {
              unbuilt: unbuiltPaths.slice(0, 50),
              deleted: deletedPaths.slice(0, 20),
              ratifiedCount: comp.rec.ratifiedArtifacts.length,
              corroborationDegraded: comp.degraded,
            },
          };
        }
      }

      const verdict = await ctx.completionEvaluator.evaluate(
        effectiveCondition,
        tail,
        signals,
      );
      // R43: a met:true final verdict at the chokepoint marks the server-owned
      // run record TERMINAL (subject to the live-test veto below, which can
      // still flip met → false — terminality is recorded only on the verdict
      // that actually leaves this handler as met:true).
      const markMetTerminal = (): void => {
        if (armedRecord && autonomousRunStore.isActive(armedRecord)) {
          autonomousRunStore.markTerminal(armedRecord.topicId, armedRecord.runId, 'met', 'met:true final verdict');
        }
      };
      // ── Live-user-channel-proof veto (spec §4) ──────────────────────────────
      // A deterministic post-check on a met:true verdict: a USER-FACING feature
      // cannot resolve "done" without a verified live-test artifact. Same shape as
      // the anti-laundering veto — filing/claiming "done" never buys the exit.
      // dry-run/warn COMPUTE the veto (telemetry) but never override; only veto-mode
      // overrides met:true → met:false (the safe direction — keep working).
      if (verdict.met && ctx.liveTestGate) {
        try {
          const body = (req.body ?? {}) as { featureId?: unknown; userFacing?: unknown };
          const featureId = typeof body.featureId === 'string' && body.featureId
            ? body.featureId
            : condition.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 80) || 'autonomous-goal';
          const userFacing = typeof body.userFacing === 'boolean' ? body.userFacing : undefined;
          const gate = ctx.liveTestGate.evaluate({ featureId, userFacing, goalText: condition, mode: ctx.liveTestGateMode });
          if (gate.outcome !== 'allow') {
            if (gate.blocks) {
              res.json({ met: false, reason: `live-test gate: ${gate.reason}`, liveTestGate: { outcome: gate.outcome, mode: gate.mode, overrode: true } });
              return;
            }
            // dry-run / warn: surface the would-block but honor the original verdict.
            if (verdict.met) markMetTerminal();
            res.json({ ...verdict, liveTestGate: { outcome: gate.outcome, mode: gate.mode, wouldBlock: gate.wouldBlock, reason: gate.reason, overrode: false } });
            return;
          }
        } catch {
          // @silent-fallback-ok — a gate error must never trap a genuine completion
          // (the completion judge is the primary authority); fall through to the verdict.
        }
      }
      if (verdict.met) markMetTerminal();
      res.json(verdict);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // P13 "The Stop Reason Is the Work" guard for the autonomous stop-hook: given the
  // recent transcript (+ optional objective signals), decide whether a stop-attempt
  // is EARNED or rests on a judgment-call / needs-real-engineering deferral, and —
  // on a `stopKind:'hard-blocker'` request — classify the blocker external-vs-buildable.
  // Fail-open: the hook treats 503/unreachable/error and stopAllowed:true as permit —
  // a SECONDARY guard must never trap a genuine completion (the completion check is the
  // primary authority).
  //
  // Every response (allow / block / error / 503) carries `p13ProtocolVersion` so a
  // newer hook can tell a NEW server from a structurally-OLD one even when the verdict
  // itself is missing (a timeout). Spec §2b.4 surface 5 + §5 version-skew detection.
  router.post('/autonomous/evaluate-stop', async (req, res) => {
    if (!ctx.completionEvaluator) {
      res.status(503).json({ error: 'No completion evaluator (IntelligenceProvider not configured)', p13ProtocolVersion: P13_PROTOCOL_VERSION });
      return;
    }
    const { transcriptTail } = req.body ?? {};
    try {
      const verdict = await ctx.completionEvaluator.evaluateStopRationale(
        typeof transcriptTail === 'string' ? transcriptTail : '',
        parseStopSignals(req.body),
      );
      res.json({ ...verdict, p13ProtocolVersion: P13_PROTOCOL_VERSION });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err), p13ProtocolVersion: P13_PROTOCOL_VERSION });
    }
  });

  // Native /goal delegation (Phase 2): drive the framework's own /goal loop by
  // INJECTING the slash command into the session (instar's core mechanism —
  // SessionManager.sendInput / tmux send-keys), and mark the job goal_mode:native so
  // the stop-hook defers completion to native /goal (still enforcing emergency/duration).
  const resolveTopicSession = (topic: string): string | null => {
    try {
      const reg = JSON.parse(fs.readFileSync(path.join(ctx.config.stateDir, 'topic-session-registry.json'), 'utf8'));
      return (reg.topicToSession || {})[topic] ?? null;
    } catch { return null; }
  };
  const setGoalMode = (topic: string, mode: 'native' | '') => {
    const f = path.join(ctx.config.stateDir, 'autonomous', `${topic}.local.md`);
    if (!fs.existsSync(f)) return;
    let c = fs.readFileSync(f, 'utf8');
    c = /^goal_mode:/m.test(c) ? c.replace(/^goal_mode:.*$/m, `goal_mode: "${mode}"`)
                              : c.replace(/^(active:.*)$/m, `$1\ngoal_mode: "${mode}"`);
    fs.writeFileSync(f, c);
  };

  router.post('/autonomous/native-goal/set', (req, res) => {
    const { topicId, condition } = req.body ?? {};
    if (!topicId || !condition || typeof condition !== 'string') {
      res.status(400).json({ error: '"topicId" and "condition" (string) required' });
      return;
    }
    const tmux = resolveTopicSession(String(topicId));
    if (!tmux) { res.status(404).json({ error: `no session for topic ${topicId}` }); return; }
    const ok = ctx.sessionManager.sendInput(tmux, `/goal ${condition}`);
    if (ok) setGoalMode(String(topicId), 'native');
    res.status(ok ? 200 : 502).json({ ok, topicId, mode: ok ? 'native' : 'unchanged' });
  });

  router.post('/autonomous/native-goal/clear', (req, res) => {
    const { topicId } = req.body ?? {};
    if (!topicId) { res.status(400).json({ error: '"topicId" required' }); return; }
    const tmux = resolveTopicSession(String(topicId));
    if (!tmux) { res.status(404).json({ error: `no session for topic ${topicId}` }); return; }
    const ok = ctx.sessionManager.sendInput(tmux, '/goal clear');
    if (ok) setGoalMode(String(topicId), '');
    res.status(ok ? 200 : 502).json({ ok, topicId });
  });

  router.get('/capabilities', (_req, res) => {
    // /capabilities used to be a 440-line hand-curated object literal — the
    // documented self-discovery primitive, but the only structural enforcement
    // of "what should be in here" lived as policy in a unit-test allowlist.
    // PR #N moved both surfaces (the response builders AND the lint policy)
    // into src/server/CapabilityIndex.ts. Adding a new top-level route prefix
    // now fails CI until the author either claims it in CAPABILITY_INDEX or
    // adds it to INTERNAL_PREFIXES — the discoverability gap closes
    // structurally instead of relying on author memory.
    const projectDir = ctx.config.projectDir;
    const stateDir = ctx.config.stateDir;

    // Identity files
    const identityFiles: Record<string, boolean> = {
      'AGENT.md': fs.existsSync(path.join(stateDir, 'AGENT.md')),
      'USER.md': fs.existsSync(path.join(stateDir, 'USER.md')),
      'MEMORY.md': fs.existsSync(path.join(stateDir, 'MEMORY.md')),
    };

    // Scripts
    const scriptsDir = path.join(projectDir, '.claude', 'scripts');
    let scripts: string[] = [];
    if (fs.existsSync(scriptsDir)) {
      try {
        scripts = fs.readdirSync(scriptsDir).filter(f => !f.startsWith('.'));
      } catch { /* permission error, etc. */ }
    }

    // Hooks
    const hooksDir = path.join(stateDir, 'hooks');
    let hooks: string[] = [];
    if (fs.existsSync(hooksDir)) {
      try {
        hooks = fs.readdirSync(hooksDir).filter(f => !f.startsWith('.'));
      } catch { /* permission error, etc. */ }
    }

    const setupIntegrity = ProcessIntegrity.getInstance();
    const capabilityBlocks = buildAllCapabilityBlocks({ ctx, scripts, secretDrop });
    res.json({
      project: ctx.config.projectName,
      version: setupIntegrity?.runningVersion || ctx.config.version || '0.0.0',
      port: ctx.config.port,
      identity: identityFiles,
      scripts,
      hooks,
      ...capabilityBlocks,
    });
  });


  // ── Capability Map ──────────────────────────────────────────────────
  //
  // Hierarchical self-knowledge map with provenance tracking and drift detection.
  // Agents use this to understand their own features, skills, and integrations.

  router.get('/capability-map', async (req, res) => {
    if (!ctx.capabilityMapper) {
      res.status(501).json({ error: 'CapabilityMapper not initialized' });
      return;
    }

    try {
      const map = await ctx.capabilityMapper.getMap();
      const format = req.query.format;

      if (format === 'md' || format === 'markdown') {
        res.type('text/markdown').send(ctx.capabilityMapper.renderMarkdown(map, 2));
      } else if (format === 'compact') {
        res.type('text/markdown').send(ctx.capabilityMapper.renderMarkdown(map, 1));
      } else {
        res.json(map);
      }
    } catch (err) {
      res.status(500).json({
        error: 'SCAN_FAILED',
        message: err instanceof Error ? err.message : String(err),
      });
    }
  });

  router.get('/capability-map/drift', async (_req, res) => {
    if (!ctx.capabilityMapper) {
      res.status(501).json({ error: 'CapabilityMapper not initialized' });
      return;
    }

    try {
      const drift = await ctx.capabilityMapper.detectDrift();
      res.json(drift);
    } catch (err) {
      res.status(500).json({
        error: 'DRIFT_FAILED',
        message: err instanceof Error ? err.message : String(err),
      });
    }
  });

  router.get('/capability-map/:domain', async (req, res) => {
    if (!ctx.capabilityMapper) {
      res.status(501).json({ error: 'CapabilityMapper not initialized' });
      return;
    }

    try {
      const map = await ctx.capabilityMapper.getMap();
      const domain = map.domains.find(d => d.id === req.params.domain);

      if (!domain) {
        res.status(404).json({
          error: 'DOMAIN_NOT_FOUND',
          message: `Domain '${req.params.domain}' not found`,
          suggestion: `Available domains: ${map.domains.map(d => d.id).join(', ')}`,
        });
        return;
      }

      res.json(domain);
    } catch (err) {
      res.status(500).json({
        error: 'SCAN_FAILED',
        message: err instanceof Error ? err.message : String(err),
      });
    }
  });

  router.post('/capability-map/refresh', async (_req, res) => {
    if (!ctx.capabilityMapper) {
      res.status(501).json({ error: 'CapabilityMapper not initialized' });
      return;
    }

    try {
      const map = await ctx.capabilityMapper.refresh();
      res.status(202).json({
        status: 'completed',
        summary: map.summary,
        generatedAt: map.generatedAt,
      });
    } catch (err) {
      if (err instanceof Error && err.message === 'REFRESH_IN_PROGRESS') {
        res.status(409).json({
          error: 'REFRESH_IN_PROGRESS',
          message: 'A scan is already running',
          retryAfter: 10,
        });
        return;
      }
      res.status(500).json({
        error: 'REFRESH_FAILED',
        message: err instanceof Error ? err.message : String(err),
      });
    }
  });

  // ── Self-Knowledge Tree ────────────────────────────────────────────
  //
  // Tree-based agent self-knowledge with LLM triage, tiered caching,
  // and cross-layer synthesis. Agents use this to answer "who am I?"

  router.get('/self-knowledge/search', async (req, res) => {
    if (!ctx.selfKnowledgeTree) {
      res.status(501).json({ error: 'SelfKnowledgeTree not initialized' });
      return;
    }

    const query = req.query.q as string;
    if (!query) {
      res.status(400).json({ error: 'Missing required query parameter: q' });
      return;
    }

    try {
      const dryRun = req.query.dry_run === 'true';
      const maxBudget = req.query.maxTokens ? parseInt(req.query.maxTokens as string, 10) : undefined;
      if (dryRun) {
        const plan = await ctx.selfKnowledgeTree.dryRun(query);
        res.json(plan);
      } else {
        const result = await ctx.selfKnowledgeTree.search(query, { maxBudget });
        res.json(result);
      }
    } catch (err) {
      res.status(500).json({
        error: 'SEARCH_FAILED',
        message: err instanceof Error ? err.message : String(err),
      });
    }
  });

  router.get('/self-knowledge/validate', (_req, res) => {
    if (!ctx.selfKnowledgeTree) {
      res.status(501).json({ error: 'SelfKnowledgeTree not initialized' });
      return;
    }

    try {
      const validation = ctx.selfKnowledgeTree.validate();
      const cacheStats = ctx.selfKnowledgeTree.cacheStats();
      res.json({ ...validation, cacheStats });
    } catch (err) {
      res.status(500).json({
        error: 'VALIDATION_FAILED',
        message: err instanceof Error ? err.message : String(err),
      });
    }
  });

  router.get('/self-knowledge/health', (_req, res) => {
    if (!ctx.selfKnowledgeTree || !ctx.coverageAuditor) {
      res.status(501).json({ error: 'SelfKnowledgeTree not initialized' });
      return;
    }

    try {
      const config = ctx.selfKnowledgeTree.getConfig();
      if (!config) {
        res.json({ status: 'no_tree', message: 'Tree not generated yet' });
        return;
      }

      const validation = ctx.selfKnowledgeTree.validate();
      const health = ctx.coverageAuditor.healthSummary();
      const totalNodes = config.layers.reduce((s: number, l: { children: unknown[] }) => s + l.children.length, 0);
      const detectedPlatforms = ctx.coverageAuditor.detectPlatforms();
      const audit = ctx.coverageAuditor.audit(config, validation, detectedPlatforms);

      res.json({
        status: 'ok',
        totalNodes,
        coverageScore: validation.coverageScore,
        cacheHitRate: health.cacheHitRate,
        avgLatencyMs: health.avgLatencyMs,
        errorRate: health.errorRate,
        searchCount: health.searchCount,
        degradedSearches: health.degradedSearches,
        gaps: audit.gaps,
        warnings: validation.warnings.length,
        errors: validation.errors.length,
      });
    } catch (err) {
      res.status(500).json({
        error: 'HEALTH_CHECK_FAILED',
        message: err instanceof Error ? err.message : String(err),
      });
    }
  });

  router.get('/self-knowledge/tree', (_req, res) => {
    if (!ctx.selfKnowledgeTree) {
      res.status(501).json({ error: 'SelfKnowledgeTree not initialized' });
      return;
    }

    const config = ctx.selfKnowledgeTree.getConfig();
    if (!config) {
      res.status(404).json({ error: 'Tree not generated yet' });
      return;
    }

    res.json(config);
  });

  // ── Project Map ───────────────────────────────────────────────────
  //
  // Auto-generated territory map of the project structure. Agents use this
  // for spatial awareness — "where am I and what does this project look like?"

  router.get('/project-map', (_req, res) => {
    if (!ctx.projectMapper) {
      res.status(501).json({ error: 'ProjectMapper not initialized' });
      return;
    }

    // Try to load saved map first; generate if missing
    let map = ctx.projectMapper.loadSavedMap();
    if (!map) {
      map = ctx.projectMapper.generateAndSave();
    }

    const format = _req.query.format;
    if (format === 'markdown') {
      res.type('text/markdown').send(ctx.projectMapper.toMarkdown(map));
    } else if (format === 'compact') {
      res.type('text/plain').send(ctx.projectMapper.getCompactSummary(map));
    } else {
      res.json(map);
    }
  });

  // Cartographer doc-tree — hierarchical, semantic map of the codebase with
  // git-hash staleness derivation (cartographer-doc-tree-schema spec #1). Ships
  // dark behind cartographer.enabled (503 when disabled). Read-only — authoring
  // is in-process only.
  //
  // fix instar#1069: NO request path runs an O(nodeCount)/67MB synchronous op on
  // the event loop. /health + /stale serve the per-host SNAPSHOT the sweep writes;
  // /tree is byte-bounded (too-large-for-request above the ceiling); the lazy
  // scaffold()/loadIndex() preamble is GONE (routes serve indexState:'not-built'
  // when no index exists — the boot-path chunked scaffold builds it off-request).
  // The Slice-5 callsite lint forbids loadIndex/staleNodes/freshnessHealth/scaffold
  // here, so this regression cannot return by accident.

  /** Snapshot-enum + provenance, computed cheaply (one `git rev-parse --short HEAD`). */
  const cartoSnapshotMeta = (
    snap: import('../core/cartographerDetect.js').CartographerSnapshot | null,
  ): { snapshot: 'present' | 'absent' | 'detect-failing'; snapshotStale: boolean; ageMs: number | null; headMoved: boolean; lastDetectStatus: string | null; lastDetectAt: string | null; headSha: string | null } => {
    if (!snap) {
      return { snapshot: 'absent', snapshotStale: true, ageMs: null, headMoved: false, lastDetectStatus: null, lastDetectAt: null, headSha: null };
    }
    const currentHead = ctx.cartographer ? ctx.cartographer.currentHeadShort() : null;
    const headMoved = snap.headSha != null && currentHead != null && snap.headSha !== currentHead;
    const ageMs = snap.generatedAt ? Math.max(0, Date.now() - Date.parse(snap.generatedAt)) : null;
    const failing = snap.lastDetectStatus !== 'ok';
    return {
      snapshot: failing ? 'detect-failing' : 'present',
      snapshotStale: headMoved || failing,
      ageMs,
      headMoved,
      lastDetectStatus: snap.lastDetectStatus,
      lastDetectAt: snap.lastDetectAt,
      headSha: snap.headSha,
    };
  };

  router.get('/cartographer/tree', (req, res) => {
    if (!ctx.cartographer) { res.status(503).json({ error: 'Cartographer not enabled' }); return; }
    const snap = ctx.cartographer.readSnapshot();
    if (req.query.format === 'compact') {
      // Cheap: nodeCount + generatedAt from the snapshot (no index parse).
      res.json({
        root: '',
        generatedAt: snap?.generatedAt ?? null,
        nodeCount: snap?.counts.nodeCount ?? 0,
        indexState: snap ? 'built' : 'not-built',
        ...cartoSnapshotMeta(snap),
      });
      return;
    }
    // Full index: byte-bounded so a huge tree never triggers the 67MB sync parse.
    const fsCfg = (ctx.config as { cartographer?: { freshnessSweep?: { maxRequestNodes?: number } } }).cartographer?.freshnessSweep;
    const maxRequestNodes = typeof fsCfg?.maxRequestNodes === 'number' ? fsCfg.maxRequestNodes : 50000;
    const byteCeiling = maxRequestNodes * 512; // generous per-entry estimate
    const loaded = ctx.cartographer.loadIndexBounded(byteCeiling);
    if (loaded.state === 'not-built') {
      res.json({ root: '', generatedAt: null, nodeCount: 0, indexState: 'not-built', ...cartoSnapshotMeta(snap) });
      return;
    }
    if (loaded.state === 'too-large') {
      res.json({
        indexState: 'too-large-for-request',
        nodeCount: snap?.counts.nodeCount ?? null,
        guidance: 'index too large to serve whole; use GET /cartographer/navigate?query=... for a bounded subtree',
        ...cartoSnapshotMeta(snap),
      });
      return;
    }
    res.json(loaded.index);
  });

  router.get('/cartographer/node', (req, res) => {
    if (!ctx.cartographer) { res.status(503).json({ error: 'Cartographer not enabled' }); return; }
    const p = typeof req.query.path === 'string' ? req.query.path : '';
    // Validate: repo-relative, no leading slash, no `..` segment. The validated
    // path indexes the in-memory node store — it never builds a filesystem path.
    if (p.startsWith('/') || p.split('/').includes('..')) {
      res.status(400).json({ error: 'invalid path' }); return;
    }
    // getNode reads ONE node file (O(1)) — no index parse, no scaffold preamble.
    const node = ctx.cartographer.getNode(p);
    if (!node) { res.status(404).json({ error: 'no such node', indexState: ctx.cartographer.readSnapshot() ? 'built' : 'not-built' }); return; }
    res.json(node);
  });

  router.get('/cartographer/stale', (_req, res) => {
    if (!ctx.cartographer) { res.status(503).json({ error: 'Cartographer not enabled' }); return; }
    const snap = ctx.cartographer.readSnapshot();
    const meta = cartoSnapshotMeta(snap);
    if (!snap) {
      res.json({ count: 0, nodes: [], total: 0, truncated: false, ...meta });
      return;
    }
    // Serve the bounded, secret-filtered sample with the honest total + truncation.
    const reasonFor = (s: string): string =>
      s === 'never-authored' ? 'no summary authored yet'
        : s === 'stale' ? 'code changed since the summary was authored'
          : s === 'path-gone' ? 'covered path no longer in HEAD' : '';
    const nodes = snap.staleSample.map((e) => ({ path: e.path, status: e.status, reason: reasonFor(e.status) }));
    res.json({ count: nodes.length, nodes, total: snap.staleTotal, truncated: snap.staleSampleTruncated, ...meta });
  });

  router.get('/cartographer/health', (_req, res) => {
    if (!ctx.cartographer) { res.status(503).json({ error: 'Cartographer not enabled' }); return; }
    const sweepCfg = (ctx.config as { cartographer?: { freshnessSweep?: { enabled?: boolean; cadenceMs?: number } } })
      .cartographer?.freshnessSweep;
    const snap = ctx.cartographer.readSnapshot();
    const meta = cartoSnapshotMeta(snap);
    // fix instar#1069: the entire freshness block is served from the SNAPSHOT — the
    // route never calls health()/freshnessHealth() (the request-thread starvers).
    // Legacy field names/semantics are preserved (additive contract); new fields
    // carry snapshot provenance so a stale/failing detect is visible on the route.
    if (!snap) {
      res.json({
        enabled: true,
        nodeCount: 0, authoredCount: 0, neverAuthoredCount: 0, staleCount: 0, generatedAt: null,
        freshness: {
          nodeCount: 0, authorableCount: 0, freshCount: 0, staleCount: 0, neverAuthoredCount: 0,
          neverAuthoredWithinGrace: 0, neverAuthoredPastGrace: 0, authorFailedCount: 0, freshRatio: 1, generatedAt: null,
        },
        sweepEnabled: sweepCfg?.enabled === true,
        ...meta,
      });
      return;
    }
    res.json({
      enabled: true,
      // Legacy health() fields, sourced from the snapshot:
      nodeCount: snap.counts.nodeCount,
      authoredCount: snap.counts.authoredCount,
      neverAuthoredCount: snap.counts.neverAuthored,
      staleCount: snap.counts.stale,
      generatedAt: snap.generatedAt,
      // Legacy freshnessHealth() block, sourced from the snapshot:
      freshness: snap.freshness,
      sweepEnabled: sweepCfg?.enabled === true,
      ...meta,
    });
  });

  // Tier-1 (inline opportunistic) write route (spec #2 — doc-freshness). The ONE
  // deliberate write surface: an agent that just edited code refreshes that node's
  // summary itself. Behind auth + BOTH gates (cartographer.enabled via the null
  // tree, AND freshnessSweep.enabled). Full path validation (incl. encoded
  // traversal) so it can only ever target a known scaffolded node, the SAME
  // deterministic quality bar as the sweep (no lower-validation backdoor),
  // instruction-shaped-content neutralization, and a modest write-rate bound.
  const cartoRefreshLog: number[] = [];
  router.post('/cartographer/node/refresh', (req, res) => {
    if (!ctx.cartographer) { res.status(503).json({ error: 'Cartographer not enabled' }); return; }
    const sweepCfg = (ctx.config as {
      cartographer?: { freshnessSweep?: { enabled?: boolean; minSummaryChars?: number; maxSummaryChars?: number; maxLeafBytes?: number } };
    }).cartographer?.freshnessSweep;
    if (!sweepCfg?.enabled) { res.status(503).json({ error: 'Cartographer freshness sweep not enabled' }); return; }

    // Write-rate bound (per-process): at most 30 inline refreshes / 60s.
    const nowMs = Date.now();
    while (cartoRefreshLog.length > 0 && nowMs - cartoRefreshLog[0] > 60_000) cartoRefreshLog.shift();
    if (cartoRefreshLog.length >= 30) { res.status(429).json({ error: 'refresh rate limit exceeded (30/min)' }); return; }

    const body = (req.body ?? {}) as { path?: unknown; summary?: unknown };
    const p = typeof body.path === 'string' ? body.path : '';
    const summaryRaw = typeof body.summary === 'string' ? body.summary : '';
    // Path validation parity with the sweep: repo-relative; no leading '/'; no '..'
    // segment; no encoded traversal; bounded length. A write route must never be
    // able to create an arbitrary file from request input.
    const decoded = (() => { try { return decodeURIComponent(p); } catch { return p; } })();
    const traversal = /(^|[\\/])\.\.([\\/]|$)/.test(p) || /(^|[\\/])\.\.([\\/]|$)/.test(decoded)
      || /%2e%2e/i.test(p) || /%2f/i.test(p);
    if (p.length > 1024 || p.startsWith('/') || p.includes('\\') || traversal) {
      res.status(400).json({ error: 'invalid path' }); return;
    }
    if (!summaryRaw || summaryRaw.length > 4096) { res.status(400).json({ error: 'invalid summary' }); return; }

    // fix instar#1069: no lazy scaffold()/loadIndex() preamble — getNode is a single
    // node-file read. An un-scaffolded node 400s (the boot scaffold builds the index).
    const node = ctx.cartographer.getNode(p);
    if (!node) { res.status(400).json({ error: 'no such node — only an existing scaffolded node can be refreshed' }); return; }

    const { text: neutralized } = neutralizeInstructionShapedContent(summaryRaw);
    // Covered symbols: leaf → committed content; dir → child summaries + basenames.
    let coveredSymbols: Set<string>;
    if (node.kind === 'file') {
      const read = ctx.cartographer.committedContent(p, sweepCfg.maxLeafBytes ?? 24576);
      coveredSymbols = extractCodeSymbols(read?.content ?? '');
    } else {
      const children = ctx.cartographer.getChildren(p);
      const basename = (s: string) => { const i = s.lastIndexOf('/'); return i >= 0 ? s.slice(i + 1) : s; };
      coveredSymbols = extractCodeSymbols(
        children.map((c) => c.summary).join('\n') + '\n' + children.map((c) => basename(c.path)).join(' '),
      );
    }
    const validation = validateSummaryDeterministic({
      summary: neutralized,
      minChars: sweepCfg.minSummaryChars ?? 24,
      maxChars: sweepCfg.maxSummaryChars ?? 600,
      coveredSymbols,
    });
    if (!validation.ok) { res.status(400).json({ error: validation.reason }); return; }

    ctx.cartographer.setSummary(p, neutralized.trim(), {
      provenance: { source: 'inline-agent' },
      meta: { lastAuthoredBy: 'inline-agent', confidence: 'medium' },
    });
    cartoRefreshLog.push(nowMs);
    res.json({ refreshed: true, path: p, status: ctx.cartographer.computeStaleness(p) });
  });

  // Subtree Navigation (cartographer-subtree-nav spec #5). Given a query, the
  // deterministic navigator walks the doc-tree's summaries top-down and returns the
  // minimal relevant subtree (paths to scope a sub-agent to). Read-only, observe-only,
  // zero egress (reads the local index/summaries only). Behind cartographer.enabled
  // (503 when off; lazy-scaffold) + Bearer-auth (inherited). NO path input is consumed
  // from the request — paths are PRODUCED, never taken — so there is no traversal
  // surface; only `query` (length-bounded) + the numeric bounds are validated.
  router.get('/cartographer/navigate', (req, res) => {
    if (!ctx.cartographer) { res.status(503).json({ error: 'Cartographer not enabled' }); return; }

    const query = typeof req.query.query === 'string' ? req.query.query : '';
    if (!query || query.trim().length === 0) { res.status(400).json({ error: 'missing query' }); return; }
    if (query.length > 2048) { res.status(400).json({ error: 'query too long (max 2048 chars)' }); return; }

    const navCfg = (ctx.config as {
      cartographer?: {
        subtreeNav?: {
          maxDepth?: number; branchingFactor?: number; maxNodesVisited?: number;
          maxResults?: number; minScore?: number; collapseFraction?: number;
        };
      };
    }).cartographer?.subtreeNav ?? {};

    // Optional per-request overrides for maxDepth/maxResults (the spec's documented
    // query params). Out-of-range or non-numeric → 400 (no silent clamp).
    const parseBound = (raw: unknown, lo: number, hi: number): number | null | undefined => {
      if (raw === undefined) return undefined; // not supplied → use config default
      const n = typeof raw === 'string' ? Number(raw) : NaN;
      if (!Number.isInteger(n) || n < lo || n > hi) return null; // invalid
      return n;
    };
    const maxDepthOverride = parseBound(req.query.maxDepth, 1, 32);
    const maxResultsOverride = parseBound(req.query.maxResults, 1, 500);
    if (maxDepthOverride === null) { res.status(400).json({ error: 'maxDepth out of range (1..32)' }); return; }
    if (maxResultsOverride === null) { res.status(400).json({ error: 'maxResults out of range (1..500)' }); return; }

    // fix instar#1069: no lazy scaffold()/loadIndex() preamble — the navigator is
    // bounded (maxNodesVisited) and returns an empty manifest when the root node is
    // absent (index not built yet); the boot-path scaffold builds it off-request.
    const manifest = cartographerNavigate(ctx.cartographer, query, {
      maxDepth: maxDepthOverride ?? navCfg.maxDepth,
      branchingFactor: navCfg.branchingFactor,
      maxNodesVisited: navCfg.maxNodesVisited,
      maxResults: maxResultsOverride ?? navCfg.maxResults,
      minScore: navCfg.minScore,
      collapseFraction: navCfg.collapseFraction,
    });
    res.json(manifest);
  });

  // Standards Enforcement-Coverage Audit (cartographer-conformance-audit spec #3).
  // For each constitutional standard in docs/STANDARDS-REGISTRY.md, verify whether
  // the structural guard its prose NAMES actually exists on disk, classify each
  // standard's enforcement strength, and surface the gaps + dangling refs.
  // Deterministic, observe-only, NON-gating. Gated behind BOTH ctx.cartographer
  // (cartographer.enabled) AND config.cartographer.conformanceAudit.enabled === true.
  // Owner-Bearer (the auth middleware) + the X-Instar-Request:1 intent header (the
  // honest control per the spec's security note — there is no PIN-scope primitive).
  // Lazily computes over config.projectDir + the on-disk registry; caches by inputHash
  // so an unchanged registry+repo short-circuits (the pass is deterministic + cheap).
  const conformanceGate = (req: ExpressRequest, res: ExpressResponse): boolean => {
    if (!ctx.cartographer) { res.status(503).json({ error: 'Cartographer not enabled' }); return false; }
    const cfg = (ctx.config as { cartographer?: { conformanceAudit?: { enabled?: boolean } } })
      .cartographer?.conformanceAudit;
    if (!resolveDevAgentGate(cfg?.enabled, ctx.config)) { res.status(503).json({ error: 'Conformance audit not enabled' }); return false; }
    if (req.headers['x-instar-request'] !== '1') {
      res.status(403).json({ error: 'GET /conformance/coverage requires the X-Instar-Request: 1 intent header' });
      return false;
    }
    return true;
  };
  let conformanceCache: StandardsCoverageReport | null = null;
  const conformanceReport = (): StandardsCoverageReport => {
    const registryPath = path.join(ctx.config.projectDir, 'docs', 'STANDARDS-REGISTRY.md');
    const report = computeStandardsCoverage({ registryPath, projectDir: ctx.config.projectDir }, conformanceCache);
    conformanceCache = report;
    return report;
  };

  router.get('/conformance/coverage', (req, res) => {
    if (!conformanceGate(req, res)) return;
    let report: StandardsCoverageReport;
    try { report = conformanceReport(); }
    catch (err) { res.status(500).json({ error: 'coverage compute failed', detail: err instanceof Error ? err.message : String(err) }); return; }

    let standards = report.standards;
    const family = typeof req.query.family === 'string' ? req.query.family : '';
    const kind = typeof req.query.kind === 'string' ? req.query.kind : '';
    const status = typeof req.query.status === 'string' ? req.query.status : '';
    if (family) standards = standards.filter((s) => s.family.toLowerCase() === family.toLowerCase());
    if (kind) standards = standards.filter((s) => s.enforcementKind === kind);
    if (status === 'gap') standards = standards.filter((s) => s.enforcementKind === 'documented-only');
    if (status === 'dangling') standards = standards.filter((s) => s.danglingRefs.length > 0);

    res.json({ generatedAt: report.generatedAt, summary: report.summary, count: standards.length, standards });
  });

  router.get('/conformance/coverage/health', (req, res) => {
    if (!conformanceGate(req, res)) return;
    let report: StandardsCoverageReport;
    try { report = conformanceReport(); }
    catch (err) { res.status(500).json({ error: 'coverage compute failed', detail: err instanceof Error ? err.message : String(err) }); return; }
    res.json({
      enabled: true,
      generatedAt: report.generatedAt,
      // The deterministic pass always converges — re-running on unchanged inputs is
      // byte-identical, so `converged` is structurally true.
      converged: true,
      ...report.summary,
    });
  });

  router.post('/project-map/refresh', (_req, res) => {
    if (!ctx.projectMapper) {
      res.status(501).json({ error: 'ProjectMapper not initialized' });
      return;
    }

    const map = ctx.projectMapper.generateAndSave();
    res.json({ refreshed: true, projectName: map.projectName, totalFiles: map.totalFiles, directories: map.directories.length });
  });

  // ── Coherence Gate ────────────────────────────────────────────────
  //
  // Pre-action coherence verification. Agents call this before high-risk
  // actions to verify they're in the right project for the right topic.

  router.post('/coherence/check', (req, res) => {
    if (!ctx.coherenceGate) {
      res.status(501).json({ error: 'ScopeVerifier not initialized' });
      return;
    }

    const { action, context } = req.body;
    if (!action || typeof action !== 'string') {
      res.status(400).json({ error: 'Missing required field: action (e.g., "deploy", "git-push")' });
      return;
    }

    const result = ctx.coherenceGate.check(action as HighRiskAction, context);
    res.json(result);
  });

  router.post('/coherence/reflect', (req, res) => {
    if (!ctx.coherenceGate) {
      res.status(501).json({ error: 'ScopeVerifier not initialized' });
      return;
    }

    const { action, context } = req.body;
    if (!action || typeof action !== 'string') {
      res.status(400).json({ error: 'Missing required field: action' });
      return;
    }

    const prompt = ctx.coherenceGate.generateReflectionPrompt(action as HighRiskAction, context);
    res.type('text/plain').send(prompt);
  });

  // ── Topic-Project Bindings ────────────────────────────────────────
  //
  // Manage which Telegram topics are bound to which projects.
  // Critical for multi-project agents — prevents cross-project confusion.

  router.get('/topic-bindings', (_req, res) => {
    if (!ctx.coherenceGate) {
      res.status(501).json({ error: 'ScopeVerifier not initialized' });
      return;
    }

    const bindings = ctx.coherenceGate.loadTopicBindings();
    res.json(bindings);
  });

  router.post('/topic-bindings', (req, res) => {
    if (!ctx.coherenceGate) {
      res.status(501).json({ error: 'ScopeVerifier not initialized' });
      return;
    }

    const { topicId, binding } = req.body;
    if (!topicId || !binding?.projectName || !binding?.projectDir) {
      res.status(400).json({ error: 'Required: topicId (number), binding.projectName, binding.projectDir' });
      return;
    }

    ctx.coherenceGate.setTopicBinding(Number(topicId), binding);
    res.json({ bound: true, topicId: Number(topicId), binding });
  });

  // ── Topic Operator (Know Your Principal #898, increment 2) ─────────
  //
  // The verified principal whose decisions the agent enacts in a topic. The
  // operator is established ONLY from the authenticated sender uid — a content
  // name can never become the operator (the "Caroline" identity-bleed failure
  // mode is impossible by construction). Decoupled from /topic-bindings: a topic
  // can have a verified operator without any project binding.

  // The session-start injection block (mirrors /intent/org/session-context) — the
  // session-start hook fetches this so the agent reasons with its VERIFIED operator
  // from message one. Declared before the param routes to avoid capture.
  router.get('/topic-operator/session-context', (req, res) => {
    if (!ctx.topicOperatorStore) {
      res.status(503).json({ error: 'topic-operator store not initialized' });
      return;
    }
    const topicId = req.query.topicId;
    if (topicId === undefined || topicId === '') {
      res.status(400).json({ error: 'Required: topicId (query param)' });
      return;
    }
    const block = ctx.topicOperatorStore.sessionContextBlock(String(topicId));
    if (!block) {
      res.json({ present: false });
      return;
    }
    res.json({ present: true, block });
  });

  // All bound operators (names + uids), for inspection.
  router.get('/topic-operator', (_req, res) => {
    if (!ctx.topicOperatorStore) {
      res.status(503).json({ error: 'topic-operator store not initialized' });
      return;
    }
    res.json({ operators: ctx.topicOperatorStore.all() });
  });

  // One topic's verified operator, or null when unbound.
  router.get('/topic-operator/:topicId', (req, res) => {
    if (!ctx.topicOperatorStore) {
      res.status(503).json({ error: 'topic-operator store not initialized' });
      return;
    }
    res.json({ operator: ctx.topicOperatorStore.getOperator(req.params.topicId) });
  });

  // Bind a topic's operator from the AUTHENTICATED sender. The `uid` is the
  // authority and is REQUIRED — a blank uid is refused (an operator cannot be
  // established without a verified id, and `displayName` is never authoritative,
  // only used to match the operator's name in the agent's own prose).
  router.post('/topic-operator', (req, res) => {
    if (!ctx.topicOperatorStore) {
      res.status(503).json({ error: 'topic-operator store not initialized' });
      return;
    }
    const { topicId, platform, uid, displayName, boundAt } = req.body ?? {};
    if (topicId === undefined || topicId === null || topicId === '') {
      res.status(400).json({ error: 'Required: topicId' });
      return;
    }
    const record = ctx.topicOperatorStore.setOperator(Number(topicId), {
      platform: typeof platform === 'string' && platform ? platform : 'telegram',
      uid: typeof uid === 'string' ? uid : String(uid ?? ''),
      displayName: typeof displayName === 'string' ? displayName : undefined,
      boundAt: typeof boundAt === 'string' ? boundAt : undefined,
    });
    if (!record) {
      // establishOperator refused a blank uid — a content name is never accepted.
      res.status(400).json({ error: 'A verified sender uid is required to establish an operator' });
      return;
    }
    res.json({ bound: true, topicId: Number(topicId), operator: record });
  });

  // ── Context Hierarchy ──────────────────────────────────────────────
  //
  // Tiered context loading for efficient agent awareness.

  router.get('/context', (_req, res) => {
    if (!ctx.contextHierarchy) {
      res.status(501).json({ error: 'ContextHierarchy not initialized' });
      return;
    }
    res.json({
      contextDir: ctx.contextHierarchy.getContextDir(),
      segments: ctx.contextHierarchy.listSegments(),
    });
  });

  router.get('/context/dispatch', (_req, res) => {
    if (!ctx.contextHierarchy) {
      res.status(501).json({ error: 'ContextHierarchy not initialized' });
      return;
    }
    res.json(ctx.contextHierarchy.getDispatchTable());
  });

  // ── Working Memory Assembly ────────────────────────────────────────
  //
  // Token-budgeted context assembly from all memory layers.
  // NOTE: Must come BEFORE /context/:segmentId to avoid param capture.

  router.get('/context/working-memory', (req, res) => {
    if (!ctx.workingMemory) {
      res.status(503).json({ error: 'Working memory assembler not enabled' });
      return;
    }
    try {
      const { prompt, jobSlug, topicId, sessionId } = req.query;
      const result = ctx.workingMemory.assemble({
        prompt: typeof prompt === 'string' ? prompt : undefined,
        jobSlug: typeof jobSlug === 'string' ? jobSlug : undefined,
        topicId: topicId ? Number(topicId) : undefined,
        sessionId: typeof sessionId === 'string' ? sessionId : undefined,
      });
      res.json(result);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : 'Assembly failed' });
    }
  });

  // ── Active Job Context ──────────────────────────────────────────────
  //
  // Returns the currently active job (if any) for scope coherence checkpoints.

  router.get('/context/active-job', (_req, res) => {
    const activeJob = ctx.state.get<{
      slug: string;
      name: string;
      description: string;
      priority: string;
      sessionName: string;
      triggeredBy: string;
      startedAt: string;
      grounding: unknown;
    }>('active-job');

    if (!activeJob) {
      res.json({ active: false });
      return;
    }

    res.json({ active: true, job: activeJob });
  });

  // ── Scope Coherence ──────────────────────────────────────────────────
  //
  // Tracks implementation depth for the scope coherence checkpoint system.
  // The 232nd Lesson: Implementation depth narrows scope.

  router.get('/scope-coherence', (_req, res) => {
    const tracker = new ScopeCoherenceTracker(ctx.state);
    res.json(tracker.getState());
  });

  router.post('/scope-coherence/record', (req, res) => {
    const { toolName, toolInput } = req.body || {};
    if (!toolName || typeof toolName !== 'string') {
      res.status(400).json({ error: 'toolName is required' });
      return;
    }
    const tracker = new ScopeCoherenceTracker(ctx.state);
    tracker.recordAction(toolName, toolInput || {});
    res.json(tracker.getState());
  });

  router.get('/scope-coherence/check', (_req, res) => {
    const tracker = new ScopeCoherenceTracker(ctx.state);
    const result = tracker.shouldTriggerCheckpoint();

    // Enrich with active job context if triggering
    let jobContext = null;
    if (result.trigger) {
      const activeJob = ctx.state.get<{
        slug: string;
        name: string;
        description: string;
      }>('active-job');
      if (activeJob) {
        jobContext = {
          slug: activeJob.slug,
          name: activeJob.name,
          description: activeJob.description,
        };
      }
      tracker.recordCheckpointShown();
    }

    res.json({ ...result, jobContext });
  });

  router.post('/scope-coherence/reset', (_req, res) => {
    const tracker = new ScopeCoherenceTracker(ctx.state);
    tracker.reset();
    res.json({ reset: true });
  });

  // NOTE: Must come AFTER all specific /context/* routes to avoid param capture.
  router.get('/context/:segmentId', (req, res) => {
    if (!ctx.contextHierarchy) {
      res.status(501).json({ error: 'ContextHierarchy not initialized' });
      return;
    }
    const content = ctx.contextHierarchy.loadSegment(req.params.segmentId);
    if (content === null) {
      res.status(404).json({ error: `Segment not found: ${req.params.segmentId}` });
      return;
    }
    res.type('text/markdown').send(content);
  });

  // ── Canonical State ───────────────────────────────────────────────
  //
  // Registry-first state management: quick facts, anti-patterns, project registry.

  router.get('/state/quick-facts', (_req, res) => {
    if (!ctx.canonicalState) {
      res.status(501).json({ error: 'CanonicalState not initialized' });
      return;
    }
    res.json(ctx.canonicalState.getQuickFacts());
  });

  router.post('/state/quick-facts', (req, res) => {
    if (!ctx.canonicalState) {
      res.status(501).json({ error: 'CanonicalState not initialized' });
      return;
    }
    const { question, answer, source } = req.body;
    if (!question || !answer) {
      res.status(400).json({ error: 'Required: question, answer' });
      return;
    }
    ctx.canonicalState.setFact(question, answer, source || 'api');
    res.json({ saved: true, question, answer });
  });

  router.get('/state/anti-patterns', (_req, res) => {
    if (!ctx.canonicalState) {
      res.status(501).json({ error: 'CanonicalState not initialized' });
      return;
    }
    res.json(ctx.canonicalState.getAntiPatterns());
  });

  router.post('/state/anti-patterns', (req, res) => {
    if (!ctx.canonicalState) {
      res.status(501).json({ error: 'CanonicalState not initialized' });
      return;
    }
    const { pattern, consequence, alternative, incident } = req.body;
    if (!pattern || !consequence || !alternative) {
      res.status(400).json({ error: 'Required: pattern, consequence, alternative' });
      return;
    }
    const entry = ctx.canonicalState.addAntiPattern({ pattern, consequence, alternative, incident });
    res.json(entry);
  });

  router.get('/state/projects', (_req, res) => {
    if (!ctx.canonicalState) {
      res.status(501).json({ error: 'CanonicalState not initialized' });
      return;
    }
    res.json(ctx.canonicalState.getProjects());
  });

  router.post('/state/projects', (req, res) => {
    if (!ctx.canonicalState) {
      res.status(501).json({ error: 'CanonicalState not initialized' });
      return;
    }
    const { name, dir, gitRemote, deploymentTargets, type, topicIds, description } = req.body;
    if (!name || !dir) {
      res.status(400).json({ error: 'Required: name, dir' });
      return;
    }
    ctx.canonicalState.setProject({ name, dir, gitRemote, deploymentTargets, type, topicIds, description });
    res.json({ saved: true, name });
  });

  router.get('/state/summary', (_req, res) => {
    if (!ctx.canonicalState) {
      res.status(501).json({ error: 'CanonicalState not initialized' });
      return;
    }
    res.type('text/plain').send(ctx.canonicalState.getCompactSummary());
  });

  // ── CI Health ─────────────────────────────────────────────────────
  //
  // On-demand CI status check. Detects GitHub repo from git remote and
  // queries GitHub Actions for recent failures. Agents can use this to
  // check CI health without waiting for the next self-diagnosis cycle.

  router.get('/ci', (_req, res) => {
    const projectDir = ctx.config.projectDir;

    // Detect GitHub repo from git remote
    let repo: string | null = null;
    try {
      const remoteUrl = SafeGitExecutor.readSync(['remote', 'get-url', 'origin'], { cwd: projectDir,
        encoding: 'utf-8',
        timeout: 5000,
        stdio: ['pipe', 'pipe', 'pipe'], operation: 'src/server/routes.ts:3037' }).trim();
      // Extract owner/repo from SSH or HTTPS URL
      const match = remoteUrl.match(/github\.com[:/](.+?)(?:\.git)?$/);
      if (match) repo = match[1];
    } catch {
      // Not a git repo or no remote
    }

    if (!repo) {
      res.json({ status: 'unknown', message: 'No GitHub repo detected', runs: [] });
      return;
    }

    // Query recent CI runs
    try {
      const result = execFileSync('gh', [
        'run', 'list', '--repo', repo, '--limit', '5',
        '--json', 'databaseId,conclusion,status,headBranch,name,createdAt',
      ], {
        encoding: 'utf-8',
        timeout: 15000,
        stdio: ['pipe', 'pipe', 'pipe'],
      });

      const runs = JSON.parse(result);
      const failures = runs.filter((r: any) => r.conclusion === 'failure');
      const inProgress = runs.filter((r: any) => r.status === 'in_progress');

      res.json({
        repo,
        status: failures.length > 0 ? 'failing' : inProgress.length > 0 ? 'in_progress' : 'passing',
        failureCount: failures.length,
        inProgressCount: inProgress.length,
        runs,
      });
    } catch (err) {
      res.json({
        repo,
        status: 'error',
        message: err instanceof Error ? err.message : 'gh CLI failed',
        runs: [],
      });
    }
  });

  // ── Sessions ────────────────────────────────────────────────────

  // Literal routes BEFORE parameterized routes to avoid capture
  router.get('/sessions/tmux', (_req, res) => {
    try {
      const tmuxPath = ctx.config.sessions.tmuxPath;
      const output = execFileSync(tmuxPath, ['list-sessions', '-F', '#{session_name}'], {
        encoding: 'utf-8',
        timeout: 5000,
        stdio: ['pipe', 'pipe', 'pipe'],
      }).trim();

      const sessions = output
        ? output.split('\n').filter(Boolean).map((name: string) => ({ name }))
        : [];

      res.json({ sessions });
    } catch {
      res.json({ sessions: [] });
    }
  });

  // SessionReaper observability (SESSION-REAPER-SPEC §3.9). Answers
  // "why did/didn't it reap X?" from a pull surface — pressure tier, active
  // threshold, and every running session's verdict + the gate that kept it.
  router.get('/sessions/reaper', (_req, res) => {
    if (!ctx.sessionReaper) {
      res.status(503).json({ error: 'session reaper unavailable' });
      return;
    }
    res.json(ctx.sessionReaper.snapshot());
  });

  // G3 lease-gated-spawn soak evidence (MESH-SELF-HEAL-SPEC §3.3). The operator's
  // PROMOTION-EVIDENCE surface — the answer to "is this dark feature actually
  // doing anything, and should I promote it?" (operator directive 2026-06-27:
  // observe-mode must produce an evaluable promotion recommendation, not rot
  // dark forever). `summary` carries the counterfactual `wouldHavePreventedDuplicate`;
  // `promotion` is the deterministic recommendation (promote | keep-soaking |
  // consider-removal | enforcing). Read-only; never gates.
  router.get('/mesh-selfheal/g3', (_req, res) => {
    res.json({
      feature: 'lease-gated-spawn',
      flag: 'multiMachine.sessionPool.ownershipCheckedSpawn',
      summary: sharedG3SoakLedger.summary(),
      promotion: sharedG3SoakLedger.promotionSignal(),
    });
  });

  // AgentWorktreeReaper (RESPONSIBLE-RESOURCE-USAGE — OS resource hygiene). The
  // pull-surface answer to "which stale worktrees can be reclaimed, and why is
  // each kept?": every `.worktrees/` worktree's verdict (active-lock /
  // uncommitted-changes / not-stale / unmerged / reap-eligible) + the reclaimable
  // count + whether reaping is armed (enabled, dryRun). Read-only, Bearer-auth.
  router.get('/worktrees/agent-reaper', (_req, res) => {
    if (!ctx.agentWorktreeReaper) {
      res.status(503).json({ error: 'agent worktree reaper unavailable' });
      return;
    }
    res.json(ctx.agentWorktreeReaper.snapshot());
  });

  // OrphanedWorkSentinel — the silent-uncommitted-death backstop. Read-only
  // snapshot: one classifier pass over the agent's worktrees (skip / orphaned +
  // reason) + the orphaned count + whether the sentinel is armed + whether the
  // optional preservation patch is on. 503 when dark (not wired). Bearer-auth.
  router.get('/orphaned-work', (_req, res) => {
    if (!ctx.orphanedWorkSentinel) {
      res.status(503).json({ error: 'orphaned-work sentinel unavailable (dark)' });
      return;
    }
    res.json(ctx.orphanedWorkSentinel.snapshot());
  });

  // McpProcessReaper (RESPONSIBLE-RESOURCE-USAGE — MCP-leak fix, Option B). The
  // pull-surface answer to "which leaked MCP-server procs can be reclaimed, and
  // why is each kept?": every matched MCP proc's verdict (session-live /
  // external-session / *-too-young / stale-instar-session / orphaned-no-session)
  // + its owning session + the reap-eligible count + whether reaping is armed
  // (enabled, dryRun). Read-only, Bearer-auth. 503 when not wired/disabled.
  router.get('/processes/mcp-reaper', (_req, res) => {
    if (!ctx.mcpProcessReaper) {
      res.status(503).json({ error: 'mcp process reaper unavailable' });
      return;
    }
    res.json(ctx.mcpProcessReaper.snapshot());
  });

  // GeminiLoopRunner (need-gem-002) — the multi-turn gemini loop-driver. Lets a
  // caller hand the gemini mentee a goal it works across turns (turn 1 one-shot →
  // resume by handle, no transcript re-send). A run can take minutes, so POST
  // ADMITS + launches async and returns a runId immediately; GET polls the result.
  // Subscription-auth only (the transport strips billing env). Ships DARK
  // (autonomousSessions.geminiLoopDriver.enabled; developmentAgent gate turns it on
  // for dev agents). 503 when not wired; 409 when disabled / at capacity / budget.
  router.post('/gemini-loop/runs', (req, res) => {
    if (!ctx.geminiLoopRunner) {
      res.status(503).json({ error: 'gemini loop runner unavailable' });
      return;
    }
    const { goalPrompt, model, maxTurns } = req.body ?? {};
    if (!goalPrompt || typeof goalPrompt !== 'string') {
      res.status(400).json({ error: 'goalPrompt (string) is required' });
      return;
    }
    const outcome = ctx.geminiLoopRunner.startRun({ goalPrompt, model, maxTurns });
    if (!outcome.ok) {
      // disabled / at-capacity / budget / invalid → 409 (cannot admit right now)
      const code = outcome.reason === 'invalid' ? 400 : 409;
      res.status(code).json({ error: outcome.reason, detail: outcome.detail });
      return;
    }
    res.status(202).json({ runId: outcome.runId, status: 'running' });
  });

  router.get('/gemini-loop/runs', (_req, res) => {
    if (!ctx.geminiLoopRunner) {
      res.status(503).json({ error: 'gemini loop runner unavailable' });
      return;
    }
    res.json({ runs: ctx.geminiLoopRunner.listRuns(), active: ctx.geminiLoopRunner.activeRuns() });
  });

  router.get('/gemini-loop/runs/:id', (req, res) => {
    if (!ctx.geminiLoopRunner) {
      res.status(503).json({ error: 'gemini loop runner unavailable' });
      return;
    }
    const run = ctx.geminiLoopRunner.getRun(req.params.id);
    if (!run) {
      res.status(404).json({ error: 'run not found' });
      return;
    }
    res.json(run);
  });

  // SleepController (RESPONSIBLE-RESOURCE-USAGE — agent hard-sleep, Stage B). The
  // pull-surface answer to "would this idle agent sleep right now, and if not,
  // which guard is holding it awake?": the live verdict (awake / idle-shallow /
  // keep-awake / would-sleep) + reason + thresholds + whether sleep is armed
  // (enabled, dryRun). Read-only, Bearer-auth. Dry-run by default — never acts.
  router.get('/sleep', (_req, res) => {
    if (!ctx.sleepController) {
      res.status(503).json({ error: 'sleep controller unavailable' });
      return;
    }
    res.json(ctx.sleepController.snapshot());
  });

  // Reap-log (UNIFIED-SESSION-LIFECYCLE §P4). The pull-surface answer to "why did
  // my session vanish?": every reap + every refused/skipped terminate, newest
  // last. Read-only, Bearer-auth (the router-level middleware). `?limit=N`
  // bounds the tail (default 200).
  router.get('/sessions/reap-log', (req, res) => {
    if (!ctx.reapLog) {
      res.status(503).json({ error: 'reap-log unavailable' });
      return;
    }
    const rawLimit = Number(req.query.limit);
    const limit = Number.isFinite(rawLimit) && rawLimit > 0 ? Math.min(Math.floor(rawLimit), 1000) : 200;
    res.json({ entries: ctx.reapLog.read(limit) });
  });

  // ── Resume Queue (reap-notify spec R2.10) ───────────────────────────
  // The durable queue of mid-work reaped sessions awaiting revival. All
  // Bearer-auth (router-level middleware). A wedged drainer is detectable
  // from lastTickAt + paused + breaker state in the GET.

  router.get('/sessions/resume-queue', (_req, res) => {
    if (!ctx.resumeQueue) {
      res.status(503).json({ error: 'resume-queue not available on this agent' });
      return;
    }
    const snapshot = ctx.resumeQueue.snapshot();
    const drainer = ctx.resumeDrainer?.status() ?? null;
    res.json({
      ...snapshot,
      lastTickAt: drainer?.lastTickAt ?? null,
      breaker: drainer
        ? { open: drainer.breakerOpen, openUntil: drainer.breakerOpenUntil, consecutiveFailures: drainer.consecutiveFailures }
        : null,
      calmTicks: drainer?.calmTicks ?? null,
    });
  });

  router.post('/sessions/resume-queue/:id/cancel', (req, res) => {
    if (!ctx.resumeQueue) {
      res.status(503).json({ error: 'resume-queue not available on this agent' });
      return;
    }
    const ok = ctx.resumeQueue.cancel(req.params.id);
    res.status(ok ? 200 : 404).json({ ok, id: req.params.id });
  });

  // Requeue clamps (R2.10): gave-up:* ONLY (never cancelled — an operator
  // stop), refused 409 while paused (a Bearer holder cannot undo an
  // emergency stop). Resets attempts + re-anchors the TTL clock.
  router.post('/sessions/resume-queue/:id/requeue', (req, res) => {
    if (!ctx.resumeQueue) {
      res.status(503).json({ error: 'resume-queue not available on this agent' });
      return;
    }
    const result = ctx.resumeQueue.requeue(req.params.id);
    if (result.ok) {
      res.json({ ok: true, id: req.params.id });
      return;
    }
    const status = result.why === 'queue-paused' ? 409 : result.why === 'not-found' ? 404 : 409;
    res.status(status).json({ ok: false, id: req.params.id, error: result.why });
  });

  // The explicit unpause lever (R2.7) — a forgotten pause is visible in the
  // GET and reversible here, never a silent feature death.
  router.post('/sessions/resume-queue/resume', (_req, res) => {
    if (!ctx.resumeQueue) {
      res.status(503).json({ error: 'resume-queue not available on this agent' });
      return;
    }
    const wasPaused = ctx.resumeQueue.isPaused();
    ctx.resumeQueue.unpause();
    res.json({ ok: true, wasPaused });
  });

  // Manual single-step drain (R2.10): skips the calm-ticks requirement ONLY —
  // every other deterministic gate still applies. Refused while paused.
  router.post('/sessions/resume-queue/drain', async (_req, res) => {
    if (!ctx.resumeQueue || !ctx.resumeDrainer) {
      res.status(503).json({ error: 'resume-queue not available on this agent' });
      return;
    }
    if (ctx.resumeQueue.isPaused()) {
      res.status(409).json({ ok: false, error: 'queue-paused' });
      return;
    }
    const result = await ctx.resumeDrainer.tick({ skipCalmTicks: true });
    res.json({ ok: true, ...result });
  });

  // ── Guard Posture (GUARD-POSTURE-ENDPOINT-SPEC) ─────────────────────
  // Read-only, Bearer-auth (router-level middleware — NEVER added to any auth
  // exemption list: posture is an attack-timing oracle, spec §3). Reports
  // every shipped guard's HONEST effective state: config-on is not working
  // (the Mini's reaper lesson). Local inventory is fully synchronous (one
  // disk-read config snapshot + sync in-memory runtime getters, <100ms);
  // ?scope=pool fans out to peers with classified per-peer failures, never a
  // 500. Deliberately NO `guards.enabled` config gate — an off-switch on the
  // guard-visibility surface would itself be an invisible disabled guard
  // (always-on read-only observability; reap-log/TokenLedger precedent).
  const guardsPoolLimiter = rateLimiter(60_000, 6);
  router.get('/guards', async (req, res) => {
    const stateDir = ctx.config.stateDir;
    const projectDir = path.dirname(stateDir);
    const snapshot = resolveGuardConfigSnapshot(projectDir);
    if (snapshot.readError) {
      // Config-read failure is a top-level error — never a truthful-looking
      // empty inventory (spec §2.2).
      res.status(500).json({ error: `guard inventory unavailable: config read failed (${snapshot.readError})` });
      return;
    }
    const selfMachineId = ctx.meshSelfId ?? null;
    // G3 (§2.6): ONE accept-file read per request, scoped to THIS machine, threaded
    // in — buildGuardInventory + deriveGuardRow stay PURE (the caller does the I/O).
    const acceptedFallbacks = scopeAcceptedFallbacks(readAcceptedFallbacks(stateDir), selfMachineId);
    const inventory = buildGuardInventory({
      snapshot,
      bootSnapshot: readGuardPostureBootSnapshot(stateDir),
      registry: ctx.guardRegistry ?? new GuardRegistry(),
      now: Date.now(),
      acceptedFallbacks,
    });
    const body: Record<string, unknown> = {
      machineId: selfMachineId,
      nickname: selfMachineId
        ? (ctx.machinePoolRegistry?.getCapacity(selfMachineId)?.nickname ?? null)
        : null,
      version: ProcessIntegrity.getInstance()?.runningVersion || ctx.config.version || '0.0.0',
      generatedAt: new Date().toISOString(),
      guards: inventory.guards,
      summary: inventory.summary,
    };

    if (req.query.scope !== 'pool') {
      res.json(body);
      return;
    }

    // scope=pool — every registered machine accounted for: a posture row or a
    // NAMED, classified failure row; silent omission re-creates the blind spot
    // at the pool level (spec §2.3). Non-recursive (peers get plain /guards),
    // rate-limited (anti-amplification, spec §3(d)).
    guardsPoolLimiter(req, res, async () => {
      const known = (ctx.listPoolMachines?.() ?? []).filter((m) => m.machineId !== selfMachineId);
      if (known.length === 0) {
        res.json({ ...body, pool: { enabled: false, peersQueried: 0, knownMachines: 0, machines: [], failed: [] } });
        return;
      }
      const extraAllowlist = (ctx.config.multiMachine as { peerUrlAllowlist?: string[] } | undefined)
        ?.peerUrlAllowlist;
      const machines: Record<string, unknown>[] = [];
      const failed: Array<{ machineId: string; reason: string; version?: string }> = [];
      let peersQueried = 0;
      await Promise.all(known.map(async (m) => {
        const capacity = ctx.machinePoolRegistry?.getCapacity(m.machineId) ?? null;
        const peerVersion = capacity?.hardware?.instarVersion;
        if (!m.lastKnownUrl) {
          failed.push({ machineId: m.machineId, reason: 'no-known-url' });
          return;
        }
        if (capacity && capacity.online === false) {
          // The heartbeat piggyback (durable last-known posture on the pool
          // view) covers dark peers — a doomed fetch buys nothing but timeout.
          failed.push({ machineId: m.machineId, reason: 'offline' });
          return;
        }
        const verdict = isPeerUrlAllowedForCredentials(m.lastKnownUrl, extraAllowlist);
        if (!verdict.ok) {
          // The Bearer token was NEVER attached (spec §3(c)) — visible, named.
          failed.push({ machineId: m.machineId, reason: 'url-rejected' });
          return;
        }
        peersQueried++;
        try {
          const r = await fetch(`${m.lastKnownUrl}/guards`, {
            headers: { Authorization: `Bearer ${ctx.config.authToken}` },
            signal: AbortSignal.timeout(5000),
          });
          if (r.status === 404) {
            // Pre-/guards peer version: "needs update to report", not a
            // phantom outage (rollout-skew honesty, spec §2.3).
            failed.push({ machineId: m.machineId, reason: 'route-missing', ...(peerVersion ? { version: peerVersion } : {}) });
            return;
          }
          if (r.status === 401 || r.status === 403) {
            failed.push({ machineId: m.machineId, reason: 'unauthorized' });
            return;
          }
          if (!r.ok) {
            failed.push({ machineId: m.machineId, reason: 'error' });
            return;
          }
          const peerBody = (await r.json()) as Record<string, unknown>;
          machines.push({
            // Merge identity: the row is keyed on the REGISTRY's machine
            // identity; the body's self-reported machineId is data and a
            // mismatch is FLAGGED, never allowed to shadow another row.
            machineId: m.machineId,
            nickname: capacity?.nickname ?? m.nickname,
            ...(typeof peerBody.machineId === 'string' && peerBody.machineId !== m.machineId
              ? { identityMismatch: true, claimedMachineId: peerBody.machineId }
              : {}),
            version: peerBody.version,
            generatedAt: peerBody.generatedAt,
            guards: peerBody.guards,
            summary: peerBody.summary,
          });
        } catch (err) {
          // Normalized enum only — raw err.message leaks URL/TLS internals.
          const name = err instanceof Error ? err.name : '';
          failed.push({
            machineId: m.machineId,
            reason: name === 'TimeoutError' || name === 'AbortError' ? 'timeout' : 'unreachable',
          });
        }
      }));
      res.json({
        ...body,
        pool: {
          enabled: !!ctx.machinePoolRegistry,
          knownMachines: known.length,
          peersQueried,
          machines,
          failed,
        },
      });
    });
  });

  // ── G3: owned operator-accept of a load-bearing guard's dark-but-load-bearing
  // gap (g3-dark-but-load-bearing-guards §2.4). PIN-GATED (checkMandatePin; Know
  // Your Principal — a Bearer token cannot accept a SAFETY RISK for the operator).
  // Per-machine record: state/guard-accepted-fallbacks.json keyed <machineId>:<key>.
  // BOTH `reason` and `owner` are REQUIRED — the PIN proves only "a PIN-holder,"
  // not a NAMED operator, so `owner` cannot be derived (Decision 12).
  router.post('/guards/:key/accept-fallback', (req, res) => {
    if (!checkMandatePin(req, res)) return; // response already sent on failure
    const key = req.params.key;
    const entry = GUARD_MANIFEST.find((e) => e.key === key);
    if (!entry || !entry.loadBearing) {
      res.status(404).json({ error: `no load-bearing guard "${key}" — accept-fallback applies only to a load-bearing guard` });
      return;
    }
    const b = req.body ?? {};
    const reason = typeof b.reason === 'string' ? b.reason.trim() : '';
    const owner = typeof b.owner === 'string' ? b.owner.trim() : '';
    if (!reason || !owner) {
      res.status(400).json({ error: 'reason and owner are BOTH required (an owned acceptance, not a shrug)' });
      return;
    }
    const record = writeAcceptedFallback(ctx.config.stateDir, ctx.meshSelfId ?? null, key, reason, owner);
    res.json({ ok: true, key, accepted: record });
  });

  // Revoke a per-machine accept — the gap reopens (loud again). Touches ONLY the
  // JSON operator record, never the manifest soak constant (reboot-stable, §2.4).
  router.delete('/guards/:key/accept-fallback', (req, res) => {
    if (!checkMandatePin(req, res)) return; // response already sent on failure
    const key = req.params.key;
    const removed = deleteAcceptedFallback(ctx.config.stateDir, ctx.meshSelfId ?? null, key);
    if (!removed) {
      res.status(404).json({ error: `no accepted-fallback record for "${key}" on this machine` });
      return;
    }
    res.json({ ok: true, key, revoked: true });
  });

  // Coherence Journal merged read API (COHERENCE-JOURNAL-SPEC §3.5). The
  // pull-surface answer to "which machine was topic N on / where are its
  // artifacts?" — a bounded, honest-about-trust merged view over this machine's
  // own streams + replicated peer copies. Read-only, Bearer-auth (router-level
  // middleware), signal-only (§3.9: nothing actuates off the journal).
  //
  // 503 when the writer is not wired (journal dark). The reader builds its own
  // file-path discipline from ctx.config.stateDir — `machine`/`kind` query
  // params are matched against the enumerated on-disk stream set, never used to
  // construct a path, so a traversal-shaped param matches nothing.
  router.get('/coherence/journal', (req, res) => {
    if (!ctx.state.getCoherenceJournal()) {
      res.status(503).json({ error: 'coherence journal not enabled' });
      return;
    }
    const reader = new CoherenceJournalReader({ stateDir: ctx.config.stateDir });
    const rawTopic = Number(req.query.topic);
    const rawLimit = Number(req.query.limit);
    try {
      const result = reader.query({
        topic: Number.isFinite(rawTopic) ? rawTopic : undefined,
        kind: typeof req.query.kind === 'string' ? req.query.kind : undefined,
        machine: typeof req.query.machine === 'string' ? req.query.machine : undefined,
        limit: Number.isFinite(rawLimit) ? rawLimit : undefined,
        cursor: typeof req.query.cursor === 'string' ? req.query.cursor : undefined,
      });
      res.json(result);
    } catch (err) {
      if (err instanceof InvalidCursorError) {
        res.status(400).json({ error: err.message });
        return;
      }
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // The evidence-driven fetch reflex (WORKING-SET-HANDOFF-SPEC §3.3): "who made
  // artifacts for this topic? go get them" — the EXO failure as a one-call
  // recovery. Bearer-auth (router-level middleware); 503 while the working-set
  // layer is dark (it rides the explicit replication gate); rate-limited per
  // topic with concurrent calls coalesced into the single-flight pull.
  router.post('/coherence/fetch-working-set', async (req, res) => {
    const coordinator = ctx.workingSetPullCoordinator;
    if (!coordinator) {
      res.status(503).json({ error: 'working-set handoff not enabled (requires coherenceJournal.replication.enabled)' });
      return;
    }
    const topic = Number(req.body?.topic);
    if (!Number.isFinite(topic)) {
      res.status(400).json({ error: 'topic (number) is required' });
      return;
    }
    try {
      const outcome = await coordinator.fetchWorkingSet(topic);
      res.status(outcome.skipReason === 'rate-limited' ? 429 : 200).json(outcome);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // Reaper decision audit (RESPONSIBLE-RESOURCE-USAGE). The pull-surface answer to
  // "what is the reaper considering, and why is it keeping/killing each session?":
  // every keep/kill DECISION transition (logged on change, not every tick) plus the
  // reap-path events, each stamped with the pressure tier (memory + CPU) that drove
  // it. Read-only, Bearer-auth (router-level middleware), silent (no notifications).
  // `?limit=N` bounds the tail (default 200, max 1000).
  router.get('/sessions/reaper/audit', (req, res) => {
    const rawLimit = Number(req.query.limit);
    const limit = Number.isFinite(rawLimit) && rawLimit > 0 ? Math.min(Math.floor(rawLimit), 1000) : 200;
    res.json({ entries: readReaperAudit(ctx.config.stateDir, limit) });
  });

  // Sleep/wake telemetry. The pull-surface answer to "why does my agent keep
  // 'restarting'?" — wakeCount is genuine sleep/wake recovery; suppressedCount
  // (with the cpu-starvation/cooldown breakdown) is the false-wake storm the
  // CPU-starvation guard absorbed instead of triggering recovery. Read-only,
  // Bearer-auth (router-level middleware). `?sinceMs=<epoch>` filters the window.
  router.get('/monitoring/sleep-wake', (req, res) => {
    if (!ctx.sleepWakeDetector) {
      res.status(503).json({ error: 'sleep-wake detector unavailable' });
      return;
    }
    const rawSince = Number(req.query.sinceMs);
    const sinceMs = Number.isFinite(rawSince) && rawSince > 0 ? rawSince : undefined;
    res.json(ctx.sleepWakeDetector.getStats(sinceMs));
  });

  router.get('/sessions', async (req, res) => {
    const status = req.query.status as string | undefined;
    const validStatuses = ['starting', 'running', 'completed', 'failed', 'killed'];
    const sessions = status && validStatuses.includes(status)
      ? ctx.state.listSessions({ status: status as 'starting' | 'running' | 'completed' | 'failed' | 'killed' })
      : ctx.state.listSessions();

    // Which machine answered — so a session row can say where it runs. Absent
    // on single-machine installs (no pool wired), so the dashboard hides the badge.
    const selfMachineId = ctx.meshSelfId ?? null;
    const selfMachineNickname = selfMachineId
      ? (ctx.machinePoolRegistry?.getCapacity(selfMachineId)?.nickname ?? null)
      : null;

    // Enrich sessions with hook event telemetry and platform info
    const enriched = sessions.map(s => {
      const result: Record<string, unknown> = { ...s };

      if (selfMachineId) {
        result.machineId = selfMachineId;
        if (selfMachineNickname) result.machineNickname = selfMachineNickname;
      }

      // Informed-consent input for the dashboard close confirm (REMOTE-SESSION-
      // CLOSE-SPEC §2.2): protected status was previously a config-side
      // membership test evaluated only inside terminateSession on the owner —
      // invisible to any UI. Additive; flows through the pool fan-out unchanged.
      result.protected = (ctx.config.sessions?.protectedSessions ?? []).includes(s.tmuxSession);

      // Add hook event telemetry
      if (req.query.enrich !== 'false' && ctx.hookEventReceiver) {
        const summary = ctx.hookEventReceiver.getSessionSummary(s.tmuxSession);
        if (summary) {
          result.telemetry = {
            eventCount: summary.eventCount,
            toolsUsed: summary.toolsUsed,
            subagentsSpawned: summary.subagentsSpawned,
            lastActivity: summary.lastEvent,
            taskCompleted: ctx.hookEventReceiver!.hasTaskCompleted(s.tmuxSession),
            exitReason: ctx.hookEventReceiver!.getExitReason(s.tmuxSession),
          };
        }
      }

      // Add platform indicator and display name
      if (ctx.telegram) {
        const topicId = ctx.telegram.getTopicForSession?.(s.tmuxSession);
        if (topicId) {
          result.platform = 'telegram';
          result.platformId = topicId;
          const topicName = ctx.telegram.getTopicName?.(topicId);
          if (topicName && !/^topic-\d+$/.test(topicName)) result.platformName = topicName;
        }
      }
      if (!result.platform && ctx.slack) {
        const channelId = ctx.slack.getChannelForSession(s.tmuxSession);
        if (channelId) {
          result.platform = 'slack';
          result.platformId = channelId;
          const registry = ctx.slack.getChannelRegistry();
          if (registry[channelId]?.channelName) result.platformName = registry[channelId].channelName;
        }
      }
      if (!result.platform) {
        result.platform = 'headless';
      }

      return result;
    });

    // scope=pool — "all my sessions, across ALL my machines" (operator ask,
    // 2026-06-05 topic 13481: every session must show on the dashboard with the
    // machine it runs on). Aggregates each ONLINE-registered peer's plain
    // GET /sessions (never scope=pool — no recursion) and tags every remote
    // session with that peer's identity. Tolerant by design: a peer that is
    // down/slow contributes a `failed` entry, never a 500 — the dashboard still
    // shows everything reachable. Response shape differs from the plain route
    // (an object, not an array) because callers opting into the pool view need
    // the per-peer health alongside the merged list.
    if (req.query.scope === 'pool') {
      const peers = ctx.resolvePeerUrls?.() ?? [];
      const failed: Array<{ machineId: string; error: string }> = [];
      const remote: Record<string, unknown>[] = [];
      // WS4.2: per-machine classified fetch verdict — null = fetch succeeded,
      // a normalized reason = the live attempt failed (feeds the empty-state
      // classifier so an idle peer reads "online — no active sessions" but a
      // dark peer reads "unreachable", never a fabricated state).
      const peerFetchReason = new Map<string, string | null>();
      await Promise.all(peers.map(async (p) => {
        try {
          const r = await fetch(`${p.url}/sessions`, {
            headers: { Authorization: `Bearer ${ctx.config.authToken}` },
            signal: AbortSignal.timeout(5000),
          });
          if (!r.ok) {
            failed.push({ machineId: p.machineId, error: `HTTP ${r.status}` });
            peerFetchReason.set(p.machineId, r.status === 401 || r.status === 403 ? 'unauthorized' : 'error');
            return;
          }
          const list = (await r.json()) as Record<string, unknown>[];
          peerFetchReason.set(p.machineId, null);
          const nickname = ctx.machinePoolRegistry?.getCapacity(p.machineId)?.nickname ?? null;
          for (const s of list) {
            remote.push({
              ...s,
              machineId: s.machineId ?? p.machineId,
              machineNickname: s.machineNickname ?? nickname ?? undefined,
              remote: true,
            });
          }
        } catch (err) {
          // @silent-fallback-ok — a peer being down/slow is the DESIGNED tolerant
          // path (spec: degrade to a named failed entry, never a 500); the failure
          // is reported up-stack in pool.failed + the per-machine empty-state, not
          // swallowed. Normalized reason (never raw err.message → no URL/TLS leak).
          const name = err instanceof Error ? err.name : '';
          failed.push({ machineId: p.machineId, error: err instanceof Error ? err.message : String(err) });
          peerFetchReason.set(p.machineId, name === 'TimeoutError' || name === 'AbortError' ? 'timeout' : 'unreachable');
        }
      }));

      // WS4.2 (F7): explicit per-machine empty-state. Account for EVERY
      // registered machine (self + every peer from listPoolMachines), not just
      // the online peers that resolvePeerUrls yielded — a machine that is
      // offline or unreachable is exactly the case the operator could not tell
      // apart from idle before this. A machine WITH sessions gets no empty-state
      // (its tiles already name it). Each empty-state is derived honestly from
      // the registry's online flag + last-seen + the live fan-out verdict.
      const allSessionsMerged = [...enriched, ...remote];
      const sessionCountByMachine = new Map<string, number>();
      for (const s of allSessionsMerged) {
        const mid = typeof s.machineId === 'string' ? s.machineId : (selfMachineId ?? '__local__');
        sessionCountByMachine.set(mid, (sessionCountByMachine.get(mid) ?? 0) + 1);
      }
      const nowMs = Date.now();
      const machines: Array<{
        machineId: string;
        nickname: string | null;
        isSelf: boolean;
        sessionCount: number;
        emptyState?: { kind: string; text: string; lastSeen: string | null };
      }> = [];
      // Registry-wide roster: self + every known machine. listPoolMachines is
      // the /guards?scope=pool accounting boundary (every registered machine,
      // online or not). Absent (single-machine/dark) → roster is just self.
      const knownMachines = ctx.listPoolMachines?.() ?? [];
      const rosterIds = new Set<string>();
      if (selfMachineId) rosterIds.add(selfMachineId);
      for (const m of knownMachines) rosterIds.add(m.machineId);
      for (const machineId of rosterIds) {
        const isSelf = machineId === selfMachineId;
        const capacity = ctx.machinePoolRegistry?.getCapacity(machineId) ?? null;
        const nickname = capacity?.nickname
          ?? knownMachines.find((m) => m.machineId === machineId)?.nickname
          ?? (isSelf ? selfMachineNickname : null)
          ?? null;
        const sessionCount = sessionCountByMachine.get(machineId)
          ?? (isSelf ? (sessionCountByMachine.get('__local__') ?? 0) : 0);
        const entry: (typeof machines)[number] = { machineId, nickname, isSelf, sessionCount };
        if (sessionCount === 0) {
          // Self is always "online" when it answered this request — it is the
          // machine serving the response. Peers derive from registry + fan-out.
          const state = classifyMachineEmptyState(
            {
              online: isSelf ? true : (capacity?.online ?? false),
              failedReason: isSelf ? null : (peerFetchReason.get(machineId) ?? (capacity?.online ? null : 'offline')),
              routerReceivedAt: capacity?.routerReceivedAt,
              selfReportedLastSeen: capacity?.selfReportedLastSeen,
            },
            nowMs,
          );
          entry.emptyState = { kind: state.kind, text: state.text, lastSeen: state.lastSeen };
        }
        machines.push(entry);
      }

      res.json({
        sessions: allSessionsMerged,
        pool: {
          enabled: !!ctx.machinePoolRegistry,
          selfMachineId,
          selfMachineNickname,
          peersQueried: peers.length,
          peersOk: peers.length - failed.length,
          failed,
          // WS4.2: every registered machine with its session count and, when
          // idle, an explicit classified empty-state. >=2 machines is the
          // multi-machine case the dashboard renders; single-machine installs
          // still get the (lone) self row, harmlessly.
          machines,
        },
      });
      return;
    }

    res.json(enriched);
  });

  router.post('/sessions/cleanup-stale', (_req, res) => {
    const cleaned = ctx.sessionManager.cleanupStaleSessions();

    // Also purge failed-messages files older than 24 hours
    const failDir = path.join(ctx.config.stateDir, 'state', 'failed-messages');
    let purgedFiles = 0;
    if (fs.existsSync(failDir)) {
      const cutoff = Date.now() - 24 * 60 * 60 * 1000;
      for (const fname of fs.readdirSync(failDir)) {
        const fpath = path.join(failDir, fname);
        try {
          if (fs.statSync(fpath).mtimeMs < cutoff) {
            SafeFsExecutor.safeUnlinkSync(fpath, { operation: 'src/server/routes.ts:3177' });
            purgedFiles++;
          }
        } catch { /* ignore individual file errors */ }
      }
    }

    res.json({ cleaned: cleaned.length, sessionIds: cleaned, purgedFailedMessages: purgedFiles });
  });

  router.get('/sessions/:name/output', (req, res) => {
    if (!SESSION_NAME_RE.test(req.params.name)) {
      res.status(400).json({ error: 'Invalid session name' });
      return;
    }
    const rawLines = parseInt(req.query.lines as string, 10) || 100;
    const lines = Math.min(Math.max(rawLines, 1), 10_000);
    const output = ctx.sessionManager.captureOutput(req.params.name, lines);

    if (output === null) {
      res.status(404).json({ error: `Session "${req.params.name}" not found or not running` });
      return;
    }

    res.json({ session: req.params.name, output });
  });

  router.post('/sessions/:name/input', (req, res) => {
    if (!SESSION_NAME_RE.test(req.params.name)) {
      res.status(400).json({ error: 'Invalid session name' });
      return;
    }
    const { text } = req.body;
    if (!text || typeof text !== 'string') {
      res.status(400).json({ error: 'Request body must include "text" field' });
      return;
    }
    if (text.length > 100_000) {
      res.status(400).json({ error: 'Input text exceeds maximum length (100KB)' });
      return;
    }

    const success = ctx.sessionManager.sendInput(req.params.name, text);
    if (!success) {
      res.status(404).json({ error: `Session "${req.params.name}" not found or not running` });
      return;
    }

    res.json({ ok: true });
  });

  // Model-Tier Escalation §5.3 (FABLE-MODEL-ESCALATION-SPEC): the ONE narrow
  // mid-session swap surface. Body carries a TIER only — the model id is
  // derived server-side via the §5.1 resolver and is never accepted from the
  // caller. Auth: the global Bearer authMiddleware (AgentServer) gates this
  // like every mutating route. All other refusals (protected, non-idle,
  // disabled, cost guards) are decided inside ModelSwapService.
  router.post('/sessions/:name/model-swap', async (req, res) => {
    if (!SESSION_NAME_RE.test(req.params.name)) {
      res.status(400).json({ error: 'Invalid session name' });
      return;
    }
    const { tier } = (req.body ?? {}) as { tier?: unknown };
    if (tier !== 'default' && tier !== 'escalated') {
      res.status(400).json({ error: '"tier" must be "default" or "escalated" — model ids are never accepted here' });
      return;
    }
    if ('model' in (req.body ?? {})) {
      // Hard refusal, not a silent ignore: a caller supplying a model id is
      // either confused or probing (Sec-F5).
      res.status(400).json({ error: 'The model id is derived server-side; remove "model" from the request' });
      return;
    }
    if (!ctx.modelTierSwap) {
      res.status(503).json({ error: 'Model-tier swap engine not wired on this server' });
      return;
    }
    try {
      // TOPIC-PROFILE-SPEC §9 — the in-flight swap is a live-session mutation:
      // serialize it through the topic's single-writer lock (orchestrator
      // runExclusive) so it can never interleave with a profile-triggered
      // kill/respawn on the same topic. The escalation reconciler hook drives
      // this same route, so one wrap covers both initiators. No orchestrator /
      // no topic binding ⇒ today's unserialized behavior (single-machine boot
      // window / non-topic sessions).
      const performSwap = (): Promise<import('../core/ModelSwapService.js').SwapResult> =>
        ctx.modelTierSwap!.swap(req.params.name, tier);
      const orch = ctx.topicProfile?.orchestrator ?? null;
      const swapTopicId = ctx.telegram?.getTopicForSession?.(req.params.name) ?? null;
      const result =
        orch && swapTopicId !== null
          ? await orch.runExclusive(swapTopicId, performSwap)
          : await performSwap();
      const httpStatus =
        result.status === 'refused'
          ? result.reason === 'unknown-session'
            ? 404
            : result.reason === 'protected-session'
              ? 403
              : result.reason === 'dwell' || result.reason?.startsWith('cost-guard:')
                ? 429
                : 409
          : result.status === 'unconfirmed'
            ? 202
            : 200;
      res.status(httpStatus).json(result);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // ── Topic Profile (TOPIC-PROFILE-SPEC §10.1 / §12) ────────────────────────
  // GET: the read surface (Bearer — profile entries carry the operator's
  // platform uid in updatedBy). POST: the TOKEN-TRUST write surface —
  // authenticated by Bearer + X-Instar-Request like sibling mutating routes,
  // recorded as `updatedBy:'api-token'`, NEVER operator-attributed; a
  // body-supplied updatedBy is ignored by construction. The §12.5 key clamp:
  // numeric Telegram topic id, or `slack:<channel>[:<thread>]`.
  const TOPIC_PROFILE_KEY_RE = /^(?:\d{1,16}|slack:[A-Za-z0-9._-]{1,64}(?::[0-9.]{1,32})?)$/;

  const topicProfileRefusalStatus = (reason: string | undefined): number => {
    switch (reason) {
      case 'validation':
      case 'empty-patch':
        return 400;
      case 'no-bound-operator':
      case 'not-bound-operator':
        return 403;
      case 'disabled':
      case 'local-model-binding-active':
      case 'lock-timeout':
      case 'nothing-to-undo':
      case 'nothing-parked':
      case 'cooldown-confirm-required':
        return 409;
      case 'flush-failed':
        return 500;
      default:
        return 400;
    }
  };

  router.get('/topic-profile/:topicId', (req, res) => {
    if (!TOPIC_PROFILE_KEY_RE.test(req.params.topicId)) {
      res.status(400).json({ error: 'Invalid topic key — numeric topic id or slack:<channel>[:<thread>]' });
      return;
    }
    if (!ctx.topicProfile) {
      res.status(503).json({ error: 'Topic profiles not wired on this server' });
      return;
    }
    const key = req.params.topicId;
    const entry = ctx.topicProfile.store.get(key);
    const resolved = ctx.topicProfile.resolver.resolve(key);
    // §5.3 — reads name their staleness: while a transfer pull from the
    // previous owner is pending, the local entry is served (a slightly-stale
    // operator pin beats defaults) but flagged "possibly stale".
    let pendingTransferPull = false;
    try {
      pendingTransferPull = ctx.topicProfile.carrier?.hasPendingPull(key) ?? false;
    } catch {
      /* @silent-fallback-ok: the staleness flag is read-surface annotation only — a carrier read error must never fail the profile read; the flag defaults to false (TOPIC-PROFILE-SPEC §5.3) */
    }
    res.json({
      topicId: key,
      resolved: {
        framework: resolved.framework,
        model: resolved.model ?? null,
        modelTier: resolved.modelTier,
        thinkingMode: resolved.thinkingMode ?? null,
        effort: resolved.effort ?? null,
        escalationOverride: resolved.escalationOverride,
        sources: resolved.sources,
      },
      // Once-per-transition fallback notices that fired on THIS resolution
      // (the read consumed them — surfaced here rather than dropped).
      notices: resolved.notices,
      pin: entry?.current ?? null,
      previous: entry?.previous ?? null,
      parked: entry?.parked ?? null,
      intendedProfile: entry?.intendedProfile ?? null,
      breakerCount: entry?.breakerCount ?? 0,
      // §5.3 staleness annotation: true while a pull from this topic's
      // previous owner is pending — the entry above is "as of when this topic
      // last lived here — possibly stale".
      pendingTransferPull,
      ...(pendingTransferPull && entry?.current
        ? { staleness: 'pending-transfer-pull — entry is as of when this topic last lived on this machine (possibly stale)' }
        : {}),
    });
  });

  const requireTopicProfileWrite = (req: import('express').Request, res: import('express').Response):
    | { key: string; surface: NonNullable<typeof ctx.topicProfile>['surface'] }
    | null => {
    if (req.headers['x-instar-request'] !== '1') {
      res.status(403).json({ error: 'Topic-profile writes require the X-Instar-Request: 1 intent header' });
      return null;
    }
    if (!TOPIC_PROFILE_KEY_RE.test(req.params.topicId)) {
      res.status(400).json({ error: 'Invalid topic key — numeric topic id or slack:<channel>[:<thread>]' });
      return null;
    }
    if (!ctx.topicProfile) {
      res.status(503).json({ error: 'Topic profiles not wired on this server' });
      return null;
    }
    return { key: req.params.topicId, surface: ctx.topicProfile.surface };
  };

  router.post('/topic-profile/:topicId', async (req, res) => {
    const gate = requireTopicProfileWrite(req, res);
    if (!gate) return;
    const body = (req.body ?? {}) as Record<string, unknown>;
    const patch: Record<string, string | null> = {};
    for (const field of ['framework', 'model', 'modelTier', 'thinkingMode', 'effort', 'escalationOverride'] as const) {
      if (!(field in body)) continue;
      const value = body[field];
      if (value !== null && typeof value !== 'string') {
        res.status(400).json({ error: `"${field}" must be a string or null` });
        return;
      }
      patch[field] = value;
    }
    // §10.1: a body-supplied updatedBy is IGNORED — the principal is the
    // shared token, stamped server-side as 'api-token'.
    try {
      const result = await gate.surface.applyWrite({
        topicKey: gate.key,
        patch,
        principal: { kind: 'token' },
        origin: 'http',
      });
      if (!result.ok) {
        res.status(topicProfileRefusalStatus(result.refusal?.reason)).json({
          ok: false,
          reason: result.refusal?.reason,
          ...(result.refusal?.validation
            ? { validation: { field: result.refusal.validation.field, failure: result.refusal.validation.failure, reason: result.refusal.validation.reason } }
            : {}),
          message: result.reply,
        });
        return;
      }
      res.json({
        ok: true,
        appliedLive: result.appliedLive ?? [],
        shadowed: result.shadowed ?? [],
        refusedFields: result.refusedFields ?? [],
        noop: result.noop ?? false,
        supersededParked: result.supersededParked ?? false,
        message: result.reply,
        pin: ctx.topicProfile?.store.resolve(gate.key) ?? null,
      });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // §10.1 propose lane — registers an AGENT-COMPOSED structured delta in the
  // server-side slot and sends the SERVER-rendered echo to the topic; the
  // operator's first-party "yes" (recognized by the ingress parse) converts
  // it to the operator-attributed write. Never writes the store itself.
  router.post('/topic-profile/:topicId/propose', async (req, res) => {
    const gate = requireTopicProfileWrite(req, res);
    if (!gate) return;
    if (!ctx.topicProfile || !ctx.telegram || !/^\d+$/.test(gate.key)) {
      res.status(409).json({ error: 'Propose-confirm needs a platform-bound numeric topic on this server' });
      return;
    }
    const body = (req.body ?? {}) as Record<string, unknown>;
    const patch: Record<string, string | null> = {};
    for (const field of ['framework', 'model', 'modelTier', 'thinkingMode', 'effort', 'escalationOverride'] as const) {
      if (!(field in body)) continue;
      const value = body[field];
      if (value !== null && typeof value !== 'string') {
        res.status(400).json({ error: `"${field}" must be a string or null` });
        return;
      }
      patch[field] = value;
    }
    const rendered = gate.surface.renderProposalEcho(gate.key, patch);
    if (!rendered.ok) {
      res.status(400).json({ ok: false, message: rendered.reply });
      return;
    }
    const armed = ctx.topicProfile.confirmSlots.arm(gate.key, 'propose-confirm', rendered.patch, rendered.echo, 'agent-composed');
    if (!armed.ok) {
      res.status(429).json({ ok: false, reason: armed.reason, message: 'Proposal churn cooldown — re-state the intent later' });
      return;
    }
    try {
      const sent = await ctx.telegram.sendToTopic(Number(gate.key), rendered.echo);
      ctx.topicProfile.confirmSlots.recordEchoMessageId(gate.key, sent.messageId);
      res.json({ ok: true, echo: rendered.echo, superseded: armed.superseded });
    } catch (err) {
      // Echo undelivered — tear the slot down (an unseen echo must never be
      // confirmable; matchConfirm would refuse on no-echo-id anyway).
      ctx.topicProfile.confirmSlots.disarm(gate.key);
      res.status(502).json({ ok: false, error: `Echo delivery failed: ${err instanceof Error ? err.message : String(err)}` });
    }
  });

  // §10.3 / §5.2(b) recovery surfaces (token-trust like the main POST).
  router.post('/topic-profile/:topicId/undo', async (req, res) => {
    const gate = requireTopicProfileWrite(req, res);
    if (!gate) return;
    const result = await gate.surface.undo({ topicKey: gate.key, principal: { kind: 'token' }, origin: 'http' });
    if (!result.ok) {
      res.status(topicProfileRefusalStatus(result.refusal?.reason)).json({ ok: false, reason: result.refusal?.reason, message: result.reply });
      return;
    }
    res.json({ ok: true, message: result.reply, pin: ctx.topicProfile?.store.resolve(gate.key) ?? null });
  });

  router.post('/topic-profile/:topicId/clear', async (req, res) => {
    const gate = requireTopicProfileWrite(req, res);
    if (!gate) return;
    const result = await gate.surface.clear({ topicKey: gate.key, principal: { kind: 'token' }, origin: 'http' });
    if (!result.ok) {
      res.status(topicProfileRefusalStatus(result.refusal?.reason)).json({ ok: false, reason: result.refusal?.reason, message: result.reply });
      return;
    }
    res.json({ ok: true, message: result.reply, pin: ctx.topicProfile?.store.resolve(gate.key) ?? null });
  });

  router.post('/topic-profile/:topicId/reapply', async (req, res) => {
    const gate = requireTopicProfileWrite(req, res);
    if (!gate) return;
    const confirmed = (req.body ?? {}).confirm === true;
    const result = await gate.surface.reapply({ topicKey: gate.key, principal: { kind: 'token' }, origin: 'http', confirmed });
    if (!result.ok) {
      res.status(topicProfileRefusalStatus(result.refusal?.reason)).json({
        ok: false,
        reason: result.refusal?.reason,
        needsConfirm: result.needsConfirm ?? false,
        message: result.reply,
      });
      return;
    }
    res.json({ ok: true, message: result.reply, pin: ctx.topicProfile?.store.resolve(gate.key) ?? null });
  });

  // Rate limit session spawning — each session is a real Claude Code process.
  // Default: 10 spawns per 60 seconds, which is generous for normal use.
  const spawnLimiter = rateLimiter(60_000, 10);
  router.post('/sessions/spawn', spawnLimiter, async (req, res) => {
    const { name, prompt, model, jobSlug, framework } = req.body;

    if (!name || !prompt) {
      res.status(400).json({ error: '"name" and "prompt" are required' });
      return;
    }
    if (typeof name !== 'string' || !SESSION_NAME_RE.test(name)) {
      res.status(400).json({ error: '"name" must contain only letters, numbers, hyphens, underscores (max 200)' });
      return;
    }
    if (typeof prompt !== 'string' || prompt.length > 500_000) {
      res.status(400).json({ error: '"prompt" must be a string under 500KB' });
      return;
    }
    const SUPPORTED_SPAWN_FRAMEWORKS = ['claude-code', 'codex-cli', 'gemini-cli'];
    if (framework !== undefined && !SUPPORTED_SPAWN_FRAMEWORKS.includes(framework)) {
      res.status(400).json({ error: `"framework" must be one of: ${SUPPORTED_SPAWN_FRAMEWORKS.join(', ')}` });
      return;
    }
    // Provider-portability v1.0.0: model whitelist is framework-aware.
    // Generic tiers ('fast'|'balanced'|'capable') are universally accepted
    // and resolve per-framework inside buildHeadlessLaunch. Framework-
    // specific names are accepted when they match the framework slot.
    const GENERIC_TIERS = ['fast', 'balanced', 'capable'];
    // E2E-PAIRING: EXEMPT — extends an existing model allowlist on the
    // already-live spawn route. No new route, no route-aliveness change, no
    // 503 surface; route-create E2E coverage is unchanged by extending the
    // accepted-model set.
    // Claude branch (FABLE-MODEL-ESCALATION-SPEC): the closed per-adapter
    // enum from ModelTierEscalation.ts — includes the concrete model ids
    // (claude-fable-5, claude-opus-4-8, …) AND the CLI tier aliases
    // (opus/sonnet/haiku), so instar can natively spawn Fable sessions.
    const CODEX_MODELS_SUBSCRIPTION = ['gpt-5.2', 'gpt-5.3-codex', 'gpt-5.4', 'gpt-5.4-mini', 'gpt-5.5'];
    if (model !== undefined) {
      if (typeof model !== 'string') {
        res.status(400).json({ error: '"model" must be a string' });
        return;
      }
      const requestedFramework = framework ?? 'claude-code';
      const allowed = requestedFramework === 'codex-cli'
        ? [...GENERIC_TIERS, ...CODEX_MODELS_SUBSCRIPTION]
        : requestedFramework === 'gemini-cli'
          ? [...GENERIC_TIERS, ...KNOWN_GEMINI_MODELS]
          : [...GENERIC_TIERS, ...KNOWN_CLAUDE_MODEL_IDS];
      if (!allowed.includes(model)) {
        res.status(400).json({
          error: `"model" must be one of: ${allowed.join(', ')} (framework: ${requestedFramework})`,
        });
        return;
      }
    }
    if (jobSlug !== undefined && (typeof jobSlug !== 'string' || !JOB_SLUG_RE.test(jobSlug))) {
      res.status(400).json({ error: '"jobSlug" must contain only letters, numbers, hyphens, underscores' });
      return;
    }

    try {
      const session = await ctx.sessionManager.spawnSession({ name, prompt, model, jobSlug, framework });
      res.status(201).json(session);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // POST /sessions/refresh — agent-initiated session respawn.
  //
  // The agent calls this when it needs new MCPs/skills (just installed via
  // `claude mcp add`) to attach. We kill its tmux session and respawn with
  // `claude --resume <uuid>`, which loads the new tools while keeping the
  // conversation. The response is 202 immediately because the kill itself
  // ends the requester's process — there is no synchronous result.
  //
  // `fresh: true` skips the `--resume` — the topic's resume UUID is cleared so
  // the respawn starts a brand-new conversation. This is the recovery path for
  // a POISONED transcript (thinking-block-400 wedge, AUP-rejection loop) where
  // resuming would just re-wedge. Before this param existed only the
  // ContextWedgeSentinel's internal wiring could fresh-respawn; the 2026-06-05
  // EXO incident required hand-editing topic-resume-map.json to recover.
  //
  // Rate limit and lifecycle live in SessionRefresh (the orchestrator);
  // this route is a thin entry point.
  router.post('/sessions/refresh', spawnLimiter, async (req, res) => {
    if (!ctx.sessionRefresh) {
      res.status(503).json({ error: 'Session refresh not enabled (no Telegram adapter wired)' });
      return;
    }

    const { sessionName, followUpPrompt, reason, fresh, force } = req.body || {};

    if (!sessionName || typeof sessionName !== 'string' || !SESSION_NAME_RE.test(sessionName)) {
      res.status(400).json({ error: '"sessionName" is required and must contain only letters, numbers, hyphens, underscores (max 200)' });
      return;
    }
    if (followUpPrompt !== undefined && (typeof followUpPrompt !== 'string' || followUpPrompt.length > 500_000)) {
      res.status(400).json({ error: '"followUpPrompt" must be a string under 500KB' });
      return;
    }
    if (reason !== undefined && (typeof reason !== 'string' || reason.length > 1000)) {
      res.status(400).json({ error: '"reason" must be a string under 1000 chars' });
      return;
    }
    if (fresh !== undefined && typeof fresh !== 'boolean') {
      res.status(400).json({ error: '"fresh" must be a boolean' });
      return;
    }
    if (force !== undefined && typeof force !== 'boolean') {
      res.status(400).json({ error: '"force" must be a boolean' });
      return;
    }

    // ── swap-continuity-antithrash §4.5: the work gate runs PRE-202 ──
    // Busy → synchronous 409 `session-busy` with the live work summary
    // (counts and ages only — no titles, no transcript paths, no message
    // content on the wire), so the caller decides: wait, or re-issue with
    // force:true. `force` overrides ONLY the work gate, never the rate guard.
    // I11: no callerClass is ever read from the request — this route pins
    // 'interactive-refresh' by construction (the refreshSession default).
    if (force !== true) {
      let busy: Awaited<ReturnType<NonNullable<typeof ctx.sessionRefresh>['precheckInteractiveBusy']>> = null;
      try {
        busy = await ctx.sessionRefresh.precheckInteractiveBusy(sessionName);
      } catch {
        // @silent-fallback-ok: the work gate is ADDITIVE (§4.5) — a precheck
        // error must never block the refresh route; SwapWorkGate's own audit
        // rows and logs carry the failure signal.
        busy = null;
      }
      if (busy) {
        res.status(409).json({
          code: 'session-busy',
          error: busy.message,
          turnInFlight: busy.turnInFlight,
          ...(busy.subagents !== undefined ? { subagents: busy.subagents } : {}),
          ...(busy.subagentLeg !== undefined ? { subagentLeg: busy.subagentLeg } : {}),
        });
        return;
      }
    }

    // Acknowledge BEFORE killing — the requester is the session being killed,
    // so it needs to receive the 202 before its process disappears.
    res.status(202).json({ ok: true, message: 'Refresh scheduled', sessionName, fresh: fresh === true });

    // Schedule the kill+spawn after the response has flushed and the agent
    // has a moment to log its last action. 500ms is enough for HTTP flush
    // on a local loopback without being a noticeable user-facing delay.
    const sessionRefresh = ctx.sessionRefresh;
    setTimeout(() => {
      sessionRefresh.refreshSession({ sessionName, followUpPrompt, reason, fresh, force: force === true }).then(result => {
        if (!result.ok) {
          // Structured logging so over-blocks (rate guard) are detectable
          // in operations per signal-vs-authority logging rule. The agent's
          // process may already be dead — nothing to reply to.
          console.warn(`[sessions/refresh] refused sessionName=${sessionName} code=${result.code} message="${result.message}"`);
        }
      }).catch(err => {
        console.error(`[sessions/refresh] unexpected error for sessionName=${sessionName}:`, err);
      });
    }, 500);
  });

  // POST /sessions/restart-all — bulk config-apply restart.
  //
  // After a config change (default model, disabled features, a newly-added
  // hook), running sessions keep their OLD config until they restart — and
  // Claude Code only loads hooks/settings at session START, so a hook added
  // mid-session never engages on the live session. Previously the only way to
  // push every session onto the new config was to wait for the reaper or
  // refresh each session by hand. This refreshes every running, Telegram-bound
  // session through SessionRefresh (kill + `claude --resume`, preserving each
  // conversation), staggered so we don't kill+respawn the whole fleet at once.
  //
  // Non-Telegram-bound sessions (Slack, iMessage, headless) are skipped — the
  // respawn path is topic-routed, the same v1 limitation as /sessions/refresh.
  router.post('/sessions/restart-all', spawnLimiter, (req, res) => {
    if (!ctx.sessionRefresh) {
      res.status(503).json({ error: 'Session refresh not enabled (no Telegram adapter wired)' });
      return;
    }

    const { reason, excludeSession, followUpPrompt } = req.body || {};
    if (reason !== undefined && (typeof reason !== 'string' || reason.length > 1000)) {
      res.status(400).json({ error: '"reason" must be a string under 1000 chars' });
      return;
    }
    if (excludeSession !== undefined && (typeof excludeSession !== 'string' || !SESSION_NAME_RE.test(excludeSession))) {
      res.status(400).json({ error: '"excludeSession" must contain only letters, numbers, hyphens, underscores (max 200)' });
      return;
    }
    if (followUpPrompt !== undefined && (typeof followUpPrompt !== 'string' || followUpPrompt.length > 500_000)) {
      res.status(400).json({ error: '"followUpPrompt" must be a string under 500KB' });
      return;
    }

    // Snapshot running sessions NOW, before any kills. Filter to Telegram-bound
    // up front (checking in-memory AND disk, mirroring SessionRefresh's own
    // resolution) so the "scheduled" list we return is honest — the rest would
    // only come back not_telegram_bound.
    const running = ctx.state.listSessions({ status: 'running' });
    const targets = running
      .map(s => s.tmuxSession)
      .filter((name): name is string => !!name && name !== excludeSession)
      .filter(name => {
        const topic = ctx.telegram?.getTopicForSession?.(name)
          ?? ctx.telegram?.resolveTopicForSessionFromDisk?.(name)
          ?? null;
        return topic !== null;
      });

    res.status(202).json({
      ok: true,
      message: 'Bulk restart scheduled',
      scheduled: targets,
      count: targets.length,
      skipped: running.length - targets.length,
    });

    // Stagger the refreshes so we don't kill+respawn the whole fleet in one
    // burst (a tmux storm + a model-load CPU spike). Each refresh is
    // independent and self-rate-limited inside SessionRefresh, so a repeated
    // restart-all inside the rate window is harmlessly refused per session.
    const sessionRefresh = ctx.sessionRefresh;
    const STAGGER_MS = 750;
    targets.forEach((sessionName, i) => {
      setTimeout(() => {
        sessionRefresh
          .refreshSession({ sessionName, followUpPrompt, reason: reason ?? 'bulk restart-all (config apply)' })
          .then(result => {
            if (!result.ok) {
              console.warn(`[sessions/restart-all] refused sessionName=${sessionName} code=${result.code} message="${result.message}"`);
            } else {
              console.log(`[sessions/restart-all] refreshed sessionName=${sessionName} -> ${result.newSessionName} (topic ${result.topicId})`);
            }
          })
          .catch(err => {
            console.error(`[sessions/restart-all] unexpected error for sessionName=${sessionName}:`, err);
          });
      }, 500 + i * STAGGER_MS);
    });
  });

  router.delete('/sessions/:id', async (req, res) => {
    if (!SESSION_NAME_RE.test(req.params.id)) {
      res.status(400).json({ error: 'Invalid session ID format' });
      return;
    }
    try {
      // Operator kill — stamped origin:'operator' so it bypasses the autonomous
      // ReapAuthority gates (protected / lease / KEEP-guard) and ALWAYS happens
      // (the user clicked "kill"). Routing through terminateSession (rather than
      // the raw killSession) gives the reap-log + lifecycle events the §P4 surface
      // depends on. (UNIFIED-SESSION-LIFECYCLE §P0.)
      // Try direct UUID lookup first, then fall back to tmux session name lookup —
      // the dashboard sends tmux session names, not UUIDs.
      let target = ctx.state.getSession(req.params.id);
      if (!target) {
        const allSessions = ctx.state.listSessions({ status: 'running' });
        target = allSessions.find(s => s.tmuxSession === req.params.id) ?? null;
      }
      if (!target) {
        res.status(404).json({ error: `Session "${req.params.id}" not found` });
        return;
      }
      // UNTRUSTED provenance claim (REMOTE-SESSION-CLOSE-SPEC §2.3): any token
      // holder could set this header. Recorded in the reap-log as `viaClaim`
      // (a signal in the audit trail); NEVER consulted in authority decisions —
      // those read the route-stamped `origin` below. Sanitized + bounded.
      const viaHeader = req.headers['x-instar-close-via'];
      const via = typeof viaHeader === 'string' && /^[a-z0-9-]{1,40}$/.test(viaHeader) ? viaHeader : undefined;
      const result = await ctx.sessionManager.terminateSession(target.id, 'operator-kill', {
        origin: 'operator',
        finalStatus: 'killed',
        ...(via ? { via } : {}),
      });
      if (!result.terminated) {
        res.status(404).json({ error: `Session "${req.params.id}" not found`, skipped: result.skipped });
        return;
      }
      res.json({ ok: true, killed: req.params.id });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // ── Remote Session Close (REMOTE-SESSION-CLOSE-SPEC) ────────────────
  // Relay an OPERATOR-origin close to the machine that owns the session —
  // the same kill the dashboard already produces locally, executed on the
  // owner (§2.0: no new authority class; reach expands, which is why the
  // rate limit + URL allowlist + relay-side audit below are load-bearing).
  // A NEW path by design: a pre-feature server 404s it cleanly, so a
  // mixed-version pool can never misroute this into a LOCAL same-named kill
  // (§2.1 — the wrong-machine-kill shape the query-param design had).
  const remoteCloseLimiter = rateLimiter(60_000, 10);
  const remoteCloseAudit = new RemoteCloseAudit(ctx.config.stateDir);
  router.post('/sessions/:name/remote-close', remoteCloseLimiter, async (req, res) => {
    const { machineId, sessionUuid } = (req.body ?? {}) as { machineId?: unknown; sessionUuid?: unknown };
    // machineId is a registry LOOKUP KEY ONLY — charset-clamped, never used
    // to construct a URL (§2.1; closes the SSRF-with-credentials shape).
    if (typeof machineId !== 'string' || !/^[A-Za-z0-9_-]{1,64}$/.test(machineId)) {
      res.status(404).json({ error: 'unknown machine' });
      return;
    }
    if (typeof sessionUuid !== 'string' || !/^[A-Za-z0-9-]{1,64}$/.test(sessionUuid)) {
      res.status(400).json({ error: 'sessionUuid required' });
      return;
    }
    const sessionName = SESSION_NAME_RE.test(req.params.name) ? req.params.name : undefined;
    const machine = (ctx.listPoolMachines?.() ?? []).find((m) => m.machineId === machineId);
    if (!machine || !machine.lastKnownUrl) {
      // Unknown or unresolvable machine: 404 with ZERO outbound request.
      res.status(404).json({ error: 'unknown machine', machineId });
      return;
    }
    const nickname = ctx.machinePoolRegistry?.getCapacity(machineId)?.nickname ?? machine.nickname;
    const extraAllowlist = (ctx.config.multiMachine as { peerUrlAllowlist?: string[] } | undefined)
      ?.peerUrlAllowlist;
    if (!isPeerUrlAllowedForCredentials(machine.lastKnownUrl, extraAllowlist).ok) {
      // The pool Bearer token NEVER travels to a non-allowlisted URL —
      // stronger here than on the read fan-out because this verb is
      // destructive (§2.1 shipping dependency).
      remoteCloseAudit.record({ targetMachineId: machineId, targetNickname: nickname, sessionUuid, sessionName, outcome: 'url-rejected' });
      res.status(502).json({ error: 'url-rejected', machineId });
      return;
    }
    try {
      // The peer's PLAIN local close — no relay params forwarded (single-hop
      // by construction, §2.1); UUID-targeted (the peer's existing route is
      // UUID-first, so on a ghost-bearing peer this closes exactly the tile
      // the operator saw). The via header is the UNTRUSTED §2.3 claim the
      // peer records as viaClaim.
      const r = await fetch(`${machine.lastKnownUrl}/sessions/${encodeURIComponent(sessionUuid)}`, {
        method: 'DELETE',
        headers: {
          Authorization: `Bearer ${ctx.config.authToken}`,
          'X-Instar-Close-Via': 'remote-dashboard',
        },
        signal: AbortSignal.timeout(5000),
      });
      let peerBody: Record<string, unknown> | null = null;
      try {
        peerBody = (await r.json()) as Record<string, unknown>;
      } catch {
        // @silent-fallback-ok — a non-JSON body (Cloudflare 502/530 HTML
        // error page) is normalized below so the dashboard's resp.json()
        // never throws into a reasonless "Network error" (§2.2).
        peerBody = null;
      }
      if (r.ok) {
        remoteCloseAudit.record({ targetMachineId: machineId, targetNickname: nickname, sessionUuid, sessionName, outcome: 'closed', peerStatus: r.status });
        res.json({ ok: true, killed: sessionUuid, machineId, nickname });
        return;
      }
      if (r.status === 404) {
        // Idempotent skip / already gone / just won by another viewer —
        // a CALM already-closed outcome, not a scary error (§2.3).
        remoteCloseAudit.record({ targetMachineId: machineId, targetNickname: nickname, sessionUuid, sessionName, outcome: 'already-closed', peerStatus: 404 });
        res.json({ ok: true, alreadyClosed: true, machineId, nickname });
        return;
      }
      if (r.status === 401 || r.status === 403) {
        remoteCloseAudit.record({ targetMachineId: machineId, targetNickname: nickname, sessionUuid, sessionName, outcome: 'unauthorized', peerStatus: r.status });
        res.status(502).json({ error: `unauthorized by ${nickname ?? machineId}` });
        return;
      }
      remoteCloseAudit.record({ targetMachineId: machineId, targetNickname: nickname, sessionUuid, sessionName, outcome: 'peer-error', peerStatus: r.status });
      res.status(502).json({
        error: typeof peerBody?.error === 'string' ? peerBody.error : `${r.status} from ${nickname ?? machineId}`,
      });
    } catch (err) {
      const name = err instanceof Error ? err.name : '';
      if (name === 'TimeoutError' || name === 'AbortError') {
        // Delivery honesty (§2.3): the peer may be mid-kill under the same
        // load that made the tile stale. UNKNOWN, never "closed nothing".
        remoteCloseAudit.record({ targetMachineId: machineId, targetNickname: nickname, sessionUuid, sessionName, outcome: 'unknown' });
        res.status(504).json({ error: 'outcome unknown — peer did not answer in time', outcomeUnknown: true, machineId, nickname });
        return;
      }
      remoteCloseAudit.record({ targetMachineId: machineId, targetNickname: nickname, sessionUuid, sessionName, outcome: 'unreachable' });
      res.status(502).json({ error: `unreachable: ${nickname ?? machineId}` });
    }
  });

  // Create an interactive session from the dashboard.
  // Set platform to 'telegram', 'slack', or 'headless'.
  // Legacy: headless=true is equivalent to platform='headless'.
  router.post('/sessions/create', spawnLimiter, async (req, res) => {
    const { name, headless, platform } = req.body;

    if (!name || typeof name !== 'string' || name.trim().length < 1) {
      res.status(400).json({ error: '"name" is required (non-empty string)' });
      return;
    }
    if (name.length > 128) {
      res.status(400).json({ error: '"name" must be 128 characters or fewer' });
      return;
    }

    const topicName = name.trim();
    let topicId: number | undefined;
    let slackChannelId: string | undefined;
    const resolvedPlatform = platform || (headless ? 'headless' : (ctx.telegram ? 'telegram' : (ctx.slack ? 'slack' : 'headless')));

    // Create Telegram topic
    if (resolvedPlatform === 'telegram' && ctx.telegram) {
      try {
        const topic = await ctx.telegram.findOrCreateForumTopic(topicName, undefined, { origin: 'user' });
        topicId = topic.topicId;
      } catch (err) {
        console.error(`[sessions/create] Telegram topic creation failed, proceeding headless: ${err}`);
      }
    }

    // Create Slack channel
    if (resolvedPlatform === 'slack' && ctx.slack) {
      try {
        const rawAgentName = (ctx.slack as unknown as { config: { workspaceName?: string } }).config?.workspaceName?.replace(/-agent$/i, '') || 'agent';
        const agentName = rawAgentName.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
        const channelName = `${agentName}-sess-${topicName.toLowerCase().replace(/[^a-z0-9]/g, '-').slice(0, 40)}`;
        slackChannelId = await ctx.slack.createChannel(channelName);
      } catch (err) {
        console.error(`[sessions/create] Slack channel creation failed, proceeding headless: ${err}`);
      }
    }

    try {
      const tmuxSession = await ctx.sessionManager.spawnInteractiveSession(
        undefined, // no initial message
        topicName,
        topicId ? { telegramTopicId: topicId } : undefined,
      );

      // Update topic-session registry if we created a Telegram topic
      if (topicId) {
        const registryPath = path.join(ctx.config.stateDir, 'topic-session-registry.json');
        try {
          const reg = fs.existsSync(registryPath)
            ? JSON.parse(fs.readFileSync(registryPath, 'utf-8'))
            : { topicToSession: {}, topicToName: {} };
          reg.topicToSession[String(topicId)] = tmuxSession;
          reg.topicToName[String(topicId)] = topicName;
          fs.writeFileSync(registryPath, JSON.stringify(reg, null, 2));
        } catch {
          // Non-fatal — registry is best-effort
        }
      }

      // Update Slack channel-session registry and invite authorized users
      if (slackChannelId && ctx.slack) {
        ctx.slack.registerChannelSession(slackChannelId, tmuxSession, topicName);
        // Invite authorized users to the new channel
        try {
          const slackConfig = ctx.config.messaging?.find(m => m.type === 'slack')?.config as Record<string, unknown> | undefined;
          const authorizedUserIds = (slackConfig?.authorizedUserIds as string[]) ?? [];
          for (const userId of authorizedUserIds) {
            await ctx.slack.api.call('conversations.invite', { channel: slackChannelId, users: userId }).catch(() => {});
          }
        } catch { /* non-fatal */ }
      }

      res.status(201).json({
        ok: true,
        session: tmuxSession,
        name: topicName,
        topicId: topicId || null,
        slackChannelId: slackChannelId || null,
        platform: resolvedPlatform,
        headless: resolvedPlatform === 'headless',
      });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // ── Token Ledger ────────────────────────────────────────────────
  // Read-only token-usage observability backed by SQLite. Source data
  // is Claude Code's per-session JSONL transcripts at
  // ~/.claude/projects/<encoded-cwd>/<sessionId>.jsonl.
  // Auth is enforced globally by authMiddleware.

  const TOKEN_DEFAULT_WINDOW_MS = 24 * 60 * 60 * 1000;
  const TOKEN_DEFAULT_ORPHAN_IDLE_MS = 30 * 60 * 1000;

  function parseSinceMs(raw: unknown): number {
    if (typeof raw === 'string' && /^\d+$/.test(raw)) {
      const n = Number(raw);
      if (n >= 0) return n;
    }
    return Date.now() - TOKEN_DEFAULT_WINDOW_MS;
  }

  router.get('/tokens/summary', (req, res) => {
    if (!ctx.tokenLedger) {
      res.status(503).json({ error: 'token ledger unavailable' });
      return;
    }
    const sinceMs = parseSinceMs(req.query.since);
    // `summary` = Claude token_events (unchanged; this is what BurnDetector reads).
    // `codex` = the separate Codex-rollout rollup — additive, observability-only.
    res.json({
      sinceMs,
      summary: ctx.tokenLedger.summary({ sinceMs }),
      codex: ctx.tokenLedger.codexSummary({ sinceMs }),
    });
  });

  // Session clock (docs/specs/ROBUST-SESSION-TIME-AWARENESS-SPEC.md) — read-only
  // observability: elapsed/remaining for each active time-boxed (autonomous)
  // session, so an agent (or the dashboard) can ask "how long have I been running
  // / how much is left" instead of guessing. Leak-bounded: returns the computed
  // clock + the sanitized derived `label` only — never the raw `goal` task text.
  // Per-machine by nature (the record is `.local`, gitignored).
  router.get('/session/clock', (req, res) => {
    const topic = typeof req.query.topic === 'string' ? req.query.topic : null;
    const now = Date.now();
    let sessions: ReturnType<typeof readSessionClocks> = [];
    try {
      sessions = readSessionClocks(ctx.config.stateDir, now, topic);
    } catch {
      sessions = [];
    }
    res.json({ now, nowIso: new Date(now).toISOString(), sessions });
  });

  // Per-feature LLM metrics (docs/specs/llm-feature-metrics-spec.md) — read-only
  // observability: per gate/sentinel cost + hit-rate, so tuning is evidence-based
  // (which to thin, which to strengthen). 503-stubs via the null ledger when
  // stateDir/metrics is unavailable. Phase 1a — the funnel tap that feeds it is
  // Phase 1b (on top of #638).
  router.get('/metrics/features', (req, res) => {
    if (!ctx.featureMetricsLedger) {
      res.status(503).json({ error: 'feature-metrics ledger unavailable' });
      return;
    }
    const sinceHours = req.query.sinceHours ? Number(req.query.sinceHours) : undefined;
    const feature = typeof req.query.feature === 'string' ? req.query.feature : undefined;
    const summary = ctx.featureMetricsLedger.summary(
      sinceHours && sinceHours > 0 ? { sinceHours } : {},
    );
    const features = feature
      ? summary.features.filter((f) => f.feature === feature)
      : summary.features;
    // ?feature= composes with the per-model breakdown (token-audit-
    // completeness): each FeatureRollup carries its own byModel slice, and
    // totals.byModel narrows to the selected feature's partition.
    const totals = feature
      ? {
          ...summary.totals,
          byModel: features.flatMap((f) =>
            (f.byModel ?? []).map(({ feature: _f, successRowsWithUsage: _s, errorRowsWithUsage: _e, ...m }) => m),
          ),
        }
      : summary.totals;
    res.json({ ...summary, totals, features });
  });

  // ── GrowthMilestoneAnalyst (the proactive growth & milestone analyst) ──────
  // Read-only observability over the maturity/initiative/spec/correction
  // surfaces. The analyst ships DARK (monitoring.growthAnalyst.enabled false) —
  // when off, ctx.growthMilestoneAnalyst is null and every route 503s. POST
  // /growth/tick only runs the OBSERVE + COMPUTE pass (updates the stage journal,
  // returns the digest); it never sends to Telegram in this slice.
  // Spec: docs/specs/PROACTIVE-GROWTH-MILESTONE-ANALYST-SPEC.md
  router.get('/growth/digest', (_req, res) => {
    if (!ctx.growthMilestoneAnalyst) {
      res.status(503).json({ error: 'GrowthMilestoneAnalyst not initialized (monitoring.growthAnalyst.enabled is false)' });
      return;
    }
    try {
      res.json(ctx.growthMilestoneAnalyst.buildDigest());
    } catch (err) {
      res.status(500).json({ error: (err as Error).message });
    }
  });

  router.get('/growth/findings', (_req, res) => {
    if (!ctx.growthMilestoneAnalyst) {
      res.status(503).json({ error: 'GrowthMilestoneAnalyst not initialized (monitoring.growthAnalyst.enabled is false)' });
      return;
    }
    try {
      res.json({ findings: ctx.growthMilestoneAnalyst.computeFindings() });
    } catch (err) {
      res.status(500).json({ error: (err as Error).message });
    }
  });

  router.get('/growth/status', (_req, res) => {
    if (!ctx.growthMilestoneAnalyst) {
      res.status(503).json({ error: 'GrowthMilestoneAnalyst not initialized (monitoring.growthAnalyst.enabled is false)' });
      return;
    }
    try {
      res.json(ctx.growthMilestoneAnalyst.getStatus());
    } catch (err) {
      res.status(500).json({ error: (err as Error).message });
    }
  });

  router.post('/growth/tick', (_req, res) => {
    if (!ctx.growthMilestoneAnalyst) {
      res.status(503).json({ error: 'GrowthMilestoneAnalyst not initialized (monitoring.growthAnalyst.enabled is false)' });
      return;
    }
    try {
      res.json(ctx.growthMilestoneAnalyst.buildDigest());
    } catch (err) {
      res.status(500).json({ error: (err as Error).message });
    }
  });

  // ── Blocker Ledger (Autonomy Principles Enforcement, Piece 1) ────────────────
  // The resolution-workflow + memory layer that COMPLETES Principle 1 ("almost
  // every blocker is a false blocker — work it"). Signal-only: it RECORDS and
  // STRUCTURES; it never blocks an outbound message (B16/B17 keep that authority).
  // Ships DARK — every route 503s unless monitoring.blockerLedger.enabled.
  const BLOCKER_DARK = 'BlockerLedger not initialized (monitoring.blockerLedger.enabled is false)';
  const blockerWriteLimiter = rateLimiter(60_000, 30);
  // Map a BlockerLedgerError code to an HTTP status. Validation/evidence failures
  // are the caller's to fix (4xx); an unexpected error is 500.
  const blockerErrStatus = (err: unknown): number => {
    const code = (err as { code?: string })?.code;
    if (!code) return 500;
    if (code === 'not_found') return 404;
    if (code === 'already_settled') return 409;
    // every other code is an input/evidence validation refusal
    return 422;
  };

  router.get('/blockers', (req, res) => {
    if (!ctx.blockerLedger) {
      res.status(503).json({ error: BLOCKER_DARK });
      return;
    }
    try {
      const limit = req.query.limit ? Number(req.query.limit) : undefined;
      const offset = req.query.offset ? Number(req.query.offset) : undefined;
      const includeArchived = req.query.includeArchived === '1' || req.query.includeArchived === 'true';
      res.json(ctx.blockerLedger.list({ limit, offset, includeArchived }));
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      res.status(500).json({ error: msg });
    }
  });

  // ── Self-Unblock Before Escalating (read-only checklist-run view, spec §7) ───
  // Extends the /blockers read surface with the recent self-unblock checklist runs
  // (per-probe results + the rung). Registered BEFORE GET /blockers/:id so the
  // literal path is not swallowed by the :id param. Bearer-gated by the same
  // router-wide authMiddleware (NOT auth-exempt); the 503-when-dark check happens
  // AFTER auth (an unauthenticated caller gets 401 from the middleware, never a 503
  // that would confirm the route exists). Cache-Control: no-store — the body is
  // credential-reachability reconnaissance. Default-bounded (?limit=, last 200) +
  // skip-corrupt-lines (the store's list() tolerates partial lines). Served through
  // the <blocker-ledger-data> envelope — each run's untrusted detail is DATA.
  const SELF_UNBLOCK_DARK =
    'Self-Unblock checklist not initialized (monitoring.blockerLedger.selfUnblockChecklist.enabled is false)';
  router.get('/blockers/self-unblock-runs', async (req, res) => {
    if (!ctx.selfUnblockRunStore) {
      res.status(503).json({ error: SELF_UNBLOCK_DARK });
      return;
    }
    try {
      const { toLlmSafeEnvelope } = await import('../monitoring/BlockerLedger.js');
      const { resolveRung } = await import('../monitoring/SelfUnblockChecklist.js');
      const rawLimit = req.query.limit ? Number(req.query.limit) : 200;
      const limit = Number.isFinite(rawLimit) ? Math.min(Math.max(rawLimit, 1), 200) : 200;
      const runs = ctx.selfUnblockRunStore.list(limit);
      const view = runs.map((run) => {
        // Derive the rung from the run (no action-class / operator-only context
        // available on a pure read — surface the BASE rung the run implies).
        const rung = resolveRung({ run }).rung;
        return {
          runId: run.runId,
          target: run.target,
          requiredAttemptType: run.requiredAttemptType,
          completedAt: run.completedAt,
          exhausted: run.exhausted,
          rung,
          probes: run.probes.map((p) => ({
            source: p.source,
            reachable: p.reachable,
            holdsRelevantCred: p.holdsRelevantCred,
            probedAt: p.probedAt,
            matchedScopeTags: p.matchedScopeTags,
            // Untrusted free text → DATA, wrapped in the ledger envelope.
            detail: p.detail ? toLlmSafeEnvelope(p.detail) : undefined,
          })),
        };
      });
      res.set('Cache-Control', 'no-store');
      res.json({ runs: view, total: view.length });
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      res.status(500).json({ error: msg });
    }
  });

  // ── Self-Unblock Before Escalating — RUN the checklist (the PRODUCER, spec §5) ─
  // POST /blockers/self-unblock-run runs the PRODUCTION checklist (real probe
  // providers + durable run store) against a target and persists the run, so a
  // true-blocker settle can REFERENCE that verified run. Without this surface
  // nothing in production could PRODUCE a run, so enabling the feature made
  // settling a credential-blocker impossible — this closes that gap.
  //
  // Bearer-gated by the router-wide authMiddleware (NOT auth-exempt); the
  // 503-when-dark check happens AFTER auth (an unauthenticated caller gets 401 from
  // the middleware, never a 503 confirming the route exists). Cache-Control:
  // no-store — the body is credential-reachability reconnaissance. Registered
  // BEFORE POST /blockers/:id/* is irrelevant (those are distinct literal paths),
  // but it MUST precede GET /blockers/:id (above) — which it does, sharing the
  // /blockers/self-unblock-* prefix that is registered first. Run is rate-limited.
  const SELF_UNBLOCK_RUN_DARK =
    'Self-Unblock checklist producer not initialized (monitoring.blockerLedger.selfUnblockChecklist.enabled is false)';
  router.post('/blockers/self-unblock-run', blockerWriteLimiter, async (req, res) => {
    if (!ctx.selfUnblockChecklist) {
      res.status(503).json({ error: SELF_UNBLOCK_RUN_DARK });
      return;
    }
    if (req.headers['x-instar-request'] !== '1') {
      res.status(403).json({ error: 'POST /blockers/self-unblock-run requires the X-Instar-Request: 1 intent header' });
      return;
    }
    try {
      const body = (req.body ?? {}) as { target?: unknown; requiredAttemptType?: unknown };
      const target = typeof body.target === 'string' ? body.target.trim() : '';
      if (!target) {
        res.status(400).json({ error: 'target (a non-empty service:scope string) is required' });
        return;
      }
      const rawType = body.requiredAttemptType;
      if (rawType !== undefined && rawType !== 'self-fetch' && rawType !== 'dry-run') {
        res.status(400).json({ error: "requiredAttemptType must be 'self-fetch' or 'dry-run'" });
        return;
      }
      const requiredAttemptType: 'self-fetch' | 'dry-run' =
        rawType === 'dry-run' ? 'dry-run' : 'self-fetch';

      const { toLlmSafeEnvelope } = await import('../monitoring/BlockerLedger.js');
      const { resolveRung } = await import('../monitoring/SelfUnblockChecklist.js');
      const run = await ctx.selfUnblockChecklist.run({ target, requiredAttemptType });
      const rung = resolveRung({ run }).rung;
      res.set('Cache-Control', 'no-store');
      res.json({
        runId: run.runId,
        target: run.target,
        requiredAttemptType: run.requiredAttemptType,
        completedAt: run.completedAt,
        exhausted: run.exhausted,
        rung,
        probes: run.probes.map((p) => ({
          source: p.source,
          reachable: p.reachable,
          holdsRelevantCred: p.holdsRelevantCred,
          probedAt: p.probedAt,
          matchedScopeTags: p.matchedScopeTags,
          // Untrusted free text → DATA, wrapped in the ledger envelope.
          detail: p.detail ? toLlmSafeEnvelope(p.detail) : undefined,
        })),
      });
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      res.status(500).json({ error: msg });
    }
  });

  router.get('/blockers/:id', (req, res) => {
    if (!ctx.blockerLedger) {
      res.status(503).json({ error: BLOCKER_DARK });
      return;
    }
    const entry = ctx.blockerLedger.get(req.params.id);
    if (!entry) {
      res.status(404).json({ error: `unknown blocker ${req.params.id}` });
      return;
    }
    res.json(entry);
  });

  router.post('/blockers', blockerWriteLimiter, async (req, res) => {
    if (!ctx.blockerLedger) {
      res.status(503).json({ error: BLOCKER_DARK });
      return;
    }
    if (req.headers['x-instar-request'] !== '1') {
      res.status(403).json({ error: 'POST /blockers requires the X-Instar-Request: 1 intent header' });
      return;
    }
    try {
      const { detectedText, origin } = (req.body ?? {}) as { detectedText?: string; origin?: string };
      if (!detectedText || !origin) {
        res.status(400).json({ error: 'detectedText and origin are required' });
        return;
      }
      const entry = await ctx.blockerLedger.open({ detectedText, origin });
      res.status(201).json(entry);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      res.status(blockerErrStatus(err)).json({ error: msg });
    }
  });

  router.post('/blockers/:id/advance', blockerWriteLimiter, async (req, res) => {
    if (!ctx.blockerLedger) {
      res.status(503).json({ error: BLOCKER_DARK });
      return;
    }
    if (req.headers['x-instar-request'] !== '1') {
      res.status(403).json({ error: 'POST /blockers/:id/advance requires the X-Instar-Request: 1 intent header' });
      return;
    }
    try {
      const entry = await ctx.blockerLedger.advance(req.params.id, req.body ?? {});
      res.json(entry);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      res.status(blockerErrStatus(err)).json({ error: msg });
    }
  });

  router.post('/blockers/:id/settle', blockerWriteLimiter, async (req, res) => {
    if (!ctx.blockerLedger) {
      res.status(503).json({ error: BLOCKER_DARK });
      return;
    }
    if (req.headers['x-instar-request'] !== '1') {
      res.status(403).json({ error: 'POST /blockers/:id/settle requires the X-Instar-Request: 1 intent header' });
      return;
    }
    try {
      const entry = await ctx.blockerLedger.settle(req.params.id, req.body ?? {});
      res.json(entry);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      res.status(blockerErrStatus(err)).json({ error: msg });
    }
  });

  // Learning-velocity metric (EXO 3.0 — Salim Ismail, "Your KPI System Is
  // Training You to Miss the Future"): measure how fast the org is LEARNING
  // (adaptability, experimentation, capability creation) rather than backward-
  // looking operational throughput. Gathers Instar's real learning events
  // (registered learnings, corrections, evolution actions) and computes velocity
  // + trend + diversity. Read-only + advisory.
  //
  // ?windowDays=N (default 30) → { totalEvents, eventsPerDay, byType,
  //   typeDiversity, trend, adaptabilityScore, reason }
  router.get('/metrics/learning-velocity', async (req, res) => {
    try {
      const windowDays = req.query.windowDays
        ? Math.max(1, parseInt(req.query.windowDays as string, 10) || 30)
        : 30;
      const { computeLearningVelocity } = await import('../core/LearningVelocityScorer.js');
      const fs = await import('node:fs');
      const path = await import('node:path');
      const events: { timestamp: string; type: string }[] = [];
      const tsField = (o: Record<string, unknown>): unknown =>
        o.createdAt ?? o.timestamp ?? o.date ?? o.ts ?? o.loggedAt ?? o.addedAt ?? o.discoveredAt;
      const push = (ts: unknown, type: string) => {
        if (ts === undefined || ts === null) return;
        const iso = typeof ts === 'number' ? new Date(ts).toISOString() : String(ts);
        events.push({ timestamp: iso, type });
      };
      // (1) Registered learnings — EvolutionManager writes to state/evolution/, and the
      // timestamp lives at source.discoveredAt (not a top-level field). The old path
      // (stateDir/learning-registry.json) and top-level tsField both missed → 0 events.
      try {
        const p = path.join(ctx.config.stateDir, 'state', 'evolution', 'learning-registry.json');
        if (fs.existsSync(p)) {
          const reg = JSON.parse(fs.readFileSync(p, 'utf-8'));
          for (const l of (reg.learnings ?? [])) {
            const src = (l && typeof l === 'object' ? (l as Record<string, unknown>).source : null) as Record<string, unknown> | null;
            push(src?.discoveredAt ?? tsField(l), 'learning');
          }
        }
      } catch { /* skip unreadable source */ }
      // (2) Evolution actions — a JSON array under .actions (each with top-level
      // createdAt), NOT a logs/*.jsonl stream.
      try {
        const p = path.join(ctx.config.stateDir, 'state', 'evolution', 'action-queue.json');
        if (fs.existsSync(p)) {
          const aq = JSON.parse(fs.readFileSync(p, 'utf-8'));
          for (const a of (aq.actions ?? [])) push(tsField(a), 'evolution');
        }
      } catch { /* skip unreadable source */ }
      // (3) Corrections — persisted in the SQLite CorrectionLedger, not a JSONL file.
      // Guarded: correctionLearning ships off on many agents (ledger may be absent).
      if (ctx.correctionLedger) {
        try {
          for (const r of ctx.correctionLedger.list({ limit: 1000 })) {
            push((r as { detectedAt?: string; createdAt?: string }).detectedAt ?? (r as { createdAt?: string }).createdAt, 'correction');
          }
        } catch { /* skip ledger error */ }
      }
      res.json(computeLearningVelocity(events, new Date().toISOString(), windowDays));
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : 'Failed to compute learning velocity' });
    }
  });

  // ── Per-agent ResourceLedger (Phase A: durable rate-limit events) ────
  // Read-only. 503 when the ledger is unavailable (no stateDir / init failed /
  // monitoring.resourceLedger.enabled:false leaves it null). Never gates.
  router.get('/resources/rate-limits', (req, res) => {
    if (!ctx.resourceLedger) {
      res.status(503).json({ error: 'resource ledger unavailable (disabled or not initialized)' });
      return;
    }
    const sinceHours = req.query.sinceHours ? Number(req.query.sinceHours) : 24;
    const windowMs = (sinceHours && sinceHours > 0 ? sinceHours : 24) * 3_600_000;
    const now = Date.now();
    res.json({
      windowHours: windowMs / 3_600_000,
      summary: ctx.resourceLedger.rateLimitSummary(now, windowMs),
      byKind: ctx.resourceLedger.rateLimitByKind(now, windowMs),
      events: ctx.resourceLedger.rateLimitEvents({ sinceMs: now - windowMs, limit: 200 }),
    });
  });

  // ── Per-agent ResourceLedger (Phase B: CPU + memory samples) ─────────
  // Read-only. Mirrors /tokens/summary: current + windowed CPU%/RSS per source
  // (agent-server, each session, aggregate) + the total sample count. 503 when
  // the ledger is unavailable (disabled / not initialized). Never gates.
  router.get('/resources/summary', (req, res) => {
    if (!ctx.resourceLedger) {
      res.status(503).json({ error: 'resource ledger unavailable (disabled or not initialized)' });
      return;
    }
    const sinceHours = req.query.sinceHours ? Number(req.query.sinceHours) : 1;
    const windowHours = sinceHours && sinceHours > 0 ? sinceHours : 1;
    const sinceMs = Date.now() - windowHours * 3_600_000;
    res.json({
      windowHours,
      sinceMs,
      sampleCount: ctx.resourceLedger.sampleCount(),
      sources: ctx.resourceLedger.summary(sinceMs),
    });
  });

  // Recent raw CPU/mem samples, newest first (paginated; ?limit= / ?source= /
  // ?sinceHours=). Read-only.
  router.get('/resources/samples', (req, res) => {
    if (!ctx.resourceLedger) {
      res.status(503).json({ error: 'resource ledger unavailable (disabled or not initialized)' });
      return;
    }
    const sinceHours = req.query.sinceHours ? Number(req.query.sinceHours) : 1;
    const windowHours = sinceHours && sinceHours > 0 ? sinceHours : 1;
    const sinceMs = Date.now() - windowHours * 3_600_000;
    let limit = 200;
    if (typeof req.query.limit === 'string' && /^\d+$/.test(req.query.limit)) {
      const n = Number(req.query.limit);
      if (n > 0 && n <= 2000) limit = n;
    }
    const source = typeof req.query.source === 'string' ? req.query.source : undefined;
    res.json({
      windowHours,
      sinceMs,
      limit,
      samples: ctx.resourceLedger.recentSamples({ sinceMs, limit, source }),
    });
  });

  // Per-machine process-footprint monitor status (observe-only; the climb
  // measurement missing before the 2026-06-26 resource-exhaustion panic). 503
  // when the monitor is disabled/dark (monitoring.processFootprintMonitor). Never
  // gates — read-only.
  router.get('/resources/footprint', (_req, res) => {
    if (!ctx.processFootprintMonitor) {
      res.status(503).json({ error: 'process-footprint monitor unavailable (disabled or not initialized)' });
      return;
    }
    res.json(ctx.processFootprintMonitor.status());
  });

  // ── Fork-bomb prevention: host-wide spawn-cap status (forkbomb-prevention-simple §P1/§P3) ──
  // Read-only observability over the host-wide concurrent-LLM-subprocess cap.
  // Reports the live holder count (this host + foreign, never-reclaimed), the
  // cap, the bounded-acquire budget, and the live concurrent-poller count
  // (P3 waiters). Always available — the cap is a safety floor that ships ON.
  router.get('/spawn-limiter', (_req, res) => {
    try {
      const status = getHostSpawnSemaphore().status();
      res.json({
        cap: status.cap,
        liveHolders: status.liveHolders,
        localHolders: status.localHolders,
        foreignHolders: status.foreignHolders,
        available: Math.max(0, status.cap - status.liveHolders),
        saturated: status.liveHolders >= status.cap,
        waiters: activeSpawnPollers(),
        acquireMs: configuredSpawnAcquireMs(),
        waitersMax: configuredSpawnWaitersMax(),
        holdersPath: status.holdersPath,
        // F5 interactive-priority reservation (Registry First: read it, never guess).
        interactivePriority: status.interactivePriority,
        liveInteractive: status.liveInteractive,
        liveBackground: status.liveBackground,
      });
    } catch (err) {
      // Observability must never throw — report an honest error rather than 500.
      res.status(500).json({ error: 'spawn-limiter status unavailable', detail: err instanceof Error ? err.message : String(err) });
    }
  });

  // ── Approval-as-Data (docs/specs/AUTONOMOUS-OPERATION-JUDGMENT-AND-APPROVAL-AS-DATA-SPEC.md, Part B / Phase 2) ──
  // Durable, signed record of every operator approval decision, and the per-class
  // agreement ratios computed from it. Tracks approvals WHEREVER they occur (a spec
  // sign-off, a decision approved in chat, …) — operator extension 2026-06-05.
  //
  // AUTHORITY INVARIANT: `mode` + `divergences` MUST reflect an EXPLICIT operator
  // statement (the approve control, or words like "go with your picks" = as-is vs
  // "change X because Y" = with-change). The agent must NOT infer/self-classify the
  // operator's intent; an ambiguous/silent decision is NOT recorded. Any row is
  // operator-correctable (append a row with `corrects` set). Read paths never gate.

  // Record an approval decision. The caller passes operator-sourced mode+divergences.
  router.post('/approvals', (req, res) => {
    if (!ctx.approvalLedger) {
      res.status(503).json({ error: 'approval ledger unavailable (no stateDir or init failed)' });
      return;
    }
    const b = req.body ?? {};
    if (typeof b.subject !== 'string' || !b.subject.trim()) {
      res.status(400).json({ error: 'subject is required' });
      return;
    }
    if (typeof b.decisionClass !== 'string' || !b.decisionClass.trim()) {
      res.status(400).json({ error: 'decisionClass is required' });
      return;
    }
    try {
      const row = ctx.approvalLedger.recordApproval({
        subject: b.subject,
        decisionClass: b.decisionClass,
        surface: b.surface ?? 'chat',
        approver: typeof b.approver === 'string' && b.approver ? b.approver : 'justin',
        mode: b.mode,
        divergences: Array.isArray(b.divergences) ? b.divergences : undefined,
        reviewIterations: typeof b.reviewIterations === 'number' ? b.reviewIterations : undefined,
        commitSha: typeof b.commitSha === 'string' ? b.commitSha : undefined,
        evidenceRef: typeof b.evidenceRef === 'string' ? b.evidenceRef : undefined,
        corrects: typeof b.corrects === 'string' ? b.corrects : undefined,
        decidedAt: typeof b.decidedAt === 'string' ? b.decidedAt : undefined,
      });
      res.status(201).json({ recorded: true, row });
    } catch (err) {
      // The store throws on an internally-inconsistent row (e.g. as-is WITH a
      // divergence, or a change WITHOUT one) — that's a 400, not a 500.
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // Per-class agreement summary + an overall surface breakdown. Read-only; never gates.
  router.get('/approvals/summary', (_req, res) => {
    if (!ctx.approvalLedger) {
      res.status(503).json({ error: 'approval ledger unavailable (no stateDir or init failed)' });
      return;
    }
    const classes = ctx.approvalLedger.summarize();
    const rows = ctx.approvalLedger.all();
    const bySurface: Record<string, { total: number; approvedAsIs: number }> = {};
    for (const r of rows) {
      const s = (bySurface[r.surface] ??= { total: 0, approvedAsIs: 0 });
      s.total++;
      if (r.mode === 'approved-as-is') s.approvedAsIs++;
    }
    res.json({
      total: rows.length,
      classes,
      bySurface,
      note: 'Read-only. The ratio is a SIGNAL; auto-approval (Phase 3) routes through a full-context authority, not the arithmetic.',
    });
  });

  // List recorded rows, newest-first (paginated; ?limit= / ?decisionClass= / ?surface=).
  router.get('/approvals', (req, res) => {
    if (!ctx.approvalLedger) {
      res.status(503).json({ error: 'approval ledger unavailable (no stateDir or init failed)' });
      return;
    }
    let limit = 100;
    if (typeof req.query.limit === 'string' && /^\d+$/.test(req.query.limit)) {
      const n = Number(req.query.limit);
      if (n > 0 && n <= 1000) limit = n;
    }
    const decisionClass = typeof req.query.decisionClass === 'string' ? req.query.decisionClass : undefined;
    const surface = typeof req.query.surface === 'string' ? req.query.surface : undefined;
    let rows = ctx.approvalLedger.all();
    if (decisionClass) rows = rows.filter((r) => r.decisionClass === decisionClass);
    if (surface) rows = rows.filter((r) => r.surface === surface);
    const recent = rows.slice(-limit).reverse();
    res.json({ count: recent.length, total: rows.length, rows: recent });
  });

  // ── Coordination Mandate (docs/specs/coordination-mandate.md §4) ──
  // Deny-by-default enforcement for autonomous A2A authority. The mandate (a
  // human-authored, signed policy) is the AUTHORIZER — never the agent. Justin's
  // resolved decisions (A/A/B, 2026-06-05): issuance + revocation are PIN-gated
  // (the human-authenticated dashboard surface — an agent's Bearer token CANNOT
  // issue/revoke); the first mandate carries only exchange-read-credential +
  // sign-code-review; execute-cutover is not delegated (the flip stays human).
  //
  // PIN verification mirrors /dashboard/unlock: sha256 + timingSafeEqual + a
  // per-IP attempt limit. Read paths + /mandate/evaluate are Bearer-gated.

  const mandatePinAttempts = new Map<string, { count: number; resetAt: number }>();
  const MANDATE_PIN_MAX_ATTEMPTS = 5;
  const MANDATE_PIN_WINDOW_MS = 5 * 60 * 1000;

  /** Verify the operator PIN for mandate issuance/revocation. Returns an error
   *  string (already sent) or null when the PIN is valid. */
  function checkMandatePin(req: import('express').Request, res: import('express').Response): boolean {
    if (!ctx.config.dashboardPin) {
      res.status(503).json({ error: 'PIN authentication not available (no dashboardPin configured)' });
      return false;
    }
    const ip = req.ip || req.socket?.remoteAddress || 'unknown';
    const now = Date.now();
    let entry = mandatePinAttempts.get(ip);
    if (entry && now > entry.resetAt) { mandatePinAttempts.delete(ip); entry = undefined; }
    if (entry && entry.count >= MANDATE_PIN_MAX_ATTEMPTS) {
      res.status(429).json({ error: 'Too many attempts. Try again later.' });
      return false;
    }
    const pin = (req.body ?? {}).pin;
    if (!pin || typeof pin !== 'string') {
      res.status(403).json({ error: 'Operator PIN required — mandate issuance/revocation is a human action, not an agent action' });
      return false;
    }
    const ha = createHash('sha256').update(pin).digest();
    const hb = createHash('sha256').update(ctx.config.dashboardPin).digest();
    if (ha.length !== hb.length || !timingSafeEqual(ha, hb)) {
      if (!entry) { entry = { count: 0, resetAt: now + MANDATE_PIN_WINDOW_MS }; mandatePinAttempts.set(ip, entry); }
      entry.count++;
      res.status(403).json({ error: 'Incorrect PIN', attemptsRemaining: MANDATE_PIN_MAX_ATTEMPTS - entry.count });
      return false;
    }
    return true;
  }

  // Evaluate an action against a mandate (the enforcement consumption point).
  // Every call — allow AND deny — lands in the hash-chained audit.
  router.post('/mandate/evaluate', (req, res) => {
    if (!ctx.coordination) {
      res.status(503).json({ error: 'coordination mandate engine unavailable (no stateDir or init failed)' });
      return;
    }
    const b = req.body ?? {};
    if (typeof b.action !== 'string' || !b.action || typeof b.agentFp !== 'string' || !b.agentFp || typeof b.mandateId !== 'string' || !b.mandateId) {
      res.status(400).json({ error: 'action, agentFp, and mandateId are required' });
      return;
    }
    const result = ctx.coordination.gate.evaluate({
      action: b.action,
      params: (b.params && typeof b.params === 'object') ? b.params : {},
      agentFp: b.agentFp,
      mandateId: b.mandateId,
    });
    res.json({ decision: result.decision, reason: result.reason, conditionResult: result.conditionResult });
  });

  // Read-only audit trail + chain integrity. MUST be registered before /mandate/:id.
  router.get('/mandate/audit', (req, res) => {
    if (!ctx.coordination) {
      res.status(503).json({ error: 'coordination mandate engine unavailable (no stateDir or init failed)' });
      return;
    }
    let limit = 100;
    if (typeof req.query.limit === 'string' && /^\d+$/.test(req.query.limit)) {
      const n = Number(req.query.limit);
      if (n > 0 && n <= 1000) limit = n;
    }
    const all = ctx.coordination.audit.all();
    res.json({
      total: all.length,
      chain: ctx.coordination.audit.verifyChain(),
      headHash: ctx.coordination.audit.headHash(),
      entries: all.slice(-limit).reverse(),
    });
  });

  // List mandates (each with its live authorship-verification status). Read-only.
  router.get('/mandate', (_req, res) => {
    if (!ctx.coordination) {
      res.status(503).json({ error: 'coordination mandate engine unavailable (no stateDir or init failed)' });
      return;
    }
    const { store } = ctx.coordination;
    res.json({
      mandates: store.list().map((m) => ({ ...m, authorshipValid: store.verifyAuthorship(m) })),
    });
  });

  // One mandate + its verification status. Read-only.
  router.get('/mandate/:id', (req, res) => {
    if (!ctx.coordination) {
      res.status(503).json({ error: 'coordination mandate engine unavailable (no stateDir or init failed)' });
      return;
    }
    const m = ctx.coordination.store.get(req.params.id);
    if (!m) {
      res.status(404).json({ error: `mandate "${req.params.id}" not found` });
      return;
    }
    res.json({ mandate: { ...m, authorshipValid: ctx.coordination.store.verifyAuthorship(m) } });
  });

  // silent-loss-refusal-conservation §2.D — mint a signed allow-marker for a
  // LEGITIMATE fixture-identity name-collision. PIN-GATED (a Bearer token is
  // structurally insufficient — else any token-holder could register a
  // fixture-with-owner-perms, reproducing the S3 escalation). Reuses
  // checkMandatePin (sha256 + timingSafeEqual + per-IP rate-limit). Returns the
  // signed `{marker, sig}`; the operator then registers the profile carrying it
  // (loadUsers/validateProfile VERIFY the HMAC with NO PIN present). The raw
  // header/marker is never logged; the authenticated principal is audited.
  router.post('/users/allow-test-identity', async (req, res) => {
    if (!checkMandatePin(req, res)) return; // 403/429 already sent
    const body = (req.body ?? {}) as { userId?: unknown; marker?: unknown };
    const userId = typeof body.userId === 'string' ? body.userId : '';
    const marker = typeof body.marker === 'string' ? body.marker : '';
    if (!userId || !marker) {
      res.status(400).json({ error: 'userId and marker are required' });
      return;
    }
    const { matchesTestIdentityToken, signAllowTestIdentity, loadTestIdentityKey } = await import('../users/testIdentityMarkers.js');
    // The marker must be a REAL fixture marker from the closed set (exact id or an
    // anchored reserved-token prefix) — a caller can't mint a signature for an
    // arbitrary string. The sig binds to (userId, marker); the load path verifies
    // it against the profile's OWN id + its matched marker.
    if (!matchesTestIdentityToken(marker)) {
      res.status(400).json({ error: 'marker is not a recognized fixture-identity marker' });
      return;
    }
    const key = loadTestIdentityKey(ctx.config.stateDir);
    if (!key) {
      res.status(503).json({ error: 'no server signing key available to mint an allow-marker' });
      return;
    }
    const sig = signAllowTestIdentity(key, userId, marker);
    console.log(`[allow-identity] minted allow-marker for a fixture-colliding user (operator-authenticated, PIN)`);
    res.json({ allowTestIdentity: { marker, sig } });
  });

  // Issue a mandate — PIN-GATED (decision 2A: the human-authenticated surface).
  router.post('/mandate/issue', (req, res) => {
    if (!ctx.coordination) {
      res.status(503).json({ error: 'coordination mandate engine unavailable (no stateDir or init failed)' });
      return;
    }
    if (!checkMandatePin(req, res)) return;
    const b = req.body ?? {};
    if (typeof b.scope !== 'string' || !b.scope.trim()) {
      res.status(400).json({ error: 'scope is required' });
      return;
    }
    if (!Array.isArray(b.agents) || b.agents.length !== 2 || b.agents.some((a: unknown) => typeof a !== 'string' || !a)) {
      res.status(400).json({ error: 'agents must be a pair of two agent fingerprints' });
      return;
    }
    if (!Array.isArray(b.authorities) || b.authorities.length === 0
      || b.authorities.some((a: any) => typeof a?.action !== 'string' || !a.action || typeof a?.bounds !== 'object' || a.bounds === null)) {
      res.status(400).json({ error: 'authorities must be a non-empty array of { action, bounds, requiresCondition? }' });
      return;
    }
    if (typeof b.expiresAt !== 'string' || isNaN(Date.parse(b.expiresAt)) || Date.parse(b.expiresAt) <= Date.now()) {
      res.status(400).json({ error: 'expiresAt must be a future ISO timestamp (mandates always expire)' });
      return;
    }
    const mandate = ctx.coordination.store.issue({
      scope: b.scope,
      agents: [b.agents[0], b.agents[1]],
      authorities: b.authorities,
      author: typeof b.author === 'string' && b.author ? b.author : 'justin',
      expiresAt: b.expiresAt,
    });
    res.status(201).json({ issued: true, mandate });
  });

  // WS5.2 R4a / R1 — ONE-DASHBOARD cross-machine mandate issuance + delivery. Issue an
  // account-follow-me mandate (PIN-gated, EXACTLY like /mandate/issue) for a REMOTE target machine,
  // then DELIVER it to that target over the signed mesh so the target's enroll-start route honors it
  // — WITHOUT the operator ever opening the target's own dashboard. The mandate is signed locally
  // (its LOCAL authProof is meaningless on the target) AND packaged with the R4a asymmetric issuance
  // signature (the ONLY thing the target can verify). A LOCAL target (targetMachineId === this
  // machine) is the unchanged /mandate/issue path and is NOT delivered (the local gate sees it).
  router.post('/mandate/issue-for-machine', async (req, res) => {
    if (!ctx.coordination) {
      res.status(503).json({ error: 'coordination mandate engine unavailable (no stateDir or init failed)' });
      return;
    }
    const afmCfg = (ctx.config as unknown as { multiMachine?: { accountFollowMe?: { enabled?: boolean } } })
      .multiMachine?.accountFollowMe;
    if (!resolveDevAgentGate(afmCfg?.enabled, ctx.config)) {
      res.status(503).json({ error: 'account follow-me not enabled' });
      return;
    }
    if (!checkMandatePin(req, res)) return;
    const b = req.body ?? {};
    // The mandate is ALWAYS an account-follow-me grant pinned to ONE account + ONE target machine +
    // re-mint (R1 exact-bounds): the body carries the bounds, never an arbitrary authority list.
    if (typeof b.accountId !== 'string' || !b.accountId.trim()) {
      res.status(400).json({ error: 'accountId is required' });
      return;
    }
    if (typeof b.targetMachineId !== 'string' || !b.targetMachineId.trim()) {
      res.status(400).json({ error: 'targetMachineId is required' });
      return;
    }
    if (!Array.isArray(b.agents) || b.agents.length !== 2 || b.agents.some((a: unknown) => typeof a !== 'string' || !a)) {
      res.status(400).json({ error: 'agents must be a pair of two agent fingerprints' });
      return;
    }
    // FD1 (ws52-operator-tap-not-text): the one-tap card sends NO expiry — the server
    // defaults to 1 hour (a mandate only needs to authorize one re-mint enrollment, not
    // standing access). A caller MAY still pass an explicit future expiry; an invalid one
    // is rejected. Mandates always expire either way.
    let expiresAt: string;
    if (b.expiresAt === undefined || b.expiresAt === null || b.expiresAt === '') {
      expiresAt = new Date(Date.now() + 60 * 60 * 1000).toISOString();
    } else if (typeof b.expiresAt !== 'string' || isNaN(Date.parse(b.expiresAt)) || Date.parse(b.expiresAt) <= Date.now()) {
      res.status(400).json({ error: 'expiresAt, if provided, must be a future ISO timestamp' });
      return;
    } else {
      expiresAt = b.expiresAt;
    }
    const { accountId, targetMachineId } = b as { accountId: string; targetMachineId: string };
    const selfMachineId = ctx.meshSelfId ?? (ctx.config as { machineId?: string }).machineId ?? 'local';

    // Issue locally (PIN-gated above) — exact-bounds account-follow-me / re-mint (R1).
    const mandate = ctx.coordination.store.issue({
      scope: typeof b.scope === 'string' && b.scope.trim() ? b.scope : 'account-follow-me',
      agents: [b.agents[0], b.agents[1]],
      authorities: [
        { action: 'account-follow-me', bounds: { accountId, targetMachineId, mechanism: 're-mint' } },
      ],
      author: typeof b.author === 'string' && b.author ? b.author : 'justin',
      expiresAt,
    });

    // A LOCAL target is the ordinary path — the local gate already sees this mandate; no delivery.
    if (targetMachineId === selfMachineId) {
      res.status(201).json({ issued: true, mandate, delivered: false, local: true });
      return;
    }

    // REMOTE target — package with the R4a issuance signature and deliver over the mesh.
    if (!ctx.packageMandateForDelivery || !ctx.deliverMandateToMachine) {
      res.status(503).json({ error: 'cross-machine mandate delivery unavailable (no mesh identity)' });
      return;
    }
    try {
      const portable = ctx.packageMandateForDelivery(mandate);
      const outcome = await ctx.deliverMandateToMachine({ targetMachineId, portable });
      if (!outcome.ok) {
        // The mandate is issued + persisted locally; only the DELIVERY failed. Honest 502 so the
        // operator can retry delivery without re-issuing (idempotent put on the target by id).
        res.status(502).json({ issued: true, mandate, delivered: false, deliveryStatus: outcome.status, reason: outcome.reason });
        return;
      }
      res.status(201).json({ issued: true, mandate, delivered: true, deliveryStatus: outcome.status });
    } catch (err) {
      res.status(502).json({ issued: true, mandate, delivered: false, error: err instanceof Error ? err.message : 'delivery failed' });
    }
  });

  // Revoke a mandate — PIN-GATED (the operator kill switch; checked on every action).
  router.post('/mandate/:id/revoke', (req, res) => {
    if (!ctx.coordination) {
      res.status(503).json({ error: 'coordination mandate engine unavailable (no stateDir or init failed)' });
      return;
    }
    if (!checkMandatePin(req, res)) return;
    const reason = typeof (req.body ?? {}).reason === 'string' && req.body.reason ? req.body.reason : 'operator revocation';
    const m = ctx.coordination.store.revoke(req.params.id, reason);
    if (!m) {
      res.status(404).json({ error: `mandate "${req.params.id}" not found` });
      return;
    }

    // WS5.2 R12 — Account Follow-Me revocation data-plane trigger (PER-SERVER model, OQ6). The
    // control-plane revoke above already fired (every subsequent MandateGate.evaluate denies). If
    // the revoked mandate carried an `account-follow-me` authority, run THIS machine's OWN local
    // data-plane wipe (the operator revoked on the target's OWN dashboard ⇒ the target IS this
    // machine ⇒ cooperative-online posture). Non-account-follow-me mandates are completely
    // unaffected. Strict no-op when the executor is unwired OR the feature gate resolves dark
    // (revoke() returns feature-disabled and runs nothing). Surfaces the honest data-plane outcome
    // on the response so the operator/dashboard never sees a false "removed".
    let accountFollowMeRevocation:
      | import('../core/AccountFollowMeRevocation.js').RevocationOutcome
      | undefined;
    try {
      const followMeAuthority = (m.authorities ?? []).find((a) => a.action === 'account-follow-me');
      if (followMeAuthority && ctx.accountFollowMeRevocation) {
        const bounds = (followMeAuthority.bounds ?? {}) as Record<string, unknown>;
        const accountId = typeof bounds.accountId === 'string' ? bounds.accountId : '';
        const targetMachineId = typeof bounds.targetMachineId === 'string' ? bounds.targetMachineId : '';
        const mechanism =
          bounds.mechanism === 'credential-transport' ? 'credential-transport' : 're-mint';
        if (accountId && targetMachineId) {
          const acct = ctx.subscriptionPool?.get(accountId) ?? null;
          accountFollowMeRevocation = ctx.accountFollowMeRevocation.revoke(
            {
              accountId,
              accountEmail: acct?.email ?? accountId,
              targetMachineId,
              targetMachineNickname:
                typeof bounds.targetMachineNickname === 'string' ? bounds.targetMachineNickname : targetMachineId,
              provider: acct?.provider ?? (typeof bounds.provider === 'string' ? bounds.provider : 'the provider'),
              mandateId: m.id,
              mechanism,
            },
            // PER-SERVER: the operator revoked on the target's own dashboard ⇒ target is online &
            // cooperative (this very machine). The local wipe runs; an offline/de-paired posture is
            // only reachable on the cross-machine path, which the per-server model does not use.
            'cooperative-online',
          );
        }
      }
    } catch {
      // @silent-fallback-ok: the data-plane effect must never break the control-plane revoke (which
      // already succeeded). A wipe error is surfaced honestly INSIDE the executor (fail-closed to
      // pending) for the normal path; this catch is the last-resort backstop so the route always
      // returns the successful revoke.
      accountFollowMeRevocation = undefined;
    }

    res.json({ revoked: true, mandate: m, ...(accountFollowMeRevocation ? { accountFollowMeRevocation } : {}) });
  });

  // Add user→agent authority grant(s) to a mandate — PIN-GATED (the same human-
  // authenticated surface as issuance; an agent's Bearer token cannot mint a grant).
  // Re-signs the mandate so `authProof` covers the new grant(s); each grant decision
  // (accepted or rejected) lands in the SAME hash-chained MandateAudit. The grant rides
  // the signed, expiring, revocable mandate model — deny-by-default is inherited.
  // Design: docs/specs/SLACK-ORG-INTEGRATION-SPEC.md (floor grants) + coordination-mandate.md.
  router.post('/mandate/:id/grants', (req, res) => {
    if (!ctx.coordination) {
      res.status(503).json({ error: 'coordination mandate engine unavailable (no stateDir or init failed)' });
      return;
    }
    if (!checkMandatePin(req, res)) return;
    const b = req.body ?? {};
    // Accept either a single grant or an array.
    const rawGrants = Array.isArray(b.grants) ? b.grants : (b.grant ? [b.grant] : []);
    if (!Array.isArray(rawGrants) || rawGrants.length === 0) {
      res.status(400).json({ error: 'grants (array) or grant (object) is required' });
      return;
    }
    // Shallow shape check at the boundary; MandateStore.addGrants is the authoritative
    // validator (incl. the expiresAt <= mandate.expiresAt clamp).
    const grants = rawGrants.map((g: any) => ({
      floorAction: typeof g?.floorAction === 'string' ? g.floorAction : '',
      grantedTo: typeof g?.grantedTo === 'string' ? g.grantedTo : '',
      authorizedBy: typeof g?.authorizedBy === 'string' ? g.authorizedBy : '',
      expiresAt: typeof g?.expiresAt === 'string' ? g.expiresAt : '',
      ...(g?.bounds && typeof g.bounds === 'object' ? { bounds: g.bounds } : {}),
    }));

    const result = ctx.coordination.store.addGrants(req.params.id, grants);
    if (!result.ok) {
      // Audit the rejection so a refused grant is reconstructable too.
      for (const g of grants) {
        ctx.coordination.audit.record({
          mandateId: req.params.id,
          agentFp: g.grantedTo || 'unknown',
          action: `grant-floor:${g.floorAction || 'unknown'}`,
          decision: 'deny',
          reason: `grant rejected: ${result.reason}`,
        });
      }
      const status = result.reason === 'mandate not found' ? 404 : 400;
      res.status(status).json({ error: result.reason });
      return;
    }
    // Audit each accepted grant.
    for (const g of grants) {
      ctx.coordination.audit.record({
        mandateId: req.params.id,
        agentFp: g.grantedTo,
        action: `grant-floor:${g.floorAction}`,
        decision: 'allow',
        reason: `grant signed by ${g.authorizedBy} until ${g.expiresAt}`,
      });
    }
    res.status(201).json({ granted: true, mandate: { ...result.mandate, authorshipValid: ctx.coordination.store.verifyAuthorship(result.mandate) } });
  });

  // ── Operator Authorization Request (agent proposes → operator approves one-tap) ──
  // The agent (Bearer) pre-fills a STRUCTURED request; the operator approves it with
  // their dashboard PIN; only then does the server issue the grant via the existing
  // signed MandateStore path. requester ≠ authorizer is preserved (the agent can never
  // approve its own request). The operator-facing card is SERVER-authored from the
  // structured proposal + the registry name — never agent free-text (deceptive-summary
  // defense). Spec: docs/specs/OPERATOR-AUTHORIZATION-REQUEST-SPEC.md.
  const authReqUnavailable = (res: import('express').Response): boolean => {
    if (!ctx.authorizationRequests || !ctx.authorizationRequests.enabled) {
      res.status(503).json({ error: 'authorization-requests feature not enabled' });
      return true;
    }
    return false;
  };

  /** Decorate a stored request with the server-rendered, plain-language card (the only
   *  text an operator surface should show). Resolves the display name from the registry. */
  const decorateAuthReq = (r: AuthorizationRequest) => {
    const ar = ctx.authorizationRequests!;
    const principal = ar.resolvePrincipal(r.proposal.grantedToSlackUserId);
    const card = renderAuthorizationCard(r, principal?.name ?? r.proposal.grantedToSlackUserId);
    return {
      id: r.id, status: r.status, kind: r.kind, createdAt: r.createdAt,
      createdByAgent: r.createdByAgent, createdOnMachine: r.createdOnMachine,
      requestExpiresAt: r.requestExpiresAt, resolvedAt: r.resolvedAt, resolvedBy: r.resolvedBy,
      resultMandateId: r.resultMandateId, denyReason: r.denyReason,
      // server-authored display (never agent free-text as the authority):
      headline: card.headline, reason: card.reason,
      heldOnThisMachine: r.createdOnMachine === ar.machineId,
    };
  };

  // Agent proposes a structured request (Bearer). Confers no authority — inert until approved.
  router.post('/authorization-requests', (req, res) => {
    if (authReqUnavailable(res)) return;
    const ar = ctx.authorizationRequests!;
    const b = req.body ?? {};
    const agentName = (typeof b.createdByAgent === 'string' && b.createdByAgent) ? b.createdByAgent : 'agent';
    // FRESH-resolve the grantee against the principal registry at create (FD-12) — reject
    // a phantom/unregistered id before it ever reaches the operator's approval queue.
    const proposedUid = b?.proposal?.grantedToSlackUserId;
    if (typeof proposedUid === 'string' && proposedUid) {
      const principal = ar.resolvePrincipal(proposedUid);
      if (!principal || !principal.registered) {
        res.status(400).json({ error: 'unknown-user — the grantee must be a registered Slack user' });
        return;
      }
    }
    const result = ar.store.create({
      createdByAgent: agentName,
      createdOnMachine: ar.machineId,
      proposal: b.proposal,
      reason: typeof b.reason === 'string' ? b.reason : undefined,
    });
    if (!result.ok) { res.status(result.status).json({ error: result.error }); return; }
    res.status(201).json({ id: result.request.id, deduped: result.deduped ?? false, request: decorateAuthReq(result.request) });
  });

  // List requests (filter ?status=pending). Each row carries the server-rendered card. Bearer.
  router.get('/authorization-requests', (req, res) => {
    if (authReqUnavailable(res)) return;
    const ar = ctx.authorizationRequests!;
    const status = typeof req.query.status === 'string' ? req.query.status : undefined;
    const valid = ['pending', 'approved', 'denied', 'expired', 'withdrawn'];
    const list = ar.store.list(valid.includes(status as string) ? (status as AuthorizationRequest['status']) : undefined);
    res.json({ requests: list.map(decorateAuthReq), count: list.length });
  });

  // One request (with server-rendered display). Bearer.
  router.get('/authorization-requests/:id', (req, res) => {
    if (authReqUnavailable(res)) return;
    const r = ctx.authorizationRequests!.store.get(req.params.id);
    if (!r) { res.status(404).json({ error: 'request not found' }); return; }
    res.json({ request: decorateAuthReq(r) });
  });

  // Operator APPROVES — PIN-GATED. The single authority-conferring step. The PIN covers
  // the whole execution incl. the carrier-mandate auto-issue (no second prompt).
  router.post('/authorization-requests/:id/approve', (req, res) => {
    if (authReqUnavailable(res)) return;
    if (!ctx.coordination) { res.status(503).json({ error: 'coordination mandate engine unavailable' }); return; }
    if (!checkMandatePin(req, res)) return;
    const ar = ctx.authorizationRequests!;
    const result = ar.store.approve(req.params.id, {
      execute: (proposal) => {
        // Re-check the allowlist (defends against a config change while pending).
        if (!PROPOSABLE_FLOOR_ACTIONS.includes(proposal.floorAction)) throw new Error('action-no-longer-proposable');
        // FRESH-resolve the grantee against the registry (rejects phantom / reflects a rename).
        const principal = ar.resolvePrincipal(proposal.grantedToSlackUserId);
        if (!principal || !principal.registered) throw new Error('unknown-user');
        // Issue a fresh per-grant carrier mandate WITH the grant signed in, via the
        // existing PIN-authored signed path. expiry == grant lifetime (no clamp).
        const now = Date.now();
        const expiresAt = new Date(now + proposal.durationMs).toISOString();
        const mandate = ctx.coordination!.store.issue({
          scope: 'user-authority-grant',
          agents: [ar.carrierSelfFp, ar.carrierSelfFp],
          authorities: [],
          author: 'system',
          expiresAt,
          grants: [{
            floorAction: proposal.floorAction,
            grantedTo: proposal.grantedToSlackUserId,
            authorizedBy: ar.ownerDisplay,
            expiresAt,
          }],
        });
        ctx.coordination!.audit.record({
          mandateId: mandate.id,
          agentFp: proposal.grantedToSlackUserId,
          action: `grant-floor:${proposal.floorAction}`,
          decision: 'allow',
          reason: `approved via authorization-request, authorizedBy ${ar.ownerDisplay} until ${expiresAt}`,
        });
        return mandate.id;
      },
    });
    if (!result.ok) { res.status(result.status).json({ error: result.error }); return; }
    res.status(result.alreadyApproved ? 200 : 201).json({
      approved: true, alreadyApproved: result.alreadyApproved ?? false, request: decorateAuthReq(result.request),
    });
  });

  // Operator DECLINES — PIN-GATED. denyReason REQUIRED.
  router.post('/authorization-requests/:id/deny', (req, res) => {
    if (authReqUnavailable(res)) return;
    if (!checkMandatePin(req, res)) return;
    const reason = typeof (req.body ?? {}).denyReason === 'string' ? req.body.denyReason : '';
    const result = ctx.authorizationRequests!.store.deny(req.params.id, reason);
    if (!result.ok) { res.status(result.status).json({ error: result.error }); return; }
    res.json({ denied: true, request: decorateAuthReq(result.request) });
  });

  // Proposing agent WITHDRAWS its own still-pending request (Bearer).
  router.post('/authorization-requests/:id/withdraw', (req, res) => {
    if (authReqUnavailable(res)) return;
    const b = req.body ?? {};
    const agentName = (typeof b.createdByAgent === 'string' && b.createdByAgent) ? b.createdByAgent : 'agent';
    const result = ctx.authorizationRequests!.store.withdraw(req.params.id, agentName);
    if (!result.ok) { res.status(result.status).json({ error: result.error }); return; }
    res.json({ withdrawn: true, request: decorateAuthReq(result.request) });
  });

  // ── ReviewExchange — autonomous code-review protocol (coordination-mandate spec §7 G2.3) ──
  // One mutual, MANDATE-GATED sign-off of a review artifact between the two agents named
  // in a mandate. Both sign-offs run through /the same/ MandateGate (named party, bounds,
  // expiry, revocation — every decision in the hash-chained audit). Deny-by-default is
  // inherited: with no mandate issued, every sign/verdict path refuses. Bearer-gated
  // (creating/recording an exchange delegates nothing; the GATE is what authorizes
  // sign-offs — there is no PIN path here by design).

  const reviewsUnavailable = (res: import('express').Response): boolean => {
    if (!ctx.coordination) {
      res.status(503).json({ error: 'coordination mandate engine unavailable (no stateDir or init failed)' });
      return true;
    }
    return false;
  };

  // Create an exchange (state: proposed).
  router.post('/review-exchange', (req, res) => {
    if (reviewsUnavailable(res)) return;
    const b = req.body ?? {};
    if (!Array.isArray(b.parties) || b.parties.length !== 2 || b.parties.some((p: unknown) => typeof p !== 'string' || !p)) {
      res.status(400).json({ error: 'parties must be [ownerFp, peerFp] — two agent fingerprints' });
      return;
    }
    const result = ctx.coordination!.reviews.create({
      mandateId: String(b.mandateId ?? ''), artifact: String(b.artifact ?? ''),
      packageRef: String(b.packageRef ?? ''), packageSha256: String(b.packageSha256 ?? ''),
      parties: [b.parties[0], b.parties[1]],
      ...(typeof b.id === 'string' && b.id ? { id: b.id } : {}),
    });
    if (!result.ok) {
      res.status(400).json({ error: result.reason });
      return;
    }
    res.status(201).json({ created: true, exchange: result.record });
  });

  // List exchanges. Read-only.
  router.get('/review-exchange', (_req, res) => {
    if (reviewsUnavailable(res)) return;
    res.json({ exchanges: ctx.coordination!.reviews.list() });
  });

  // One exchange. Read-only.
  router.get('/review-exchange/:id', (req, res) => {
    if (reviewsUnavailable(res)) return;
    const record = ctx.coordination!.reviews.get(req.params.id);
    if (!record) {
      res.status(404).json({ error: `exchange "${req.params.id}" not found` });
      return;
    }
    res.json({ exchange: record });
  });

  // proposed → delivered (record the Threadline delivery evidence).
  router.post('/review-exchange/:id/delivered', (req, res) => {
    if (reviewsUnavailable(res)) return;
    const result = ctx.coordination!.reviews.markDelivered(req.params.id, String((req.body ?? {}).evidence ?? ''));
    if (!result.ok) {
      res.status(result.reason.includes('not found') ? 404 : 409).json({ error: result.reason });
      return;
    }
    res.json({ delivered: true, exchange: result.record });
  });

  // delivered → verdict-recorded | changes-requested. An 'approve' verdict is the
  // PEER's sign-off → mandate-gated for the peer's fingerprint (deny → 403).
  router.post('/review-exchange/:id/peer-verdict', (req, res) => {
    if (reviewsUnavailable(res)) return;
    const b = req.body ?? {};
    if (b.verdict !== 'approve' && b.verdict !== 'request-changes') {
      res.status(400).json({ error: 'verdict must be "approve" or "request-changes"' });
      return;
    }
    const result = ctx.coordination!.reviews.recordPeerVerdict(req.params.id, {
      verdict: b.verdict, summary: String(b.summary ?? ''),
      evidence: String(b.evidence ?? ''), peerFp: String(b.peerFp ?? ''),
    });
    if (!result.ok) {
      // Gate denials are 403 FIRST — a deny may itself say "mandate not found"
      // (deny-by-default), which must not masquerade as an exchange 404.
      const status = result.reason.startsWith('mandate denied') ? 403
        : result.reason.includes('not found') ? 404 : 409;
      res.status(status).json({ error: result.reason });
      return;
    }
    res.json({ recorded: true, exchange: result.record });
  });

  // verdict-recorded → complete. The OWNER's countersignature → mandate-gated (deny → 403).
  router.post('/review-exchange/:id/sign', (req, res) => {
    if (reviewsUnavailable(res)) return;
    const result = ctx.coordination!.reviews.sign(req.params.id, String((req.body ?? {}).agentFp ?? ''));
    if (!result.ok) {
      // Same precedence as peer-verdict: gate deny (403) before not-found (404).
      const status = result.reason.startsWith('mandate denied') ? 403
        : result.reason.includes('not found') ? 404 : 409;
      res.status(status).json({ error: result.reason });
      return;
    }
    res.json({ signed: true, exchange: result.record });
  });

  // ── Cutover-READINESS (coordination-mandate spec §7 G2.4, decision 1A) ──
  // Everything UP TO the door: the two objective cutover conditions resolved from
  // REAL durable state (persisted IntegrityReport + durable parity window). The
  // flip itself is the operator's manual click — there is NO fire-cutover route
  // here by design, and `door` says so machine-readably.

  // ── Feedback-inbox drainer status (Option-B receiving end, Q2b) ──
  // Read-only counters for the cloud-inbox → canonical-store mover. 503 when the
  // feature is dark (config off / no Blob token) — the standard null-dep pattern.
  router.get('/feedback-inbox/status', (_req, res) => {
    if (!ctx.inboxDrainer) {
      res.status(503).json({ error: 'feedback-inbox drainer unavailable (feedbackFactory.receiverPersistence disabled or no Blob token)' });
      return;
    }
    res.json(ctx.inboxDrainer.status());
  });

  // ── Dynamic MCP Lifecycle (DYNAMIC-MCP-LIFECYCLE-SPEC) ──
  // Load-on-demand / idle-offload of heavy MCP servers. Bearer-gated; the routes
  // 503 when the service is absent/disabled (dark by default). The agent-facing
  // load/offload routes ALWAYS act as {kind:'agent'} — they NEVER honor a
  // caller-supplied nonce, because the agent receives the nonce in a needs-approval
  // response and could otherwise self-approve over the shared Bearer (C4). The
  // operator-authenticated approval route (PIN/sentinel-gated nonce consume) is a
  // tracked follow-up; until then a non-preapproved change returns needs-approval
  // and performs no restart.
  const dynMcpEnabled = (): boolean => {
    const svc = ctx.dynamicMcpService;
    return !!svc && svc.enabled();
  };

  router.get('/mcp/session/:topicId', (req, res) => {
    if (!dynMcpEnabled()) { res.status(503).json({ error: 'dynamic-mcp disabled' }); return; }
    const topicId = Number(req.params.topicId);
    if (!Number.isFinite(topicId)) { res.status(400).json({ error: 'invalid topicId' }); return; }
    res.json({ ok: true, ...ctx.dynamicMcpService!.getSessionState(topicId) });
  });

  const handleMcpChange = (op: 'load' | 'offload') => async (req: ExpressRequest, res: ExpressResponse): Promise<void> => {
    if (!dynMcpEnabled()) { res.status(503).json({ error: 'dynamic-mcp disabled' }); return; }
    const body = (req.body ?? {}) as { topicId?: unknown; server?: unknown };
    const topicId = Number(body.topicId);
    const server = typeof body.server === 'string' ? body.server.trim() : '';
    if (!Number.isFinite(topicId) || !server) { res.status(400).json({ error: 'topicId (number) and server (string) are required' }); return; }
    // ALWAYS {kind:'agent'} — never trust a nonce from the Bearer caller (C4).
    const svc = ctx.dynamicMcpService!;
    const result = op === 'load'
      ? await svc.requestLoad(topicId, server, { kind: 'agent' })
      : await svc.requestOffload(topicId, server, { kind: 'agent' });
    const httpStatus =
      result.status === 'applied' || result.status === 'no-op' ? 200
        : result.status === 'needs-approval' ? 202
          : result.status === 'aborted' ? 409
            : result.status === 'unsupported-unbound' ? 409
              : 409; // restart-failed
    res.status(httpStatus).json({ ok: result.status === 'applied' || result.status === 'no-op', ...result });
  };

  router.post('/mcp/load', (req, res) => { void handleMcpChange('load')(req, res); });
  router.post('/mcp/offload', (req, res) => { void handleMcpChange('offload')(req, res); });

  // POST /mcp/approve — the OPERATOR-AUTHENTICATED approval for a non-preapproved
  // load/offload. PIN-GATED (the dashboard PIN), so the agent — which only holds the
  // shared Bearer token and NEVER the PIN — structurally cannot reach this route to
  // self-approve (the C4 invariant: an interactive change completes only via a live
  // preapproval OR this operator-PIN-authenticated path). The operator supplies the
  // server-minted nonce (which the agent surfaced from its needs-approval response)
  // + the PIN; this consumes the nonce via the {kind:'operator-approved'} actor. A
  // wrong/expired nonce simply fails the gate and returns needs-approval again.
  const handleMcpApprove = async (req: ExpressRequest, res: ExpressResponse): Promise<void> => {
    const svc = ctx.dynamicMcpService;
    if (!svc || !svc.enabled()) { res.status(503).json({ error: 'dynamic-mcp disabled' }); return; }
    if (!checkMandatePin(req, res)) return; // dashboard-PIN gate (rate-limited); response already sent on failure
    const body = (req.body ?? {}) as { topicId?: unknown; kind?: unknown; server?: unknown; nonce?: unknown };
    const topicId = Number(body.topicId);
    const kind: 'load' | 'offload' = body.kind === 'offload' ? 'offload' : 'load';
    const server = typeof body.server === 'string' ? body.server.trim() : '';
    const nonce = typeof body.nonce === 'string' ? body.nonce : '';
    if (!Number.isFinite(topicId) || !server || !nonce) {
      res.status(400).json({ error: 'topicId (number), server (string), and nonce (string) are required' }); return;
    }
    const result = kind === 'load'
      ? await svc.requestLoad(topicId, server, { kind: 'operator-approved', nonce })
      : await svc.requestOffload(topicId, server, { kind: 'operator-approved', nonce });
    const httpStatus =
      result.status === 'applied' || result.status === 'no-op' ? 200
        : result.status === 'needs-approval' ? 403 // the nonce didn't match/expired → approval did NOT take
          : 409;
    res.status(httpStatus).json({ ok: result.status === 'applied' || result.status === 'no-op', ...result });
  };
  router.post('/mcp/approve', (req, res) => { void handleMcpApprove(req, res); });

  // ── Operator-approval TAP surface (Mobile-Complete: tap a link, enter PIN) ──
  // The agent registers a pending change (it holds the nonce from needs-approval) and
  // surfaces the returned link; the operator taps it, sees the request (NO nonce on
  // the page), and approves with the dashboard PIN. The nonce stays server-side
  // (opaque requestId in the URL), and the PIN gate keeps the agent (Bearer-only,
  // no PIN) from self-approving — the C4 invariant, made tappable.
  const mcpHtmlEscape = (s: string): string => s.replace(/[&<>"']/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c] as string));

  // The agent (Bearer) registers a pending approval → opaque requestId + a tap URL.
  router.post('/mcp/approval-link', (req, res) => {
    const svc = ctx.dynamicMcpService;
    if (!svc || !svc.enabled()) { res.status(503).json({ error: 'dynamic-mcp disabled' }); return; }
    const body = (req.body ?? {}) as { topicId?: unknown; kind?: unknown; server?: unknown; nonce?: unknown };
    const topicId = Number(body.topicId);
    const kind: 'load' | 'offload' = body.kind === 'offload' ? 'offload' : 'load';
    const server = typeof body.server === 'string' ? body.server.trim() : '';
    const nonce = typeof body.nonce === 'string' ? body.nonce : '';
    if (!Number.isFinite(topicId) || !server || !nonce) { res.status(400).json({ error: 'topicId, server, nonce required' }); return; }
    const requestId = svc.registerApproval(topicId, kind, server, nonce);
    const path = `/mcp/approve/${requestId}`;
    res.json({ ok: true, requestId, path, url: ctx.tunnel?.getExternalUrl(path) ?? `http://localhost:${ctx.config.port}${path}` });
  });

  // The operator opens the link → a tappable approval page (NO nonce, NO PIN shown).
  router.get('/mcp/approve/:requestId', (req, res) => {
    const svc = ctx.dynamicMcpService;
    if (!svc || !svc.enabled()) { res.status(503).type('html').send('<p>This approval feature is not enabled.</p>'); return; }
    const view = svc.peekApproval(String(req.params.requestId));
    if (!view) { res.status(404).type('html').send('<p>This approval request is no longer valid (used or expired).</p>'); return; }
    const verb = view.kind === 'load' ? 'load' : 'drop';
    res.type('html').send(`<!DOCTYPE html><html><head><meta name="viewport" content="width=device-width,initial-scale=1"><title>Approve MCP change</title>
<style>body{font-family:system-ui,sans-serif;max-width:30rem;margin:2rem auto;padding:0 1rem}button{font-size:1.1rem;padding:.6rem 1.2rem;width:100%}input{font-size:1.1rem;padding:.5rem;width:100%;box-sizing:border-box}</style></head>
<body><h2>Approve a tool change?</h2>
<p>The agent wants to <b>${mcpHtmlEscape(verb)}</b> the <b>${mcpHtmlEscape(view.server)}</b> tool for this conversation (topic ${view.topicId}).</p>
<p>Enter your dashboard PIN to approve. The agent cannot approve this itself.</p>
<form id="mcpForm">
<p><input id="mcpPin" type="password" inputmode="numeric" autocomplete="off" placeholder="Dashboard PIN" required></p>
<p><button type="submit">Approve</button></p></form>
<script>
// Submit the PIN as JSON via fetch (the server parses application/json, not
// urlencoded form bodies) and render the returned result page in place.
document.getElementById('mcpForm').addEventListener('submit', async function (e) {
  e.preventDefault();
  var btn = this.querySelector('button'); btn.disabled = true; btn.textContent = 'Approving…';
  try {
    var r = await fetch(${JSON.stringify('/mcp/approve/' + view.requestId)}, {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ pin: document.getElementById('mcpPin').value })
    });
    var html = await r.text();
    document.open(); document.write(html); document.close();
  } catch (err) {
    btn.disabled = false; btn.textContent = 'Approve';
    alert('Could not reach the server — please try again.');
  }
});
</script></body></html>`);
  });

  // The PIN-gated submit → consume the request server-side + drive the change.
  router.post('/mcp/approve/:requestId', (req, res) => {
    void (async (): Promise<void> => {
      const svc = ctx.dynamicMcpService;
      if (!svc || !svc.enabled()) { res.status(503).type('html').send('<p>Not enabled.</p>'); return; }
      if (!checkMandatePin(req, res)) return; // dashboard-PIN gate (rate-limited); response already sent on failure
      const result = await svc.approveByRequestId(String(req.params.requestId));
      if (result.status === 'unknown-request') { res.status(404).type('html').send('<p>This approval request is no longer valid (used or expired).</p>'); return; }
      const ok = result.status === 'applied';
      res.status(ok ? 200 : 409).type('html').send(`<!DOCTYPE html><html><head><meta name="viewport" content="width=device-width,initial-scale=1"><style>body{font-family:system-ui,sans-serif;max-width:30rem;margin:2rem auto;padding:0 1rem}</style></head><body><h2>${ok ? '✅ Approved' : '⚠️ Not applied'}</h2><p>${ok ? 'The tool change was approved and is being applied — the session will restart briefly and continue.' : `The change was not applied (status: ${mcpHtmlEscape(result.status)}). You can close this page.`}</p></body></html>`);
    })();
  });

  // ── Feedback-factory processing (feedback-factory-migration §191) ──
  // Wires the already-parity'd processUnprocessed clustering pass into a real
  // triggerable capability. Both routes are dev-gated: ctx.feedbackProcessing is
  // null on the fleet (resolveDevAgentGate dark) → 503, live on a dev agent.

  // Read-only stats over the canonical store. Never mutates.
  router.get('/feedback-factory/stats', (_req, res) => {
    if (!ctx.feedbackProcessing) {
      res.status(503).json({ error: 'feedback-factory processing unavailable (feedbackFactory.processing dark for this agent)' });
      return;
    }
    res.json(ctx.feedbackProcessing.stats());
  });

  // Trigger ONE clustering pass over the canonical store. Appends local JSONL
  // only (create/merge clusters + flip items unprocessed→processing); no external
  // action. Idempotent + forward-only — a re-run is a no-op over already-processed
  // items. This is the server-side work the cadenced feedback-factory-process job
  // drives (the agent asks; the server computes — same shape as the cutover-readiness
  // parity-pass + release-readiness tick triggers).
  router.post('/feedback-factory/process', (_req, res) => {
    if (!ctx.feedbackProcessing) {
      res.status(503).json({ error: 'feedback-factory processing unavailable (feedbackFactory.processing dark for this agent)' });
      return;
    }
    const { result, stats } = ctx.feedbackProcessing.processNow();
    res.json({
      processed: result.results.length,
      metrics: result.metrics,
      stats,
    });
  });

  // The readiness signal. Read-only.
  router.get('/cutover-readiness', (_req, res) => {
    if (!ctx.cutoverReadiness) {
      res.status(503).json({ error: 'cutover-readiness unavailable (no stateDir or init failed)' });
      return;
    }
    res.json(ctx.cutoverReadiness.status());
  });

  // TRIGGER a server-side parity pass (T7: the agent may ask; the server computes).
  // The request body contributes NOTHING to the result. 409 when no source is
  // configured or the live check fails (nothing recorded on failure). A real pass
  // takes minutes (full live cluster fetch) — the route has a per-path timeout
  // override (PARITY_PASS_TIMEOUT_MS); if the response window is EVER outlived
  // anyway, the outcome is logged server-side and the late response is skipped
  // (never a double-respond crash, never a silent outcome).
  router.post('/cutover-readiness/parity-pass', async (_req, res) => {
    if (!ctx.cutoverReadiness) {
      res.status(503).json({ error: 'cutover-readiness unavailable (no stateDir or init failed)' });
      return;
    }
    const outcome = await ctx.cutoverReadiness.runParityPass();
    // The outcome always leaves a trace, even when the client's response timed out.
    if (outcome.ok) {
      console.log(`[cutover-readiness] parity pass recorded: divergent=${outcome.pass.divergent} clusters=${outcome.pass.clustersCompared} gateCleared=${outcome.gate.cleared}`);
    } else {
      console.warn(`[cutover-readiness] parity pass FAILED (nothing recorded): ${outcome.reason}`);
    }
    if (res.headersSent) return; // 408 already went out — outcome logged above
    if (!outcome.ok) {
      res.status(409).json({ error: outcome.reason });
      return;
    }
    res.json({ recorded: true, pass: outcome.pass, gate: outcome.gate });
  });

  // TRIGGER a server-side import REHEARSAL (dry-run): live source fetch → AS-IS
  // import into an in-memory target → integrity gate over what the target reads
  // back. Zero durable data writes; the envelope persists to the SEPARATE dry-run
  // path and NEVER greens the canonical integrity condition — `ready` still
  // requires the REAL import's report. Same T7 discipline and same always-logged
  // outcome contract as the parity-pass trigger above.
  router.post('/cutover-readiness/import-dryrun', async (_req, res) => {
    if (!ctx.cutoverReadiness) {
      res.status(503).json({ error: 'cutover-readiness unavailable (no stateDir or init failed)' });
      return;
    }
    const outcome = await ctx.cutoverReadiness.runImportDryRunPass();
    if (outcome.ok) {
      const r = outcome.result;
      console.log(`[cutover-readiness] import dry-run recorded: passed=${r.passed} clusters=${r.imported.clusters} feedback=${r.imported.feedback}${r.abortedPreImport ? ` abortedPreImport=${r.abortedPreImport.reason}` : ''}`);
    } else {
      console.warn(`[cutover-readiness] import dry-run FAILED (nothing recorded): ${outcome.reason}`);
    }
    if (res.headersSent) return; // 408 already went out — outcome logged above
    if (!outcome.ok) {
      res.status(409).json({ error: outcome.reason });
      return;
    }
    res.json({ recorded: true, mode: 'dry-run', generatedAt: outcome.generatedAt, result: outcome.result });
  });

  // TRIGGER the REAL pre-click integrity pass: live source fetch → AS-IS import into a
  // PERSISTED shadow (run OFF the event loop, in a child process) → integrity gate over
  // the readback → the report is recorded to the CANONICAL integrity path. UNLIKE the
  // import-dryrun, this IS load-bearing on `ready`: a passing report greens the integrity
  // leg, a failing one flips it closed (the door reflects the LATEST real verdict). The
  // cutover flip itself remains the operator's manual click — this only resolves the
  // confidence signal up to the door. Same T7 discipline + always-logged outcome.
  router.post('/cutover-readiness/integrity-pass', async (_req, res) => {
    if (!ctx.cutoverReadiness) {
      res.status(503).json({ error: 'cutover-readiness unavailable (no stateDir or init failed)' });
      return;
    }
    const outcome = await ctx.cutoverReadiness.runIntegrityPass();
    if (outcome.ok) {
      const r = outcome.result;
      console.log(`[cutover-readiness] integrity pass recorded=${outcome.recorded}: passed=${r.passed} clusters=${r.imported.clusters} feedback=${r.imported.feedback}${r.abortedPreImport ? ` abortedPreImport=${r.abortedPreImport.reason}` : ''}`);
    } else {
      console.warn(`[cutover-readiness] integrity pass FAILED (nothing recorded): ${outcome.reason}`);
    }
    if (res.headersSent) return; // 408 already went out — outcome logged above
    if (!outcome.ok) {
      res.status(409).json({ error: outcome.reason });
      return;
    }
    res.json({ recorded: outcome.recorded, generatedAt: outcome.generatedAt, result: outcome.result });
  });

  // The last import dry-run's verdict. Read-only, informational — never a `ready` input.
  router.get('/cutover-readiness/import-dryrun', (_req, res) => {
    if (!ctx.cutoverReadiness) {
      res.status(503).json({ error: 'cutover-readiness unavailable (no stateDir or init failed)' });
      return;
    }
    res.json(ctx.cutoverReadiness.importDryRunStatus());
  });

  // ── Parallel-Work Awareness (docs/specs/parallel-activity-coherence.md, Phase A) ──
  // Read-only cross-topic index: every topic with intent state + its current focus +
  // high-specificity tags + whether a session is live on it. Signal-only; never gates.
  // 503 when the index is unavailable (no stateDir / init failed).
  router.get('/parallel-work/activities', async (req, res) => {
    if (!ctx.parallelActivityIndex) {
      res.status(503).json({ error: 'parallel-activity index unavailable (no stateDir or init failed)' });
      return;
    }
    const activities = ctx.parallelActivityIndex.activities();
    // P4 (POOL-WIDE-PARALLEL-WORK-SPEC §3): ?scope=pool composes the local
    // rows with replica-derived remote rows (LOCAL replica files — no peer
    // fan-out; an offline peer's last-replicated streams still answer).
    // Default scope stays byte-identical; a dark replica layer degrades the
    // pool scope to local rows only (200, never a new 503).
    if (req.query.scope === 'pool') {
      try {
        const poolMod = await import('../core/PoolActivityView.js');
        const readerMod = await import('../core/CoherenceJournalReader.js');
        const view = poolMod.buildPoolActivityView({
          ownMachineId: ctx.meshSelfId ?? 'local',
          local: activities,
          reader: new readerMod.CoherenceJournalReader({ stateDir: ctx.config.stateDir }),
        });
        res.json({
          scope: 'pool',
          count: view.rows.length,
          runningCount: view.rows.filter((a) => a.running).length,
          activities: view.rows,
          pool: view.pool,
        });
        return;
      } catch (err) {
        res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
        return;
      }
    }
    res.json({
      count: activities.length,
      runningCount: activities.filter((a) => a.running).length,
      activities,
      note: 'Cross-topic read over the existing Topic-Intent layer. The overlap sentinel (Phase B) ships separately.',
    });
  });

  // ── Per-component framework routing (docs/specs/per-component-framework-routing.md) ──
  // Read-only: what framework each known component resolves to right now (live config),
  // whether that framework is available, and the per-framework breaker isolation. 503
  // when no IntelligenceRouter is wired (e.g. no LLM CLI available).
  router.get('/intelligence/routing', (_req, res) => {
    const intel = ctx.intelligence;
    if (!intel || !(intel instanceof IntelligenceRouter)) {
      res.status(503).json({ error: 'intelligence router unavailable (no LLM provider configured)' });
      return;
    }
    // '__nonexistent__' is not in the registry, so it resolves to category 'other'
    // → the effective DEFAULT framework (what an unrouted call gets).
    const defaultFramework = intel.for('__nonexistent__').framework;
    const components = knownComponents().map((name) => intel.for(name));
    res.json({
      defaultFramework,
      components,
      coverage: {
        known: components.length,
        // how many known components are routed OFF the default framework right now
        routedOffDefault: components.filter((c) => c.framework !== defaultFramework).length,
      },
      note: 'Routes INTERNAL component LLM calls only; spawned interactive sessions use topicFrameworks.',
    });
  });

  // ── Release-readiness (Layer B of release-readiness-visibility) ──────
  // Null when there's no analyzable instar git repo or the feature is off.
  router.get('/release-readiness', (_req, res) => {
    if (!ctx.releaseReadinessSentinel) {
      res.status(503).json({ error: 'release-readiness watchdog not configured (no analyzable instar repo or disabled)' });
      return;
    }
    const s = ctx.releaseReadinessSentinel.snapshot();
    const openEpisode = s.episodes.find((e) => !e.resolvedMs && e.openedMs);
    // Served from the local host's cache; on a multi-machine follower this may
    // lag the leader by up to one lease-handoff (spec §4.2.7).
    res.setHeader('X-Readiness-Source', 'leader');
    res.json({
      disabled: s.disabled ?? false,
      lastTickAt: s.lastTickAt,
      lastSignalAt: s.lastSignalAt,
      cacheHeadSha: s.cacheHeadSha,
      canonicalRemoteOverridden: s.canonicalRemoteOverridden ?? false,
      openEpisodes: s.episodes.filter((e) => !e.resolvedMs).length,
      oldestOpenSha: openEpisode?.oldestSha,
      openAttentionId: openEpisode?.attentionId,
      rollbackHistory: (s.rollbackHistory ?? []).slice(-5),
    });
  });

  // The job (off by default) calls this on its cadence — tick() is the cron
  // entry point. Runs one evaluation; the sentinel owns all signalling.
  router.post('/release-readiness/tick', async (_req, res) => {
    if (!ctx.releaseReadinessSentinel) {
      res.status(503).json({ error: 'release-readiness watchdog not configured' });
      return;
    }
    await ctx.releaseReadinessSentinel.tick();
    res.json({ ok: true });
  });

  // Rollback is bearer-gated AND loud: it raises a HIGH-priority Attention item
  // + audits, so it can't silently mute the alarm (spec §4.2.7 / iter-3 V5).
  router.post('/release-readiness/rollback', async (req, res) => {
    if (!ctx.releaseReadinessSentinel) {
      res.status(503).json({ error: 'release-readiness watchdog not configured' });
      return;
    }
    await ctx.releaseReadinessSentinel.rollback({
      sessionId: typeof req.body?.sessionId === 'string' ? req.body.sessionId : undefined,
      sourceIp: req.ip,
    });
    res.json({ ok: true, rolledBack: true });
  });

  router.post('/release-readiness/enable', (_req, res) => {
    if (!ctx.releaseReadinessSentinel) {
      res.status(503).json({ error: 'release-readiness watchdog not configured' });
      return;
    }
    ctx.releaseReadinessSentinel.enable();
    res.json({ ok: true, enabled: true });
  });

  // ── Green-PR auto-merge (green-pr-automerge-enforcement) ──────────────
  // The watcher is null on installs with no analyzable instar repo + safe-merge,
  // or when disabled in config → routes 503. The GuardLatchStore may exist even
  // when the watcher does not (single-machine rollback still needs to persist).
  router.get('/green-pr-automerge', (_req, res) => {
    if (!ctx.greenPrAutoMerger) {
      res.status(503).json({ error: 'green-pr auto-merge not configured (no analyzable instar repo + safe-merge, or disabled)' });
      return;
    }
    const state = ctx.greenPrAutoMerger.snapshot();
    const latch = ctx.guardLatchStore?.snapshot() ?? null;
    // mergerunner-auto-arm-handoff: armed/armed-overdue is first-class observable
    // (Observable Intelligence — an in-flight autonomous merge must never be
    // invisible). NON-OPTIONAL — a NUMBER (0) / EMPTY ARRAY when nothing is armed.
    const armedEpisodes = Object.values(state.episodes ?? {}).filter((e) => e.armedAt != null);
    const armed = armedEpisodes.map((e) => ({ pr: e.pr, armedAt: e.armedAt ?? null, armedHead: e.armedHead ?? null, overdue: e.overdue === true }));
    res.json({
      lastTickAt: state.lastTickAt ?? null,
      lastSuccessfulListAt: state.lastSuccessfulListAt ?? null,
      consecutiveWarmupOnlyTenures: state.consecutiveWarmupOnlyTenures,
      breaker: state.breaker,
      episodes: Object.values(state.episodes ?? {}),
      armedCount: armed.length,
      armed,
      snapshot: state.snapshot,
      gate: latch,
      invariantOk: ctx.greenPrAutoMerger.invariantOk,
    });
  });

  router.post('/green-pr-automerge/tick', async (_req, res) => {
    if (!ctx.greenPrAutoMerger) {
      res.status(503).json({ error: 'green-pr auto-merge not configured' });
      return;
    }
    const r = await ctx.greenPrAutoMerger.tick({ manual: true });
    res.json({ ok: true, ...r });
  });

  // Rollback is Bearer-gated and LOUD: anyone may STOP. The latch is absorbing
  // and pool-replicated, so a STOP survives a lease move (R9).
  router.post('/green-pr-automerge/rollback', async (req, res) => {
    if (!ctx.guardLatchStore) {
      res.status(503).json({ error: 'green-pr auto-merge not configured' });
      return;
    }
    const reason = typeof req.body?.reason === 'string' ? req.body.reason : 'operator-rollback';
    const latchId = ctx.guardLatchStore.set('rollback', reason);
    // The latch set (stop NEW arming) and the in-line disarm (un-arm what is
    // already armed) are the two halves of one kill switch (mergerunner-auto-arm-
    // handoff Blocker 3a). The disarm must be IN-LINE here, not in the tick — the
    // latch the operator just set is the very thing that stops the tick reaching
    // the disarm code. Null-safe no-op when the watcher is absent (the
    // GuardLatchStore can exist when greenPrAutoMerger is null).
    let disarm: { disarmed: number[]; failed: number[] } | undefined;
    try { disarm = await ctx.greenPrAutoMerger?.disarmAllArmed(reason); }
    catch { /* disarm failure is surfaced via the watcher's own attention line; the latch still landed */ }
    res.json({ ok: true, rolledBack: true, latchId, disarmed: disarm?.disarmed ?? [], disarmFailed: disarm?.failed ?? [] });
  });

  // Re-arming merge authority is the operator's: dashboard-PIN-gated (the Mandates
  // precedent). Clears only the named latch id(s), or all active rollback ids.
  router.post('/green-pr-automerge/enable', (req, res) => {
    if (!ctx.guardLatchStore) {
      res.status(503).json({ error: 'green-pr auto-merge not configured' });
      return;
    }
    if (!checkMandatePin(req, res)) return;
    const named = Array.isArray(req.body?.latchIds) ? req.body.latchIds.filter((s: unknown): s is string => typeof s === 'string') : [];
    const ids = named.length > 0 ? named : ctx.guardLatchStore.activeLatchIds('rollback');
    ctx.guardLatchStore.clear('rollback', ids, 're-arm');
    res.json({ ok: true, enabled: true, cleared: ids });
  });

  // Conversational-hold assist (R3): apply the [HOLD: …] marker via gh in one call.
  router.post('/green-pr-automerge/hold', async (req, res) => {
    if (!ctx.greenPrAutoMerger) {
      res.status(503).json({ error: 'green-pr auto-merge not configured' });
      return;
    }
    const pr = Number(req.body?.pr);
    if (!Number.isInteger(pr) || pr <= 0) {
      res.status(400).json({ error: 'pr must be a positive integer' });
      return;
    }
    const reason = typeof req.body?.reason === 'string' ? req.body.reason.replace(/[\]\n\r]/g, ' ').slice(0, 200) : '';
    const result = await ctx.greenPrAutoMerger.applyHold(pr, reason);
    res.status(result.ok ? 200 : (result.status ?? 502)).json(result);
  });

  // Pool-disarm marker (R7): PIN-gated, superseding entry → grades back to healthy.
  router.post('/green-pr-automerge/pool-disarm', async (req, res) => {
    if (!ctx.guardLatchStore) {
      res.status(503).json({ error: 'green-pr auto-merge not configured' });
      return;
    }
    if (!checkMandatePin(req, res)) return;
    ctx.guardLatchStore.markPoolDisarmed();
    // Same kill-switch two-halves contract as rollback (Blocker 3a): also disarm
    // every already-armed PR in-line. Null-safe no-op when the watcher is absent.
    let disarm: { disarmed: number[]; failed: number[] } | undefined;
    try { disarm = await ctx.greenPrAutoMerger?.disarmAllArmed('pool-disarm'); }
    catch { /* disarm failure is surfaced via the watcher's own attention line; the pool-disarm marker still landed */ }
    res.json({ ok: true, poolDisarmed: true, disarmed: disarm?.disarmed ?? [], disarmFailed: disarm?.failed ?? [] });
  });

  // ── Human-as-Detector heat map ───────────────────────────────────────
  // "Where the human is doing the system's job": coherence breaks a human had
  // to surface, grouped by the automated layer that should plausibly have
  // caught each. Observability-only, read-only. The singleton is always
  // configured at startup, so no availability guard is needed.
  router.get('/human-as-detector/summary', (_req, res) => {
    const log = HumanAsDetectorLog.getInstance();
    res.json({
      byLayer: log.summarizeByLayer(),
      recent: log.getRecent().slice(-50),
    });
  });

  router.get('/tokens/codex-sessions', (req, res) => {
    if (!ctx.tokenLedger) {
      res.status(503).json({ error: 'token ledger unavailable' });
      return;
    }
    const sinceMs = parseSinceMs(req.query.since);
    let limit = 50;
    if (typeof req.query.limit === 'string' && /^\d+$/.test(req.query.limit)) {
      const n = Number(req.query.limit);
      if (n > 0 && n <= 500) limit = n;
    }
    res.json({ sinceMs, limit, sessions: ctx.tokenLedger.codexSessions({ limit, sinceMs }) });
  });

  router.get('/tokens/sessions', (req, res) => {
    if (!ctx.tokenLedger) {
      res.status(503).json({ error: 'token ledger unavailable' });
      return;
    }
    const sinceMs = parseSinceMs(req.query.since);
    let limit = 20;
    if (typeof req.query.limit === 'string' && /^\d+$/.test(req.query.limit)) {
      const n = Number(req.query.limit);
      if (n > 0 && n <= 500) limit = n;
    }
    res.json({ sinceMs, limit, sessions: ctx.tokenLedger.topSessions({ limit, sinceMs }) });
  });

  router.get('/tokens/by-project', (req, res) => {
    if (!ctx.tokenLedger) {
      res.status(503).json({ error: 'token ledger unavailable' });
      return;
    }
    const sinceMs = parseSinceMs(req.query.since);
    res.json({ sinceMs, projects: ctx.tokenLedger.byProject({ sinceMs }) });
  });

  router.get('/tokens/orphans', (req, res) => {
    if (!ctx.tokenLedger) {
      res.status(503).json({ error: 'token ledger unavailable' });
      return;
    }
    let idleMs = TOKEN_DEFAULT_ORPHAN_IDLE_MS;
    if (typeof req.query.idleMs === 'string' && /^\d+$/.test(req.query.idleMs)) {
      const n = Number(req.query.idleMs);
      if (n > 0) idleMs = n;
    }
    res.json({ idleMs, orphans: ctx.tokenLedger.orphans({ idleMs }) });
  });

  // ── Codex usage (the codex `/status` equivalent, read from disk) ─────
  // Codex has no usage API, but the codex CLI persists the authoritative
  // account rate-limit windows (primary=5h, secondary=weekly) into each
  // session rollout's `token_count` events. This route surfaces the freshest
  // snapshot so an agent can answer "where does codex usage sit?" and so the
  // model-swap policy can react to an exhausted window — without the
  // interactive TUI. Read-only; never mutates session state. Always 200 when
  // wired ("alive"): `available:false` (not 503) means simply no codex data
  // on disk yet (e.g. a pure-Claude agent).
  router.get('/codex/usage', async (req, res) => {
    const codexHome =
      typeof req.query.codexHome === 'string' && req.query.codexHome
        ? req.query.codexHome
        : undefined;
    let usage = null;
    try {
      usage = await readLatestCodexUsage({ codexHome });
    } catch {
      usage = null;
    }
    if (!usage) {
      res.json({
        available: false,
        usage: null,
        reason: 'no codex rollout with rate-limit data found',
      });
      return;
    }
    res.json({ available: true, usage });
  });

  // ── Framework-Onboarding Mentor System: issue ledger (read-only) ──
  // Signal-only observability. Bearer auth is applied globally by middleware;
  // these routes never gate behaviour. See FRAMEWORK-ONBOARDING-MENTOR-SPEC §5.

  // Clamp a list limit to 1..500 (§5/§17). Local to avoid import churn; mirrors
  // FrameworkIssueLedger.clampLimit (the ledger re-clamps server-side too).
  const clampFwLimit = (raw: unknown): number => {
    const n = typeof raw === 'string' ? parseInt(raw, 10) : typeof raw === 'number' ? raw : NaN;
    if (!Number.isFinite(n)) return 100;
    return Math.max(1, Math.min(500, Math.floor(n)));
  };

  router.get('/framework-issues', (req, res) => {
    if (!ctx.frameworkIssueLedger) {
      res.status(503).json({ error: 'framework issue ledger unavailable' });
      return;
    }
    const limit = clampFwLimit(req.query.limit);
    // Validate framework against the known-framework allowlist (§17) — an
    // unknown value yields an empty result, never an unbounded/injection query.
    const known = ctx.frameworkIssueLedger.knownFrameworks();
    let framework: string | undefined;
    if (typeof req.query.framework === 'string') {
      if (!known.includes(req.query.framework)) {
        res.json({ framework: req.query.framework, knownFrameworks: known, issues: [] });
        return;
      }
      framework = req.query.framework;
    }
    const bucket = typeof req.query.bucket === 'string' ? req.query.bucket : undefined;
    const status = typeof req.query.status === 'string' ? req.query.status : undefined;
    try {
      const issues = ctx.frameworkIssueLedger.listIssues({
        framework,
        // listIssues validates these enums and throws on bad input.
        bucket: bucket as never,
        status: status as never,
        limit,
      });
      res.json({ framework, knownFrameworks: known, limit, issues });
    } catch (err) {
      res.status(400).json({ error: (err as Error).message });
    }
  });

  router.get('/framework-issues/playbook', (req, res) => {
    if (!ctx.frameworkIssueLedger) {
      res.status(503).json({ error: 'framework issue ledger unavailable' });
      return;
    }
    const targetFramework = typeof req.query.targetFramework === 'string' ? req.query.targetFramework : '';
    if (!targetFramework) {
      res.status(400).json({ error: 'targetFramework query param is required' });
      return;
    }
    const limit = clampFwLimit(req.query.limit);
    const playbook = ctx.frameworkIssueLedger.playbook({ targetFramework, limit });
    res.json({ targetFramework, limit, playbook });
  });

  router.get('/framework-issues/capture-stats', (_req, res) => {
    if (!ctx.frameworkIssueLedger) {
      res.status(503).json({ error: 'framework issue ledger unavailable' });
      return;
    }
    // The capture funnel: runs vs observations written. A nonzero run count with
    // a stuck-at-zero observation count over time flags an inert/broken writer.
    res.json(ctx.frameworkIssueLedger.captureStats());
  });

  router.get('/framework-issues/observability', (_req, res) => {
    if (!ctx.frameworkIssueLedger) {
      res.status(503).json({ error: 'framework issue ledger unavailable' });
      return;
    }
    // Adversarial telemetry (§15): bucket-distribution skew, leak-suspected and
    // probable-loop counts, playbook-extracted count. Read-only signal.
    res.json(ctx.frameworkIssueLedger.observability());
  });

  // Durable write path (§5) — lets an agent (or the mentor loop, or a backfill
  // script) record an engineering-DISCOVERED framework issue into the ledger,
  // not just the ones a live mentor tick trips over. Thin wrapper over the
  // already-validated recordObservation (+ optional status transition for
  // backfilling an already-fixed issue). bucket/severity/status enums are
  // validated by the ledger, which throws → 400. New framework strings are
  // intentionally allowed (onboarding the NEXT framework introduces one).
  router.post('/framework-issues/observe', (req, res) => {
    if (!ctx.frameworkIssueLedger) {
      res.status(503).json({ error: 'framework issue ledger unavailable' });
      return;
    }
    const b = (req.body ?? {}) as Record<string, unknown>;
    const str = (v: unknown): string | undefined => (typeof v === 'string' && v.trim() ? v : undefined);
    for (const field of ['framework', 'bucket', 'title', 'dedupKey'] as const) {
      if (!str(b[field])) {
        res.status(400).json({ error: `${field} (non-empty string) is required` });
        return;
      }
    }
    try {
      const result = ctx.frameworkIssueLedger.recordObservation({
        framework: b.framework as string,
        bucket: b.bucket as never, // ledger assertEnum-validates → throws → 400
        title: b.title as string,
        severity: str(b.severity) as never,
        dedupKey: b.dedupKey as string,
        signature: str(b.signature),
        evidence: str(b.evidence),
        observedVersion: str(b.observedVersion),
        bucketPrimary: str(b.bucketPrimary) as never,
        relatedSpec: str(b.relatedSpec),
      });
      // Optional terminal-status transition in the same call. recordObservation
      // always creates as 'open'; a backfill of an already-fixed issue passes
      // status:'fixed' (+ fixedInVersion). wont-fix requires a reason (the
      // ledger enforces this → 400 if missing).
      let issue = ctx.frameworkIssueLedger.getIssue(result.issueId);
      const status = str(b.status);
      if (status && status !== 'open') {
        issue =
          ctx.frameworkIssueLedger.updateIssue(result.issueId, {
            status: status as never,
            fixedInVersion: str(b.fixedInVersion),
            wontFixReason: str(b.wontFixReason),
          }) ?? issue;
      }
      res.json({ ...result, issue });
    } catch (err) {
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  router.post('/framework-issues/:id/promote', (req, res) => {
    if (!ctx.frameworkIssueLedger) {
      res.status(503).json({ error: 'framework issue ledger unavailable' });
      return;
    }
    const target = typeof req.body?.status === 'string' ? req.body.status : '';
    const promotedBy = typeof req.body?.promotedBy === 'string' ? req.body.promotedBy : '';
    try {
      // candidate→extracted requires a non-Echo attestation (§13.6); the ledger
      // throws if Echo attempts to promote its own lesson into the playbook.
      const updated = ctx.frameworkIssueLedger.promotePlaybook(req.params.id, target as never, promotedBy);
      if (!updated) {
        res.status(404).json({ error: 'issue not found' });
        return;
      }
      res.json(updated);
    } catch (err) {
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // ── Mentor-onboarding job (§19.4) — dormant by default ──
  router.get('/mentor/status', (_req, res) => {
    if (!ctx.mentorRunner) {
      res.status(503).json({ error: 'mentor runner unavailable' });
      return;
    }
    res.json(ctx.mentorRunner.status());
  });

  router.post('/mentor/tick', (_req, res) => {
    if (!ctx.mentorRunner) {
      res.status(503).json({ error: 'mentor runner unavailable' });
      return;
    }
    // The built-in mentor job (off by default) hits this each tick. The tick runs
    // FIRE-AND-FORGET (a slow Stage-A spawn must not hang this request — the
    // gate-latency-vs-client-timeout failure mode); the outcome lands in
    // GET /mentor/status .lastResult. When disabled, this returns 200 disabled.
    const r = ctx.mentorRunner.startTick();
    if (r.reason === 'disabled') {
      res.json({ ran: false, reason: 'disabled' });
      return;
    }
    res.status(202).json({ accepted: r.accepted, reason: r.reason ?? null });
  });

  // ── Failure-Learning Loop (docs/specs/FAILURE-LEARNING-LOOP-SPEC.md §4.5) ──
  // instar self-hosting dev-process forensics. Inline (like /tokens) so the
  // /capabilities discoverability lint sees the routes. 503-stub when the
  // ledger is null (feature OFF, default). Reads serve toApiView ONLY —
  // detail.full NEVER crosses the boundary (§4.8). POST is the one mutating
  // route: requires X-Instar-Request intent + server-validated initiative.

  // ETag/304 for the Process Health tab's diff-aware polling (tab spec §3/§4.3).
  // Deterministic SHA over the fully-assembled body (incl. any rollout block);
  // rely on V8 insertion order — do NOT sort keys.
  const sendFailureJson = (req: ExpressRequest, res: ExpressResponse, body: unknown): void => {
    const etag = `"${createHash('sha256').update(JSON.stringify(body)).digest('hex').slice(0, 16)}"`;
    res.setHeader('ETag', etag);
    if (req.headers['if-none-match'] === etag) { res.status(304).end(); return; }
    res.json(body);
  };
  // Parse a ?before=<ISO-ts> upper-bound param. Returns 400 sentinel on NaN.
  const parseBeforeMs = (raw: unknown): { ok: true; ms?: number } | { ok: false } => {
    if (typeof raw !== 'string') return { ok: true, ms: undefined };
    const ms = Date.parse(raw);
    return Number.isNaN(ms) ? { ok: false } : { ok: true, ms };
  };

  router.get('/failures', (req, res) => {
    if (!ctx.failureLedger) { res.status(503).json({ error: 'failure-learning disabled' }); return; }
    const q = req.query;
    const before = parseBeforeMs(q.before);
    if (!before.ok) { res.status(400).json({ error: 'invalid before= (expected an ISO timestamp)' }); return; }
    const records = ctx.failureLedger.list({
      source: typeof q.source === 'string' ? (q.source as never) : undefined,
      category: typeof q.category === 'string' ? (q.category as never) : undefined,
      initiativeId: typeof q.initiativeId === 'string' ? q.initiativeId : undefined,
      attribution: q.attribution === 'automatic' || q.attribution === 'one-tap' || q.attribution === 'inferred' ? q.attribution : undefined,
      status: typeof q.status === 'string' ? (q.status as never) : undefined,
      beforeMs: before.ms,
      limit: typeof q.limit === 'string' && /^\d+$/.test(q.limit) ? Number(q.limit) : undefined,
    });
    sendFailureJson(req, res, { failures: records.map((r) => FailureLedger.toApiView(r)) });
  });

  router.get('/failures/analysis', (req, res) => {
    if (!ctx.failureLedger) { res.status(503).json({ error: 'failure-learning disabled' }); return; }
    const sinceDays = typeof req.query.sinceDays === 'string' ? Number(req.query.sinceDays) : undefined;
    const sinceMs = sinceDays && sinceDays > 0 ? Date.now() - sinceDays * 86400_000 : undefined;
    // rollout is assembled HERE (analyze() has no config access). Stage derives
    // from the two failureLearning booleans; the 4th "default-on" stage has no
    // per-agent flag and is never returned (tab renders it as a future step).
    const fl = ctx.config.monitoring?.failureLearning;
    const enabled = !!fl?.enabled;
    const insightTelegramEscalation = !!fl?.insightTelegramEscalation;
    const stage = !enabled ? 'dark' : insightTelegramEscalation ? 'insight-push' : 'capture-only';
    const rollout = { stage, enabled, insightTelegramEscalation };
    sendFailureJson(req, res, { ...ctx.failureLedger.analyze({ sinceMs }), rollout });
  });

  router.get('/failures/insights', (req, res) => {
    if (!ctx.failureLedger) { res.status(503).json({ error: 'failure-learning disabled' }); return; }
    const q = req.query;
    const before = parseBeforeMs(q.before);
    if (!before.ok) { res.status(400).json({ error: 'invalid before= (expected an ISO timestamp)' }); return; }
    const status = typeof q.status === 'string' ? q.status : undefined;
    const insights = ctx.failureLedger.listInsights({
      status: status ? (status as never) : undefined,
      beforeMs: before.ms,
      limit: typeof q.limit === 'string' && /^\d+$/.test(q.limit) ? Number(q.limit) : 50,
    });
    sendFailureJson(req, res, { insights });
  });

  // The analyzer + closed-loop tick (spec §4.4/§4.6.1). Invoked by the off-by-
  // default `failure-analyzer` builtin job (Tier-1 supervised). Discovers
  // insights, then — if the Evolution Action queue + InitiativeTracker are wired
  // — opens human-approved tracked items (by-construction guard: only Actions +
  // draft Initiatives, NEVER a proposal) and runs the verify step.
  router.post('/failures/analyze', async (req, res) => {
    if (!ctx.failureLedger) { res.status(503).json({ error: 'failure-learning disabled' }); return; }
    try {
      const gates = {
        minSupport: ctx.config.monitoring?.failureLearning?.minSupport ?? 4,
        minDistinctSessions: ctx.config.monitoring?.failureLearning?.minDistinctSessions ?? 3,
        minDistinctCauseCommits: ctx.config.monitoring?.failureLearning?.minDistinctCauseCommits ?? 3,
      };
      const analysis = new FailureAnalyzer(ctx.failureLedger, gates).analyze();

      let actedOn = 0;
      let verified = 0;
      const evo = ctx.evolution as { addAction?: (o: never) => { id: string } } | null;
      const tracker = ctx.initiativeTracker;
      if (evo?.addAction && tracker?.create) {
        const driver = new FailureLoopDriver(ctx.failureLedger, {
          addAction: (o) => evo.addAction!(o as never),
          createInitiative: async (i) => {
            const created = await tracker.create(i as never);
            return { id: created.id };
          },
        });
        actedOn = (await driver.actOnNewInsights()).actedOn.length;
        verified = driver.runVerification().evaluated.length;
      }
      res.json({ analysis, actedOn, verified });
    } catch (err) {
      // Fail-open: the analyzer never crashes the caller (job).
      res.status(200).json({ error: 'analyze failed (logged)', detail: err instanceof Error ? err.message : String(err) });
    }
  });

  router.get('/failures/:id', (req, res) => {
    if (!ctx.failureLedger) { res.status(503).json({ error: 'failure-learning disabled' }); return; }
    const rec = ctx.failureLedger.get(req.params.id);
    if (!rec) { res.status(404).json({ error: 'not found' }); return; }
    res.json(FailureLedger.toApiView(rec));
  });

  router.post('/failures', (req, res) => {
    if (!ctx.failureLedger) { res.status(503).json({ error: 'failure-learning disabled' }); return; }
    // Intent marker (§4.2#B) — NOT a transport boundary; paired with filedBy audit.
    if (req.headers['x-instar-request'] !== '1') {
      res.status(403).json({ error: 'POST /failures requires the X-Instar-Request: 1 intent header' });
      return;
    }
    const body = req.body ?? {};
    const summary = typeof body.summary === 'string' ? body.summary.trim() : '';
    const initiativeId = typeof body.initiativeId === 'string' ? body.initiativeId.trim() : '';
    if (!summary || !initiativeId) {
      res.status(400).json({ error: 'summary and initiativeId are required' });
      return;
    }
    if (!ctx.failureAttributionEngine) {
      res.status(503).json({ error: 'attribution engine not configured' });
      return;
    }
    const verdict = ctx.failureAttributionEngine.validateAgentDiagnosed({
      initiativeId,
      causeCommitOid: typeof body.causeCommitOid === 'string' ? body.causeCommitOid : undefined,
    });
    if (!verdict.ok) { res.status(400).json({ error: verdict.reason }); return; }
    const severity = body.severity === 'low' || body.severity === 'high' ? body.severity : 'medium';
    const redacted = typeof body.detail === 'string' && body.detail ? body.detail : summary;
    const filedBy =
      (req.headers['x-instar-agentid'] as string) ||
      (req.headers['x-instar-session'] as string) ||
      'agent-diagnosed';
    const rec = ctx.failureLedger.open({
      filedBy,
      source: 'agent-diagnosed',
      severity,
      summary,
      detail: { redacted, full: redacted },
      category: FailureAttributionEngine.coerceCategory(typeof body.category === 'string' ? body.category : undefined),
      initiativeId: verdict.verdict.initiativeId,
      projectId: verdict.verdict.projectId,
      specPath: verdict.verdict.specPath,
      causeCommitOid: verdict.verdict.causeCommitOid,
      attribution: verdict.verdict.attribution, // one-tap — never upgrades (B6)
      attributionConfidence: verdict.verdict.attributionConfidence,
      provenance: 'unknown',
    });
    if (!rec) { res.status(500).json({ error: 'failed to record (logged via fail-open path)' }); return; }
    res.status(201).json(FailureLedger.toApiView(rec));
  });

  // ── Jobs ────────────────────────────────────────────────────────

  // Pool-scope job aggregation (WS4.3, MULTI-MACHINE-SEAMLESSNESS-SPEC §WS4.3 —
  // READ-SIDE only). Mirrors the proven sessions?scope=pool / attention?scope=pool
  // fan-out shape: a short-TTL cache so dashboard polls don't re-fan-out, a
  // known-offline-peer skip, a per-peer timeout → failed marker (never a 500).
  const jobsPoolCache = new Map<string, { at: number; payload: unknown }>();
  const JOBS_POOL_CACHE_TTL_MS = 3_000;
  const JOBS_PEER_TIMEOUT_MS = 5_000;

  // Build THIS machine's local job list — the same shape the plain GET /jobs
  // returns (so a peer's GET /jobs reply merges in identically).
  function buildLocalJobs(): Array<Record<string, unknown>> {
    if (!ctx.scheduler) return [];
    const nextRunTimes = ctx.scheduler.getNextRunTimes();
    return ctx.scheduler.getJobs().map((job) => {
      const jobState = ctx.state.getJobState(job.slug);
      // Merge live scheduler nextRun into state — fixes display bug where
      // never-run jobs show as "unscheduled" despite having active cron tasks
      const liveNext = nextRunTimes[job.slug];
      const mergedState = jobState
        ? { ...jobState, nextScheduled: jobState.nextScheduled ?? liveNext }
        : liveNext
          ? { slug: job.slug, lastRun: null, lastResult: null, nextScheduled: liveNext, consecutiveFailures: 0 }
          : null;
      return { ...job, state: mergedState, runsOnThisMachine: ctx.scheduler!.isJobLocal(job.slug) };
    });
  }

  // F8 job-placement divergence detector (observe-only — NEVER gates). Honest
  // derivation: capacity carries no declared-job count, so we work from each
  // machine's own /jobs reply. A divergence row flags ONLY the real F8 case — a
  // machine that DECLARES jobs (its scheduler returned N>0) but RUNS none of
  // them locally (runsOnThisMachine === true for 0 of them): "config says jobs
  // here, machine isn't running them." A machine that declares ZERO jobs is NOT
  // a divergence — a scheduler-less/dispatcher-only machine (or any machine
  // with no jobs configured) legitimately has none, and flagging it is
  // self-noise (2026-06-12 review finding). We never fabricate an expected
  // count — only what the reply proves.
  function detectJobDivergences(
    perMachine: Array<{ machineId: string; nickname?: string | null; jobs: Array<Record<string, unknown>> }>,
  ): Array<{ machineId: string; machineNickname?: string | null; declared: number; running: number; reason: string }> {
    const out: Array<{ machineId: string; machineNickname?: string | null; declared: number; running: number; reason: string }> = [];
    for (const m of perMachine) {
      const declared = m.jobs.length;
      const running = m.jobs.filter((j) => j.runsOnThisMachine === true).length;
      if (declared > 0 && running === 0) {
        out.push({
          machineId: m.machineId,
          machineNickname: m.nickname ?? undefined,
          declared,
          running,
          reason: `machine ${m.nickname ?? m.machineId}: declares ${declared} jobs, running 0 locally`,
        });
      }
    }
    return out;
  }

  async function jobsPoolMerge(localJobs: Array<Record<string, unknown>>): Promise<Record<string, unknown>> {
    const cacheKey = 'jobs';
    const cached = jobsPoolCache.get(cacheKey);
    if (cached && Date.now() - cached.at < JOBS_POOL_CACHE_TTL_MS) {
      return cached.payload as Record<string, unknown>;
    }

    const selfMachineId = ctx.meshSelfId ?? null;
    const selfNickname = selfMachineId
      ? ctx.machinePoolRegistry?.getCapacity(selfMachineId)?.nickname ?? null
      : null;

    const peers = ctx.resolvePeerUrls?.() ?? [];
    const failed: Array<{ machineId: string; error: string }> = [];
    const remote: Array<Record<string, unknown>> = [];
    // WS4.4(f): set true when ANY peer body was served stale by the shared
    // pool-cache under CPU load-shed — surfaced as an honest `pool.stale` tag.
    let poolStale = false;
    // Per-machine declared/running view feeding the F8 divergence detector.
    const perMachine: Array<{ machineId: string; nickname?: string | null; jobs: Array<Record<string, unknown>> }> = [
      { machineId: selfMachineId ?? '(self)', nickname: selfNickname, jobs: localJobs },
    ];
    await Promise.all(
      peers.map(async (p) => {
        // Skip a peer the registry knows to be offline — saves the timeout
        // wait; an unknown peer (no capacity row) is still tried.
        const cap = ctx.machinePoolRegistry?.getCapacity(p.machineId);
        if (cap && cap.online === false) {
          failed.push({ machineId: p.machineId, error: 'offline' });
          return;
        }
        try {
          // The actual peer fetch — called WITHOUT scope=pool (no recursion).
          const fetchPeerJobs = async () => {
            const r = await fetch(`${p.url}/jobs`, {
              headers: { Authorization: `Bearer ${ctx.config.authToken}` },
              signal: AbortSignal.timeout(JOBS_PEER_TIMEOUT_MS),
            });
            if (!r.ok) throw new Error(`HTTP ${r.status}`);
            return (await r.json()) as { jobs?: Array<Record<string, unknown>> };
          };
          // WS4.4(f): when the shared pool-cache is wired (dark flag on), route
          // the per-peer fetch through it so two pool-scope surfaces hitting the
          // SAME peer in the same poll window share ONE fan-out, and a CPU
          // load-shed serves last-cached (stale-tagged) instead of re-fanning.
          // When null (flag dark / single-machine), call the fetcher directly —
          // byte-for-byte today's behavior.
          let body: { jobs?: Array<Record<string, unknown>> };
          if (ctx.poolPollCache) {
            const res = await ctx.poolPollCache.fetchPeer(p.machineId, '/jobs', fetchPeerJobs);
            body = res.body;
            if (res.stale) poolStale = true;
          } else {
            body = await fetchPeerJobs();
          }
          const nickname = cap?.nickname ?? null;
          const peerJobs = body.jobs ?? [];
          perMachine.push({ machineId: p.machineId, nickname, jobs: peerJobs });
          for (const j of peerJobs) {
            remote.push({
              ...j,
              machineId: j.machineId ?? p.machineId,
              machineNickname: j.machineNickname ?? nickname ?? undefined,
              remote: true,
            });
          }
        } catch (err) {
          failed.push({ machineId: p.machineId, error: err instanceof Error ? err.message : String(err) });
        }
      }),
    );

    // Tag local jobs with this machine's identity (additive — present only when
    // the pool is wired). Mirrors sessions/attention self-tagging.
    const localTagged = localJobs.map((j) => ({
      ...j,
      machineId: j.machineId ?? selfMachineId ?? undefined,
      machineNickname: j.machineNickname ?? selfNickname ?? undefined,
    }));

    const jobs = [...localTagged, ...remote];
    const payload = {
      jobs,
      count: jobs.length,
      pool: {
        enabled: !!ctx.machinePoolRegistry,
        selfMachineId,
        peersQueried: peers.length,
        peersOk: peers.length - failed.length,
        failed,
        divergences: detectJobDivergences(perMachine),
        // WS4.4(f): honestly labeled when the shared pool-cache served any peer
        // body from its last-cached value under CPU load-shed (load-shed, never
        // silent stale). Absent/false ⇒ every peer body in this merge is fresh.
        ...(poolStale ? { stale: true } : {}),
      },
    };
    jobsPoolCache.set(cacheKey, { at: Date.now(), payload });
    return payload;
  }

  router.get('/jobs', async (req, res) => {
    if (!ctx.scheduler) {
      // scope=pool from a scheduler-less self still answers a coherent pool
      // view (local-only empty) so the dashboard never 500s on a single role.
      if (req.query.scope === 'pool') {
        res.json(await jobsPoolMerge([]));
        return;
      }
      res.json({ jobs: [], scheduler: null });
      return;
    }

    const jobs = buildLocalJobs();

    // scope=pool (WS4.3, MULTI-MACHINE-SEAMLESSNESS-SPEC §WS4.3): merge every
    // ONLINE peer's plain GET /jobs into one view, each job tagged with its
    // machine, plus an observe-only job-placement divergence list. Tolerant by
    // design (per-peer timeout → a `failed` marker, never a 500), short-TTL
    // cached so dashboard polling doesn't re-fan-out per request. Plain GET
    // stays a back-compatible { jobs, queue } object.
    if (req.query.scope === 'pool') {
      res.json(await jobsPoolMerge(jobs));
      return;
    }

    res.json({ jobs, queue: ctx.scheduler.getQueue() });
  });

  // ── Category Overseer Reports ────────────────────────────────────
  // These MUST be registered before /jobs/:slug routes to avoid Express
  // matching "categories" and "category-report" as :slug params.

  /**
   * GET /jobs/categories
   * List all unique category tags and their job counts.
   */
  router.get('/jobs/categories', (_req, res) => {
    if (!ctx.scheduler) {
      res.json({ categories: {} });
      return;
    }

    const allJobs = ctx.scheduler.getJobs();
    const categories: Record<string, string[]> = {};

    for (const job of allJobs) {
      for (const tag of job.tags ?? []) {
        if (tag.startsWith('cat:')) {
          const cat = tag.slice(4);
          if (!categories[cat]) categories[cat] = [];
          categories[cat].push(job.slug);
        }
      }
    }

    res.json({ categories });
  });

  /**
   * GET /jobs/category-report/:category
   * Aggregates run history, skip data, handoff notes, and health for all jobs
   * matching the given category tag. Used by overseer jobs to review their domain.
   */
  router.get('/jobs/category-report/:category', (req, res) => {
    const category = req.params.category;
    if (!category || !/^[a-z][a-z0-9-]{0,31}$/.test(category)) {
      res.status(400).json({ error: 'Invalid category name' });
      return;
    }
    if (!ctx.scheduler) {
      res.status(503).json({ error: 'Scheduler not running' });
      return;
    }

    const sinceHours = parseInt(req.query.sinceHours as string) || 24;
    const allJobs = ctx.scheduler.getJobs();
    const history = ctx.scheduler.getRunHistory();
    const skipLedger = ctx.scheduler.getSkipLedger();

    // Find jobs matching this category (tag starts with "cat:" or exact match)
    const categoryTag = `cat:${category}`;
    const matchingJobs = allJobs.filter(j =>
      j.tags?.includes(categoryTag) || j.tags?.includes(category)
    );

    if (matchingJobs.length === 0) {
      res.json({ category, jobs: [], summary: { totalJobs: 0, healthy: 0, failing: 0, skipping: 0 } });
      return;
    }

    const jobReports = matchingJobs.map(job => {
      const jobState = ctx.state.getJobState(job.slug);
      const stats = history.stats(job.slug, sinceHours);
      const lastHandoff = history.getLastHandoff(job.slug);
      const skipSummary = skipLedger.getSkipSummary(sinceHours);
      const jobSkips = skipSummary[job.slug] || { total: 0, byReason: {} };
      const workloadTrend = skipLedger.getWorkloadTrend(job.slug);

      // Recent runs (last 5)
      const recentRuns = history.query({ slug: job.slug, limit: 5 }).runs.map(r => ({
        runId: r.runId,
        startedAt: r.startedAt,
        completedAt: r.completedAt,
        result: r.result,
        durationSeconds: r.durationSeconds,
        model: r.model,
        error: r.error,
      }));

      return {
        slug: job.slug,
        name: job.name,
        enabled: job.enabled,
        priority: job.priority,
        model: job.model,
        schedule: job.schedule,
        tags: job.tags,
        state: {
          lastRun: jobState?.lastRun,
          lastResult: jobState?.lastResult,
          consecutiveFailures: jobState?.consecutiveFailures ?? 0,
        },
        stats: stats ? {
          totalRuns: stats.totalRuns,
          successes: stats.successes,
          failures: stats.failures,
          successRate: stats.successRate,
          avgDurationSeconds: stats.avgDurationSeconds,
          runsPerDay: stats.runsPerDay,
        } : null,
        skips: {
          total: jobSkips.total,
          byReason: jobSkips.byReason,
        },
        workloadTrend: workloadTrend ? {
          avgSaturation: workloadTrend.avgSaturation,
          skipFastRate: workloadTrend.skipFastRate,
          avgDuration: workloadTrend.avgDuration,
          runCount: workloadTrend.runCount,
        } : null,
        lastHandoff: lastHandoff ? {
          notes: lastHandoff.handoffNotes,
          from: lastHandoff.completedAt,
        } : null,
        recentRuns,
      };
    });

    // Compute summary
    const healthy = jobReports.filter(j => j.state.consecutiveFailures === 0 && j.enabled).length;
    const failing = jobReports.filter(j => j.state.consecutiveFailures > 0).length;
    const skipping = jobReports.filter(j => j.skips.total > 0).length;
    const disabled = jobReports.filter(j => !j.enabled).length;
    const totalRuns = jobReports.reduce((sum, j) => sum + (j.stats?.totalRuns ?? 0), 0);
    const totalFailures = jobReports.reduce((sum, j) => sum + (j.stats?.failures ?? 0), 0);
    const avgSuccessRate = jobReports.length > 0
      ? jobReports.reduce((sum, j) => sum + (j.stats?.successRate ?? 100), 0) / jobReports.length
      : 100;

    res.json({
      category,
      sinceHours,
      generatedAt: new Date().toISOString(),
      summary: {
        totalJobs: matchingJobs.length,
        healthy,
        failing,
        skipping,
        disabled,
        totalRuns,
        totalFailures,
        avgSuccessRate: Math.round(avgSuccessRate * 10) / 10,
      },
      jobs: jobReports,
    });
  });

  /**
   * GET /jobs/migration-status
   * Phase 4 — surface the jobs-as-agentmd migration state so the Dashboard
   * can render the "Confirm migration complete" / "Roll back" buttons.
   *
   * Returns:
   *   - hasLegacyJobsJson: boolean (whether .instar/jobs.json exists)
   *   - hasMigrationComplete: boolean
   *   - hasMigrationAbandoned: boolean
   *   - canConfirm: boolean (legacy + schedule/ exist, no marker)
   *   - canAbandon: boolean (schedule/ exists, no completion marker)
   *   - scheduleEntryCount: number
   */
  /**
   * GET /jobs/reconcile
   *
   * Boot-time consistency check for the agentmd job tree. Surfaces
   * orphan manifests, shadow .md files, missing-from-jobs.json entries,
   * staged .new files from interrupted saves, and case-collisions per
   * INSTAR-JOBS-AS-AGENTMD spec §Runtime "Load lifecycle (boot)".
   *
   * Dashboard Issues-card consumes the returned `findings` array.
   */
  router.get('/jobs/reconcile', async (_req, res) => {
    try {
      const stateDir = ctx.config.stateDir;
      if (!stateDir) {
        res.status(503).json({ error: 'state dir not configured' });
        return;
      }
      const { reconcileAgentMdTree } = await import('../scheduler/AgentMdReconcile.js');
      const report = reconcileAgentMdTree({ stateDir });
      res.json(report);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  router.get('/jobs/migration-status', (_req, res) => {
    try {
      const stateDir = ctx.config.stateDir;
      if (!stateDir) {
        res.status(503).json({ error: 'state dir not configured' });
        return;
      }
      const jobsJson = path.join(stateDir, 'jobs.json');
      const jobsRoot = path.join(stateDir, 'jobs');
      const scheduleDir = path.join(jobsRoot, 'schedule');
      const completed = path.join(jobsRoot, '.migration-complete.json');
      const abandoned = path.join(jobsRoot, '.migration-abandoned.json');
      const hasLegacyJobsJson = fs.existsSync(jobsJson);
      const hasMigrationComplete = fs.existsSync(completed);
      const hasMigrationAbandoned = fs.existsSync(abandoned);
      let scheduleEntryCount = 0;
      if (fs.existsSync(scheduleDir)) {
        scheduleEntryCount = fs.readdirSync(scheduleDir).filter((f) => f.endsWith('.json')).length;
      }
      res.json({
        hasLegacyJobsJson,
        hasMigrationComplete,
        hasMigrationAbandoned,
        canConfirm: hasLegacyJobsJson && scheduleEntryCount > 0 && !hasMigrationComplete && !hasMigrationAbandoned,
        canAbandon: scheduleEntryCount > 0 && !hasMigrationComplete && !hasMigrationAbandoned,
        scheduleEntryCount,
      });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  /**
   * POST /jobs/migration-confirm
   * Phase 4 — operator confirms migration is complete. Writes
   * .instar/jobs/.migration-complete.json which the release-cut gate
   * consumes to allow jobs.json deletion.
   *
   * Idempotent — re-confirming is a no-op.
   */
  router.post('/jobs/migration-confirm', (_req, res) => {
    try {
      const stateDir = ctx.config.stateDir;
      if (!stateDir) {
        res.status(503).json({ error: 'state dir not configured' });
        return;
      }
      const jobsRoot = path.join(stateDir, 'jobs');
      const completed = path.join(jobsRoot, '.migration-complete.json');
      const abandoned = path.join(jobsRoot, '.migration-abandoned.json');
      if (fs.existsSync(abandoned)) {
        res.status(409).json({ error: 'Migration has been abandoned; cannot confirm. Run `instar job migrate` first.' });
        return;
      }
      fs.mkdirSync(jobsRoot, { recursive: true });
      fs.writeFileSync(
        completed,
        JSON.stringify({ confirmedAt: new Date().toISOString(), confirmedBy: 'dashboard' }, null, 2),
        'utf-8',
      );
      res.json({ ok: true, marker: completed });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  /**
   * POST /jobs/migration-abandon
   * Phase 4 — operator rolls back migration. Invokes
   * `jobsMigrate({ abandon: true })` to remove `.instar/jobs/schedule/`,
   * write `.migration-abandoned.json`, and leave `jobs.json` intact.
   */
  router.post('/jobs/migration-abandon', async (_req, res) => {
    try {
      const stateDir = ctx.config.stateDir;
      if (!stateDir) {
        res.status(503).json({ error: 'state dir not configured' });
        return;
      }
      const { jobsMigrate } = await import('../commands/jobMigrate.js');
      const packageRoot = path.resolve(__dirname, '..', '..');
      const outcome = jobsMigrate({ agentStateDir: stateDir, packageRoot, abandon: true });
      res.json(outcome);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  router.post('/jobs/:slug/trigger', async (req, res) => {
    if (!JOB_SLUG_RE.test(req.params.slug)) {
      res.status(400).json({ error: 'Invalid job slug' });
      return;
    }
    if (!ctx.scheduler) {
      res.status(503).json({ error: 'Scheduler not running' });
      return;
    }

    const rawReason = (req.body?.reason as string) || 'manual';
    const reason = typeof rawReason === 'string' ? rawReason.slice(0, 500) : 'manual';

    try {
      const result = await ctx.scheduler.triggerJob(req.params.slug, reason);
      res.json({ slug: req.params.slug, result });
    } catch (err) {
      res.status(404).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // ── Manual Job Trigger (Dashboard) ─────────────────────────────
  //
  // Rate-limited manual job trigger with security logging.
  // Used by the dashboard — stricter than /jobs/:slug/trigger.

  const manualTriggerLastRun = new Map<string, number>();
  let manualTriggerConcurrent = 0;
  const MANUAL_TRIGGER_MAX_CONCURRENT = 5;

  router.post('/jobs/:slug/run', async (req, res) => {
    const { slug } = req.params;

    if (!/^[a-z0-9-]+$/.test(slug)) {
      res.status(400).json({ error: 'Invalid job slug' });
      return;
    }
    if (!ctx.scheduler) {
      res.status(503).json({ error: 'Scheduler not running' });
      return;
    }

    const job = ctx.scheduler.getJobs().find(j => j.slug === slug);
    if (!job) {
      res.status(404).json({ error: `Job not found: ${slug}` });
      return;
    }

    const jobState = ctx.state.getJobState(slug);
    if (jobState?.lastResult === 'pending') {
      res.status(409).json({ error: 'Job is already running' });
      return;
    }

    // Rate limit: minimum interval based on job's expected duration (in ms)
    const minIntervalMs = (job.expectedDurationMinutes ?? 5) * 60 * 1000;
    const lastTrigger = manualTriggerLastRun.get(slug);
    if (lastTrigger && Date.now() - lastTrigger < minIntervalMs) {
      const retryAfterSec = Math.ceil((minIntervalMs - (Date.now() - lastTrigger)) / 1000);
      res.status(429).json({
        error: 'Too soon — job was manually triggered recently',
        retryAfterSeconds: retryAfterSec,
      });
      return;
    }

    // Global concurrency cap
    if (manualTriggerConcurrent >= MANUAL_TRIGGER_MAX_CONCURRENT) {
      res.status(429).json({ error: 'Too many concurrent manual triggers' });
      return;
    }

    try {
      manualTriggerConcurrent++;
      manualTriggerLastRun.set(slug, Date.now());

      const result = await ctx.scheduler.triggerJob(slug, 'dashboard-manual');
      const runId = `manual-${slug}-${Date.now().toString(36)}`;

      // Decrement concurrent counter after a reasonable time
      // (the job itself is tracked by the scheduler, this just gates manual triggers)
      setTimeout(() => { manualTriggerConcurrent = Math.max(0, manualTriggerConcurrent - 1); }, 5000);

      // Security log
      try {
        const securityEntry = JSON.stringify({
          timestamp: new Date().toISOString(),
          action: 'job-run',
          slug,
          source: 'dashboard',
          ip: req.ip,
          result,
        });
        fs.appendFileSync(path.join(ctx.config.stateDir, 'security.jsonl'), securityEntry + '\n');
      } catch {
        // Security logging failure is non-fatal
      }

      res.status(202).json({ status: 'accepted', runId, result, message: 'Job queued for execution' });
    } catch (err) {
      manualTriggerConcurrent = Math.max(0, manualTriggerConcurrent - 1);
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // ── Job Enable/Disable (Dashboard) ────────────────────────────

  router.patch('/jobs/:slug', (req, res) => {
    const { slug } = req.params;

    if (!/^[a-z0-9-]+$/.test(slug)) {
      res.status(400).json({ error: 'Invalid job slug' });
      return;
    }
    if (!ctx.scheduler) {
      res.status(503).json({ error: 'Scheduler not running' });
      return;
    }

    // Allow-list: only { enabled: boolean } is accepted
    const body = req.body;
    const allowedKeys = ['enabled'];
    const bodyKeys = Object.keys(body || {});
    if (bodyKeys.length === 0 || bodyKeys.some(k => !allowedKeys.includes(k))) {
      res.status(400).json({ error: 'Only { enabled: boolean } is accepted' });
      return;
    }
    if (typeof body.enabled !== 'boolean') {
      res.status(400).json({ error: '"enabled" must be a boolean' });
      return;
    }

    const job = ctx.scheduler.getJobs().find(j => j.slug === slug);
    if (!job) {
      res.status(404).json({ error: `Job not found: ${slug}` });
      return;
    }

    // Update the job's enabled state in the jobs.json config file
    try {
      const jobsFile = ctx.config.scheduler.jobsFile ?? path.join(ctx.config.stateDir, '..', 'jobs.json');
      if (fs.existsSync(jobsFile)) {
        const jobsData = JSON.parse(fs.readFileSync(jobsFile, 'utf-8'));
        const jobEntry = (jobsData.jobs || jobsData).find((j: { slug: string }) => j.slug === slug);
        if (jobEntry) {
          jobEntry.enabled = body.enabled;
          fs.writeFileSync(jobsFile, JSON.stringify(jobsData, null, 2) + '\n');
        }
      }
    } catch (err) {
      res.status(500).json({ error: `Failed to update job config: ${err instanceof Error ? err.message : String(err)}` });
      return;
    }

    // Security log
    try {
      const securityEntry = JSON.stringify({
        timestamp: new Date().toISOString(),
        action: 'job-toggle',
        slug,
        enabled: body.enabled,
        source: 'dashboard',
        ip: req.ip,
      });
      fs.appendFileSync(path.join(ctx.config.stateDir, 'security.jsonl'), securityEntry + '\n');
    } catch {
      // Security logging failure is non-fatal
    }

    res.json({ slug, enabled: body.enabled, message: `Job ${body.enabled ? 'enabled' : 'disabled'}` });
  });

  // ── Reset Job State ───────────────────────────────────────────
  //
  // Clears stale pending/failure state for a job. Useful when a session dies
  // without reporting back, leaving lastResult stuck on 'pending' forever.

  router.post('/jobs/:slug/reset-state', (req, res) => {
    const { slug } = req.params;

    if (!/^[a-z0-9-]+$/.test(slug)) {
      res.status(400).json({ error: 'Invalid job slug' });
      return;
    }
    if (!ctx.scheduler) {
      res.status(503).json({ error: 'Scheduler not running' });
      return;
    }

    const job = ctx.scheduler.getJobs().find(j => j.slug === slug);
    if (!job) {
      res.status(404).json({ error: `Job not found: ${slug}` });
      return;
    }

    const existing = ctx.state.getJobState(slug);
    const previousResult = existing?.lastResult ?? 'none';

    const resetState: import('../core/types.js').JobState = {
      slug,
      lastRun: existing?.lastRun,
      lastResult: 'failure',
      lastError: `Manually reset from '${previousResult}' state`,
      lastHandoff: existing?.lastHandoff,
      nextScheduled: existing?.nextScheduled,
      consecutiveFailures: 0,
    };
    ctx.state.saveJobState(resetState);

    ctx.state.appendEvent({
      type: 'job_state_reset',
      summary: `Job "${slug}" state manually reset from '${previousResult}'`,
      timestamp: new Date().toISOString(),
      metadata: { slug, previousResult },
    });

    // Security log
    try {
      const securityEntry = JSON.stringify({
        timestamp: new Date().toISOString(),
        action: 'job-reset-state',
        slug,
        previousResult,
        source: req.body?.source ?? 'api',
        ip: req.ip,
      });
      fs.appendFileSync(path.join(ctx.config.stateDir, 'security.jsonl'), securityEntry + '\n');
    } catch {
      // Security logging failure is non-fatal
    }

    res.json({
      slug,
      previousResult,
      newResult: 'failure',
      message: `Job state reset from '${previousResult}' to 'failure'. Job can now be re-triggered.`,
    });
  });

  // ── Job Events (SSE) ──────────────────────────────────────────
  //
  // Server-Sent Events stream for real-time job state changes.
  // Auth checked inline since SSE connections don't go through normal middleware cleanly.

  router.get('/jobs/events', (req, res) => {
    // Inline auth check for SSE — supports both Authorization header and ?token= query param
    // (EventSource API cannot send custom headers, so token in query is required for browser SSE)
    if (ctx.config.authToken) {
      let tokenValue: string | undefined;
      const header = req.headers.authorization;
      if (header?.startsWith('Bearer ')) {
        tokenValue = header.slice(7);
      } else if (typeof req.query.token === 'string') {
        tokenValue = req.query.token;
      }
      if (!tokenValue) {
        res.status(401).json({ error: 'Missing Authorization header or token query param' });
        return;
      }
      const ha = createHash('sha256').update(tokenValue).digest();
      const hb = createHash('sha256').update(ctx.config.authToken).digest();
      if (!timingSafeEqual(ha, hb)) {
        res.status(403).json({ error: 'Invalid token' });
        return;
      }
    }

    // Set SSE headers
    res.writeHead(200, {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      'Connection': 'keep-alive',
      'X-Accel-Buffering': 'no',
    });

    let eventId = 0;

    // Send retry directive on first message
    res.write(`retry: 1000\n\n`);

    // Heartbeat every 15 seconds
    const heartbeat = setInterval(() => {
      eventId++;
      res.write(`id: ${eventId}\nevent: heartbeat\ndata: ${JSON.stringify({ ts: Date.now() })}\n\n`);
    }, 15_000);

    // Send initial state snapshot
    if (ctx.scheduler) {
      eventId++;
      const jobs = ctx.scheduler.getJobs().map(job => {
        const jobState = ctx.state.getJobState(job.slug);
        return { slug: job.slug, name: job.name, enabled: job.enabled, state: jobState };
      });
      res.write(`id: ${eventId}\nevent: snapshot\ndata: ${JSON.stringify({ jobs, ts: Date.now() })}\n\n`);
    }

    // Poll for job state changes every 5 seconds and emit deltas
    let lastStates = new Map<string, string>();
    if (ctx.scheduler) {
      for (const job of ctx.scheduler.getJobs()) {
        const st = ctx.state.getJobState(job.slug);
        if (st) lastStates.set(job.slug, JSON.stringify(st));
      }
    }

    const poller = setInterval(() => {
      if (!ctx.scheduler) return;
      for (const job of ctx.scheduler.getJobs()) {
        const st = ctx.state.getJobState(job.slug);
        const stStr = st ? JSON.stringify(st) : '';
        const prev = lastStates.get(job.slug) ?? '';
        if (stStr !== prev) {
          lastStates.set(job.slug, stStr);
          eventId++;
          res.write(`id: ${eventId}\nevent: job-state\ndata: ${JSON.stringify({ slug: job.slug, state: st, ts: Date.now() })}\n\n`);
        }
      }
    }, 5_000);

    // Cleanup on close
    req.on('close', () => {
      clearInterval(heartbeat);
      clearInterval(poller);
    });
  });

  // ── Job Run History ─────────────────────────────────────────────

  router.get('/jobs/history', (_req, res) => {
    if (!ctx.scheduler) {
      res.json({ runs: [], total: 0, stats: [] });
      return;
    }

    const history = ctx.scheduler.getRunHistory();
    const sinceHours = parseInt(_req.query.sinceHours as string) || undefined;
    const result = _req.query.result as string | undefined;
    const slug = _req.query.slug as string | undefined;
    const limit = Math.min(parseInt(_req.query.limit as string) || 50, 500);
    const offset = parseInt(_req.query.offset as string) || 0;

    if (slug && !JOB_SLUG_RE.test(slug)) {
      res.status(400).json({ error: 'Invalid job slug' });
      return;
    }

    const validResults = ['pending', 'success', 'failure', 'timeout', 'spawn-error'];
    const resultFilter = result && validResults.includes(result) ? result as 'success' | 'failure' | 'timeout' | 'spawn-error' | 'pending' : undefined;

    const data = history.query({ slug, sinceHours, result: resultFilter, limit, offset });
    const stats = slug ? history.stats(slug, sinceHours) : history.allStats(sinceHours);

    res.json({ ...data, stats });
  });

  router.get('/jobs/:slug/history', (req, res) => {
    if (!JOB_SLUG_RE.test(req.params.slug)) {
      res.status(400).json({ error: 'Invalid job slug' });
      return;
    }
    if (!ctx.scheduler) {
      res.json({ runs: [], total: 0, stats: null });
      return;
    }

    const history = ctx.scheduler.getRunHistory();
    const slug = req.params.slug;
    const sinceHours = parseInt(req.query.sinceHours as string) || undefined;
    const result = req.query.result as string | undefined;
    const limit = Math.min(parseInt(req.query.limit as string) || 50, 500);
    const offset = parseInt(req.query.offset as string) || 0;

    const validResults = ['pending', 'success', 'failure', 'timeout', 'spawn-error'];
    const resultFilter = result && validResults.includes(result) ? result as 'success' | 'failure' | 'timeout' | 'spawn-error' | 'pending' : undefined;

    const data = history.query({ slug, sinceHours, result: resultFilter, limit, offset });
    const stats = history.stats(slug, sinceHours);

    res.json({ ...data, stats });
  });

  // ── Skip Ledger ──────────────────────────────────────────────────

  router.get('/skip-ledger', (_req, res) => {
    if (!ctx.scheduler) {
      res.json({ sinceHours: 24, summary: {}, totalSkips: 0 });
      return;
    }

    const ledger = ctx.scheduler.getSkipLedger();
    const sinceHours = parseInt(_req.query.sinceHours as string) || 24;
    const slug = _req.query.slug as string | undefined;

    if (slug && !JOB_SLUG_RE.test(slug)) {
      res.status(400).json({ error: 'Invalid job slug' });
      return;
    }

    const summary = ledger.getSkipSummary(sinceHours);
    const events = ledger.getSkips({ slug, sinceHours });

    res.json({
      sinceHours,
      summary,
      events: slug ? events : undefined,
      totalSkips: events.length,
    });
  });

  router.get('/skip-ledger/workloads', (_req, res) => {
    if (!ctx.scheduler) {
      res.json({ trends: {} });
      return;
    }

    const ledger = ctx.scheduler.getSkipLedger();
    const slug = _req.query.slug as string | undefined;

    if (slug && !JOB_SLUG_RE.test(slug)) {
      res.status(400).json({ error: 'Invalid job slug' });
      return;
    }

    if (slug) {
      const trend = ledger.getWorkloadTrend(slug);
      const signals = ledger.getWorkloads({ slug, limit: 20 });
      res.json({ slug, trend, recentSignals: signals });
    } else {
      const jobs = ctx.scheduler.getJobs();
      const trends: Record<string, ReturnType<typeof ledger.getWorkloadTrend>> = {};
      for (const job of jobs) {
        trends[job.slug] = ledger.getWorkloadTrend(job.slug);
      }
      res.json({ trends });
    }
  });

  router.post('/skip-ledger/workload', (req, res) => {
    if (!ctx.scheduler) {
      res.status(503).json({ error: 'Scheduler not running' });
      return;
    }

    const { slug, duration, skipFast, itemsFound, itemsProcessed, saturation, notes } = req.body;

    if (!slug || typeof slug !== 'string' || !JOB_SLUG_RE.test(slug)) {
      res.status(400).json({ error: '"slug" must be a valid job slug' });
      return;
    }
    if (typeof duration !== 'number' || duration < 0) {
      res.status(400).json({ error: '"duration" must be a non-negative number (seconds)' });
      return;
    }
    if (typeof itemsFound !== 'number' || typeof itemsProcessed !== 'number') {
      res.status(400).json({ error: '"itemsFound" and "itemsProcessed" must be numbers' });
      return;
    }

    const ledger = ctx.scheduler.getSkipLedger();
    ledger.recordWorkload({
      slug,
      timestamp: new Date().toISOString(),
      duration,
      skipFast: !!skipFast,
      itemsFound,
      itemsProcessed,
      saturation: typeof saturation === 'number' ? saturation : (itemsFound > 0 ? itemsProcessed / itemsFound : 0),
      notes: typeof notes === 'string' ? notes.slice(0, 500) : undefined,
    });

    res.status(201).json({ recorded: true, slug });
  });

  // ── Telegram ────────────────────────────────────────────────────

  router.get('/telegram/topics', (_req, res) => {
    if (!ctx.telegram) {
      res.json({ topics: [] });
      return;
    }
    res.json({ topics: ctx.telegram.getAllTopicMappings() });
  });

  router.post('/telegram/topics', async (req, res) => {
    if (!ctx.telegram) {
      res.status(503).json({ error: 'Telegram not configured' });
      return;
    }

    const { name, color, firstMessage } = req.body;
    if (!name || typeof name !== 'string' || name.trim().length < 1) {
      res.status(400).json({ error: '"name" is required (non-empty string)' });
      return;
    }
    if (name.length > 128) {
      res.status(400).json({ error: '"name" must be 128 characters or fewer' });
      return;
    }
    if (firstMessage !== undefined && (typeof firstMessage !== 'string' || firstMessage.length > 4096)) {
      res.status(400).json({ error: '"firstMessage" must be a string of 4096 characters or fewer' });
      return;
    }

    // Color is optional — defaults to green (9367192)
    const iconColor = typeof color === 'number' ? color : 9367192;

    try {
      const topic = await ctx.telegram.findOrCreateForumTopic(name.trim(), iconColor, { origin: 'user' });

      // Send initial message if provided — goes through sendToTopic so it's
      // properly logged to JSONL + TopicMemory. This ensures new sessions
      // spawned in this topic will see the context in their thread history.
      let messageSent = false;
      if (firstMessage && !topic.reused) {
        await ctx.telegram.sendToTopic(topic.topicId, firstMessage);
        messageSent = true;
      }

      res.status(topic.reused ? 200 : 201).json({
        topicId: topic.topicId,
        name: name.trim(),
        created: !topic.reused,
        reused: topic.reused,
        messageSent,
      });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // ── POST /messaging/preflight — the inform-only advisory preflight ──
  // Deterministic detectors ONLY (no LLM call); 200 with advisories, never a
  // content-4xx; fail-open contract: the calling script treats any non-200 /
  // timeout / malformed response as an empty advisory list and proceeds to
  // the send. Spec: outbound-jargon-filepath-gap §2.4(1).
  router.post('/messaging/preflight', (req, res) => {
    const { text, topicId, jobSlug } = (req.body ?? {}) as Record<string, unknown>;
    if (!text || typeof text !== 'string') {
      res.status(400).json({ error: '"text" field required' });
      return;
    }
    const kind = coerceMessageKind((req.body ?? {}).messageKind) ?? 'reply';
    const enabled = ctx.liveConfig?.get<boolean>('messaging.outboundAdvisory.enabled', true) ?? true;
    if (!enabled) {
      // Rollback lever (live config, no restart): behave exactly like a clean
      // preflight so the script proceeds straight to the send.
      res.json({ advisories: [], disabled: true });
      return;
    }
    const topic = Number(topicId);
    if (kind === 'automated' && (!Number.isFinite(topic) || typeof jobSlug !== 'string' || jobSlug.length === 0)) {
      // Required for audit keying, escalation, and spoof correlation — a
      // localhost POST carries no server-visible session identity to derive
      // them from. (The shipped script always sends both; a 400 here fails
      // open script-side anyway.)
      res.status(400).json({ error: 'automated preflight requires numeric "topicId" and string "jobSlug"' });
      return;
    }
    const capped = text.length > PREFLIGHT_TEXT_CAP ? text.slice(0, PREFLIGHT_TEXT_CAP) : text;
    // TIME_CLAIM (operator mandate 2026-06-12, topic 13481 — "MANDATE accurate
    // time reporting"): when the sending topic has an ACTIVE time-boxed
    // (autonomous) session, elapsed/remaining/percent claims in the candidate
    // text are verified against the live session clock. Dev-gated dark
    // (standard_development_agent_dark_feature_gate); resolution failure
    // degrades to "no clocks" — fail-open like every detector.
    const timeClaimEnabled = resolveDevAgentGate(
      ctx.liveConfig?.get<boolean | undefined>('messaging.outboundAdvisory.timeClaim.enabled', undefined),
      ctx.config,
    );
    let activeClocks: ReturnType<typeof readSessionClocks> = [];
    if (timeClaimEnabled && Number.isFinite(topic) && topic > 0) {
      try {
        activeClocks = readSessionClocks(ctx.config.stateDir, Date.now(), String(topic)).filter(
          (c) => c.status === 'active',
        );
      } catch {
        /* @silent-fallback-ok — fail-open by the advisory contract (outbound-jargon-filepath-gap §2.3): a clock-read error skips the TIME_CLAIM signal, never withholds a message */
        activeClocks = [];
      }
    }
    // Full detector set for automated sends only — the conversational path
    // already has the full authority pipeline, and the operator's over-block
    // concern argues against any new friction there (§4 Q2). TIME_CLAIM is the
    // ONE exception, for every non-script sender kind: an unstamped interactive
    // session running an autonomous job is exactly where the founding "~7h
    // elapsed" mis-report came from, and a contradicted time claim is wrong
    // regardless of message kind. No active clock for the topic → no-op.
    const advisories =
      kind === 'automated'
        ? composeAdvisories(capped, { sessionClocks: activeClocks })
        : composeTimeClaimAdvisories(capped, activeClocks);
    outboundAdvisoryAudit.recordPreflight({
      topicId: Number.isFinite(topic) ? topic : 0,
      // Non-automated (conversational-session) preflights carry no job slug —
      // key their audit/escalation rows under a fixed readable label instead
      // of an empty string.
      jobSlug:
        typeof jobSlug === 'string' && jobSlug.length > 0
          ? jobSlug
          : kind === 'automated'
            ? ''
            : 'interactive-session',
      kind,
      text: capped,
      advisories: advisories.map((a) => a.code),
    });
    res.json({ advisories });
  });

  // ── GET /messaging/advisory-log — bounded tail of the advisory audit ──
  router.get('/messaging/advisory-log', (req, res) => {
    const rawLimit = parseInt(String(req.query.limit ?? '50'), 10);
    const limit = Number.isFinite(rawLimit) ? Math.min(Math.max(rawLimit, 1), 500) : 50;
    res.json({ entries: outboundAdvisoryAudit.readTail(limit) });
  });

  router.post('/telegram/reply/:topicId', async (req, res) => {
    if (!ctx.telegram) {
      res.status(503).json({ error: 'Telegram not configured' });
      return;
    }

    const topicId = parseInt(req.params.topicId, 10);
    if (isNaN(topicId)) {
      res.status(400).json({ error: 'topicId must be a number' });
      return;
    }
    // durable-conversation-identity §5 funnel hardening (increment 2 — a
    // behavior change, deliberately NOT in the foundation): a NEGATIVE id is a
    // minted conversation and never a Telegram topic. The 400 is classified
    // terminal/non-retryable by the recovery policy (4xx → escalate), so no
    // negative-id relay row retries forever.
    if (topicId < 0) {
      res.status(400).json({
        error: 'negative topicId = minted conversation — use the conversation funnel (deliverToConversation, durable-conversation-identity §5)',
      });
      return;
    }
    const { text, metadata } = req.body;
    if (!text || typeof text !== 'string') {
      res.status(400).json({ error: '"text" field required' });
      return;
    }
    if (text.length > 4096) {
      res.status(400).json({ error: '"text" must be 4096 characters or fewer' });
      return;
    }

    // ── X-Instar-DeliveryId server-side dedup (Layer 3 spec §3d step 4) ──
    // 24h LRU keyed on the header value. A duplicate POST with the same
    // delivery_id returns 200 idempotent without sending again. This
    // closes the "200-but-client-blind" double-send class where the
    // sentinel re-sends a queued message that actually landed the first
    // time but the script-side response was lost.
    const deliveryIdHeader = req.headers['x-instar-deliveryid'];
    const deliveryId = Array.isArray(deliveryIdHeader) ? deliveryIdHeader[0] : deliveryIdHeader;
    if (deliveryId && typeof deliveryId === 'string' && /^[0-9a-f-]{16,64}$/i.test(deliveryId)) {
      if (deliveryLruHas(deliveryId)) {
        res.json({ ok: true, topicId, idempotent: true });
        return;
      }
    }

    // ── X-Instar-System bypass (Layer 3 spec §3f) ──
    // For sentinel-emitted templates, bypass the tone gate IF the body
    // matches a known system template. The bypass is deliberately
    // restricted to fixed templates whose content was reviewed at
    // code-review time. Membership check uses regex / SHA-256 against
    // the compiled-in template set; arbitrary text fails through to the
    // normal gate.
    const systemHeader = req.headers['x-instar-system'];
    const systemFlag = Array.isArray(systemHeader) ? systemHeader[0] : systemHeader;
    const isSystemTemplate = systemFlag === 'true' && matchesSystemTemplate(text);

    // Outbound gate — single authority. Skipped for proxy messages (PresenceProxy
    // etc. are system-generated). The authority receives structured signals from
    // the junk-payload and dedup detectors alongside conversational context, and
    // makes ONE block/allow decision with reasoning traceable to rule ids B1–B9.
    // See docs/signal-vs-authority.md.
    const isProxy = metadata?.isProxy === true;
    const allowDebugText = metadata?.allowDebugText === true;
    const allowDuplicate = metadata?.allowDuplicate === true;
    const allowLocalhostLink = metadata?.allowLocalhostLink === true;

    // ── Message kind (spec outbound-jargon-filepath-gap §2.1) ──
    // Stamped structurally by the scheduler env → forwarded by
    // telegram-reply.sh as metadata.messageKind. Absent → 'reply' (default
    // behavior, unchanged). Unrecognized values coerce to 'unknown' before
    // threading anywhere (runtime enum validation).
    const messageKind = coerceMessageKind(metadata?.messageKind);
    const senderClass = coerceSenderClass(metadata?.senderClass);
    const advisoryAck = metadata?.advisoryAck === true;
    const advisoryCodes = coerceAdvisoryCodes(metadata?.advisoryCodes);
    const metadataJobSlug = typeof metadata?.jobSlug === 'string' ? metadata.jobSlug.slice(0, 128) : '';

    // ── Observability breadcrumbs (§2.1 — visibility on the named dodge
    // classes; sovereignty over the send is accepted, nothing is gated). ──
    try {
      const sessionName = resolveTopicSession(String(topicId));
      const topicSession = sessionName
        ? ctx.state.listSessions().find((s) => s.tmuxSession === sessionName)
        : undefined;
      const topicJobSlug = topicSession?.jobSlug;
      if (topicJobSlug && messageKind === undefined) {
        // A kindless send whose topic maps to a job session — possible
        // hand-curl / env-unset bypass. EXEMPT: a sentinel redrive carrying
        // X-Instar-DeliveryId that matches an ACTUAL queue row (legacy queued
        // rows may lack a kind; a redrive is not a bypass — §2.5). A
        // fabricated header must not buy the exemption.
        const isValidRedrive =
          typeof deliveryId === 'string' &&
          /^[0-9a-f-]{16,64}$/i.test(deliveryId) &&
          ctx.pendingRelayLookup?.(deliveryId) === true;
        if (!isValidRedrive) {
          console.log(
            `[telegram/reply] breadcrumb: kindless send to topic ${topicId} mapping to job session (slug ${topicJobSlug}) — possible preflight bypass (observability only)`,
          );
        }
      }
      if (messageKind === 'automated' && topicJobSlug && !advisoryAck) {
        // Automated send with no recent PREFLIGHT-written clean/advised row —
        // possible class-spoof or modified script. Counts only preflight rows
        // (a send's own acked row must not self-license it) and only on the
        // ORIGINATING machine (the index is process-local by construction).
        if (!outboundAdvisoryAudit.hasRecentPreflight(metadataJobSlug || topicJobSlug, topicId)) {
          console.log(
            `[telegram/reply] breadcrumb: automated send to topic ${topicId} (slug ${metadataJobSlug || topicJobSlug}) with no recent preflight row — possible class-spoof (observability only)`,
          );
        }
      }
      if (senderClass === 'script' && metadataJobSlug && ctx.scheduler) {
        // A declared script class is validated against the job definition —
        // the scheduler KNOWS whether this slug is script-mode. A spoofed
        // 'script' on an LLM-session job is breadcrumbed, never trusted.
        const jobDef = ctx.scheduler.getJobs().find((j) => j.slug === metadataJobSlug);
        if (jobDef && jobDef.execute?.type !== 'script') {
          console.log(
            `[telegram/reply] breadcrumb: senderClass 'script' declared for non-script job "${metadataJobSlug}" — possible class spoof (observability only)`,
          );
        }
      }
    } catch {
      /* @silent-fallback-ok — §2.1 breadcrumbs are observe-only; never affect delivery */
    }

    // ── Content-dedup (2026-06-06): suppress the agent re-sending the SAME
    // text to the same topic within the window (an agent re-announcing its last
    // status after a restart/recovery, or a relay re-emitting identical content
    // under a fresh delivery id — the delivery-id LRU above can't catch that).
    // Deterministic, before the tone gate, so it also covers proxy/relay sends
    // the gate skips. Honors the existing `allowDuplicate` escape hatch; brief
    // acks are below the length floor and never suppressed. Recorded only after
    // a successful send (below), so a failed send's retry isn't lost.
    if (!allowDuplicate && outboundContentDedup.isDuplicate(topicId, text)) {
      console.log(`[telegram/reply] suppressed duplicate content for topic ${topicId} (identical text within window)`);
      res.json({ ok: true, topicId, suppressedDuplicate: true });
      return;
    }
    // Skip the LOCAL tone gate when this server will RELAY the reply through the
    // lease holder (a tokenless pool standby). The holder runs ITS OWN tone gate
    // on receipt, so the standby gating too is redundant — and worse, it adds a
    // serial LLM call to every cross-machine reply that, under a rate-limited
    // circuit, can wait up to 120s (MessagingToneGate rateLimitWaitMs) BEFORE the
    // relay even starts (observed: the standby's /telegram/reply hung >50s before
    // relaying). The holder is the single Telegram owner and the correct place to
    // gate. (Direct, non-relay sends still gate locally — unchanged.)
    const willRelay = typeof ctx.telegram.willRelay === 'function' && ctx.telegram.willRelay();
    if (
      !isProxy &&
      !isSystemTemplate &&
      !willRelay &&
      (await checkOutboundMessage(text, 'telegram', res, {
        topicId,
        allowDebugText,
        allowDuplicate,
        allowLocalhostLink,
        messageKind,
      }))
    )
      return;

    try {
      // Capture the SendResult so the response can carry the REAL Telegram
      // messageId. A tokenless-standby relay reads this messageId to decide
      // whether the reply actually landed — without it the relay could only
      // ever return a placeholder 0 and so reported "ok" even when nothing was
      // delivered (the false-success-under-load class).
      const sendResult = await ctx.telegram.sendToTopic(topicId, text, {
        skipStallClear: isProxy,
        // Relay-hop forwarding (§2.5): when this standby relays through the
        // lease holder, the kind metadata must survive the hop so the
        // HOLDER's gate/audit see accurate context. Direct sends ignore it.
        kindMetadata:
          messageKind || senderClass || advisoryAck
            ? {
                ...(messageKind ? { messageKind } : {}),
                ...(senderClass ? { senderClass } : {}),
                ...(metadataJobSlug ? { jobSlug: metadataJobSlug } : {}),
                ...(advisoryAck ? { advisoryAck: true, advisoryCodes } : {}),
              }
            : undefined,
      });
      // Record the content fingerprint AFTER a successful send so an identical
      // re-send within the window is suppressed — but a FAILED send (which
      // throws before here) is never recorded, so its legitimate retry isn't lost.
      outboundContentDedup.record(topicId, text);
      // Clear injection tracker — but NOT for proxy messages (PresenceProxy)
      // Proxy messages should not reset stall detection timers
      if (!isProxy) {
        ctx.sessionManager.clearInjectionTracker(topicId);
      }
      // ── Usher precision, path (a): the agent's genuine reply just went out. If
      // it actually USED a faded context the Usher re-surfaced for this topic,
      // mark that signal acted — the precision numerator that gates rung-5
      // mid-task injection. Proxy/system templates aren't the agent reasoning, so
      // they can't "use" a nudge and are excluded. Best-effort (never throws).
      if (!isProxy && !isSystemTemplate) {
        const credited = creditUsherOnOutbound(ctx.usherSignalStore, topicId, text);
        if (credited.length) {
          console.log(`[Usher] ${credited.length} signal(s) marked acted (use) on topic ${topicId}`);
        }
      }
      // ── Exactly-once ingress: commit reply_committed (spec §8 G3a) ──
      // The agent's real reply just went out → mark the inbound event this topic
      // is processing as answered, so a provider redelivery or handoff-window
      // replay of that same inbound is dropped by the gate above. Skipped for
      // proxy/system sends (they aren't replies to a user inbound). FAIL-OPEN.
      if (!isProxy && ctx.messageLedger && ctx.currentInboundByTopic) {
        try {
          const dedupeKey = ctx.currentInboundByTopic.get(String(topicId));
          if (dedupeKey) {
            const epoch = ctx.coordinator?.getLeaseEpoch() ?? 0;
            commitInboundReply(ctx.messageLedger, dedupeKey, epoch);
            ctx.currentInboundByTopic.delete(String(topicId));
            // Cross-machine half (spec §8 G3a): tell standby peers this event was
            // answered, so a post-handoff redelivery is deduped on the new holder.
            // Best-effort, fire-and-forget — the dedup gate + provider redelivery
            // are the backstop if a marker is lost.
            const entry = ctx.messageLedger.get(dedupeKey);
            if (ctx.replyMarkerTransport && entry?.replyIdempotencyKey) {
              void ctx.replyMarkerTransport.broadcast({
                dedupeKey,
                platform: 'telegram',
                replyIdempotencyKey: entry.replyIdempotencyKey,
                epoch,
                topic: String(topicId),
              });
            }
          }
        } catch (err) {
          console.error(`[telegram/reply] exactly-once commit error (non-fatal): ${err instanceof Error ? err.message : err}`);
        }
      }
      // Record successful delivery in the dedup LRU so a sentinel retry
      // with the same delivery_id returns 200-idempotent.
      if (deliveryId && typeof deliveryId === 'string' && /^[0-9a-f-]{16,64}$/i.test(deliveryId)) {
        deliveryLruRecord(deliveryId);
      }
      // ── Acked advisory audit (§2.4(5) — the server is the single writer
      // of 'acked'). Written on SUCCESSFUL delivery so an acked-then-queued
      // send still lands its row after the sentinel redrive (the queue
      // carries the metadata whole) instead of false-firing the escalation.
      if (advisoryAck) {
        try {
          outboundAdvisoryAudit.recordAck({
            topicId,
            // Same slug fallback as the preflight writer: a non-automated
            // (conversational-session) ack must land under the SAME signature
            // key its advised episodes were recorded under, or the episodes
            // never resolve and the ignore-escalation false-fires on messages
            // that actually delivered (second-pass review concern 2).
            jobSlug:
              metadataJobSlug.length > 0
                ? metadataJobSlug
                : (messageKind ?? 'reply') === 'automated'
                  ? ''
                  : 'interactive-session',
            kind: messageKind ?? 'reply',
            text,
            advisories: advisoryCodes,
          });
        } catch {
          /* @silent-fallback-ok — §2.4(5) acked-audit is observe-only; never affects delivery */
        }
      }
      res.json({ ok: true, topicId, messageId: sendResult?.messageId });
    } catch (err) {
      // @silent-fallback-ok — NOT a silent fallback: this catch surfaces a 500 to the
      // caller. The tag exists because the no-silent-fallbacks scanner's fixed 20-line
      // window reaches past this route's end into the next route's `db = null`
      // initializer (pattern-3 false positive after nearby line shifts).
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // ── GET /delivery-queue (Layer 3 spec §3i) ──
  // Authed read-only view of the pending-relay queue depth/oldest age
  // for the current agent. Used by the dashboard "Pending Replies" panel
  // and ops health checks. Read-only: never mutates queue rows.
  router.get('/delivery-queue', (_req, res) => {
    const stateDir = ctx.config.stateDir;
    const agentId = ctx.config.projectName;
    if (!stateDir || !agentId) {
      res.status(503).json({ error: 'state directory or agent id not configured' });
      return;
    }
    const dbPath = resolvePendingRelayPath(stateDir, agentId);
    let db: import('better-sqlite3').Database | null = null;
    try {
      db = new Database(dbPath, { readonly: true, fileMustExist: true });
      const totalRow = db.prepare('SELECT COUNT(*) AS n FROM entries').get() as { n: number };
      const total = totalRow?.n ?? 0;
      const byState = db.prepare(
        'SELECT state, COUNT(*) AS n FROM entries GROUP BY state',
      ).all() as Array<{ state: string; n: number }>;
      const oldestRow = db.prepare(
        "SELECT MIN(attempted_at) AS oldest FROM entries WHERE state IN ('queued','claimed')",
      ).get() as { oldest: string | null };
      const oldestAgeSeconds = oldestRow?.oldest
        ? Math.max(0, Math.floor((Date.now() - Date.parse(oldestRow.oldest)) / 1000))
        : 0;
      res.json({
        depth: total,
        oldest_age_seconds: oldestAgeSeconds,
        by_state: Object.fromEntries(byState.map((r) => [r.state, r.n])),
      });
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      // Missing-file is a normal "no queue yet" state — return zeros, not 500.
      if (/unable to open|no such file|does not exist|cannot open/i.test(msg)) {
        res.json({ depth: 0, oldest_age_seconds: 0, by_state: {} });
        return;
      }
      res.status(500).json({ error: msg });
    } finally {
      if (db) {
        try { db.close(); } catch { /* best-effort */ }
      }
    }
  });

  // POST /build/heartbeat — /build pipeline status relay.
  //
  // BUILD-STALL-VISIBILITY-SPEC Fix 2. The /build skill / build-state.py calls
  // this on phase transitions (and optionally from a server-side cadence tick)
  // so the user sees signs of life during long-running tool waits.
  //
  // Content shape is locked: enumerated phase + allowlisted tool + elapsed.
  // No free-form agent prose, no argv, no paths — the caller cannot smuggle
  // sensitive content through this endpoint. The message goes out as a proxy
  // class (isProxy: true), which bypasses the outbound tone/dedup gates on
  // purpose: there's nothing free-form to judge in an enumerated template.
  //
  // The dispatch also records the heartbeat in ProxyCoordinator so
  // PresenceProxy suppresses its generic Tier 2/3 standby for the same
  // topic within the suppression window (one progress voice per channel).
  {
    const HEARTBEAT_PHASES = new Set([
      'idle', 'clarify', 'planning', 'executing',
      'verifying', 'fixing', 'hardening', 'complete', 'failed', 'escalated',
    ]);
    const HEARTBEAT_TOOLS = new Set([
      'Monitor', 'Bash-test', 'Bash-tsc', 'Bash-install',
      'Bash-lint', 'Bash-other', 'none',
    ]);
    const HEARTBEAT_STATUSES = new Set(['still-working', 'no-progress-detected', 'phase-boundary']);
    const RUNID_RE = /^[a-zA-Z0-9_-]{1,64}$/;

    router.post('/build/heartbeat', async (req, res) => {
      const body = req.body as {
        runId?: unknown;
        phase?: unknown;
        topicId?: unknown;
        channelId?: unknown;
        tool?: unknown;
        elapsedMs?: unknown;
        status?: unknown;
      };

      const runId = typeof body.runId === 'string' ? body.runId : '';
      if (!RUNID_RE.test(runId)) {
        res.status(400).json({ error: '"runId" must match /^[a-zA-Z0-9_-]{1,64}$/' });
        return;
      }
      const phase = typeof body.phase === 'string' ? body.phase : '';
      if (!HEARTBEAT_PHASES.has(phase)) {
        res.status(400).json({ error: `"phase" must be one of: ${[...HEARTBEAT_PHASES].join(', ')}` });
        return;
      }
      const tool = typeof body.tool === 'string' ? body.tool : 'none';
      if (!HEARTBEAT_TOOLS.has(tool)) {
        res.status(400).json({ error: `"tool" must be one of: ${[...HEARTBEAT_TOOLS].join(', ')}` });
        return;
      }
      const status = typeof body.status === 'string' ? body.status : 'phase-boundary';
      if (!HEARTBEAT_STATUSES.has(status)) {
        res.status(400).json({ error: `"status" must be one of: ${[...HEARTBEAT_STATUSES].join(', ')}` });
        return;
      }
      const elapsedMs = typeof body.elapsedMs === 'number' && Number.isFinite(body.elapsedMs) && body.elapsedMs >= 0 && body.elapsedMs < 86_400_000
        ? Math.floor(body.elapsedMs)
        : 0;

      // Route by topicId (Telegram) or channelId (Slack). Exactly one must be set.
      const topicId = typeof body.topicId === 'number' && Number.isInteger(body.topicId) ? body.topicId : null;
      const channelId = typeof body.channelId === 'string' && body.channelId.length > 0 && body.channelId.length <= 128
        ? body.channelId
        : null;
      if ((topicId === null) === (channelId === null)) {
        res.status(400).json({ error: 'Exactly one of "topicId" (number) or "channelId" (string) must be provided' });
        return;
      }

      const elapsedMin = Math.floor(elapsedMs / 60_000);
      const elapsedStr = elapsedMin >= 1 ? `${elapsedMin}m` : `${Math.floor(elapsedMs / 1000)}s`;
      const text = `🔨 /build — phase=${phase}, tool=${tool}, elapsed=${elapsedStr}, status=${status}`;

      try {
        if (topicId !== null) {
          if (!ctx.telegram) {
            res.status(503).json({ error: 'Telegram not configured' });
            return;
          }
          await ctx.telegram.sendToTopic(topicId, text, { skipStallClear: true });
          ctx.proxyCoordinator?.recordBuildHeartbeat(topicId);
        } else if (channelId !== null) {
          if (!ctx.slack) {
            res.status(503).json({ error: 'Slack not configured' });
            return;
          }
          await ctx.slack.sendToChannel(channelId, text);
          // Slack uses synthetic negative topic IDs internally. §4
          // consolidation (durable-conversation-identity increment 2): the
          // inline hash copy is RETIRED — this callsite MINTS (get-or-create)
          // through the registry so PresenceProxy's Slack path sees the same
          // suppression signal, falling back to the ONE shared candidate when
          // the registry is degraded/absent (§3.6 fail-toward-delivery).
          const synthetic =
            ctx.conversationRegistry?.idForSessionKey(channelId) ?? candidateIdForRoutingKey(channelId);
          ctx.proxyCoordinator?.recordBuildHeartbeat(synthetic);
        }
        res.json({ ok: true, runId, phase, tool, status, elapsedMs });
      } catch (err) {
        res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
      }
    });
  }

  // POST /telegram/post-update — route an update/announcement message to the
  // Agent Updates topic, deterministically.
  //
  // The caller cannot specify a topic. The topic is resolved server-side from
  // `agent-updates-topic` state. This closes off an entire class of bugs where
  // agents sent update messages to whatever topic happened to spawn their
  // session (typically the most recently active Telegram topic).
  //
  // If the Updates topic is not configured, the endpoint returns 400 — never
  // a silent fallback to Attention or any other topic. Update messages MUST
  // end up in the Updates topic or not be sent at all.
  router.post('/telegram/post-update', async (req, res) => {
    if (!ctx.telegram) {
      res.status(503).json({ error: 'Telegram not configured' });
      return;
    }

    const updatesTopicId = ctx.state.get<number>('agent-updates-topic');
    if (!updatesTopicId || typeof updatesTopicId !== 'number') {
      res.status(400).json({
        error: 'Agent Updates topic is not configured',
        hint: 'The Updates topic is provisioned automatically at server startup when Telegram is configured. Check server logs for "Failed to ensure Agent Updates topic" errors. Update messages are not routed to any fallback topic by design.',
      });
      return;
    }

    const { text, metadata } = req.body;
    if (!text || typeof text !== 'string') {
      res.status(400).json({ error: '"text" field required' });
      return;
    }
    if (text.length > 4096) {
      res.status(400).json({ error: '"text" must be 4096 characters or fewer' });
      return;
    }

    const updateAllowDebugText = metadata?.allowDebugText === true;
    const updateAllowDuplicate = metadata?.allowDuplicate === true;
    if (
      await checkOutboundMessage(text, 'telegram', res, {
        topicId: updatesTopicId,
        allowDebugText: updateAllowDebugText,
        allowDuplicate: updateAllowDuplicate,
        // §Design 6 availability carve-out: post-update is an automated,
        // fixed-template channel (release/"I'm back up" notices). A slow gate
        // must NOT hold these — they fail OPEN on the budget timeout. Real
        // verdicts (a fast block) still hold; only the no-verdict-in-time path
        // delivers. (Block/allow on a returned verdict is unchanged.)
        failClosedOnBudgetTimeout: false,
      })
    )
      return;

    try {
      await ctx.telegram.sendToTopic(updatesTopicId, text);
      // Note: intentionally do NOT clear the injection tracker for the Updates
      // topic. Update posts are proactive broadcasts, not replies to a stuck
      // session — resetting stall timers here would mask real hangs elsewhere.
      res.json({ ok: true, topicId: updatesTopicId });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  router.get('/telegram/topics/:topicId/messages', (req, res) => {
    if (!ctx.telegram) {
      res.status(503).json({ error: 'Telegram not configured' });
      return;
    }

    const topicId = parseInt(req.params.topicId, 10);
    if (isNaN(topicId)) {
      res.status(400).json({ error: 'topicId must be a number' });
      return;
    }

    const limit = parseInt(req.query.limit as string, 10) || 20;
    const messages = ctx.telegram.getTopicHistory(topicId, Math.min(limit, 100));
    res.json({ topicId, messages });
  });

  // ── Message Log Search ──────────────────────────────────────────

  router.get('/telegram/search', (req, res) => {
    if (!ctx.telegram) {
      res.status(503).json({ error: 'Telegram not configured' });
      return;
    }

    const query = req.query.q as string | undefined;
    const topicId = req.query.topicId ? parseInt(req.query.topicId as string, 10) : undefined;
    const since = req.query.since ? new Date(req.query.since as string) : undefined;
    const rawLimit = parseInt(req.query.limit as string, 10) || 50;
    const limit = Math.min(Math.max(rawLimit, 1), 500);

    if (topicId !== undefined && isNaN(topicId)) {
      res.status(400).json({ error: 'topicId must be a number' });
      return;
    }
    if (since !== undefined && isNaN(since.getTime())) {
      res.status(400).json({ error: 'since must be a valid ISO date' });
      return;
    }

    const results = ctx.telegram.searchLog({ query, topicId, since, limit });
    res.json({ results, count: results.length });
  });

  router.get('/telegram/log-stats', (req, res) => {
    if (!ctx.telegram) {
      res.status(503).json({ error: 'Telegram not configured' });
      return;
    }

    res.json(ctx.telegram.getLogStats());
  });

  // ── Threadline → Telegram Bridge: settings surface ─────────────
  //
  // Read/write toggles + allow-list/deny-list that gate the bridge module
  // (deliverable b). Default-OFF auto-create is a hard requirement — these
  // endpoints are how the user opts in. Bearer-auth enforced globally.

  router.get('/threadline/telegram-bridge/config', (_req, res) => {
    if (!ctx.telegramBridgeConfig) {
      res.status(503).json({ error: 'Telegram bridge config not initialized' });
      return;
    }
    res.json(ctx.telegramBridgeConfig.getSettings());
  });

  // ── Threadline observability — read-only views over inbox/outbox/bindings ──

  // P3 (THREADLINE-CONVERSATION-COHERENCE-SPEC §3.2) — which machine holds
  // each A2A conversation. The STRUCTURAL surface for "never claim the
  // thread doesn't exist": own rows from the LIVE store; ?scope=mesh adds
  // replica-folded rows (composite (holder, conversationId) keys, staleness
  // + streamStatus honesty). 200 even when replication is dark (own rows
  // only); 503 only when the conversation store itself is absent.
  router.get('/threadline/conversations', async (req, res) => {
    if (!ctx.conversationStore) {
      res.status(503).json({ error: 'conversation store not available' });
      return;
    }
    try {
      const meshMod = await import('../threadline/ConversationMeshView.js');
      const readerMod = await import('../core/CoherenceJournalReader.js');
      const wantMesh = req.query.scope === 'mesh';
      const own = ctx.conversationStore.all();
      const view = meshMod.buildMeshConversationView({
        ownMachineId: ctx.meshSelfId ?? 'local',
        ownConversations: own,
        ...(wantMesh ? { reader: new readerMod.CoherenceJournalReader({ stateDir: ctx.config.stateDir }) } : {}),
      });
      res.json({ scope: wantMesh ? 'mesh' : 'local', conversations: view.rows, partial: view.partial });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  router.get('/threadline/observability/threads', (req, res) => {
    if (!ctx.threadlineObservability) {
      res.status(503).json({ error: 'Threadline observability not initialized' });
      return;
    }
    const remoteAgent = typeof req.query.remoteAgent === 'string' ? req.query.remoteAgent : undefined;
    const sinceIso = typeof req.query.since === 'string' ? req.query.since : undefined;
    const untilIso = typeof req.query.until === 'string' ? req.query.until : undefined;
    const hasTopicRaw = typeof req.query.hasTopic === 'string' ? req.query.hasTopic : undefined;
    const hasTopic = hasTopicRaw === 'yes' || hasTopicRaw === 'no' ? hasTopicRaw : undefined;
    const threads = ctx.threadlineObservability.listThreads({ remoteAgent, sinceIso, untilIso, hasTopic });
    res.json({ threads, count: threads.length });
  });

  router.get('/threadline/observability/threads/:threadId', (req, res) => {
    if (!ctx.threadlineObservability) {
      res.status(503).json({ error: 'Threadline observability not initialized' });
      return;
    }
    const detail = ctx.threadlineObservability.getThread(req.params.threadId);
    if (!detail) { res.status(404).json({ error: 'Thread not found' }); return; }
    // Robustness Phase 2 (E6): surface the CANONICAL log head + advisory symmetry
    // state onto the dashboard thread view, so corrected history + divergence are
    // visible to the human (the canonical log is the authoritative count, not the
    // lossy aggregate). Additive — absent when threadline/canonical-history is off.
    let canonicalHistory: unknown;
    try {
      const tid = req.params.threadId;
      if (ctx.threadLog && THREAD_ID_RE.test(tid) && ctx.threadLog.isPathConfined(tid)) {
        const head = ctx.threadLog.head(tid);
        const verify = ctx.threadLog.verify(tid);
        const conv = ctx.conversationStore?.get(tid);
        canonicalHistory = {
          count: head.count,
          headHash: head.headHash,
          setAccum: head.setAccum,
          chainOk: verify.ok,
          symmetryState: conv?.symmetryState ?? 'unknown',
          collisionCount: conv?.collisionCount ?? 0,
        };
      }
    } catch { /* @silent-fallback-ok: observability augmentation is best-effort; the base detail still returns */ }
    res.json(canonicalHistory ? { ...detail, canonicalHistory } : detail);
  });

  // ── A2A peer-health (A2A-DURABLE-DELIVERY-SPEC.md) ──────────────────────
  // "Is my channel to <peer> alive?" as a lookup, not a guess. Read-only
  // observability over the durable delivery tracker — never gates a send.
  router.get('/threadline/peers/health', (req, res) => {
    if (!ctx.a2aDeliveryTracker) {
      res.status(503).json({ error: 'A2A delivery tracker not initialized' });
      return;
    }
    const staleAfterMs = typeof req.query.staleAfterMs === 'string' && Number.isFinite(Number(req.query.staleAfterMs))
      ? Number(req.query.staleAfterMs)
      : undefined;
    const peers = ctx.a2aDeliveryTracker.allPeerHealth({ staleAfterMs });
    res.json({ peers, count: peers.length, staleCount: peers.filter((p) => p.stale).length });
  });

  router.get('/threadline/peers/:fp/health', (req, res) => {
    if (!ctx.a2aDeliveryTracker) {
      res.status(503).json({ error: 'A2A delivery tracker not initialized' });
      return;
    }
    const staleAfterMs = typeof req.query.staleAfterMs === 'string' && Number.isFinite(Number(req.query.staleAfterMs))
      ? Number(req.query.staleAfterMs)
      : undefined;
    res.json(ctx.a2aDeliveryTracker.peerHealth(req.params.fp, { staleAfterMs }));
  });

  // ── Secure A2A Verified Pairing surfaces (§3.6) ────────────────────────
  // List + detail + the PIN-gated operator verify. Ships DARK behind
  // threadline.verifiedPairing.enabled (resolved via the developmentAgent gate
  // when omitted, devAgentGate.ts) — when off, every route 503s and legacy
  // behavior is byte-identical. SAS WORDS are shown ONLY on the detail route to a
  // PIN-authed operator request while the pairing is pending-verification (§3.9);
  // they are never on the list route and never to a bearer-only request. The
  // verify route additionally REQUIRES the dashboard PIN (FD7): the agent Bearer
  // token is structurally insufficient to confirm a pairing — checkMandatePin is
  // the exact mechanism /mandate/issue uses (sha256 + timingSafeEqual + per-IP cap).
  const verifiedPairingRouteEnabled = (): boolean =>
    resolveDevAgentGate(
      (ctx.config.threadline?.verifiedPairing as { enabled?: boolean } | undefined)?.enabled,
      ctx.config as { developmentAgent?: boolean },
    );

  // Build THIS machine's local pairings list (the shape the plain + pool reads share,
  // so a peer's plain reply merges in identically). No SAS words ever.
  const buildLocalPairings = (): Array<Record<string, unknown>> => {
    const trustManager = ctx.unifiedTrust?.trustManager;
    if (!trustManager) return [];
    return trustManager
      .listProfiles()
      .filter((p) => p.pairingState !== undefined)
      .map((p) => ({
        peerFp: p.fingerprint ?? null,
        peerName: p.agent,
        state: p.pairingState,
        verifiedAt: p.verifiedAt,
        trustSource: p.source,
        peerAcked: p.peerAcked,
      }));
  };

  // Pool-scope pairing aggregation (Secure A2A Verified Pairing §3.8 — "is my channel to
  // <peer> verified?" gives ONE consistent answer regardless of fronting machine). Mirrors
  // the proven jobsPoolMerge shape: short-TTL cache, known-offline-peer skip, per-peer
  // timeout → failed marker (never a 500), shared pool-cache when wired. Single-machine ⇒
  // just the local list tagged scope:'pool'. The replicated RESULT itself flows via the
  // stateSync transport; THIS read is the cross-machine VIEW.
  const pairingPoolCache = new Map<string, { at: number; payload: unknown }>();
  const PAIRING_POOL_CACHE_TTL_MS = 3_000;
  const PAIRING_PEER_TIMEOUT_MS = 5_000;
  async function pairingPoolMerge(localPairings: Array<Record<string, unknown>>): Promise<Record<string, unknown>> {
    const cached = pairingPoolCache.get('pairing');
    if (cached && Date.now() - cached.at < PAIRING_POOL_CACHE_TTL_MS) {
      return cached.payload as Record<string, unknown>;
    }
    const selfMachineId = ctx.meshSelfId ?? null;
    const selfNickname = selfMachineId
      ? ctx.machinePoolRegistry?.getCapacity(selfMachineId)?.nickname ?? null
      : null;
    const peers = ctx.resolvePeerUrls?.() ?? [];
    const failed: Array<{ machineId: string; error: string }> = [];
    const remote: Array<Record<string, unknown>> = [];
    let poolStale = false;
    await Promise.all(
      peers.map(async (p) => {
        const cap = ctx.machinePoolRegistry?.getCapacity(p.machineId);
        if (cap && cap.online === false) {
          failed.push({ machineId: p.machineId, error: 'offline' });
          return;
        }
        try {
          const fetchPeer = async () => {
            const r = await fetch(`${p.url}/threadline/pairing`, {
              headers: { Authorization: `Bearer ${ctx.config.authToken}` },
              signal: AbortSignal.timeout(PAIRING_PEER_TIMEOUT_MS),
            });
            if (!r.ok) throw new Error(`HTTP ${r.status}`);
            return (await r.json()) as { pairings?: Array<Record<string, unknown>> };
          };
          let body: { pairings?: Array<Record<string, unknown>> };
          if (ctx.poolPollCache) {
            const res = await ctx.poolPollCache.fetchPeer(p.machineId, '/threadline/pairing', fetchPeer);
            body = res.body;
            if (res.stale) poolStale = true;
          } else {
            body = await fetchPeer();
          }
          const nickname = cap?.nickname ?? null;
          for (const pr of body.pairings ?? []) {
            remote.push({ ...pr, machineId: pr.machineId ?? p.machineId, machineNickname: pr.machineNickname ?? nickname ?? undefined, remote: true });
          }
        } catch (err) {
          failed.push({ machineId: p.machineId, error: err instanceof Error ? err.message : String(err) });
        }
      }),
    );
    const localTagged = localPairings.map((pr) => ({
      ...pr,
      machineId: pr.machineId ?? selfMachineId ?? undefined,
      machineNickname: pr.machineNickname ?? selfNickname ?? undefined,
    }));
    const pairings: Array<Record<string, unknown>> = [...localTagged, ...remote];
    const mutualVerifiedCount = pairings.filter((pr) => pr.state === 'mutual-verified' || pr.state === 'identity-verified').length;
    const payload = {
      pairings,
      mutualVerifiedCount,
      scope: 'pool',
      pool: {
        enabled: !!ctx.machinePoolRegistry,
        selfMachineId,
        peersQueried: peers.length,
        peersOk: peers.length - failed.length,
        failed,
        ...(poolStale ? { stale: true } : {}),
      },
    };
    pairingPoolCache.set('pairing', { at: Date.now(), payload });
    return payload;
  }

  // List all pairings (read-only, no SAS words ever). 503 when the feature is off.
  // `?scope=pool` merges every online machine's pairings (dark-peer-tolerant) so the
  // "is this channel verified?" answer is consistent regardless of fronting machine (§3.8).
  router.get('/threadline/pairing', async (req, res) => {
    if (!verifiedPairingRouteEnabled()) {
      res.status(503).json({ error: 'verified pairing not enabled' });
      return;
    }
    const trustManager = ctx.unifiedTrust?.trustManager;
    if (!trustManager) {
      res.status(503).json({ error: 'trust manager unavailable' });
      return;
    }
    const pairings = buildLocalPairings();
    if (req.query.scope === 'pool') {
      res.json(await pairingPoolMerge(pairings));
      return;
    }
    res.json({ pairings });
  });

  // One pairing's detail. The SAS WORDS are included ONLY while the pairing is
  // pending-verification AND the request carries a valid dashboard-PIN operator
  // auth (§3.9). Without the PIN the words are omitted (the rest is returned).
  // The PIN arrives in the request body (mirrors checkMandatePin's body.pin); a
  // GET with a JSON body is accepted by the express.json() middleware. Detection
  // of "PIN present" is non-throwing — an absent/incorrect PIN simply omits words,
  // it does not 403 the read (the read itself is bearer-gated, like the list).
  router.get('/threadline/pairing/:peerFp', (req, res) => {
    if (!verifiedPairingRouteEnabled()) {
      res.status(503).json({ error: 'verified pairing not enabled' });
      return;
    }
    const trustManager = ctx.unifiedTrust?.trustManager;
    if (!trustManager) {
      res.status(503).json({ error: 'trust manager unavailable' });
      return;
    }
    const peerFp = req.params.peerFp;
    const profile = trustManager.getProfileByFingerprint(peerFp);
    if (!profile || profile.pairingState === undefined) {
      res.status(404).json({ error: `no pairing for fingerprint "${peerFp}"` });
      return;
    }

    const detail: Record<string, unknown> = {
      peerFp: profile.fingerprint ?? peerFp,
      peerName: profile.agent,
      state: profile.pairingState,
      verifiedAt: profile.verifiedAt,
      trustSource: profile.source,
      peerAcked: profile.peerAcked,
      pairingId: profile.pairingId,
      sasFingerprint: profile.sasFingerprint,
    };

    // SAS words: pending-verification ONLY, and ONLY to a valid-PIN operator.
    // We validate the PIN WITHOUT sending a response (the detail read succeeds
    // regardless) — a non-throwing constant-time compare mirroring checkMandatePin.
    const pin = (req.body ?? {}).pin;
    const pinValid =
      !!ctx.config.dashboardPin &&
      typeof pin === 'string' &&
      pin.length > 0 &&
      (() => {
        const ha = createHash('sha256').update(pin).digest();
        const hb = createHash('sha256').update(ctx.config.dashboardPin!).digest();
        return ha.length === hb.length && timingSafeEqual(ha, hb);
      })();
    if (profile.pairingState === 'pending-verification' && pinValid) {
      const pending = trustManager.getPendingPairing(peerFp);
      if (pending) detail.sasWords = pending.sasWords;
    }

    res.json({ pairing: detail });
  });

  // Operator confirm/deny of a pairing — PIN-GATED (FD7). The local human SAS
  // comparison is the load-bearing security event; the agent Bearer token CANNOT
  // confirm. checkMandatePin is the EXACT mechanism /mandate/issue uses.
  router.post('/threadline/pairing/:peerFp/verify', (req, res) => {
    if (!verifiedPairingRouteEnabled()) {
      res.status(503).json({ error: 'verified pairing not enabled' });
      return;
    }
    if (!checkMandatePin(req, res)) return; // FD7 — PIN required (response already sent)

    const trustManager = ctx.unifiedTrust?.trustManager;
    if (!trustManager) {
      res.status(503).json({ error: 'trust manager unavailable' });
      return;
    }
    const peerFp = req.params.peerFp;
    const body = req.body ?? {};
    if (typeof body.match !== 'boolean') {
      res.status(400).json({ error: 'match (boolean) is required' });
      return;
    }

    const profile = trustManager.getProfileByFingerprint(peerFp);
    if (!profile || profile.pairingState === undefined) {
      res.status(404).json({ error: `no pairing for fingerprint "${peerFp}"` });
      return;
    }

    if (body.match === false) {
      const ok = trustManager.markVerificationFailed(
        peerFp,
        'Operator-asserted SAS mismatch (POST /threadline/pairing/:peerFp/verify)',
      );
      if (!ok) {
        res.status(409).json({ error: 'could not mark verification-failed for this pairing' });
        return;
      }
      // §3.2 / §3.7 — an operator-asserted SAS mismatch is a potential MITM and must
      // raise ONE HIGH attention item, deduped per (peerFp) episode, NEVER coalesced
      // (a re-attempt LOOP — repeated handshake-then-mismatch — collapses onto the SAME
      // item by its stable per-peerFp id rather than spawning one topic per attempt).
      // HIGH priority is itself never coalesced by the AttentionTopicGuard, so the
      // flood-guard chokepoint enforces the burst invariant for free. Best-effort —
      // a notification failure never breaks the local trust write (which already landed).
      void ctx.telegram?.createAttentionItem?.({
        id: `threadline-pairing-verification-failed:${peerFp}`,
        title: 'Threadline pairing verification FAILED — possible MITM',
        summary: `The SAS for peer ${peerFp.slice(0, 12)}… was asserted NOT to match. The peer was forced to untrusted and credential-share revoked. Re-handshake before retrying.`,
        category: 'general',
        priority: 'HIGH',
        sourceContext: 'threadline-verified-pairing',
      });
      res.json({ ok: true, peerFp, state: 'verification-failed' });
      return;
    }

    // match === true → confirm. Bind to the CURRENT pairingId from the pending
    // record (epoch binding, FD4). markMutualVerified is the SOLE writer of the
    // mutual-verified source (§3.3) and re-verifies the operator-confirm precondition.
    const pending = trustManager.getPendingPairing(peerFp);
    const pairingId = pending?.pairingId ?? profile.pairingId;
    if (!pairingId) {
      res.status(409).json({ error: 'no current pairingId for this pairing — re-handshake required' });
      return;
    }
    const ok = trustManager.markMutualVerified(peerFp, {
      pairingId,
      operatorConfirm: true,
      peerAcked: profile.peerAcked,
    });
    if (!ok) {
      res.status(409).json({ error: 'could not confirm pairing (state/epoch mismatch or not pending) — re-handshake required' });
      return;
    }
    res.json({ ok: true, peerFp, state: 'mutual-verified' });
  });

  // ── Negotiator lease state (Robustness Phase 1, FD-9) ──────────────────
  // "Which session owns each conversation's voice?" — bearer-gated, paginated,
  // own-data-only. Returns this agent's lease per active conversation (holder +
  // epoch + expiry) plus dry-run would-hold / hold / CAS-retry / fail-open counts.
  router.get('/threadline/negotiator', (req, res) => {
    // Bearer-gated (defense in depth — own lease/voice state is agent-private).
    if (ctx.config.authToken) {
      const header = req.headers.authorization;
      if (!header?.startsWith('Bearer ') || header.slice(7) !== ctx.config.authToken) {
        res.status(401).json({ error: 'Unauthorized' });
        return;
      }
    }
    if (!ctx.conversationStore) {
      res.status(503).json({ error: 'conversation store not available' });
      return;
    }
    try {
      const rawCfg = (ctx.config as { threadline?: { singleNegotiator?: unknown } }).threadline?.singleNegotiator;
      const cfg = resolveSingleNegotiatorConfig(rawCfg, ctx.config as { developmentAgent?: boolean });
      // Paginate by threadId (stable order). Default 100, `after` cursor.
      const limitRaw = typeof req.query.limit === 'string' ? parseInt(req.query.limit, 10) : 100;
      const limit = Number.isFinite(limitRaw) && limitRaw > 0 ? Math.min(limitRaw, 500) : 100;
      const after = typeof req.query.after === 'string' ? req.query.after : undefined;

      const all = ctx.conversationStore.all()
        .filter((c) => c.negotiatorLease)
        .sort((a, b) => (a.threadId < b.threadId ? -1 : a.threadId > b.threadId ? 1 : 0));
      const startIdx = after ? all.findIndex((c) => c.threadId === after) + 1 : 0;
      const page = all.slice(startIdx, startIdx + limit);
      const nextCursor = startIdx + limit < all.length ? page[page.length - 1]?.threadId : null;

      const leases = page.map((c) => ({
        threadId: c.threadId,
        owner: c.negotiatorLease!.ownerSessionName,
        ownerMachineId: c.negotiatorLease!.ownerMachineId,
        epoch: c.negotiatorLease!.epoch,
        expiresAt: c.negotiatorLease!.expiresAt,
        lastHoldingNoticeEpoch: c.lastHoldingNoticeEpoch ?? null,
        lastHoldingNoticeAt: c.lastHoldingNoticeAt ?? null,
      }));

      const counts = readNegotiatorCounts(negotiatorLogDir(ctx.config.stateDir), cfg.dryRunRetentionDays);
      res.json({
        enabled: cfg.enabled,
        dryRun: cfg.dryRun,
        leaseTtlMs: cfg.leaseTtlMs,
        machineId: ctx.meshSelfId ?? (ctx.config as { machineId?: string }).machineId ?? 'local',
        leases,
        counts,
        total: all.length,
        nextCursor: nextCursor ?? null,
      });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  router.get('/threadline/observability/search', (req, res) => {
    if (!ctx.threadlineObservability) {
      res.status(503).json({ error: 'Threadline observability not initialized' });
      return;
    }
    const q = typeof req.query.q === 'string' ? req.query.q : '';
    const limitRaw = typeof req.query.limit === 'string' ? parseInt(req.query.limit, 10) : 50;
    const limit = Number.isFinite(limitRaw) && limitRaw > 0 ? Math.min(limitRaw, 200) : 50;
    const hits = ctx.threadlineObservability.searchMessages(q, limit);
    res.json({ hits, count: hits.length });
  });

  router.patch('/threadline/telegram-bridge/config', (req, res) => {
    if (!ctx.telegramBridgeConfig) {
      res.status(503).json({ error: 'Telegram bridge config not initialized' });
      return;
    }
    try {
      const body = req.body as {
        enabled?: unknown;
        autoCreateTopics?: unknown;
        mirrorExisting?: unknown;
        allowList?: unknown;
        denyList?: unknown;
      };
      const patch: Record<string, unknown> = {};
      if ('enabled' in body) patch.enabled = body.enabled;
      if ('autoCreateTopics' in body) patch.autoCreateTopics = body.autoCreateTopics;
      if ('mirrorExisting' in body) patch.mirrorExisting = body.mirrorExisting;
      if ('allowList' in body) patch.allowList = body.allowList;
      if ('denyList' in body) patch.denyList = body.denyList;
      const settings = ctx.telegramBridgeConfig.update(patch);
      res.json(settings);
    } catch (err) {
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // ── Slack ──────────────────────────────────────────────────────

  router.post('/slack/reply/:channelId', async (req, res) => {
    if (!ctx.slack) {
      res.status(503).json({ error: 'Slack not configured' });
      return;
    }

    const { channelId } = req.params;
    const { text, thread_ts, metadata } = req.body;
    if (!text || typeof text !== 'string') {
      res.status(400).json({ error: '"text" field required' });
      return;
    }

    if (
      await checkOutboundMessage(text, 'slack', res, {
        allowDebugText: metadata?.allowDebugText === true,
        allowDuplicate: metadata?.allowDuplicate === true,
        // Kind threading mirrors /telegram/reply — the jargon/filePath signal
        // computation is single-sourced inside evaluateOutbound, so every
        // channel gets it uniformly (spec outbound-jargon-filepath-gap §2.2).
        messageKind: coerceMessageKind(metadata?.messageKind),
      })
    )
      return;

    try {
      // Per-call formatter opt-out (roadmap 0.1): a caller that already
      // authors Slack mrkdwn passes metadata.formatMode 'legacy-passthrough'
      // so the GFM->mrkdwn converter does not re-process its bytes.
      const requestedFormatMode = metadata?.formatMode;
      const formatMode =
        requestedFormatMode === 'legacy-passthrough' || requestedFormatMode === 'mrkdwn'
          ? requestedFormatMode
          : undefined;
      const ts = await ctx.slack.sendToChannel(channelId, text, { thread_ts, formatMode });

      // Notify onMessageLogged that the agent responded (so PresenceProxy cancels standby)
      if (ctx.slack.onMessageLogged) {
        ctx.slack.onMessageLogged({
          messageId: ts,
          channelId,
          text,
          fromUser: false,
          timestamp: new Date().toISOString(),
          sessionName: null,
          platform: 'slack',
        });
      }

      // Track for promise detection (detect "give me a minute" patterns).
      // Thread→session (§5.3): when this reply targets a thread, the session is
      // registered on the thread routing key — resolve it so promise tracking finds
      // the right session. Falls back to the channel key (today's behavior).
      if (ctx.slack.trackPromise) {
        const routingKey = thread_ts
          ? ctx.slack.resolveRoutingKey(channelId, thread_ts as string)
          : channelId;
        const sessionName = ctx.slack.getSessionForChannel(routingKey)
          ?? ctx.slack.getSessionForChannel(channelId);
        if (sessionName) {
          ctx.slack.trackPromise(channelId, sessionName, text);
        }
      }

      res.json({ ok: true, topicId: channelId, ts });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  router.post('/internal/slack-forward', async (req, res) => {
    if (!ctx.slack) {
      res.status(503).json({ error: 'Slack not configured' });
      return;
    }

    const { channelId, text } = req.body;
    if (!channelId || !text) {
      res.status(400).json({ error: '"channelId" and "text" fields required' });
      return;
    }

    try {
      await ctx.slack.sendToChannel(channelId, text);
      res.json({ ok: true });
    } catch (err) {
      res.status(500).json({ error: (err as Error).message });
    }
  });

  router.get('/slack/channels', async (req, res) => {
    if (!ctx.slack) {
      res.status(503).json({ error: 'Slack not configured' });
      return;
    }

    try {
      const channels = await ctx.slack.api.call('conversations.list', {
        types: 'public_channel,private_channel',
        exclude_archived: req.query.include_archived !== 'true',
        limit: 200,
      });
      res.json({ ok: true, channels: channels.channels ?? [] });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  router.post('/slack/channels', async (req, res) => {
    if (!ctx.slack) {
      res.status(503).json({ error: 'Slack not configured' });
      return;
    }

    const { name, is_private } = req.body;
    if (!name || typeof name !== 'string') {
      res.status(400).json({ error: '"name" field required' });
      return;
    }

    try {
      const channelId = await ctx.slack.createChannel(name, is_private);
      res.json({ ok: true, channelId });
    } catch (err) {
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  router.get('/slack/channels/:channelId/messages', (req, res) => {
    if (!ctx.slack) {
      res.status(503).json({ error: 'Slack not configured' });
      return;
    }

    const { channelId } = req.params;
    const limit = Math.min(parseInt(req.query.limit as string, 10) || 30, 100);

    const messages = ctx.slack.getChannelMessages(channelId, limit);
    res.json({ ok: true, messages, count: messages.length });
  });

  router.get('/slack/search', (req, res) => {
    if (!ctx.slack) {
      res.status(503).json({ error: 'Slack not configured' });
      return;
    }

    const query = req.query.q as string | undefined;
    const channelId = req.query.channelId as string | undefined;
    const since = req.query.since ? new Date(req.query.since as string) : undefined;
    const rawLimit = parseInt(req.query.limit as string, 10) || 50;
    const limit = Math.min(Math.max(rawLimit, 1), 500);

    const results = ctx.slack.searchLog({ query, channelId, since, limit });
    res.json({ results, count: results.length });
  });

  router.get('/slack/log-stats', (req, res) => {
    if (!ctx.slack) {
      res.status(503).json({ error: 'Slack not configured' });
      return;
    }

    res.json(ctx.slack.getLogStats());
  });

  // ── Attention Queue ─────────────────────────────────────────────

  router.post('/attention', async (req, res) => {
    if (!ctx.telegram) {
      res.status(503).json({ error: 'Telegram not configured' });
      return;
    }

    const { id, title, category, description } = req.body;
    const summary = typeof req.body.summary === 'string' ? req.body.summary : req.body.body;
    const sourceContext = typeof req.body.sourceContext === 'string' ? req.body.sourceContext : req.body.source;
    const priority = normalizeAttentionPriority(req.body.priority);
    // Agent-Health lane: a routine self-health notice routed into the ONE calm
    // "🩺 Agent Health" topic (never a per-item topic). Opt-in via lane.
    const lane = req.body.lane === 'agent-health' ? 'agent-health' as const : undefined;
    const healthKey = typeof req.body.healthKey === 'string' && req.body.healthKey ? req.body.healthKey : undefined;
    if (!id || typeof id !== 'string' || id.length > 200) {
      res.status(400).json({ error: '"id" must be a string under 200 characters' });
      return;
    }
    if (!title || typeof title !== 'string' || title.length > 500) {
      res.status(400).json({ error: '"title" must be a string under 500 characters' });
      return;
    }
    if (!summary || typeof summary !== 'string' || summary.length > 2000) {
      res.status(400).json({ error: '"summary" must be a string under 2000 characters' });
      return;
    }
    if (!priority) {
      res.status(400).json({ error: `"priority" must be one of: ${ATTENTION_PRIORITIES.join(', ')} (aliases: urgent, high, medium, normal, low)` });
      return;
    }

    // Standby-write reconciliation §3.4 (I1/I3): the P2-6 route — admission is
    // the FIRST await-free statement after body validation, BEFORE the tone
    // gate below (a refused POST /attention has created no topic, persisted no
    // item, spent no LLM tokens). Runs first in EVERY mode (§9.15); while dry
    // the verdict is log-only and the route proceeds into today's exact flow,
    // tone gate included.
    if (refuseInadmissibleWrite(req, res)) return;

    // Attention items reach the user as a new Telegram topic with the title,
    // summary, and (optional) description as the body. Run that user-facing
    // candidate through the outbound-message authority before creating the
    // topic. For health-class categories ("degradation", "health"), invoke
    // the health-alert ruleset (B12/B13/B14) so jargon-laden, no-CTA, and
    // self-healed-event messages get suppressed instead of spawning topics.
    const isHealthAlert = typeof category === 'string' && /^(degradation|health|health-alert|alert)$/i.test(category);
    const candidate = [title, summary, description].filter((s): s is string => typeof s === 'string' && s.length > 0).join('\n\n');
    // Agent-Health-lane notices do NOT spawn a per-item topic — they land in the
    // ONE opt-in calm lane and are already named + next-step-bearing by
    // construction, so they bypass the per-topic outbound gate (which exists to
    // suppress jargon/no-CTA topic spawns). Skipping it here prevents a
    // well-formed lane heads-up from being silently 422'd and never delivered.
    if (!lane) {
      const blocked = await checkOutboundMessage(candidate, 'telegram', res, {
        messageKind: isHealthAlert ? 'health-alert' : 'reply',
        // jargon arg dropped — the kind decides: evaluateOutbound now computes
        // the jargon signal itself for health-alert/automated kinds (§2.2).
        // No topicId — attention items create new topics; no prior thread context applies.
      });
      if (blocked) {
        // checkOutboundMessage already wrote the 422 response.
        return;
      }
    }

    // CMT-519 — structural guard: threadline/agent-messaging-class attention
    // items must NOT spawn a per-event Telegram topic (the "wall of topics").
    // Redirect them through the SILENT Threadline hub (parent-or-hub routing).
    // This makes the no-per-event-topic property structural — even an agent
    // ad-hoc-posting a threadline alert can't regress into topic spam.
    const threadlineClass =
      /^(threadline|inter-agent|relay|spawn)/i.test(String(category || '')) ||
      /\bthreadline\b|inter[- ]agent|spawn[- ]?storm|spawn to (receive|RECEIVE)|cannot spawn/i.test(candidate);
    if (threadlineClass && ctx.collaborationSurfacer) {
      const relatedThreadId =
        (typeof req.body?.threadId === 'string' && req.body.threadId) ||
        (typeof req.body?.relatedThreadId === 'string' && req.body.relatedThreadId) ||
        `attn-${id}`;
      const r = await ctx.collaborationSurfacer.notify({
        threadId: relatedThreadId,
        title: title || 'Threadline activity',
        body: summary || description || title || '',
      });
      res.status(201).json({ redirected: 'threadline-hub', surfaced: r.surfaced, topicId: r.topicId });
      return;
    }

    try {
      const item = await ctx.telegram.createAttentionItem({
        id,
        title,
        summary,
        category: category || 'general',
        priority,
        description: description || undefined,
        sourceContext: sourceContext || undefined,
        lane,
        healthKey,
      });
      res.status(201).json(item);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // ── WS4.1 pool-scope merge helpers ───────────────────────────────────
  // Short-TTL cache keyed by status, so repeated dashboard polls within the
  // window reuse one fan-out instead of re-querying every peer per request.
  const attentionPoolCache = new Map<string, { at: number; payload: unknown }>();
  const ATTENTION_POOL_CACHE_TTL_MS = 3_000;
  const ATTENTION_PEER_TIMEOUT_MS = 5_000;

  // WS4.1 follow-up (CMT-1416): durable operator-bound /ack across machines.
  // DEV-AGENT DARK GATE (operator directive 2026-06-13, topic 13481): read
  // ws41DurableAck through resolveDevAgentGate so it resolves LIVE on a dev agent
  // (config OMITS it → undefined → !!developmentAgent) / DARK on the fleet. An
  // explicit config value still wins. Off ⇒ POST /attention/:id/remote-ack 503s,
  // the PATCH precedence guard is inert, and the store is never touched (strict
  // no-op); single-machine agents are a no-op even live (no peers to route to).
  const ws41DurableAckEnabled = (): boolean =>
    resolveDevAgentGate(
      ((ctx.config as Record<string, any>).multiMachine?.seamlessness ?? {}).ws41DurableAck,
      ctx.config,
    );
  const remoteAckStore = new RemoteAckStore(ctx.config.stateDir);
  const remoteAckLimiter = rateLimiter(60_000, 30);
  const REMOTE_ACK_GIVE_UP_ATTEMPTS = 50;

  // Best-effort delivery of one pending ack intent to its owning machine via the
  // peer's existing PATCH /attention/:id (carrying the X-Instar-Remote-Ack
  // annotation so the owner runs its precedence guard). Returns the terminal
  // disposition; 'queued' means the owner is still unreachable (keep the intent).
  async function deliverRemoteAck(
    intent: { itemId: string; targetMachineId: string; status: string; operatorUid: string; operatorDisplayName?: string },
  ): Promise<'delivered' | 'stale-superseded' | 'queued'> {
    const machine = (ctx.listPoolMachines?.() ?? []).find((m) => m.machineId === intent.targetMachineId);
    if (!machine || !machine.lastKnownUrl) return 'queued';
    const extraAllowlist = (ctx.config.multiMachine as { peerUrlAllowlist?: string[] } | undefined)?.peerUrlAllowlist;
    if (!isPeerUrlAllowedForCredentials(machine.lastKnownUrl, extraAllowlist).ok) return 'queued';
    try {
      const r = await fetch(`${machine.lastKnownUrl}/attention/${encodeURIComponent(intent.itemId)}`, {
        method: 'PATCH',
        headers: {
          Authorization: `Bearer ${ctx.config.authToken}`,
          'Content-Type': 'application/json',
          'X-Instar-Remote-Ack': intent.operatorUid || 'operator',
        },
        body: JSON.stringify({ status: intent.status }),
        signal: AbortSignal.timeout(ATTENTION_PEER_TIMEOUT_MS),
      });
      if (r.ok) return 'delivered';
      // 425 = the owner's precedence guard rejected a stale resolve (item since
      // escalated). 404 = item already gone on the owner. Both are TERMINAL —
      // drop the intent; retrying can never succeed.
      if (r.status === 425 || r.status === 404) return 'stale-superseded';
      return 'queued';
    } catch {
      // @silent-fallback-ok — unreachable owner (timeout/offline) keeps the
      // intent durable for the next drain; never a thrown error in the ack path.
      return 'queued';
    }
  }

  // Drain every still-pending intent (called on the route's enqueue path AND on
  // a peer-online signal). Gives up loudly past the attempt cap so a permanently
  // unreachable owner doesn't leave an intent retrying forever.
  async function drainRemoteAcks(): Promise<{ delivered: number; dropped: number; pending: number }> {
    if (!ws41DurableAckEnabled()) return { delivered: 0, dropped: 0, pending: 0 };
    let delivered = 0;
    let dropped = 0;
    for (const intent of remoteAckStore.list()) {
      if (intent.attempts >= REMOTE_ACK_GIVE_UP_ATTEMPTS) {
        remoteAckStore.resolve(intent.itemId, intent.targetMachineId);
        dropped += 1;
        continue;
      }
      const disposition = await deliverRemoteAck(intent);
      if (disposition === 'delivered') {
        remoteAckStore.resolve(intent.itemId, intent.targetMachineId);
        delivered += 1;
      } else if (disposition === 'stale-superseded') {
        remoteAckStore.resolve(intent.itemId, intent.targetMachineId);
        dropped += 1;
      } else {
        remoteAckStore.recordAttempt(intent.itemId, intent.targetMachineId, 'unreachable');
      }
    }
    return { delivered, dropped, pending: remoteAckStore.size };
  }
  // P17 coalesce key: items sharing this key across machines collapse to ONE
  // merged row (a pool-wide event whose per-machine tripwires each raised an
  // item). Mirrors the WS3.3 episode-key pattern: prefer an explicit
  // sourceContext (the deduped escalation source), else category+title.
  const attentionCoalesceKey = (it: { sourceContext?: string; category?: string; title?: string }): string =>
    it.sourceContext && it.sourceContext.length > 0
      ? `src:${it.sourceContext}`
      : `ct:${it.category ?? ''}:${it.title ?? ''}`;

  async function attentionPoolMerge(
    localItems: Array<Record<string, unknown>>,
    status: string | undefined,
  ): Promise<Record<string, unknown>> {
    const cacheKey = status ?? '*';
    const cached = attentionPoolCache.get(cacheKey);
    if (cached && Date.now() - cached.at < ATTENTION_POOL_CACHE_TTL_MS) {
      return cached.payload as Record<string, unknown>;
    }

    const peers = ctx.resolvePeerUrls?.() ?? [];
    const failed: Array<{ machineId: string; error: string }> = [];
    const remote: Array<Record<string, unknown>> = [];
    await Promise.all(
      peers.map(async (p) => {
        // Skip a peer the registry knows to be offline — saves the timeout
        // wait; an unknown peer (no capacity row) is still tried.
        const cap = ctx.machinePoolRegistry?.getCapacity(p.machineId);
        if (cap && cap.online === false) {
          failed.push({ machineId: p.machineId, error: 'offline' });
          return;
        }
        try {
          const qs = status ? `?status=${encodeURIComponent(status)}` : '';
          const r = await fetch(`${p.url}/attention${qs}`, {
            headers: { Authorization: `Bearer ${ctx.config.authToken}` },
            signal: AbortSignal.timeout(ATTENTION_PEER_TIMEOUT_MS),
          });
          if (!r.ok) throw new Error(`HTTP ${r.status}`);
          const body = (await r.json()) as { items?: Array<Record<string, unknown>> };
          const nickname = cap?.nickname ?? null;
          for (const it of body.items ?? []) {
            remote.push({
              ...it,
              machineId: it.machineId ?? p.machineId,
              machineNickname: it.machineNickname ?? nickname ?? undefined,
              remote: true,
            });
          }
        } catch (err) {
          failed.push({ machineId: p.machineId, error: err instanceof Error ? err.message : String(err) });
        }
      }),
    );

    // P17 merge-point coalesce: collapse same-key items across machines into
    // ONE row carrying the contributing machine list. Local items win the
    // canonical row (the operator's own machine view); remote duplicates fold
    // into coalescedFrom. HIGH/URGENT are NEVER coalesced (every critical item
    // stays individually visible — same rule as the write-side flood guard).
    const byKey = new Map<string, Record<string, unknown>>();
    const out: Array<Record<string, unknown>> = [];
    for (const it of [...localItems, ...remote]) {
      const priority = String(it.priority ?? 'NORMAL');
      if (priority === 'HIGH' || priority === 'URGENT') {
        out.push(it);
        continue;
      }
      const key = attentionCoalesceKey(it as { sourceContext?: string; category?: string; title?: string });
      const existing = byKey.get(key);
      if (!existing) {
        const row = { ...it, coalescedFrom: [it.machineId] };
        byKey.set(key, row);
        out.push(row);
      } else {
        (existing.coalescedFrom as unknown[]).push(it.machineId);
      }
    }

    const payload = {
      items: out,
      count: out.length,
      pool: {
        enabled: !!ctx.machinePoolRegistry,
        selfMachineId: ctx.meshSelfId ?? null,
        peersQueried: peers.length,
        peersOk: peers.length - failed.length,
        failed,
      },
    };
    attentionPoolCache.set(cacheKey, { at: Date.now(), payload });
    return payload;
  }

  router.get('/attention', async (req, res) => {
    if (!ctx.telegram) {
      res.status(503).json({ error: 'Telegram not configured' });
      return;
    }

    const requestedStatus = req.query.status as string | undefined;
    const status = requestedStatus ? (normalizeAttentionStatus(requestedStatus) ?? requestedStatus) : undefined;
    const selfMachineId = ctx.meshSelfId ?? null;
    // Local items are stamped with THIS machine's id at read time (mirrors the
    // sessions?scope=pool precedent — the store stays machine-agnostic; the
    // route is where the machine view is composed). machineNickname resolved
    // from the registry when wired.
    const selfNickname = selfMachineId
      ? ctx.machinePoolRegistry?.getCapacity(selfMachineId)?.nickname ?? undefined
      : undefined;
    const localItems = ctx.telegram.getAttentionItems(status).map((it) => ({
      ...it,
      machineId: it.machineId ?? selfMachineId ?? undefined,
      machineNickname: selfNickname,
    }));

    // scope=pool (WS4.1, MULTI-MACHINE-SEAMLESSNESS-SPEC §WS4.1): merge every
    // ONLINE peer's attention items so the dashboard shows one queue across the
    // whole pool. Tolerant by design (per-peer timeout → a `failed` marker,
    // never a 500), short-TTL cached so dashboard polling doesn't re-fan-out
    // per request, and P17-coalesced at the merge point: N machines raising the
    // SAME episode (same coalesce key) present as ONE row (the read-side bound;
    // per-machine budgets remain the write-side bound). Plain GET stays a
    // back-compatible object.
    if (req.query.scope === 'pool') {
      // WS4.1 follow-up: opportunistically drain any pending durable remote-acks
      // — the pool read is exactly when a previously-dark owner is likely back
      // online (the dashboard polls this). Fire-and-forget; never blocks the read.
      if (ws41DurableAckEnabled() && remoteAckStore.size > 0) {
        void drainRemoteAcks().catch(() => {
          /* @silent-fallback-ok — drain is best-effort; failures keep intents durable */
        });
      }
      const merged = await attentionPoolMerge(localItems, status);
      res.json(merged);
      return;
    }

    res.json({ items: localItems, count: localItems.length });
  });

  router.get('/attention/:id', (req, res) => {
    if (!ctx.telegram) {
      res.status(503).json({ error: 'Telegram not configured' });
      return;
    }

    const item = ctx.telegram.getAttentionItem(req.params.id);
    if (!item) {
      res.status(404).json({ error: 'Attention item not found' });
      return;
    }
    res.json(item);
  });

  router.patch('/attention/:id', async (req, res) => {
    if (!ctx.telegram) {
      res.status(503).json({ error: 'Telegram not configured' });
      return;
    }

    const status = normalizeAttentionStatus(req.body.status);
    if (!status) {
      res.status(400).json({ error: `"status" must be one of: ${ATTENTION_STATUSES.join(', ')} (aliases: resolved, done, ack, in_progress, wontdo, reopen)` });
      return;
    }

    // Standby-write reconciliation §3.4 (I1): admission first after validation.
    if (refuseInadmissibleWrite(req, res)) return;

    // WS4.1 follow-up (CMT-1416) receiver-side precedence guard. When a PATCH
    // arrives carrying X-Instar-Remote-Ack (a relayed operator ack from a peer,
    // possibly enqueued while THIS machine was offline), the OWNER's CURRENT
    // item state wins: a stale resolve against an item that has SINCE escalated
    // to HIGH/URGENT is rejected (and surfaced) rather than silently applied.
    // Gated on ws41DurableAck — off ⇒ this whole block is inert (the header is
    // ignored and the PATCH behaves exactly as before). The header is only an
    // ANNOTATION; the Bearer auth (already enforced upstream) is the authority.
    if (req.get('X-Instar-Remote-Ack') && ws41DurableAckEnabled()) {
      const current = ctx.telegram.getAttentionItem(req.params.id);
      if (!current) {
        res.status(404).json({ error: 'Attention item not found' });
        return;
      }
      const currentPriority = String(current.priority ?? 'NORMAL');
      const downgrades = status === 'DONE' || status === 'WONT_DO' || status === 'ACKNOWLEDGED';
      if ((currentPriority === 'HIGH' || currentPriority === 'URGENT') && downgrades) {
        // Reconcile precedence: never auto-resolve a since-escalated critical
        // item via a stale relayed ack. Surfaced to the relayer (425) so the
        // RemoteAckStore drops the stale intent rather than retrying forever.
        res.status(425).json({
          error: 'stale-superseded',
          reason: `item has escalated to ${currentPriority} since the ack was issued — current state wins`,
          itemId: req.params.id,
          currentPriority,
        });
        return;
      }
    }

    const success = await ctx.telegram.updateAttentionStatus(req.params.id, status);
    if (!success) {
      res.status(404).json({ error: 'Attention item not found' });
      return;
    }

    const item = ctx.telegram.getAttentionItem(req.params.id);
    res.json(item);
  });

  // WS4.1 follow-up (CMT-1416): durable operator-bound /ack for an attention
  // item OWNED BY ANOTHER MACHINE. The dashboard sends this when the operator
  // acks a pooled (remote) item; the ack is delivered to the owner immediately
  // when reachable, else persisted (with the authenticated operator principal)
  // and re-delivered when the owner returns — so the operator's intent survives
  // a briefly-dark owner instead of evaporating. Bearer auth (already enforced)
  // is the operator authority; the topicId resolves the bound operator uid for
  // the owner's revalidation. Mutating mesh verb → rate-limited like remote-close.
  router.post('/attention/:id/remote-ack', remoteAckLimiter, async (req, res) => {
    if (!ws41DurableAckEnabled()) {
      res.status(503).json({ error: 'WS4.1 durable remote-ack is disabled (multiMachine.seamlessness.ws41DurableAck)' });
      return;
    }
    const { machineId, status: rawStatus, topicId } = (req.body ?? {}) as {
      machineId?: unknown;
      status?: unknown;
      topicId?: unknown;
    };
    // machineId is a registry LOOKUP KEY ONLY — charset-clamped, never a URL.
    if (typeof machineId !== 'string' || !/^[A-Za-z0-9_-]{1,64}$/.test(machineId)) {
      res.status(400).json({ error: 'machineId required (the owning machine)' });
      return;
    }
    const status = normalizeAttentionStatus(rawStatus);
    if (!status) {
      res.status(400).json({ error: `"status" must be one of: ${ATTENTION_STATUSES.join(', ')}` });
      return;
    }
    // Self-ack is a plain local PATCH — refuse the mesh verb for own items so a
    // single-machine agent (or an item that lives here) never round-trips.
    if (ctx.meshSelfId && machineId === ctx.meshSelfId) {
      res.status(400).json({ error: 'item is owned by this machine — use PATCH /attention/:id' });
      return;
    }
    // Bind the authenticated operator principal from the topic-operator store
    // when a topicId is supplied (the same VERIFIED-binding source as Operator
    // Binding — never a name from content). Absent/unresolvable → 'operator'.
    let operatorUid = 'operator';
    let operatorDisplayName: string | undefined;
    if (typeof topicId === 'number' || (typeof topicId === 'string' && topicId.trim())) {
      const op = ctx.topicOperatorStore?.asVerifiedOperator(topicId as number | string);
      if (op) {
        operatorUid = op.uid;
        operatorDisplayName = op.names?.[0];
      }
    }
    const intent = { itemId: req.params.id, targetMachineId: machineId, status, operatorUid, operatorDisplayName };
    // Try immediate delivery; on success no durable row is needed.
    const disposition = await deliverRemoteAck(intent);
    if (disposition === 'delivered') {
      res.json({ ok: true, delivered: true, itemId: req.params.id, machineId });
      return;
    }
    if (disposition === 'stale-superseded') {
      res.status(409).json({ ok: false, staleSuperseded: true, itemId: req.params.id, machineId, reason: 'owner rejected — item has since escalated; current state wins' });
      return;
    }
    // Owner unreachable: persist the intent durably and report it queued.
    remoteAckStore.enqueue(intent);
    res.json({ ok: true, queued: true, itemId: req.params.id, machineId, reason: 'owner unreachable — ack persisted and will be delivered when it returns', pending: remoteAckStore.size });
  });

  // Pending durable remote-acks (observability + a manual drain trigger). Two
  // segments past /attention so it never collides with GET /attention/:id.
  router.get('/attention/_remote-ack/pending', (_req, res) => {
    if (!ws41DurableAckEnabled()) {
      res.status(503).json({ error: 'WS4.1 durable remote-ack is disabled (multiMachine.seamlessness.ws41DurableAck)' });
      return;
    }
    res.json({ pending: remoteAckStore.list(), count: remoteAckStore.size });
  });

  router.post('/attention/_remote-ack/drain', async (_req, res) => {
    if (!ws41DurableAckEnabled()) {
      res.status(503).json({ error: 'WS4.1 durable remote-ack is disabled (multiMachine.seamlessness.ws41DurableAck)' });
      return;
    }
    const result = await drainRemoteAcks();
    res.json({ ok: true, ...result });
  });

  router.delete('/attention/:id', async (req, res) => {
    if (!ctx.telegram) {
      res.status(503).json({ error: 'Telegram not configured' });
      return;
    }

    const item = ctx.telegram.getAttentionItem(req.params.id);
    if (!item) {
      res.status(404).json({ error: 'Attention item not found' });
      return;
    }

    // Soft-delete: mark as DONE
    await ctx.telegram.updateAttentionStatus(req.params.id, 'DONE');

    // Security log
    try {
      const securityEntry = JSON.stringify({
        timestamp: new Date().toISOString(),
        action: 'attention-dismiss',
        itemId: req.params.id,
        source: 'dashboard',
        ip: req.ip,
      });
      fs.appendFileSync(path.join(ctx.config.stateDir, 'security.jsonl'), securityEntry + '\n');
    } catch {
      // Security logging failure is non-fatal
    }

    res.json({ id: req.params.id, deleted: true });
  });

  // ── Initiatives (multi-phase long-running work tracker) ─────────

  const initiativeIdRe = /^[a-z0-9][a-z0-9-]{0,62}$/;

  router.get('/initiatives', (req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    const status = typeof req.query.status === 'string' ? req.query.status : undefined;
    // Phase 1b PR 5 — server-side filters added so the dashboard
    // Initiatives tab can hide project-kind records (rendered in the
    // separate Projects tab) and any record that's a child of a
    // project (rendered inside its parent's card).
    const excludeKind = typeof req.query.excludeKind === 'string' ? req.query.excludeKind : undefined;
    const excludeParented = req.query.excludeParented === 'true';
    let items = status
      ? ctx.initiativeTracker.list({ status: status as 'active' | 'completed' | 'archived' | 'abandoned' })
      : ctx.initiativeTracker.list();
    if (excludeKind) {
      items = items.filter((i) => (i.kind ?? 'task') !== excludeKind);
    }
    if (excludeParented) {
      items = items.filter((i) => !i.parentProjectId);
    }
    res.json({ items, count: items.length });
  });

  router.get('/initiatives/digest', (_req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    res.json(ctx.initiativeTracker.digest());
  });

  router.get('/initiatives/:id', (req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    if (!initiativeIdRe.test(req.params.id)) {
      res.status(400).json({ error: 'invalid initiative id' });
      return;
    }
    const initiative = ctx.initiativeTracker.get(req.params.id);
    if (!initiative) {
      res.status(404).json({ error: 'initiative not found' });
      return;
    }
    res.json(initiative);
  });

  router.post('/initiatives', async (req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    const { id, title, description, phases, links, nextCheckAt, needsUser, needsUserReason, blockers } = req.body ?? {};
    if (typeof id !== 'string' || !initiativeIdRe.test(id)) {
      res.status(400).json({ error: '"id" must be lowercase kebab-case, 1–63 chars' });
      return;
    }
    if (typeof title !== 'string' || !title.trim() || title.length > 200) {
      res.status(400).json({ error: '"title" required, ≤200 chars' });
      return;
    }
    if (typeof description !== 'string' || description.length > 4000) {
      res.status(400).json({ error: '"description" required, ≤4000 chars' });
      return;
    }
    if (!Array.isArray(phases) || phases.length === 0) {
      res.status(400).json({ error: '"phases" must be a non-empty array' });
      return;
    }
    try {
      const created = await ctx.initiativeTracker.create({
        id, title, description, phases, links, nextCheckAt,
        needsUser, needsUserReason, blockers,
      });
      res.status(201).json(created);
    } catch (err) {
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  router.patch('/initiatives/:id', async (req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    if (!initiativeIdRe.test(req.params.id)) {
      res.status(400).json({ error: 'invalid initiative id' });
      return;
    }
    try {
      const updated = await ctx.initiativeTracker.update(req.params.id, req.body ?? {});
      res.json(updated);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      const status = msg.includes('not found') ? 404 : 400;
      res.status(status).json({ error: msg });
    }
  });

  router.post('/initiatives/:id/phase/:phaseId', async (req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    const { status } = req.body ?? {};
    if (!['pending', 'in-progress', 'done', 'blocked'].includes(status)) {
      res.status(400).json({ error: '"status" must be one of pending|in-progress|done|blocked' });
      return;
    }
    try {
      const updated = await ctx.initiativeTracker.setPhaseStatus(req.params.id, req.params.phaseId, status);
      res.json(updated);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      res.status(msg.includes('not found') ? 404 : 400).json({ error: msg });
    }
  });

  router.delete('/initiatives/:id', async (req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    const removed = await ctx.initiativeTracker.remove(req.params.id);
    if (!removed) {
      res.status(404).json({ error: 'initiative not found' });
      return;
    }
    res.json({ id: req.params.id, deleted: true });
  });

  // ── Projects (project-scope, Phase 1a PR 2) ─────────────────────
  //
  // Subset of Phase 1.3 endpoints from PROJECT-SCOPE-SPEC.md. Full
  // advance/halt/ack endpoints ship in PR 3 (skill) + Phase 1b (runner).
  //
  // Auth is enforced globally by `authMiddleware` on the AgentServer; we
  // don't re-check the bearer here. Rate limiting on POST /projects is
  // enforced via a small per-token counter in `.instar/local/projects-rate.json`.

  router.get('/projects', (_req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    const items = ctx.initiativeTracker.list({ kind: 'project' });
    res.json({ items, count: items.length });
  });

  router.get('/projects/:id', async (req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    if (!initiativeIdRe.test(req.params.id)) {
      res.status(400).json({ error: 'invalid project id' });
      return;
    }
    const project = ctx.initiativeTracker.get(req.params.id);
    if (!project || (project.kind ?? 'task') !== 'project') {
      res.status(404).json({ error: 'project not found' });
      return;
    }
    // Join children that point at this project via parentProjectId.
    let children = ctx.initiativeTracker
      .list()
      .filter((i) => i.parentProjectId === project.id);

    // Lazy merged-state reconciler — spec § Phase 1.4 lines 256-258.
    //
    // GET /projects/:id is documented as "may mutate": when a 'building' child's
    // mergeCommitOid is no longer ancestor of origin/main, we transition it to
    // 'regressed' and clear future autoAdvanceAt on its round.
    //
    // Selection contract:
    //   - debounce: skip any child with `ciCheckedAt < 6h ago`
    //   - cap: at most 3 child-revalidations per GET
    //   - order: oldest `ciCheckedAt` first (treat undefined as 1970), ties broken
    //     by `roundIndex` ASC, then `itemId` ASC — no child can starve.
    //   - opt-out: `?reconcile=false` (or `?reconcile=0`) skips entirely
    const reconcileFlag = req.query.reconcile;
    const wantReconcile = reconcileFlag !== 'false' && reconcileFlag !== '0';
    if (wantReconcile && project.targetRepoPath) {
      const nowMs = Date.now();
      const debounceMs = 6 * 60 * 60 * 1000; // 6 hours
      const roundIndexOf = (childId: string): number => {
        const rounds = project.rounds ?? [];
        for (let i = 0; i < rounds.length; i++) {
          if ((rounds[i].itemIds ?? []).includes(childId)) return i;
        }
        return Number.MAX_SAFE_INTEGER;
      };
      const candidates = children
        .filter((c) => c.pipelineStage === 'building' && typeof c.mergeCommitOid === 'string' && c.mergeCommitOid)
        .filter((c) => {
          const t = c.ciCheckedAt ? Date.parse(c.ciCheckedAt) : 0;
          return !(Number.isFinite(t) && t > 0 && nowMs - t < debounceMs);
        })
        .sort((a, b) => {
          const ta = a.ciCheckedAt ? Date.parse(a.ciCheckedAt) : 0;
          const tb = b.ciCheckedAt ? Date.parse(b.ciCheckedAt) : 0;
          if (ta !== tb) return ta - tb;
          const ra = roundIndexOf(a.id);
          const rb = roundIndexOf(b.id);
          if (ra !== rb) return ra - rb;
          return a.id < b.id ? -1 : a.id > b.id ? 1 : 0;
        })
        .slice(0, 3);
      const candidateIds = candidates.map((c) => c.id);
      if (candidateIds.length > 0) {
        let verified: Set<string> = new Set();
        try {
          verified = await verifyMergedItemsViaGit(project.targetRepoPath, candidateIds, ctx.initiativeTracker);
        } catch {
          // git not available, no network, etc. — leave verified empty so we
          // still update ciCheckedAt to back off; better than a hot loop.
        }
        let touched = false;
        for (const cand of candidates) {
          const child = ctx.initiativeTracker.get(cand.id);
          if (!child) continue;
          const isMerged = verified.has(cand.id);
          try {
            await ctx.initiativeTracker.update(cand.id, {
              pipelineStage: isMerged ? 'merged' : 'regressed',
              ciCheckedAt: new Date(nowMs).toISOString(),
              ifMatch: child.version,
            });
            touched = true;
            if (!isMerged) {
              // On regression: clear future autoAdvanceAt on the child's round
              // so the next round doesn't auto-fire while this one is broken.
              const projAfter = ctx.initiativeTracker.get(project.id);
              const rIdx = roundIndexOf(cand.id);
              if (projAfter && rIdx < (projAfter.rounds ?? []).length) {
                const newRounds = (projAfter.rounds ?? []).map((r, i) =>
                  i > rIdx ? { ...r, autoAdvanceAt: undefined } : r
                );
                try {
                  await ctx.initiativeTracker.update(project.id, {
                    rounds: newRounds,
                    ifMatch: projAfter.version,
                  });
                } catch {
                  // OCC race; next GET will retry.
                }
              }
            }
          } catch {
            // OCC race or validator reject; leave as-is for next GET.
          }
        }
        if (touched) {
          children = ctx.initiativeTracker
            .list()
            .filter((i) => i.parentProjectId === project.id);
        }
      }
    }

    // Optional field selector: `?fields=id,title,pipelineStage`. Used by
    // the dashboard projects selector (Phase 1.10). Always preserves `id`.
    const fieldsParam = typeof req.query.fields === 'string' ? req.query.fields : '';
    if (fieldsParam.trim()) {
      const fields = new Set(
        fieldsParam
          .split(',')
          .map((s) => s.trim())
          .filter(Boolean)
      );
      fields.add('id');
      const pickProj = pickFields(project as unknown as Record<string, unknown>, fields);
      const pickKids = children.map((c) => pickFields(c as unknown as Record<string, unknown>, fields));
      res.json({ project: pickProj, children: pickKids });
      return;
    }
    res.json({ project, children });
  });

  // GET /projects/:id/next — structured next-action payload.
  //
  // Spec § Phase 1.5 (line 268): returns `{ action, params, estimatedCost?,
  // skillCommand? }` for the FIRST round whose status is not 'complete'.
  // Ordering: roundIndex ASC, then pipelineStage ASC, then itemId ASC.
  //
  // Action verbs the spec enumerates (a non-exhaustive contract):
  //   - 'await-user-approval' — first round needs `firstLaunchAckAt`
  //   - 'ack-required'         — unacknowledgedAdvanceCount >= cap
  //   - 'resolve-conflict'     — `awaitingReconciliation` non-empty
  //   - 'accept-partial'       — round is partially-complete
  //   - 'run-spec-converge'    — at least one item is `spec-drafted`
  //   - 'run-drift-check'      — at least one item is `approved`, no fresh
  //                              drift verdict
  //   - 'start-round'          — all preconditions met, ready to fire
  //
  // The endpoint does NOT run the runner's preflight — that's a heavier
  // check at fire time. The action is a hint for the dashboard + skill UI.
  router.get('/projects/:id/next', (req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    if (!initiativeIdRe.test(req.params.id)) {
      res.status(400).json({ error: 'invalid project id' });
      return;
    }
    const project = ctx.initiativeTracker.get(req.params.id);
    if (!project || (project.kind ?? 'task') !== 'project') {
      res.status(404).json({ error: 'project not found' });
      return;
    }
    const rounds = project.rounds ?? [];
    const idx = rounds.findIndex((r) => (r.status ?? 'pending') !== 'complete');
    if (idx === -1) {
      res.status(204).end();
      return;
    }
    const r = rounds[idx];

    // Determine the action verb from project + round state.
    type ActionVerb =
      | 'await-user-approval'
      | 'ack-required'
      | 'resolve-conflict'
      | 'accept-partial'
      | 'run-spec-converge'
      | 'run-drift-check'
      | 'start-round';
    let action: ActionVerb = 'start-round';
    const childrenById = new Map(
      ctx.initiativeTracker
        .list()
        .filter((i) => i.parentProjectId === project.id)
        .map((c) => [c.id, c])
    );
    const itemsForRound = (r.itemIds ?? []).map((id) => childrenById.get(id)).filter(Boolean);

    if ((project.awaitingReconciliation ?? []).length > 0) {
      action = 'resolve-conflict';
    } else if ((r.status ?? 'pending') === 'partially-complete') {
      action = 'accept-partial';
    } else if (idx === 0 && !project.firstLaunchAckAt) {
      action = 'await-user-approval';
    } else if ((project.unacknowledgedAdvanceCount ?? 0) >= 2) {
      action = 'ack-required';
    } else if (itemsForRound.some((c) => c?.pipelineStage === 'spec-drafted')) {
      action = 'run-spec-converge';
    } else if (
      itemsForRound.some(
        (c) => c?.pipelineStage === 'approved' && !r.lastDriftVerdict
      )
    ) {
      action = 'run-drift-check';
    }

    res.json({
      action,
      params: {
        projectId: project.id,
        projectVersion: project.version,
        roundIndex: idx,
        name: r.name,
        itemIds: r.itemIds,
        status: r.status ?? 'pending',
        autoAdvanceAt: r.autoAdvanceAt,
      },
      skillCommand: skillCommandForAction(action, project.id, idx),
    });
  });

  // ── /projects/:id mutating routes (Phase 1b PR 3) ──────────────
  //
  // All mutating endpoints require `If-Match: <version>` (OCC). Missing
  // header → 428. Stale version → 409. Spec § Phase 1.3.
  //
  // /advance is a single-item stage transition driven by StageTransitionValidator.
  // /halt, /ack, /accept-partial route through ProjectRoundRunner.

  function parseIfMatch(req: ExpressRequest, res: ExpressResponse): number | null {
    const header = req.headers['if-match'];
    if (typeof header !== 'string' || !header.trim()) {
      res.status(428).json({ error: 'If-Match header required' });
      return null;
    }
    const n = parseInt(header.replace(/"/g, ''), 10);
    if (!Number.isInteger(n) || n <= 0) {
      res.status(400).json({ error: 'If-Match must be a positive integer version' });
      return null;
    }
    return n;
  }

  function lookupProject(req: ExpressRequest, res: ExpressResponse) {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return null;
    }
    if (!initiativeIdRe.test(req.params.id)) {
      res.status(400).json({ error: 'invalid project id' });
      return null;
    }
    const project = ctx.initiativeTracker.get(req.params.id);
    if (!project || (project.kind ?? 'task') !== 'project') {
      res.status(404).json({ error: 'project not found' });
      return null;
    }
    return project;
  }

  // POST /projects/:id/advance — advance one child item by one stage.
  //
  // Body shape:
  //   {
  //     "itemId": "<child id>",
  //     "fromStage": "<optional explicit current stage>",
  //     "targetStage": "spec-drafted|spec-converged|approved|building|merged|skipped|outline",
  //     "artifact": {
  //       "specPath"?: "...",          // outline → spec-drafted
  //       "prNumber"?: 123,            // building → merged
  //       "taskFlowRecordId"?: "...",  // approved → building
  //       "skippedReason"?: "...",     // any → skipped
  //       "skippedBy"?: "...",         // any → skipped
  //       "unskippedAt"?: "..."        // skipped → outline
  //     }
  //   }
  //
  // The HTTP layer does NOT enforce gates the ProjectRoundRunner already
  // enforces — `/advance` is a single-item transition that operates on
  // child records, not on round status. Round-level invariants (lock,
  // first-launch ack, owner machine, etc.) apply only to /run-round
  // and to the autonomous loop, both of which ship in a later PR.
  router.post('/projects/:id/advance', async (req, res) => {
    const project = lookupProject(req, res);
    if (!project) return;
    if (!ctx.initiativeTracker) return; // narrow for TS
    const ifMatch = parseIfMatch(req, res);
    if (ifMatch === null) return;
    if (ifMatch !== project.version) {
      res.status(409).json({ error: 'version mismatch', currentVersion: project.version });
      return;
    }

    const body = (req.body ?? {}) as {
      itemId?: unknown;
      fromStage?: unknown;
      targetStage?: unknown;
      artifact?: Record<string, unknown>;
    };
    const itemId = typeof body.itemId === 'string' ? body.itemId : '';
    const targetStage = typeof body.targetStage === 'string' ? (body.targetStage as PipelineStage) : null;
    if (!itemId) {
      res.status(400).json({ error: '"itemId" required' });
      return;
    }
    if (!targetStage) {
      res.status(400).json({ error: '"targetStage" required' });
      return;
    }
    const child = ctx.initiativeTracker.get(itemId);
    if (!child || child.parentProjectId !== project.id) {
      res.status(404).json({ error: `child item "${itemId}" not found under project ${project.id}` });
      return;
    }

    if (!project.targetRepoPath) {
      res.status(400).json({ error: 'project has no targetRepoPath; cannot validate artifacts' });
      return;
    }

    const artifact = body.artifact ?? {};
    const validationCtx: StageValidationContext = {
      targetRepoPath: project.targetRepoPath,
      specPath: typeof artifact.specPath === 'string' ? artifact.specPath : undefined,
      prNumber: typeof artifact.prNumber === 'number' ? artifact.prNumber : undefined,
      taskFlowRecordId: typeof artifact.taskFlowRecordId === 'string' ? artifact.taskFlowRecordId : undefined,
      skippedReason: typeof artifact.skippedReason === 'string' ? artifact.skippedReason : undefined,
      skippedBy: typeof artifact.skippedBy === 'string' ? artifact.skippedBy : undefined,
      unskippedAt: typeof artifact.unskippedAt === 'string' ? artifact.unskippedAt : undefined,
      // #866: `building → merged` requires ghPrView + gitMergeBaseIsAncestor, but
      // the validator has NO internal default for these (unlike readSpecFrontmatter,
      // which loadFrontmatter defaults). Without injecting them here EVERY
      // building→merged transition fails GH_PR_VIEW_UNAVAILABLE — i.e. no project
      // item can ever reach `merged` through the live API (found 2026-06-06 closing
      // out multimachine-coherence P0). Both helpers are READ-ONLY git/gh against
      // the project's target repo.
      ghPrView: async (prNumber: number) => {
        const out = execFileSync(
          'gh',
          ['pr', 'view', String(prNumber), '--json', 'state,mergeCommit,statusCheckRollup'],
          { cwd: project.targetRepoPath, encoding: 'utf-8', stdio: ['ignore', 'pipe', 'pipe'] },
        );
        return JSON.parse(out) as import('../core/StageTransitionValidator.js').GhPrView;
      },
      gitMergeBaseIsAncestor: (sha: string, branch: string) => {
        // `merge-base --is-ancestor` is a READ-ONLY verb (in SafeGitExecutor's
        // READONLY_GIT_VERBS) — routed through readSync (the sanctioned read
        // path), not raw execFileSync, per the destructive-tool funnel. It
        // exits 0 (ancestor → readSync returns) or 1 (not → readSync throws).
        try {
          SafeGitExecutor.readSync(['merge-base', '--is-ancestor', sha, branch], {
            cwd: project.targetRepoPath,
            operation: 'projects.advance.mergeBaseIsAncestor',
            stdio: ['ignore', 'ignore', 'ignore'],
          });
          return true; // exit 0 = sha is an ancestor of branch
        } catch { /* @silent-fallback-ok: merge-base --is-ancestor signals via exit code (0 ancestor / 1 not); a non-zero exit IS the negative answer, not a degradation — returning false is the correct, complete result, and the validator surfaces MERGE_COMMIT_UNREACHABLE to the caller. */
          return false; // exit 1 = not an ancestor; any other failure = treat as not-ancestor (validator re-checks)
        }
      },
      // Resolve the canonical-main ref the merge commit must be reachable from.
      // The validator defaults to `origin/main`, but on a dev-agent home `origin`
      // is the agent's FORK while merges land on the upstream remote — so we map
      // the gh-resolved PR repo (e.g. JKHeadley/instar) to the LOCAL remote whose
      // URL points at it and use `<remote>/main`. Falls back to `origin/main`.
      mergeBaseBranch: resolveCanonicalMainRef(project.targetRepoPath),
    };

    const fromStage =
      typeof body.fromStage === 'string'
        ? (body.fromStage as PipelineStage)
        : (child.pipelineStage as PipelineStage | undefined);

    const result = await validateStageTransition(fromStage, targetStage, validationCtx);
    if (!result.ok) {
      res.status(409).json({ error: 'stage transition rejected', code: result.code, reason: result.reason });
      return;
    }

    try {
      const updated = await ctx.initiativeTracker.update(itemId, {
        pipelineStage: targetStage,
        ifMatch: child.version,
      });
      // Bump the project version too so concurrent advance calls don't
      // operate on a stale view. We touch description ("last advance
      // <timestamp>") to force a meaningful update.
      const refreshed = await ctx.initiativeTracker.update(project.id, {
        // No-op-but-bump: nudge `lastTouchedAt` indirectly via update.
        nextCheckAt: project.nextCheckAt,
        ifMatch: project.version,
      });
      res.json({
        item: { id: updated.id, pipelineStage: updated.pipelineStage, version: updated.version },
        project: { id: refreshed.id, version: refreshed.version },
      });
    } catch (err) {
      if (err instanceof Error && err.name === 'OccVersionMismatchError') {
        const cv = (err as Error & { currentVersion?: number }).currentVersion;
        res.status(409).json({ error: 'version mismatch', currentVersion: cv });
        return;
      }
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // POST /projects/:id/halt — kills the active round. Idempotent.
  router.post('/projects/:id/halt', async (req, res) => {
    const project = lookupProject(req, res);
    if (!project) return;
    if (!ctx.projectRoundRunner) {
      res.status(503).json({ error: 'ProjectRoundRunner not configured' });
      return;
    }
    const reason = typeof (req.body ?? {}).reason === 'string' ? (req.body as { reason: string }).reason : 'no reason given';
    try {
      const result = await ctx.projectRoundRunner.halt(project.id, reason);
      if (!result) {
        res.status(409).json({ error: 'project has no halt-able round' });
        return;
      }
      res.json({ id: result.project.id, roundIndex: result.roundIndex, version: result.project.version });
    } catch (err) {
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // POST /projects/:id/ack — record user acknowledgment.
  router.post('/projects/:id/ack', async (req, res) => {
    const project = lookupProject(req, res);
    if (!project) return;
    if (!ctx.projectRoundRunner) {
      res.status(503).json({ error: 'ProjectRoundRunner not configured' });
      return;
    }
    const body = (req.body ?? {}) as { forRoundIndex?: unknown; roundIndex?: unknown };
    const idx = typeof body.forRoundIndex === 'number' ? body.forRoundIndex : (typeof body.roundIndex === 'number' ? body.roundIndex : 0);
    if (!Number.isInteger(idx) || idx < 0) {
      res.status(400).json({ error: '"forRoundIndex" must be a non-negative integer' });
      return;
    }
    try {
      const updated = await ctx.projectRoundRunner.recordAck(project.id, idx);
      if (!updated) {
        res.status(404).json({ error: 'project not found' });
        return;
      }
      res.json({
        id: updated.id,
        firstLaunchAckAt: updated.firstLaunchAckAt,
        lastAckedRoundIndex: updated.lastAckedRoundIndex,
        unacknowledgedAdvanceCount: updated.unacknowledgedAdvanceCount,
        version: updated.version,
      });
    } catch (err) {
      if (err instanceof Error && err.name === 'OccVersionMismatchError') {
        const cv = (err as Error & { currentVersion?: number }).currentVersion;
        res.status(409).json({ error: 'version mismatch', currentVersion: cv });
        return;
      }
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // POST /projects/:id/accept-partial — close a partially-complete round.
  router.post('/projects/:id/accept-partial', async (req, res) => {
    const project = lookupProject(req, res);
    if (!project) return;
    if (!ctx.projectRoundRunner) {
      res.status(503).json({ error: 'ProjectRoundRunner not configured' });
      return;
    }
    const body = (req.body ?? {}) as { roundIndex?: unknown; reason?: unknown; skippedBy?: unknown };
    const idx = typeof body.roundIndex === 'number' ? body.roundIndex : -1;
    const reason = typeof body.reason === 'string' ? body.reason : '';
    const skippedBy = typeof body.skippedBy === 'string' ? body.skippedBy : '';
    if (!Number.isInteger(idx) || idx < 0) {
      res.status(400).json({ error: '"roundIndex" must be a non-negative integer' });
      return;
    }
    if (!reason.trim()) {
      res.status(400).json({ error: '"reason" required' });
      return;
    }
    if (!skippedBy.trim()) {
      res.status(400).json({ error: '"skippedBy" required' });
      return;
    }
    try {
      const result = await ctx.projectRoundRunner.acceptPartial(project.id, idx, reason, skippedBy);
      if (!result) {
        res.status(404).json({ error: 'project or round not found' });
        return;
      }
      res.json({
        id: result.project.id,
        skippedItemIds: result.skippedItemIds,
        version: result.project.version,
      });
    } catch (err) {
      if (err instanceof Error && err.name === 'OccVersionMismatchError') {
        const cv = (err as Error & { currentVersion?: number }).currentVersion;
        res.status(409).json({ error: 'version mismatch', currentVersion: cv });
        return;
      }
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // POST /projects/:id/claim-ownership — multi-machine ownership transfer.
  //
  // Body: {} or { force?: boolean }
  // Header: If-Match: <version> (OCC)
  //
  // Spec § P5: the claimer must (a) commit-and-push the claim before
  // acting on it, (b) wait 60s for git-sync to converge, (c) re-read
  // before any auto-action. This endpoint ONLY records the ownership
  // change; the wait-and-converge happens at the caller level (the
  // round runner, the auto-advance poller, the dashboard). Claim is
  // refused (409) if the current owner's heartbeat is still fresh and
  // `force: true` was not set.
  router.post('/projects/:id/claim-ownership', async (req, res) => {
    const project = lookupProject(req, res);
    if (!project) return;
    if (!ctx.initiativeTracker) return; // narrow for TS
    if (!ctx.machineHeartbeat || !ctx.machineHeartbeat.config) {
      res.status(503).json({ error: 'machine heartbeat not configured' });
      return;
    }
    const ifMatch = parseIfMatch(req, res);
    if (ifMatch === null) return;
    if (ifMatch !== project.version) {
      res.status(409).json({ error: 'version mismatch', currentVersion: project.version });
      return;
    }
    const force = (req.body ?? {}).force === true;
    const heartbeat = ctx.machineHeartbeat.api;
    const currentOwner = project.ownerMachineId;
    const claimer = ctx.machineHeartbeat.config.machineId;
    if (currentOwner === claimer) {
      // Already owned by claimer — idempotent success.
      res.json({ id: project.id, ownerMachineId: claimer, version: project.version, alreadyOwned: true });
      return;
    }
    if (currentOwner && !heartbeat.isStale(currentOwner) && !force) {
      res.status(409).json({
        error: 'current owner heartbeat is still fresh; pass {force:true} to claim anyway',
        currentOwner,
      });
      return;
    }
    try {
      const updated = await ctx.initiativeTracker.update(project.id, {
        ownerMachineId: claimer,
        ifMatch: project.version,
      });
      res.json({
        id: updated.id,
        ownerMachineId: updated.ownerMachineId,
        previousOwner: currentOwner ?? null,
        version: updated.version,
      });
    } catch (err) {
      if (err instanceof Error && err.name === 'OccVersionMismatchError') {
        const cv = (err as Error & { currentVersion?: number }).currentVersion;
        res.status(409).json({ error: 'version mismatch', currentVersion: cv });
        return;
      }
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // ── Multi-Machine Session Pool (§L2): the live machine-pool view ──────
  //
  // GET /pool — router holder + every machine's capacity (nickname, hardware,
  // liveness, load, clock-skew status). Backs the Machines dashboard tab. Always
  // 200 (Bearer-auth via the global middleware); `enabled:false` + an empty/
  // single-machine view on installs where the pool registry isn't wired (dark).
  router.get('/pool', (_req, res) => {
    const sync = ctx.coordinator ? ctx.coordinator.getSyncStatus() : null;
    const machines = ctx.machinePoolRegistry ? ctx.machinePoolRegistry.getCapacities() : [];
    res.json({
      enabled: !!ctx.machinePoolRegistry,
      router: sync
        ? {
            holder: sync.leaseHolder,
            epoch: sync.leaseEpoch,
            holdsLease: sync.holdsLease,
            awakeMachineCount: sync.awakeMachineCount,
            splitBrainState: sync.splitBrainState,
          }
        : null,
      machines,
    });
  });

  // GET /pool/reconciler — Fix #3 observability (Observable Intelligence). The WS1.3
  // OwnershipReconciler's last-tick status, and (with ?topic=N) the read-only per-topic
  // decision explanation — so a stuck cross-machine move is inspectable, not a black box.
  // Bearer-gated like every route; credential-free (topic ids, machine ids, epochs, decision
  // reasons only). 503 when the reconciler is absent (single-machine / pool dark).
  router.get('/pool/reconciler', (req, res) => {
    if (!ctx.ownershipReconciler) {
      res.status(503).json({ error: 'ownership reconciler not active (single-machine / pool dark)' });
      return;
    }
    const topic = typeof req.query.topic === 'string' ? req.query.topic.trim() : '';
    if (topic) {
      res.json({ status: ctx.ownershipReconciler.status(), topic: ctx.ownershipReconciler.explainTopic(topic) });
      return;
    }
    res.json({ status: ctx.ownershipReconciler.status() });
  });

  // GET /pool/stale-owner-release — U4.2 §2.9 (docs/specs/u4-2-stale-owner-release.md,
  // R-r2-6): the FD-7-style telemetry surface the dry-run soak is judged on BEFORE
  // graduation — counters for attempts / would-claims / refusals BY REASON, the
  // evidence-class distribution, P19 give-ups, probe-breaker state, and the last +
  // open episodes. Read-only, credential-free (machine ids, topic ids, verdict
  // labels). 503 when the feature is dark / single-machine / pool dark.
  router.get('/pool/stale-owner-release', (_req, res) => {
    if (!ctx.staleOwnerEngine || !ctx.staleOwnerEngine.isActive()) {
      res.status(503).json({ error: 'stale-owner release not active (feature dark / single-machine / pool dark)' });
      return;
    }
    res.json(ctx.staleOwnerEngine.status());
  });

  // GET /pool/lease-handback — U4.4 (docs/specs/u4-4-lease-handback.md §4): the
  // hand-back reconciler's status (state machine position, hysteresis window,
  // latch visibility — "hand-back suppressed until <t> — operator flip", last
  // episode, per-event counters). Read-only. 503 when the reconciler is absent
  // (single-machine / mesh dark); when merely HARD-DARK (enabled:false) the
  // status answers honestly with enabled:false — the loud-latch visibility the
  // spec requires must survive the feature being off.
  router.get('/pool/lease-handback', (_req, res) => {
    if (!ctx.leaseHandback) {
      res.status(503).json({ error: 'lease hand-back reconciler not constructed (single-machine / mesh dark)' });
      return;
    }
    res.json({ ...ctx.leaseHandback.status(), latch: ctx.leaseHandback.latchRecord() });
  });

  // POST /pool/lease-handback/latch — U4.4 R-r2-5 ("the human always wins", with a
  // MECHANICAL attribution definition): the operator-flip latch marker is WRITTEN
  // BY the explicit flip action itself — the PIN-gated captain-flip lever calls
  // this, and until that lever ships the manual captain-flip playbook's explicit
  // POST step lands here. Writing the latch only SUPPRESSES automation (the safe
  // direction — the reconciler goes fully inert), so Bearer suffices; body:
  // { reason?: string }. NEVER inferred from a transfer's origin.
  router.post('/pool/lease-handback/latch', (req, res) => {
    if (!ctx.leaseHandback) {
      res.status(503).json({ error: 'lease hand-back reconciler not constructed (single-machine / mesh dark)' });
      return;
    }
    const reason = typeof (req.body ?? {}).reason === 'string' ? String((req.body as { reason: string }).reason).slice(0, 300) : undefined;
    const latch = ctx.leaseHandback.latchWrite(reason);
    res.json({ ok: true, latch });
  });

  // DELETE /pool/lease-handback/latch — clear the operator latch EARLY (the
  // re-flip / config-edit path). Clearing RE-ENABLES automation against a human
  // decision, so it is PIN-GATED (checkMandatePin — Know Your Principal): the
  // agent's Bearer token is structurally insufficient to un-latch the human's
  // flip. Body: { pin: "<dashboard PIN>" }.
  router.delete('/pool/lease-handback/latch', (req, res) => {
    if (!ctx.leaseHandback) {
      res.status(503).json({ error: 'lease hand-back reconciler not constructed (single-machine / mesh dark)' });
      return;
    }
    if (!checkMandatePin(req, res)) return; // response already sent on failure
    ctx.leaseHandback.latchClear();
    res.json({ ok: true });
  });

  // GET /pool/poller-count — B5 (multimachine-lease-poll-robustness, Decision 11):
  // the exactly-one-Telegram-listener verdict over the pool — ok (exactly one
  // fresh poller) / dual (≥2 → 409 war) / silence (real zero) / indeterminate (a
  // peer is dark → can't confirm; NEVER a false alarm). Observe-only, never gates.
  // localSaw409 isn't yet plumbed from the lifeline to the server, so the verdict
  // is driven by the heartbeat pollingActive count here (the 409 cross-check is a
  // follow-up); single-machine → ok when self is polling.
  router.get('/pool/poller-count', (_req, res) => {
    const caps = ctx.machinePoolRegistry?.getCapacities() ?? [];
    const verdict = poolPollerVerdict(
      caps.map((c) => ({ machineId: c.machineId, online: c.online, pollingActive: c.pollingActive })),
      false,
    );
    res.json({
      enabled: !!ctx.machinePoolRegistry,
      ...verdict,
      machines: caps.map((c) => ({ machineId: c.machineId, nickname: c.nickname, online: c.online, pollingActive: c.pollingActive })),
    });
  });

  // ── U4.5 — rope-health alerts (u4-5-rope-health-alerts §2) ──
  // The monitor's read surface: current classification + episode state + the
  // deterministic ≤3-sentence digest the rope-health-digest job consumes.
  // Dev-gated: ctx.ropeHealthMonitor is null on the fleet (resolveDevAgentGate
  // dark) → 503; live on a dev agent day one. Bearer-authed via the standard
  // router middleware. `?digest=1` records a digest-emission metric (the job's
  // read); a plain read records nothing extra. Content-scrubbed by construction
  // (rope KIND + machine NICKNAME + relative times only — never IPs/URLs/
  // tailnet names/emails).
  router.get('/mesh/rope-health', (req, res) => {
    const monitor = ctx.ropeHealthMonitor;
    if (!monitor) {
      res.status(503).json({ error: 'rope-health monitor unavailable (monitoring.ropeHealth dark for this agent)' });
      return;
    }
    if (req.query.digest === '1') monitor.recordDigestEmission();
    res.json(monitor.status());
  });

  // G2 nobody-polling silence debounce — module-scoped streak across reads, so a
  // transient handoff-gap silence never reads as confirmed (Adv-F9).
  const G2_NOBODY_POLLING_CONFIRM_OBSERVATIONS = 3;
  let _g2SilenceStreak = 0;
  // GET /mesh-selfheal/g2 — MESH-SELF-HEAL-SPEC §3.2 G2 OBSERVE surface (increment
  // 2: detector + single-claimant election, REPORT-only). Computes the B5 verdict
  // over the live pool, debounces a `silence` across reads (nobodyPollingConfirmObservations),
  // runs the pure G2 decision (who should claim poll-ownership), records the
  // counterfactual to the shared soak ledger, and returns it. OBSERVE-only: it
  // does NOT actuate (no fenced-CAS acquire, no poll-lever write) — the enforce
  // actuation is the next increment. Read-driven: each poll advances the soak.
  router.get('/mesh-selfheal/g2', (_req, res) => {
    const caps = ctx.machinePoolRegistry?.getCapacities() ?? [];
    const sync = ctx.coordinator ? ctx.coordinator.getSyncStatus() : null;
    const selfMachineId = ctx.coordinator?.identity?.machineId ?? null;
    const verdict = poolPollerVerdict(
      caps.map((c) => ({ machineId: c.machineId, online: c.online, pollingActive: c.pollingActive })),
      false,
    );
    // Debounce a silence across reads (Adv-F9: a normal handoff gap is transient
    // and must not trip a claim). Module-scoped streak counter.
    if (verdict.verdict === 'silence') _g2SilenceStreak += 1; else _g2SilenceStreak = 0;
    const silenceConfirmed = _g2SilenceStreak >= G2_NOBODY_POLLING_CONFIRM_OBSERVATIONS;
    // fit (observe approximation): heartbeat-fresh = a candidate that COULD take
    // over polling. In a `silence` NOBODY is polling, so fitness is NOT tied to
    // pollingActive (that would exclude exactly the idle-but-healthy machines that
    // should claim). The enforce increment refines this with the machine-local
    // pollSucceededMonoMs re-verify (post-CAS) + self-exclusion advertisement.
    const machines = caps.map((c) => ({ machineId: c.machineId, fit: !!c.online }));
    const decision = decideNobodyPollingClaim({
      selfMachineId: selfMachineId ?? '(unknown)',
      pollerVerdict: verdict.verdict,
      silenceConfirmed,
      preferredAwakeMachineId: sync?.preferredAwakeMachineId ?? null,
      machines,
      // Peer-evidence-of-global-outage plumbing is the enforce increment; observe
      // never claims a global outage (false → a confirmed silence proceeds to elect).
      globalOutageEvidence: false,
    });
    sharedG2NobodyPollingLedger.recordClaim(decision, new Date().toISOString());
    res.json({
      enabled: !!ctx.machinePoolRegistry,
      verdict,
      silenceStreak: _g2SilenceStreak,
      silenceConfirmed,
      selfMachineId,
      decision,
      ledger: sharedG2NobodyPollingLedger.summary(),
    });
  });

  // GET /pool/poll-cache — WS4.4(f) global pool-cache observability
  // (MULTI-MACHINE-SEAMLESSNESS-SPEC §WS4.4 clause (f)). Read-only: reports
  // whether the shared per-peer poll cache is wired, its TTL + load-shed
  // threshold, the live load-per-core, whether it is currently load-shedding,
  // and the cumulative counters (fan-outs avoided via cache hits + load-sheds,
  // single-flight coalesces). 503 while the dark `ws44PoolCache` flag is off
  // (the ships-dark contract — like /pool/queue), so the route's presence
  // honestly reflects whether the unification is engaged on this agent.
  router.get('/pool/poll-cache', (_req, res) => {
    if (!ctx.poolPollCache) {
      res.status(503).json({
        enabled: false,
        error:
          'pool-cache unification not enabled on this agent (ships dark; multiMachine.seamlessness.ws44PoolCache — dev-agent gated)',
      });
      return;
    }
    res.json(ctx.poolPollCache.snapshot());
  });

  // GET /pool/queue — Durable Inbound Message Queue observability (spec
  // §Observability). Bearer-gated like every route; 503 while the queue is
  // dark/gated (the spec's ships-dark contract). delivered24h EXCLUDES
  // possibly-not-injected rows (success totals never overstate — they are
  // summed separately as deliveredUnconfirmed24h).
  router.get('/pool/queue', (_req, res) => {
    const engine = ctx.getInboundQueue?.() ?? null;
    if (!engine) {
      res.status(503).json({ error: 'inbound queue not enabled on this agent (ships dark; multiMachine.sessionPool.inboundQueue)' });
      return;
    }
    const snap = engine.snapshot();
    res.json({
      enabled: true,
      paused: snap.paused,
      tenure: snap.tenure,
      counts: snap.counts,
      counters: snap.counters,
      held: snap.heldSeqs,
      // §1 storage posture as a live field (round-8 external): this build
      // detects nothing beyond "local filesystem present", reported honestly.
      custodyDurability: 'unknown',
      oldestQueuedAgeMs: snap.counts.oldestQueuedAt ? Math.max(0, Date.now() - Date.parse(snap.counts.oldestQueuedAt)) : null,
    });
  });

  // ── Replicated-store conflict + rollback surfaces (multi-machine-replicated-
  //    store-foundation §7.2/§7.3/§7.4). All Bearer-gated like every route; 503
  //    while the foundation is dark (no store enabled). Signal vs Authority: the
  //    foundation NEVER picks a conflict winner — POST /state/resolve-conflict is
  //    the OPERATOR's authority, surfaced.

  // GET /state/conflicts — the open (unresolved) replicated-store conflicts the
  // union-reader flagged for operator resolution (§7.3 dashboard surface).
  router.get('/state/conflicts', (_req, res) => {
    const store = ctx.conflictStore ?? null;
    if (!store) {
      res.status(503).json({ error: 'replicated-store conflicts not enabled on this agent (ships dark; multiMachine.stateSync.<store>)' });
      return;
    }
    res.json({ enabled: true, open: store.listOpen(), lossCounter: store.lossCounter });
  });

  // GET /state/quarantine — the replicated-store quarantine + rollback view: the
  // currently un-merged (store, origin) pairs (§7.4) + the conflict ledger loss
  // counter. (Per-record receiver quarantine lives in the journal applier; this
  // surface reports the FOUNDATION's rollback/conflict state.)
  router.get('/state/quarantine', (_req, res) => {
    const dropped = ctx.droppedOriginRegistry ?? null;
    const store = ctx.conflictStore ?? null;
    if (!dropped && !store) {
      res.status(503).json({ error: 'replicated-store quarantine not enabled on this agent (ships dark; multiMachine.stateSync.<store>)' });
      return;
    }
    res.json({
      enabled: true,
      droppedOrigins: dropped?.list() ?? [],
      conflictLossCounter: store?.lossCounter ?? 0,
    });
  });

  // POST /state/resolve-conflict — the OPERATOR designates a winner or supplies a
  // merged version (§7.3). Body: { conflictId, winnerOrigin } OR
  // { conflictId, mergedVersion }. EXACTLY ONE of winnerOrigin/mergedVersion. The
  // foundation records the resolution; the operator's chosen/merged record
  // replicates as a normal record. 404 unknown id; 400 bad input; 503 dark.
  router.post('/state/resolve-conflict', (req, res) => {
    const store = ctx.conflictStore ?? null;
    if (!store) {
      res.status(503).json({ error: 'replicated-store conflicts not enabled on this agent (ships dark; multiMachine.stateSync.<store>)' });
      return;
    }
    const body = (req.body ?? {}) as { conflictId?: unknown; winnerOrigin?: unknown; mergedVersion?: unknown };
    const conflictId = typeof body.conflictId === 'string' ? body.conflictId.trim() : '';
    if (!conflictId) {
      res.status(400).json({ error: 'conflictId (string) is required' });
      return;
    }
    const resolution: { winnerOrigin?: string; mergedVersion?: Record<string, unknown> } = {};
    if (typeof body.winnerOrigin === 'string' && body.winnerOrigin.length > 0) resolution.winnerOrigin = body.winnerOrigin;
    if (body.mergedVersion && typeof body.mergedVersion === 'object' && !Array.isArray(body.mergedVersion)) {
      resolution.mergedVersion = body.mergedVersion as Record<string, unknown>;
    }
    try {
      const entry = store.resolveConflict(conflictId, resolution);
      if (!entry) {
        res.status(404).json({ error: `unknown conflictId "${conflictId}"` });
        return;
      }
      res.json({ resolved: true, entry });
    } catch (e) {
      res.status(400).json({ error: (e as Error).message });
    }
  });

  // GET /pool/placement?topic=N — authoritative "which machine is this topic running
  // on, and WHY (deliberately pinned vs. load-placed)" + the current lease-holder.
  // Answerable from ANY machine: a non-holder PROXIES to the holder, whose local pin
  // store is authoritative for the pinned-vs-placed distinction. Closes the gap where
  // a standby session could only INFER its placement and narrate a guess as fact.
  // Read-only — never moves a session. 503 when the pool isn't wired (dark/single).
  router.get('/pool/placement', async (req, res) => {
    const topicRaw = req.query.topic;
    const topicId =
      typeof topicRaw === 'string'
        ? topicRaw.trim()
        : Array.isArray(topicRaw) && topicRaw.length
          ? String(topicRaw[0]).trim()
          : '';
    if (!topicId) {
      res.status(400).json({ error: 'topic (query param) is required, e.g. /pool/placement?topic=13481' });
      return;
    }
    if (!ctx.sessionOwnershipRegistry) {
      res.status(503).json({ error: 'session pool not available (dark / single-machine install)' });
      return;
    }
    // Proxy to the holder when this machine isn't it (its pin store is authoritative).
    const holderUrl = ctx.resolveRouterUrl?.() ?? null;
    if (holderUrl) {
      try {
        const r = await fetch(`${holderUrl}/pool/placement?topic=${encodeURIComponent(topicId)}`, {
          headers: { Authorization: `Bearer ${ctx.config.authToken}` },
        });
        if (r.ok) {
          const j = (await r.json()) as Record<string, unknown>;
          res.json({ ...j, answeredBy: 'holder-proxy' });
          return;
        }
        // proxy returned non-2xx → fall through to a labelled local best-effort answer
      } catch {
        // @silent-fallback-ok — holder unreachable → fall through to the local best-effort
        // answer, which is explicitly labelled `answeredBy: 'local-fallback'` in the response
        // (the caller sees it is degraded; nothing is silently masked).
      }
    }
    const sync = ctx.coordinator ? ctx.coordinator.getSyncStatus() : null;
    const owner = ctx.sessionOwnershipRegistry.ownerOf(topicId);
    const pin = ctx.topicPinStore?.get(topicId) ?? null;
    const pinnedTo = pin && pin.pinned ? pin.preferredMachine : null;
    const nicknameOf = (id: string | null): string | null =>
      id ? (ctx.machinePoolRegistry?.getCapacity(id)?.nickname ?? null) : null;
    const description = describeTopicPlacement({
      topicId,
      owner,
      pinnedTo,
      leaseHolder: sync?.leaseHolder ?? null,
      selfMachineId: ctx.meshSelfId ?? null,
      nicknameOf,
    });
    // WS1.3 (MULTI-MACHINE-SEAMLESSNESS-SPEC): a pin that disagrees with live
    // ownership is a first-class PENDING state, surfaced honestly with its age —
    // never a silent internal contradiction (the 2026-06-12 stuck-divergence
    // incident). `since` is the conflicting pin's own set-time: the divergence
    // cannot predate the pin that defines it.
    const pendingReplacement = !!(pinnedTo && owner && owner !== pinnedTo);
    // U4.2 §2.9 (R-r2 minor): `ownershipLeaseState` DERIVED from record status +
    // evidence state per the spec's table (held | stale | releasing | claimed).
    // Absent when the stale-owner engine is dark (no evidence state to derive
    // from beyond the record itself — still derived, evidence inputs false).
    const ownershipLeaseState = await (async () => {
      try {
        const { deriveOwnershipLeaseState } = await import('../core/StaleOwnerReleaseEngine.js');
        const record = ctx.sessionOwnershipRegistry!.read(topicId);
        const engineStatus = ctx.staleOwnerEngine?.isActive() ? ctx.staleOwnerEngine.status() : null;
        const evidenceEpisodeOpen = !!engineStatus?.openEpisodes.some((e) => e.owner === record?.ownerMachineId);
        const suspensionAnnotationPresent = typeof record?.nonce === 'string' && record.nonce.includes(':stale-owner-release:');
        return deriveOwnershipLeaseState(record, { evidenceEpisodeOpen, suspensionAnnotationPresent });
      } catch {
        return null; /* @silent-fallback-ok — a derivation fault omits the ADVISORY field; owner/pin/lease facts above stay authoritative */
      }
    })();
    // U4.1 §2D: the VERIFIED pin actuation state — `pinState` (actuated | pending |
    // diverged | suspended-pending-owner-return; readers tolerate the U4.2 joint
    // value from day one) + `pinHeldSince` (the winning record's HLC PHYSICAL
    // component, never a separate wall-clock read). Derived by the reconciler when
    // wired; a pin-only fallback keeps the read honest on a reconciler-less install.
    const pinStateBlock = (() => {
      try {
        if (ctx.ownershipReconciler) {
          const r = ctx.ownershipReconciler.pinStateOf(topicId);
          if (r.pinned && r.pinState) {
            return {
              pinState: r.pinState,
              ...(r.pinHeldSince !== undefined ? { pinHeldSince: r.pinHeldSince } : {}),
              ...(r.pendingReason ? { pendingReason: r.pendingReason } : {}),
            };
          }
          return null;
        }
        if (pin && pin.pinned) {
          const heldSince = pin.hlc?.physical ?? Date.parse(pin.updatedAt);
          return {
            pinState: owner === pin.preferredMachine ? 'actuated' : 'pending',
            ...(Number.isFinite(heldSince) ? { pinHeldSince: heldSince } : {}),
          };
        }
        return null;
      } catch {
        return null; /* @silent-fallback-ok — a derivation fault omits the ADVISORY pinState block; owner/pin/lease facts stay authoritative */
      }
    })();
    // U4.1 §2F: pinnedBy is LOCAL-ONLY provenance, serve-time LENGTH-CLAMPED on
    // this Bearer-gated read surface (never replicated).
    const clamp = (s: unknown, n = 128) => (typeof s === 'string' ? s.slice(0, n) : '');
    const pinnedByBlock = pin?.pinnedBy
      ? {
          pinnedBy: pin.pinnedBy.kind === 'operator'
            ? { kind: 'operator' as const, platform: clamp(pin.pinnedBy.platform, 32), uid: clamp(pin.pinnedBy.uid, 64) }
            : { kind: 'agent' as const, sessionRef: clamp((pin.pinnedBy as { sessionRef?: string }).sessionRef, 64) },
        }
      : {};
    res.json({
      ...description,
      pendingReplacement,
      ...(pendingReplacement && pin ? { pendingSince: pin.updatedAt } : {}),
      ...(pinStateBlock ?? {}),
      ...pinnedByBlock,
      ...(ownershipLeaseState ? { ownershipLeaseState } : {}),
      answeredBy: holderUrl ? 'local-fallback' : 'local',
    });
  });

  // POST /pool/transfer — deterministic topic transfer that does NOT depend on
  // natural-language phrasing. Body: { topic, to: "<nickname|machineId>", confirm? }.
  // Runs the SAME validated planner as "move this to <nickname>" (rate-limit, online,
  // already-there checks), sets the placement pin, and releases local ownership so the
  // next message re-places onto the target. A non-holder PROXIES to the holder (whose
  // pin store drives routing). This is the reliable lever a session can call directly
  // instead of hoping a phrase is recognized. 503 when the pool isn't wired (dark).
  router.post('/pool/transfer', async (req, res) => {
    const body = (req.body ?? {}) as { topic?: unknown; to?: unknown; confirm?: unknown };
    const topicId = body.topic != null ? String(body.topic).trim() : '';
    const to = typeof body.to === 'string' ? body.to.trim() : '';
    if (!topicId || !to) {
      res.status(400).json({ error: 'topic and to are required, e.g. {"topic":13481,"to":"Laptop"}' });
      return;
    }
    if (!ctx.sessionOwnershipRegistry || !ctx.topicPinStore) {
      res.status(503).json({ error: 'session pool not available (dark / single-machine install)' });
      return;
    }
    // The holder's pin store drives routing — proxy there when this machine isn't it.
    const holderUrl = ctx.resolveRouterUrl?.() ?? null;
    if (holderUrl) {
      try {
        const r = await fetch(`${holderUrl}/pool/transfer`, {
          method: 'POST',
          headers: { Authorization: `Bearer ${ctx.config.authToken}`, 'Content-Type': 'application/json' },
          body: JSON.stringify({ topic: topicId, to, confirm: body.confirm === true }),
        });
        // @silent-fallback-ok — if the holder's body isn't JSON we still forward its
        // status code with an empty object; the status is the signal, not the body.
        const j = (await r.json().catch(() => ({}))) as Record<string, unknown>;
        res.status(r.status).json({ ...j, handledBy: 'holder-proxy' });
      } catch (err) {
        // @silent-fallback-ok — NOT silent: a failed proxy surfaces an explicit 502 with the
        // reason to the caller (the transfer did not happen), rather than masking the failure.
        res.status(502).json({ error: `could not reach lease-holder to perform transfer: ${err instanceof Error ? err.message : String(err)}` });
      }
      return;
    }
    // We are the holder (or single-machine) — perform authoritatively.
    const self = ctx.meshSelfId ?? null;
    const caps = ctx.machinePoolRegistry?.getCapacities() ?? [];
    // Resolve THIS machine's own nickname robustly (not caps-only): a machine's capacity
    // view can omit its own nickname (the live-caught self-nickname gap). The
    // self-nickname convergence task persists it into caps; this resolver is the
    // consistent path + boot-window backstop.
    const selfNickname = resolveSelfNickname({ selfMachineId: self, localCapacities: caps });
    const { nickToMachine, knownNicknames } = buildRelocationNicknameSet({ capacities: caps, selfMachineId: self, selfNickname });
    const knownMachineIds = new Set(caps.map((c) => c.machineId));
    // Resolve `to` as a nickname OR a raw machineId, so callers can use either.
    const resolveTarget = (n: string): string | null => {
      const byNick = nickToMachine.get(n.trim().toLowerCase());
      if (byNick) return byNick;
      if (knownMachineIds.has(n)) return n;
      if (self && n === self) return self;
      return null;
    };
    // WS1.4: a LIVE autonomous run on this topic (this machine's stateDir is
    // the run registry — the run lives where its state file lives).
    const liveAutonomousRun = (sk: string): { goal: string | null; remainingMinutes: number | null } | null => {
      try {
        const job = listAutonomousJobs(ctx.config.stateDir).find((j) => j.topic === sk && j.active && !j.paused);
        if (!job) return null;
        let remainingMinutes: number | null = null;
        if (job.startedAt && job.durationSeconds != null) {
          const endMs = Date.parse(job.startedAt) + job.durationSeconds * 1000;
          if (Number.isFinite(endMs)) remainingMinutes = Math.max(0, Math.round((endMs - Date.now()) / 60_000));
        }
        return { goal: job.goal, remainingMinutes };
      } catch { return null; /* @silent-fallback-ok — unreadable run registry → veto not applied; the transfer behaves as before WS1.4 */ }
    };
    const plan = planTransferByNickname(
      { intent: 'transfer', nickname: to, matchedVerb: 'transfer' },
      {
        resolveNickname: resolveTarget,
        validNicknames: () => knownNicknames,
        isOnline: (m) => m === self || (ctx.machinePoolRegistry?.getCapacity(m)?.online ?? false),
        currentOwnerOf: (sk) => ctx.sessionOwnershipRegistry!.ownerOf(sk),
        isMidReply: () => false,
        lastPlacementUpdateAt: (sk) => ctx.topicPinStore!.lastUpdatedAtMs(sk) ?? null,
        now: () => Date.now(),
        // WS1.4 consent gate. NOT suppressed on confirm:true — the planner
        // stacks every live condition into ONE prompt + '+'-joined detail, so
        // the confirmed call re-evaluates the full chain and a confirm can
        // never silently consent to a condition the caller was not shown
        // (second-pass finding, 2026-06-13).
        autonomousRunActive: liveAutonomousRun,
      },
      topicId,
    );
    if (plan.action === 'reject') {
      res.status(plan.rejectReason === 'unknown-machine-nickname' ? 404 : 409).json({
        error:
          plan.rejectReason === 'unknown-machine-nickname'
            ? `unknown machine "${to}". Known: ${(plan.validNicknames ?? []).join(', ') || '(none)'}`
            : `cannot transfer right now (${plan.rejectReason})`,
        rejectReason: plan.rejectReason,
      });
      return;
    }
    if (plan.action === 'confirm-required' && body.confirm !== true) {
      // `detail` names every condition the confirm would consent to
      // ('+'-joined) — callers relay the prompt, which already states all of them.
      res.status(409).json({ needsConfirmation: true, prompt: plan.confirmationPrompt, targetMachine: plan.targetMachine, detail: plan.detail });
      return;
    }
    // transfer | noop | confirmed → set the pin and release local ownership if we hold it.
    const target = plan.targetMachine!;
    // ── WS1.2 drain leg (MULTI-MACHINE-SEAMLESSNESS-SPEC): an ACTIVE
    // conversation's transfer must COMPLETE, not half-move. When the topic has
    // a current owner that can drain — itself (the live-swap topology: owner ==
    // holder == this machine) or a remote peer that is online AND advertises
    // ws12DrainReceive in its heartbeat — order the drain BEFORE the pin:
    // finish the in-flight turn (bounded), suspend any autonomous run, close
    // the owner's session, land the target's claim (the queue-barrier release).
    //   · drain ok → proceed to pin+journal exactly as today (the place/claim
    //     repair below sees active@target and correctly no-ops).
    //   · aborted-emergency-stop → 409 failed-needs-retry, NO pin — an abort
    //     leaves nothing split (the topic stays whole on its current machine).
    //   · refused-*/no-handler/timeout/no-flag → DEGRADE to today's pin path
    //     (recorded in the response; the reconciler + closeout converge it).
    // The capability gate means an old peer is never sent a doomed order.
    let drainLeg: { attempted: boolean; ok?: boolean; status?: string; reason?: string } = { attempted: false };
    let drainRunSuspended = false;
    try {
      const currentOwner = plan.action !== 'noop' ? ctx.sessionOwnershipRegistry.ownerOf(topicId) : null;
      const ownerCap = currentOwner && currentOwner !== self ? ctx.machinePoolRegistry?.getCapacity(currentOwner) : null;
      const ownerCanDrain =
        currentOwner != null &&
        currentOwner !== target &&
        ctx.sendDrain != null &&
        (currentOwner === self ||
          ((ownerCap?.online ?? false) && ownerCap?.seamlessnessFlags?.ws12DrainReceive === true));
      if (ownerCanDrain) {
        const observedEpoch = ctx.sessionOwnershipRegistry.read(topicId)?.ownershipEpoch ?? 0;
        const r = await ctx.sendDrain!(currentOwner!, topicId, target, observedEpoch);
        drainLeg = { attempted: true, ok: r.ok, status: r.status, reason: r.reason };
        drainRunSuspended = r.runSuspended === true;
        if (r.status === 'aborted-emergency-stop') {
          res.status(409).json({
            error: 'transfer aborted: emergency stop fired during the drain — the topic stays whole on its current machine',
            failedNeedsRetry: true,
            drain: drainLeg,
          });
          return;
        }
      }
    } catch (err) {
      // @silent-fallback-ok — NOT silent: recorded in the response's drain field;
      // the transfer degrades to today's pin path (the safe direction — never a
      // half-drain). A drain failure must never fail the transfer itself.
      drainLeg = { attempted: true, ok: false, reason: err instanceof Error ? err.message : String(err) };
    }
    // WS1.4 confirmed move: suspend the in-flight autonomous run AT ITS NEXT
    // TURN BOUNDARY (active:false releases the stop hook) while the state file
    // SURVIVES to ride the working-set carrier — the atomic fsync'd rewrite +
    // the journal `stopped` emit (which re-fires the receiver's working-set
    // pull) happen inside the suspend. Runs before the pin/release so the
    // re-fired pull sees the final, consistent file. Only fires for a real
    // move (noop/already-there never suspends).
    let autonomousRunSuspended = false;
    if (plan.action !== 'noop' && liveAutonomousRun(topicId)) {
      try {
        autonomousRunSuspended = suspendAutonomousTopicForMove(
          ctx.config.stateDir, topicId, target, ctx.state.getCoherenceJournal() ?? undefined,
        ).suspended;
      } catch (err) {
        // NOT silent: a failed suspend is reported in the response below
        // (autonomousRunSuspended:false) — the transfer still proceeds (the
        // pin is the user's explicit, confirmed intent), and the run's own
        // stop hook keeps it honest on the old machine.
        console.warn(`[pool/transfer] autonomous-run suspend failed for topic ${topicId}: ${err instanceof Error ? err.message : String(err)}`);
      }
    }
    // ── WS5.3 (escalation-rides-topic) SOURCE capture ───────────────────────
    // When the moving topic has a LIVE session running on the escalated tier,
    // file an EPHEMERAL escalation hint keyed by topic. The destination's
    // acquire pull serves it and RE-ADMITS through its OWN governor — a trigger
    // carry, NEVER a tier grant. Gated under tierEscalation.enabled && ridesTopic
    // (default false ⇒ strict no-op). Honors escalationOverride:'suppress' (a
    // suppressed topic files NO hint — it must never be re-escalated on arrival).
    // Only a REAL move files (noop/already-there never does).
    let escalationHintFiled = false;
    if (plan.action !== 'noop' && ctx.escalationHints) {
      try {
        const teCfg = normalizeTierEscalationConfig(
          (ctx.config as { models?: { tierEscalation?: unknown } }).models?.tierEscalation,
        );
        if (teCfg.enabled && teCfg.ridesTopic) {
          // The topic's live session on THIS machine (the source in the
          // live-swap topology owner==holder==self; a remote-owner move
          // degrades safely — no local session, no hint, default tier).
          const topicNum = Number(topicId);
          const srcSessionName = Number.isFinite(topicNum)
            ? ctx.telegram?.getSessionForTopic?.(topicNum) ?? null
            : null;
          const srcSession = srcSessionName
            ? ctx.sessionManager.getCachedRunningSessions().sessions.find(
                (s) => s.name === srcSessionName || s.tmuxSession === srcSessionName,
              ) ?? null
            : null;
          const escalatedIds = escalatedModelIds(teCfg);
          const isEscalated = srcSession?.model != null && escalatedIds.has(srcSession.model);
          // suppress consult: a 'suppress'-pinned topic files no hint.
          const suppressed =
            ctx.topicProfile?.resolver?.resolve(topicNum)?.escalationOverride === 'suppress';
          if (isEscalated && !suppressed) {
            ctx.escalationHints.file(topicId, {
              trigger: 'transfer', // audit label only — the destination governor re-decides from real state
              sourceTier: 'escalated',
              ...(self ? { sourceMachineId: self } : {}),
            });
            escalationHintFiled = true;
          }
        }
      } catch {
        // @silent-fallback-ok — filing the hint is fire-and-forget enrichment of
        // the transfer: a capture error must never fail the move. Worst case the
        // resumed session re-evaluates escalation only when its heavy-work trigger
        // fires again on the destination (default tier in the meantime — the safe
        // direction, identical to WS5.3 being off).
      }
    }
    // U4.1 §2B — the ONE-HLC pin mutation funnel (fixes the set()-without-hlc
    // gap): the funnel mints ONE HLC inside the replicated emit and stamps the
    // local set() with the SAME stamp, so local and replicated pins compare
    // cleanly under HLC-highest-wins (previously the local pin fell back to a
    // derived wall-clock). Emission stays gated by ws13PinReplicate inside the
    // emitter (dark/single-machine ⇒ local-only set, today's exact behavior).
    // pinnedBy (§2F, Know Your Principal): the topic's auto-bound VERIFIED
    // operator when one exists (never a content name), else the Bearer-authed
    // agent surface — local-only provenance, never replicated.
    try {
      const { setPinWithOneHlc } = await import('../core/TopicPinMutation.js');
      const boundOperator = (() => {
        try {
          const op = ctx.topicOperatorStore?.getOperator(topicId);
          return op && typeof op.uid === 'string' && op.uid
            ? { kind: 'operator' as const, platform: String(op.platform || 'telegram'), uid: op.uid }
            : null;
        } catch { return null; /* @silent-fallback-ok — an unreadable binding degrades to agent provenance, never a blocked pin */ }
      })();
      setPinWithOneHlc(
        { pinStore: ctx.topicPinStore, emitter: ctx.replicatedRecordEmitter ?? null },
        topicId,
        target,
        plan.setPin ?? true,
        boundOperator ?? { kind: 'agent', sessionRef: 'pool-transfer-api' },
      );
    } catch {
      // @silent-fallback-ok — NOT silent to the pin itself: the funnel import/emit
      // failing must never lose the user's explicit move, so fall back to the plain
      // local set (no hlc — the reconciler's documented updatedAt derivation covers it).
      ctx.topicPinStore.set(topicId, target, plan.setPin ?? true);
    }
    let releasedLocalOwnership = false;
    try {
      if (self && ctx.sessionOwnershipRegistry.ownerOf(topicId) === self) {
        const prevOwner = ctx.sessionOwnershipRegistry.read(topicId)?.ownerMachineId;
        const r = ctx.sessionOwnershipRegistry.cas(
          { type: 'release', machineId: self },
          { sessionKey: topicId, sender: self, nonce: `${self}:rel:${topicId}:${Date.now()}` },
        );
        releasedLocalOwnership = r.ok;
        // Coherence journal §3.3: the deterministic transfer API's release half.
        try {
          const topicNum = Number(topicId);
          if (r.ok && Number.isFinite(topicNum)) {
            ctx.state.getCoherenceJournal()?.emitPlacement(topicNum, {
              owner: r.record.ownerMachineId ?? '',
              ...(prevOwner ? { prevOwner } : {}),
              epoch: r.record.ownershipEpoch,
              reason: 'user-move',
            });
          }
        } catch { /* observability never endangers the observed */ }
      }
    } catch {
      // @silent-fallback-ok — the pin (set above) is what drives re-placement; releasing local
      // ownership is a best-effort optimization. If it throws, route() re-places off the pin on
      // the next message regardless, and `releasedLocalOwnership:false` is reported to the caller.
    }
    // Coherence finding #5 (2026-06-06): the transfer's PLACE half. A QUIET topic
    // (never-seen or released ownership record) previously journaled NOTHING on
    // transfer — the pin is router-local and the release half above only fires when
    // this machine held ownership — so the pinned-to machine could never prove
    // ownership and its working-set fetch reflex stayed refused ("not-owner") even
    // after the #926/#930 read-side fallbacks. Land place→claim for the target (the
    // FSM permits the router to confirm a claim on the placed owner's behalf — the
    // bug-#11 confirmClaim precedent), which records a REAL epoch and journals a
    // placement entry that replicates to the target. Claim immediately follows place
    // so the record never rests at 'placing' (a resting 'placing' record queues every
    // later message as ownership-contention). Guarded: place is only legal on
    // never-seen/released records, so an active or in-flight record is never stolen.
    let placedOwnership = false;
    try {
      // Skip only when the target already holds CONFIRMED (active) ownership — a
      // resting 'placing' record naming the target must still fall through to the
      // claim repair below (ownerOf reports an owner for 'placing' records too,
      // which is why this guard reads the record's status directly).
      const cur0 = ctx.sessionOwnershipRegistry.read(topicId);
      if (self && !(cur0?.status === 'active' && cur0.ownerMachineId === target)) {
        const prevOwner = cur0?.ownerMachineId;
        // Each landed CAS journals (§3.3 call-site pairing — placement history
        // never grows a hole): the place half AND the placing→active confirm,
        // exactly like the router's casClaimOwnership/confirmClaim pair. The
        // entry is what the target's wsOwnerOf journal-placement fallback
        // (#930) reads after replication.
        const casAndJournal = (action: { type: 'place'; machineId: string } | { type: 'claim'; machineId: string }, half: string): boolean => {
          const r = ctx.sessionOwnershipRegistry!.cas(action, {
            sessionKey: topicId,
            sender: self,
            nonce: `${self}:${half}:${topicId}:${Date.now()}`,
          });
          if (!r.ok) return false;
          try {
            const topicNum = Number(topicId);
            if (Number.isFinite(topicNum)) {
              ctx.state.getCoherenceJournal()?.emitPlacement(topicNum, {
                owner: r.record.ownerMachineId ?? target,
                ...(prevOwner ? { prevOwner } : {}),
                epoch: r.record.ownershipEpoch,
                reason: 'user-move',
              });
            }
          } catch { /* observability never endangers the observed */ }
          return true;
        };
        if (casAndJournal({ type: 'place', machineId: target }, 'tplace')) {
          placedOwnership = casAndJournal({ type: 'claim', machineId: target }, 'tclaim');
          // TOPIC-PROFILE-SPEC §5.3 acquire seam (deterministic-transfer arm):
          // when THIS machine is the transfer target, the landed tclaim is an
          // ownership ACQUIRE — pull the topic's profile from its previous
          // owner. (target !== self: the target machine fires its own acquire
          // seam when the first forwarded message lands — deliverMessage
          // onAccepted; firing here would stage a pull on a non-owner, which
          // the carrier's apply-time ownership recheck would just discard.)
          if (placedOwnership && target === self && prevOwner && prevOwner !== self) {
            try {
              ctx.topicProfile?.carrier?.onTopicAcquired(topicId, prevOwner);
            } catch {
              /* @silent-fallback-ok: the §5.3 pull is fire-and-forget enrichment of the transfer — a carrier failure must never fail the transfer itself; the durable retry ledger re-files on the next acquire/tick (TOPIC-PROFILE-SPEC §5.3) */
            }
          }
        } else {
          // A resting 'placing' record already naming the target (legacy pre-fix
          // state, or a raced earlier transfer) → confirm the claim (placing→active),
          // the bug-#11 repair. Any other record shape is left strictly untouched.
          const cur = ctx.sessionOwnershipRegistry.read(topicId);
          if (cur?.status === 'placing' && cur.ownerMachineId === target) {
            placedOwnership = casAndJournal({ type: 'claim', machineId: target }, 'tclaim');
            // §5.3 acquire seam — same self-target arm as the place→claim path above.
            if (placedOwnership && target === self && prevOwner && prevOwner !== self) {
              try {
                ctx.topicProfile?.carrier?.onTopicAcquired(topicId, prevOwner);
              } catch {
                /* @silent-fallback-ok: fire-and-forget §5.3 pull — never fails the transfer; the durable ledger re-files (TOPIC-PROFILE-SPEC §5.3) */
              }
            }
          }
        }
      }
    } catch {
      // @silent-fallback-ok — landing the place half is the quiet-topic ownership-evidence
      // repair (coherence finding #5); the pin (set above) still drives re-placement on the
      // next real message, so a CAS failure must never fail the transfer itself.
      // `placedOwnership:false` is reported to the caller.
    }
    // §7.4 (live-user-channel-proof spec): surface whether the seat ACTUALLY moved,
    // not just ok:true. The 2026-06-15 bug was `ok:true` with the topic never moving —
    // a lie-by-omission. The honest signal is the post-transfer owner: did the target
    // end up the active owner? A real transfer that did NOT land that is reported
    // `seatMoved:false` + a reason, so a caller (or the live-test harness) can never
    // read `ok` as `moved`.
    let seatMoved: boolean;
    let seatMoveReason: string | undefined;
    {
      const ownerNow = ctx.sessionOwnershipRegistry.ownerOf(topicId);
      const post = ctx.sessionOwnershipRegistry.read(topicId);
      if (plan.action === 'noop') {
        seatMoved = true; // already-there / no move required — the seat is at the target
      } else if (post?.status === 'active' && ownerNow === target) {
        seatMoved = true; // the target is the confirmed active owner — a real move
      } else {
        seatMoved = false;
        seatMoveReason =
          drainLeg.attempted && drainLeg.ok === false
            ? 'drain failed — the seat did not move (topic stays whole on its current machine)'
            : 'ownership did not transfer to the target (the pin is set, but the target is not the active owner)';
      }
    }
    res.json({
      ok: true,
      // seatMoved is the load-bearing honesty field — ok:true means "request processed",
      // seatMoved means "the conversation actually runs on the target now".
      seatMoved,
      ...(seatMoveReason ? { seatMoveReason } : {}),
      topicId,
      targetMachine: target,
      targetNickname: ctx.machinePoolRegistry?.getCapacity(target)?.nickname ?? null,
      action: plan.action,
      pinned: plan.setPin ?? true,
      releasedLocalOwnership,
      placedOwnership,
      autonomousRunSuspended: autonomousRunSuspended || drainRunSuspended,
      ...(drainLeg.attempted ? { drain: drainLeg } : {}),
      ...(escalationHintFiled ? { escalationHintFiled: true } : {}),
    });
  });

  // POST /pool/unpin — U4.1 §2B: the deliberate UNPIN surface. Body: { topic }.
  // Clears the topic's placement pin through the one-HLC tombstone funnel
  // (`clearPinWithTombstone`), so the clear REPLICATES: a stale replicated PUT
  // on a peer can never silently re-pin the topic the operator just unpinned
  // (the live defect-2 bug — `buildTopicPinTombstone` had ZERO callers). A
  // non-holder PROXIES to the holder (whose pin store drives routing), exactly
  // like POST /pool/transfer. 503 when the pool isn't wired (dark / single).
  router.post('/pool/unpin', async (req, res) => {
    const body = (req.body ?? {}) as { topic?: unknown };
    const topicId = body.topic != null ? String(body.topic).trim() : '';
    if (!topicId) {
      res.status(400).json({ error: 'topic is required, e.g. {"topic":13481}' });
      return;
    }
    if (!ctx.topicPinStore) {
      res.status(503).json({ error: 'session pool not available (dark / single-machine install)' });
      return;
    }
    const holderUrl = ctx.resolveRouterUrl?.() ?? null;
    if (holderUrl) {
      try {
        const r = await fetch(`${holderUrl}/pool/unpin`, {
          method: 'POST',
          headers: { Authorization: `Bearer ${ctx.config.authToken}`, 'Content-Type': 'application/json' },
          body: JSON.stringify({ topic: topicId }),
        });
        // @silent-fallback-ok — if the holder's body isn't JSON we still forward its
        // status code with an empty object; the status is the signal, not the body.
        const j = (await r.json().catch(() => ({}))) as Record<string, unknown>;
        res.status(r.status).json({ ...j, handledBy: 'holder-proxy' });
      } catch (err) {
        // @silent-fallback-ok — NOT silent: a failed proxy surfaces an explicit 502 with
        // the reason (the unpin did not happen), never a masked failure.
        res.status(502).json({ error: `could not reach lease-holder to unpin: ${err instanceof Error ? err.message : String(err)}` });
      }
      return;
    }
    try {
      const { clearPinWithTombstone } = await import('../core/TopicPinMutation.js');
      const r = clearPinWithTombstone(
        { pinStore: ctx.topicPinStore, emitter: ctx.replicatedRecordEmitter ?? null },
        topicId,
      );
      res.json({ topic: topicId, unpinned: true, hadPin: r.hadPin, tombstoneReplicated: r.hlc !== undefined });
    } catch (err) {
      res.status(500).json({ error: `unpin failed: ${err instanceof Error ? err.message : String(err)}` });
    }
  });

  // GET /pool/pin-quarantine — U4.1 §2C: the sticky skew-quarantine set (read-only)
  // + the fold view's status. 503 when the pin fold isn't wired (dark).
  router.get('/pool/pin-quarantine', (_req, res) => {
    if (!ctx.topicPinSkewQuarantine) {
      res.status(503).json({ error: 'pin skew-quarantine not available (pin replication dark on this agent)' });
      return;
    }
    res.json({
      quarantined: ctx.topicPinSkewQuarantine.all(),
      ...(ctx.topicPinFoldView ? { fold: ctx.topicPinFoldView.status() } : {}),
    });
  });

  // POST /pool/pin-quarantine/readmit — U4.1 R-r4-1: the DELIBERATE, explicit
  // per-record re-admission (an authority decision distinct from dismissing the
  // attention NOTIFICATION — acking the alert never re-admits). Body: the exact
  // { key, hlc } pair from GET /pool/pin-quarantine. Forces a full re-fold so the
  // re-admitted record re-enters the comparison; a record STILL beyond the live
  // skew gate simply re-quarantines on that fold (honest — it is still poison by
  // the gate's judgment until wall time catches up).
  router.post('/pool/pin-quarantine/readmit', (req, res) => {
    if (!ctx.topicPinSkewQuarantine) {
      res.status(503).json({ error: 'pin skew-quarantine not available (pin replication dark on this agent)' });
      return;
    }
    const body = (req.body ?? {}) as { key?: unknown; hlc?: unknown };
    const key = typeof body.key === 'string' ? body.key : '';
    const hlc = body.hlc as { physical?: unknown; logical?: unknown; node?: unknown } | undefined;
    if (!key || !hlc || typeof hlc.physical !== 'number' || typeof hlc.logical !== 'number' || typeof hlc.node !== 'string') {
      res.status(400).json({ error: 'key and hlc {physical, logical, node} are required (copy them from GET /pool/pin-quarantine)' });
      return;
    }
    const removed = ctx.topicPinSkewQuarantine.readmit(key, { physical: hlc.physical, logical: hlc.logical, node: hlc.node });
    if (!removed) {
      res.status(404).json({ error: 'no quarantined record matches that (key, hlc) pair' });
      return;
    }
    try { ctx.topicPinFoldView?.resetFold(); } catch { /* the next refresh full-folds regardless of a reset fault */ }
    res.json({ readmitted: true, key, note: 'a full re-fold will re-evaluate the record; if it is still beyond the skew gate it re-quarantines honestly' });
  });

  // GET /secrets/sync-status — read-only view of cross-machine secret-sync (spec Phase 4).
  // Returns WHICH secret key-paths this machine holds (NAMES only — never a value) and the
  // online peers it would sync to. Never exposes a secret value. 503 when sync is disabled.
  router.get('/secrets/sync-status', (_req, res) => {
    const ss = ctx.secretSync;
    if (!ss || !ss.enabled) {
      res.status(503).json({ error: 'secret-sync not available (dark / single-machine install)' });
      return;
    }
    res.json({
      enabled: true,
      pushEnabled: ss.pushEnabled,
      mode: ss.pushEnabled ? 'full' : 'receive-only',
      localKeyPaths: ss.localKeyPaths(),
      // 'decrypt-failed' means the vault has DATA but no resolvable key opens it
      // — categorically different from 'empty' (the 2026-06-05 masking bug).
      vault: ss.vaultStatus ? ss.vaultStatus() : undefined,
      syncTargets: ss.syncTargets(),
    });
  });

  // POST /secrets/sync-now — deterministic push-on-provision lever (spec Phase 4). Encrypts
  // the current secret set per online peer (to that peer's X25519 key) and pushes it. Returns
  // a per-peer result — NEVER a secret value. This is the reliable lever (the analog of
  // POST /pool/transfer) for live-verify and for a manual re-sync. 503 when sync is disabled.
  router.post('/secrets/sync-now', async (_req, res) => {
    const ss = ctx.secretSync;
    if (!ss || !ss.enabled) {
      res.status(503).json({ error: 'secret-sync not available (dark / single-machine install)' });
      return;
    }
    // Receive-only machines refuse to push (safety): they must not send their possibly-stale
    // set to peers. Set multiMachine.secretSync.pushEnabled=true on the AUTHORITATIVE machine.
    if (!ss.pushEnabled) {
      res.status(409).json({
        error: 'push disabled (receive-only). Set multiMachine.secretSync.pushEnabled=true on the machine whose secret store is authoritative.',
        mode: 'receive-only',
      });
      return;
    }
    try {
      const results = await ss.provisionAll();
      res.json({ ok: true, pushed: results.length, results });
    } catch (err) {
      res.status(500).json({ error: `sync failed: ${err instanceof Error ? err.message : String(err)}` });
    }
  });

  // GET /session-pool/e2e-results — the rollout gate's observable state (§Rollout).
  // Read-only; returns the latest E2E result per stage + whether each verifies. The
  // StageAdvancer gates activation on these; this surfaces them (no mutation here).
  router.get('/session-pool/e2e-results', (_req, res) => {
    const store = ctx.sessionPoolE2EResultStore;
    if (!store) {
      res.status(503).json({ error: 'session-pool rollout gate not available (dark / single-machine install)' });
      return;
    }
    const stages = [0, 1, 2, 3];
    const latestPerStage = stages.map((stage) => {
      const row = store.getLatestForStage(stage);
      return { stage, result: row?.result ?? null, commitSha: row?.commitSha ?? null, ranAt: row?.ranAt ?? null, verified: row ? store.verify(row) : null };
    });
    res.json({ latestPerStage, total: store.all().length });
  });

  // PATCH /pool/machines/:id — rename a machine (§L2 user-editable nickname).
  // Body: { nickname: string }. Validates format + pool-uniqueness; a collision
  // is rejected (400), an unknown machine is 404, a malformed nickname is 400.
  // Metadata-only — renaming NEVER moves a session or touches lease/ownership.
  router.patch('/pool/machines/:id', (req, res) => {
    const idMgr = ctx.coordinator?.managers?.identityManager ?? null;
    if (!idMgr) {
      res.status(503).json({ error: 'machine registry not available (single-machine install)' });
      return;
    }
    const nickname = (req.body ?? {}).nickname;
    if (typeof nickname !== 'string') {
      res.status(400).json({ error: 'nickname (string) is required' });
      return;
    }
    try {
      idMgr.updateNickname(req.params.id, nickname);
      res.json({ ok: true, machineId: req.params.id, nickname: nickname.trim() });
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      res.status(/not found/i.test(msg) ? 404 : 400).json({ error: msg });
    }
  });

  // POST /mesh/rpc — the MeshRpc receive endpoint (§L0). Body = a signed,
  // recipient-bound MeshEnvelope. The dispatcher runs verify→RBAC→nonce-burn→
  // handler and returns a typed reason + HTTP status (401/403 auth, 409 freshness,
  // 501 unimplemented). NOTE: m2m authenticity is the ENVELOPE's own Ed25519
  // signature (verified by the dispatcher), independent of the Bearer middleware.
  router.post('/mesh/rpc', async (req, res) => {
    if (!ctx.meshRpcDispatcher) {
      res.status(503).json({ error: 'mesh-rpc not configured (single-machine install)' });
      return;
    }
    const env = req.body;
    if (!env || typeof env !== 'object' || typeof (env as { sender?: unknown }).sender !== 'string') {
      res.status(400).json({ error: 'a signed MeshEnvelope is required' });
      return;
    }
    try {
      const r = await ctx.meshRpcDispatcher.dispatch(env as import('../core/MeshRpc.js').MeshEnvelope);
      if (r.ok) {
        res.json({ ok: true, result: r.result });
      } else {
        res.status(r.status).json({ ok: false, reason: r.reason });
      }
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // POST /projects/:id/drift-check — run the drift checker for a given
  // round and return the verdict. Wraps ProjectDriftChecker.run().
  //
  // Body: { roundIndex: number, specPath: string, referencedFiles: string[],
  //         timeoutMs?: number, modelId?: string }
  //
  // Mutex-guarded per project (spec § Phase 1.5 line 279). Without it two
  // concurrent calls would double-spend the drift-spend ledger and
  // double-bill the LLM. A second concurrent call returns 409 with
  // `{error: 'drift-check already in flight'}` so the caller can poll.
  //
  // 400 on validation; 503 if no checker configured; 200 with verdict envelope
  // on success. We do NOT require If-Match: drift is a read-only signal.
  const driftInFlight: Set<string> = new Set();
  router.post('/projects/:id/drift-check', async (req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    if (!ctx.projectDriftChecker) {
      res.status(503).json({ error: 'ProjectDriftChecker not configured' });
      return;
    }
    if (!initiativeIdRe.test(req.params.id)) {
      res.status(400).json({ error: 'invalid project id' });
      return;
    }
    const project = ctx.initiativeTracker.get(req.params.id);
    if (!project || (project.kind ?? 'task') !== 'project') {
      res.status(404).json({ error: 'project not found' });
      return;
    }
    if (!project.targetRepoPath) {
      res.status(400).json({ error: 'project has no targetRepoPath' });
      return;
    }
    const body = (req.body ?? {}) as {
      roundIndex?: unknown;
      specPath?: unknown;
      referencedFiles?: unknown;
      timeoutMs?: unknown;
      modelId?: unknown;
    };
    const roundIndex = typeof body.roundIndex === 'number' ? body.roundIndex : -1;
    const specPath = typeof body.specPath === 'string' ? body.specPath : '';
    const referencedFiles = Array.isArray(body.referencedFiles)
      ? body.referencedFiles.filter((f): f is string => typeof f === 'string')
      : [];
    if (!Number.isInteger(roundIndex) || roundIndex < 0) {
      res.status(400).json({ error: '"roundIndex" (non-negative integer) required' });
      return;
    }
    if (!specPath.trim()) {
      res.status(400).json({ error: '"specPath" (string) required' });
      return;
    }
    const rounds = project.rounds ?? [];
    if (roundIndex >= rounds.length) {
      res.status(400).json({ error: 'roundIndex out of range', rounds: rounds.length });
      return;
    }
    if (driftInFlight.has(project.id)) {
      res.status(409).json({ error: 'drift-check already in flight for this project' });
      return;
    }
    driftInFlight.add(project.id);
    try {
      const verdict = await ctx.projectDriftChecker.run({
        projectId: project.id,
        roundIndex,
        targetRepoPath: project.targetRepoPath,
        specPath,
        referencedFiles,
        timeoutMs: typeof body.timeoutMs === 'number' ? body.timeoutMs : undefined,
        modelId: typeof body.modelId === 'string' ? body.modelId : undefined,
      });
      res.json({ verdict, projectId: project.id, roundIndex });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    } finally {
      driftInFlight.delete(project.id);
    }
  });

  // POST /projects/:id/run-round — manual round-start trigger.
  //
  // Spec § Phase 1.7: `/project run-round` is the user-invoked entry path.
  // Per § Phase 1.5, every entry path goes through `ProjectRoundRunner.preflight`.
  // On a successful preflight the route schedules the round for the auto-advance
  // poller by setting `autoAdvanceAt = now`; the poller fires the executor on
  // its next tick (≤60s). This avoids spawning a long-running child process
  // from a request handler and keeps a single fire path through the poller.
  //
  // Body: { roundIndex: number }
  // Returns 200 with the preflight verdict + scheduling timestamp on accept,
  // 409 with the preflight reason on reject, 503 if the runner is not wired.
  router.post('/projects/:id/run-round', async (req, res) => {
    const project = lookupProject(req, res);
    if (!project) return;
    if (!ctx.initiativeTracker) return;
    if (!ctx.projectRoundRunner) {
      res.status(503).json({ error: 'ProjectRoundRunner not configured' });
      return;
    }
    const body = (req.body ?? {}) as { roundIndex?: unknown };
    const idx = typeof body.roundIndex === 'number' ? body.roundIndex : 0;
    if (!Number.isInteger(idx) || idx < 0) {
      res.status(400).json({ error: '"roundIndex" must be a non-negative integer' });
      return;
    }
    const rounds = project.rounds ?? [];
    if (idx >= rounds.length) {
      res.status(404).json({ error: `round index ${idx} out of range (0..${rounds.length - 1})` });
      return;
    }
    const verdict = ctx.projectRoundRunner.preflight(project.id, idx);
    if (!verdict.ok) {
      res.status(409).json({ error: 'preflight rejected', code: verdict.code, reason: verdict.reason });
      return;
    }
    try {
      const now = new Date().toISOString();
      const nextRounds = rounds.map((r, i) => (i === idx ? { ...r, autoAdvanceAt: now } : r));
      const updated = await ctx.initiativeTracker.update(project.id, {
        rounds: nextRounds,
        ifMatch: project.version,
      });
      res.json({
        id: updated.id,
        roundIndex: idx,
        scheduledAt: now,
        version: updated.version,
      });
    } catch (err) {
      if (err instanceof Error && err.name === 'OccVersionMismatchError') {
        const cv = (err as Error & { currentVersion?: number }).currentVersion;
        res.status(409).json({ error: 'version mismatch', currentVersion: cv });
        return;
      }
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // POST /projects/:id/resume — resume a halted round.
  //
  // Spec § Phase 1.5: clears `haltedAt`/`haltReason` on the round and schedules
  // it for the auto-advance poller. For rounds with status='failed' that have
  // hit the 3-attempt resume cap (`resumeAttempts >= 3`), the body must include
  // `{ force: true }`; otherwise the route returns 409. Resetting a `failed`
  // round also zeroes `resumeAttempts` so the runner gets a fresh budget.
  //
  // Body: { roundIndex?: number (default 0), force?: boolean }
  router.post('/projects/:id/resume', async (req, res) => {
    const project = lookupProject(req, res);
    if (!project) return;
    if (!ctx.initiativeTracker) return;
    const body = (req.body ?? {}) as { roundIndex?: unknown; force?: unknown };
    const idx = typeof body.roundIndex === 'number' ? body.roundIndex : 0;
    const force = body.force === true;
    if (!Number.isInteger(idx) || idx < 0) {
      res.status(400).json({ error: '"roundIndex" must be a non-negative integer' });
      return;
    }
    const rounds = project.rounds ?? [];
    if (idx >= rounds.length) {
      res.status(404).json({ error: `round index ${idx} out of range (0..${rounds.length - 1})` });
      return;
    }
    const round = rounds[idx];
    if (round.status === 'failed' && (round.resumeAttempts ?? 0) >= 3 && !force) {
      res.status(409).json({
        error: 'round at resume-attempts cap; pass {force:true} to override',
        resumeAttempts: round.resumeAttempts,
      });
      return;
    }
    if (!round.haltedAt && round.status !== 'failed') {
      res.status(409).json({
        error: 'round is not halted or failed',
        status: round.status,
      });
      return;
    }
    try {
      const now = new Date().toISOString();
      const nextRounds = rounds.map((r, i) => {
        if (i !== idx) return r;
        const { haltedAt: _h, haltReason: _r, ...rest } = r;
        const resetAttempts = r.status === 'failed' && force;
        return {
          ...rest,
          status: 'pending' as RoundStatus,
          autoAdvanceAt: now,
          resumeAttempts: resetAttempts ? 0 : r.resumeAttempts,
        };
      });
      const nextStatus = project.status === 'halted' || project.status === 'abandoned' ? 'active' : project.status;
      const updated = await ctx.initiativeTracker.update(project.id, {
        rounds: nextRounds,
        status: nextStatus,
        ifMatch: project.version,
      });
      res.json({
        id: updated.id,
        roundIndex: idx,
        scheduledAt: now,
        forced: force,
        version: updated.version,
      });
    } catch (err) {
      if (err instanceof Error && err.name === 'OccVersionMismatchError') {
        const cv = (err as Error & { currentVersion?: number }).currentVersion;
        res.status(409).json({ error: 'version mismatch', currentVersion: cv });
        return;
      }
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // POST /projects/:id/abandon — archive a halted/failed project.
  //
  // Spec § Phase 1.7: "archive a halted round; children remain at current stage."
  // Sets project.status='abandoned' and clears any future `autoAdvanceAt` on
  // remaining rounds so the poller stops considering them. Children's
  // `pipelineStage` is left untouched (per spec). Idempotent.
  //
  // Refuses (409) if any round is currently in-progress — halt first.
  router.post('/projects/:id/abandon', async (req, res) => {
    const project = lookupProject(req, res);
    if (!project) return;
    if (!ctx.initiativeTracker) return;
    const rounds = project.rounds ?? [];
    const active = rounds.find((r) => r.status === 'in-progress');
    if (active) {
      res.status(409).json({
        error: 'cannot abandon while a round is in-progress; halt the round first',
        activeRound: active.name,
      });
      return;
    }
    if (project.status === 'abandoned') {
      res.json({ id: project.id, status: 'abandoned', version: project.version, alreadyAbandoned: true });
      return;
    }
    try {
      const clearedRounds = rounds.map((r) => {
        if (r.autoAdvanceAt) {
          const { autoAdvanceAt: _x, ...rest } = r;
          return rest;
        }
        return r;
      });
      const updated = await ctx.initiativeTracker.update(project.id, {
        rounds: clearedRounds,
        status: 'abandoned',
        ifMatch: project.version,
      });
      res.json({ id: updated.id, status: updated.status, version: updated.version });
    } catch (err) {
      if (err instanceof Error && err.name === 'OccVersionMismatchError') {
        const cv = (err as Error & { currentVersion?: number }).currentVersion;
        res.status(409).json({ error: 'version mismatch', currentVersion: cv });
        return;
      }
      res.status(400).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  router.post('/projects', async (req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    const planDocPath = (req.body ?? {}).planDocPath;
    if (typeof planDocPath !== 'string' || !planDocPath.trim()) {
      res.status(400).json({ error: '"planDocPath" required (absolute path)' });
      return;
    }

    // ── Rate limit: 5 creates/hour per auth token ──────────────────
    // Per-token counter persisted under `.instar/local/projects-rate.json`.
    // `.instar/local/` is gitignored (Phase 1.12) so the counter never
    // syncs across machines — matches the spec's per-agent semantics.
    const tokenHash = hashAuthHeader(req.headers.authorization);
    const rateCheck = checkAndIncrementProjectsRate(ctx.config.stateDir, tokenHash);
    if (!rateCheck.ok) {
      res.status(429).json({
        error: 'rate limit exceeded',
        windowEnds: rateCheck.windowEnds,
        limit: 5,
      });
      return;
    }

    const { parsePlanDoc } = await import('../core/PlanDocParser.js');
    const parsed = await parsePlanDoc(planDocPath);
    if (!parsed.project || parsed.errors.length > 0) {
      res.status(400).json({
        error: 'plan doc validation failed',
        errors: parsed.errors,
      });
      return;
    }

    // Existing slug? Reject unless `unarchive: true` (Phase 1.6).
    const existing = ctx.initiativeTracker.get(parsed.project.id);
    if (existing) {
      if (existing.status !== 'archived' || parsed.project.unarchive !== true) {
        res.status(409).json({
          error: `project "${parsed.project.id}" already exists`,
          archived: existing.status === 'archived',
        });
        return;
      }
      // Un-archive path is implemented in Phase 1.6 via re-parse rules.
      // Phase 1a defers full re-parse mutation table to PR 3+; for now we
      // reject with a clear message so users don't accidentally clobber.
      res.status(409).json({
        error: 'unarchive flow not yet implemented; archive then re-create with a new id',
      });
      return;
    }

    try {
      const created = await createProjectAndChildren(ctx.initiativeTracker, parsed);
      res.status(201).json(created);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  router.post('/projects/validate', async (req, res) => {
    const planDocPath = (req.body ?? {}).planDocPath;
    if (typeof planDocPath !== 'string' || !planDocPath.trim()) {
      res.status(400).json({ error: '"planDocPath" required (absolute path)' });
      return;
    }
    const { parsePlanDoc } = await import('../core/PlanDocParser.js');
    const parsed = await parsePlanDoc(planDocPath);
    res.json({
      ok: parsed.errors.length === 0 && !!parsed.project,
      project: parsed.project,
      children: parsed.children,
      errors: parsed.errors,
    });
  });

  router.delete('/projects/:id', async (req, res) => {
    if (!ctx.initiativeTracker) {
      res.status(503).json({ error: 'Initiative tracker not configured' });
      return;
    }
    if (!initiativeIdRe.test(req.params.id)) {
      res.status(400).json({ error: 'invalid project id' });
      return;
    }
    const project = ctx.initiativeTracker.get(req.params.id);
    if (!project || (project.kind ?? 'task') !== 'project') {
      res.status(404).json({ error: 'project not found' });
      return;
    }
    // If-Match required for archive (P4: OCC on mutating endpoints).
    const ifMatchHeader = req.headers['if-match'];
    if (typeof ifMatchHeader !== 'string' || !ifMatchHeader.trim()) {
      res.status(428).json({ error: 'If-Match header required for archive' });
      return;
    }
    const ifMatch = parseInt(ifMatchHeader.replace(/"/g, ''), 10);
    if (!Number.isInteger(ifMatch) || ifMatch <= 0) {
      res.status(400).json({ error: 'If-Match must be a positive integer version' });
      return;
    }
    // Refuse archive if any round is in-progress.
    const activeRound = (project.rounds ?? []).find((r) => r.status === 'in-progress');
    if (activeRound) {
      res.status(409).json({
        error: 'cannot archive while a round is in-progress',
        activeRound: activeRound.name,
      });
      return;
    }
    try {
      const updated = await ctx.initiativeTracker.update(project.id, {
        status: 'archived',
        ifMatch,
      });
      res.json({ id: updated.id, status: updated.status, version: updated.version });
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      if (err && (err as Error).name === 'OccVersionMismatchError') {
        const currentVersion = (err as unknown as { currentVersion: number }).currentVersion;
        res.status(409).json({ error: 'version mismatch', currentVersion });
        return;
      }
      res.status(400).json({ error: msg });
    }
  });

